let pokemonCatalogSearchModulePromise = null;
let catalogAliasModulePromise = null;
let emberAssistBrainModulePromise = null;
let catalogImportStatusModulePromise = null;
let calendarDataBundlePromise = null;
let scoutRestockIntelBundlePromise = null;

function loadPokemonCatalogSearchModule() {
  if (!pokemonCatalogSearchModulePromise) {
    pokemonCatalogSearchModulePromise = import("./services/pokemonCatalogSearch");
  }
  return pokemonCatalogSearchModulePromise;
}

async function searchPokemonCatalogOnDemand(options = {}) {
  const catalogSearchModule = await loadPokemonCatalogSearchModule();
  return catalogSearchModule.searchPokemonCatalog(options);
}

async function analyzeCatalogSearchOnDemand(query = "") {
  if (!catalogAliasModulePromise) {
    catalogAliasModulePromise = import("./data/catalogSearchAliases.mjs");
  }
  const catalogAliasModule = await catalogAliasModulePromise;
  return catalogAliasModule.analyzeCatalogSearch(query);
}

function loadEmberAssistBrainModule() {
  if (!emberAssistBrainModulePromise) {
    emberAssistBrainModulePromise = import("./utils/emberAssist");
  }
  return emberAssistBrainModulePromise;
}

async function loadCatalogImportStatusOnDemand() {
  if (!catalogImportStatusModulePromise) {
    catalogImportStatusModulePromise = import("./data/generated/catalogImportStatus.json");
  }
  const statusModule = await catalogImportStatusModulePromise;
  const status = statusModule.default || statusModule;
  return {
    source: "supabase",
    totalCards: status.cardsImported || 0,
    totalSealedProducts: status.sealedProductsImported || 0,
    generatedAt: status.lastImportedAt || "",
    ...status,
  };
}

function renderGenericProductImageFallback(product = {}, options = {}) {
  const fallback = getProductImageFallback(product, {
    title: options.title || product.name || product.productName || product.product_name || product.cardName || product.card_name,
    setName: options.setName || product.setName || product.set_name || product.expansion,
    productType: options.productType || product.productType || product.product_type || product.sealedProductType || product.sealed_product_type,
  });
  const className = ["image-needed-placeholder", "branded-product-fallback", options.className].filter(Boolean).join(" ");
  return (
    <div className={className} hidden={Boolean(options.hidden)}>
      <strong>{fallback.title}</strong>
      <span>{fallback.meta}</span>
      <b>{options.badge || "Photo coming soon"}</b>
    </div>
  );
}

async function loadCalendarDataOnDemand() {
  if (!calendarDataBundlePromise) {
    calendarDataBundlePromise = Promise.all([
      import("./data/generated/releaseCalendar.json"),
      import("./data/generated/dropCalendarSeed.json"),
      import("./data/generated/retailerDropEvents.json"),
      import("./data/generated/calendarSyncStatus.json"),
      import("./utils/calendarDataUtils.mjs"),
      import("./utils/retailerDropSources.mjs"),
    ]).then(([
      releaseCalendarModule,
      dropCalendarSeedModule,
      retailerDropEventsModule,
      calendarSyncStatusModule,
      calendarDataUtils,
      retailerDropSources,
    ]) => ({
      generatedReleaseCalendar: releaseCalendarModule.default || releaseCalendarModule,
      generatedDropCalendarSeed: dropCalendarSeedModule.default || dropCalendarSeedModule,
      generatedRetailerDropEvents: retailerDropEventsModule.default || retailerDropEventsModule,
      calendarSyncStatus: calendarSyncStatusModule.default || calendarSyncStatusModule || EMPTY_CALENDAR_SYNC_STATUS,
      filterCalendarEventsForViewer: calendarDataUtils.filterCalendarEventsForViewer,
      normalizeDropCalendarEvent: calendarDataUtils.normalizeDropCalendarEvent,
      normalizeReleaseCalendarEvent: calendarDataUtils.normalizeReleaseCalendarEvent,
      retailerDropToCalendarEvent: retailerDropSources.retailerDropToCalendarEvent,
    }));
  }
  return calendarDataBundlePromise;
}

async function loadScoutRestockIntelOnDemand() {
  if (!scoutRestockIntelBundlePromise) {
    scoutRestockIntelBundlePromise = import("./data/scoutRestockIntelSeed").then((module) => ({
      scoutHistoricalIntelSeed: module.SCOUT_HISTORICAL_INTEL_SEED || [],
      buildScoutRestockPatterns: module.buildScoutRestockPatterns || (() => []),
    }));
  }
  return scoutRestockIntelBundlePromise;
}

function normalizeLocalCatalogSeedProducts(products = []) {
  return Array.isArray(products)
    ? products.map((product) => ({
      ...product,
      sourceType: product.sourceType || LOCAL_CATALOG_SEED_SOURCE,
      source: product.source || LOCAL_CATALOG_SEED_SOURCE,
    }))
    : [];
}

function catalogProductMergeKey(product = {}) {
  const sourceId = product.externalProductId || product.external_product_id || product.tcgplayerProductId || product.tcgplayer_product_id || "";
  return String(
    product.id ||
      (sourceId ? `${product.marketSource || product.market_source || ""}-${sourceId}` : "") ||
      `${product.catalogType || product.catalog_type || "sealed"}-${product.name || product.productName || product.product_name || product.cardName || product.card_name || ""}-${product.setName || product.set_name || product.expansion || ""}-${product.productType || product.product_type || ""}`
  ).toLowerCase();
}

function mergeCatalogProductLists(...lists) {
  const seen = new Set();
  return lists.flat().filter(Boolean).filter((product) => {
    const key = catalogProductMergeKey(product);
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

