const MASTER_CARD_GROUPING_PREVIEW_CARDS = (emberTideData.masterCards || []).map((masterCard) => {
  const variants = (masterCard.variants || []).map((variant) => ({
    ...variant,
    wantedCount: Number(variant.ownedCount || 0) > 0 ? 0 : 1,
    isPreview: true,
  }));
  const ownedTotal = Number(masterCard.ownedTotal || variants.reduce((sum, variant) => sum + Number(variant.ownedCount || 0), 0));
  const variantOwnedCount = variants.filter((variant) => Number(variant.ownedCount || 0) > 0).length;
  const variantWantedCount = variants.filter((variant) => Number(variant.ownedCount || 0) < 1).length;
  return {
    ...masterCard,
    id: `preview-${masterCard.id}`,
    isPreview: true,
    ownedTotal,
    variantCount: variants.length,
    variantOwnedCount,
    variantWantedCount,
    totalEstimatedValue: variants.reduce((sum, variant) => (
      sum + Number(variant.estimatedValue || 0) * Math.max(1, Number(variant.ownedCount || 0))
    ), 0),
    variants,
  };
});

function masterCardTextKey(value = "") {
  return normalizeSearchText(value).replace(/\s+/g, "-");
}

function masterCardDisplayName(item = {}) {
  return String(item.cardName || item.card_name || item.name || item.itemName || item.item_name || item.catalogProductName || item.catalog_product_name || "Card").trim();
}

function masterCardSetName(item = {}) {
  return String(item.setName || item.set_name || item.expansionOfficialName || item.expansion_official_name || item.expansion || item.productLine || item.product_line || "Set unknown").trim();
}

function masterCardSetCode(item = {}) {
  return String(item.setCode || item.set_code || item.expansionCode || item.expansion_code || item.expansionId || item.expansion_id || "").trim();
}

function masterCardNumber(item = {}) {
  return String(
    item.cardNumber ||
    item.card_number ||
    item.collectorNumber ||
    item.collector_number ||
    item.number ||
    vaultCardNumberLabel(item) ||
    ""
  ).trim();
}

function masterCardIdentityKey(item = {}) {
  const canonical = getCanonicalCardKey(item);
  if (canonical && !canonical.startsWith("product:")) return canonical;
  const name = masterCardTextKey(masterCardDisplayName(item));
  const setName = masterCardTextKey(masterCardSetName(item));
  const number = masterCardTextKey(masterCardNumber(item));
  if (name && setName && number) return `card:${setName}|number:${number}|title:${name}`;
  if (name && setName) return `card:${setName}|title:${name}`;
  if (name && number) return `card:number:${number}|title:${name}`;
  return name ? `card:title:${name}` : "";
}

function normalizeMasterCardCondition(value = "") {
  const text = normalizeSearchText(value);
  if (!text) return "";
  if (text.includes("mint") && !text.includes("near")) return "mint";
  if (text.includes("near mint") || text === "nm") return "near_mint";
  if (text.includes("light")) return "light_play";
  if (text.includes("moderate")) return "moderate_play";
  if (text.includes("heavy")) return "heavy_play";
  if (text.includes("damaged")) return "damaged";
  if (text.includes("sealed")) return "sealed";
  return "";
}

function inferMasterCardVariantType(item = {}) {
  if (item.graded || item.grade || item.gradingCompany || item.grading_company) return "graded";
  const text = normalizeSearchText([
    item.variantType,
    item.variant_type,
    item.variant,
    item.variantName,
    item.variant_name,
    item.finish,
    item.printing,
    item.priceSubtype,
    item.price_subtype,
    item.rarity,
    item.productType,
    item.product_type,
    item.condition,
    item.conditionName,
    vaultVariantLabel(item),
  ].filter(Boolean).join(" "));
  if (text.includes("special illustration")) return "special_illustration";
  if (text.includes("illustration")) return "illustration";
  if (text.includes("full art")) return "full_art";
  if (text.includes("secret")) return "secret";
  if (text.includes("promo")) return "promo";
  if (text.includes("stamp") || text.includes("staff") || text.includes("prerelease")) return "stamped";
  if (text.includes("master ball") || text.includes("masterball")) return "masterball";
  if (text.includes("poke ball") || text.includes("pokeball")) return "pokeball";
  if (text.includes("reverse")) return "reverse_holo";
  if (text.includes("holo")) return "holo";
  if (text.includes("etched")) return "etched";
  if (text.includes("foil")) return "foil";
  if (text.includes("sealed")) return "sealed_related";
  if (text.includes("normal") || text.includes("standard") || text.includes("regular")) return "normal";
  return "other";
}

function masterCardVariantLabel(item = {}) {
  const explicit = String(item.variantLabel || item.variant_label || item.variantName || item.variant_name || item.variant || "").trim();
  if (explicit) return explicit;
  const grade = String(item.grade || "").trim();
  const gradingCompany = String(item.gradingCompany || item.grading_company || "").trim();
  if (grade || gradingCompany) return [gradingCompany || "Graded", grade ? `Grade ${grade}` : ""].filter(Boolean).join(" ");
  const setMasteryLabel = vaultVariantLabel(item);
  if (setMasteryLabel && !/unknown/i.test(setMasteryLabel)) return setMasteryLabel;
  const type = inferMasterCardVariantType(item);
  return MASTER_CARD_VARIANT_LABELS[type] || "Variant";
}

function masterCardLooksLikeCard(item = {}) {
  if (!item || isInventorySealedProduct(item)) return false;
  if (isInventoryCardProduct(item)) return true;
  const typeText = normalizeSearchText([
    item.productType,
    item.product_type,
    item.category,
    item.recordType,
    item.record_type,
    item.status,
    item.rarity,
    item.grade,
    item.gradingCompany,
    item.grading_company,
  ].filter(Boolean).join(" "));
  return Boolean(masterCardNumber(item) || /\bcard\b|\bpromo\b|\bgraded\b|\bslab\b/.test(typeText));
}

function buildMasterCardsFromItems(records = []) {
  const groups = new Map();
  records.filter(Boolean).forEach((record) => {
    if (!masterCardLooksLikeCard(record)) return;
    const key = masterCardIdentityKey(record);
    if (!key) return;
    const name = masterCardDisplayName(record);
    const setName = masterCardSetName(record);
    const cardNumber = masterCardNumber(record);
    const setCode = masterCardSetCode(record);
    const isWishlist = isWishlistLikeVaultItem(record);
    const ownedCount = isWishlist ? 0 : Math.max(0, Number(record.quantity || record.ownedQuantity || record.owned_count || 1));
    const wantedCount = isWishlist ? Math.max(1, Number(record.quantityWanted || record.wantedQuantity || record.quantity || 1)) : 0;
    const variantType = inferMasterCardVariantType(record);
    const variantLabel = masterCardVariantLabel(record);
    const condition = normalizeMasterCardCondition(record.conditionName || record.condition || (isInventorySealedProduct(record) ? "sealed" : ""));
    const grade = String(record.grade || "").trim();
    const gradingCompany = String(record.gradingCompany || record.grading_company || "").trim();
    const variantKey = [
      variantType,
      masterCardTextKey(variantLabel),
      condition,
      gradingCompany,
      grade,
    ].filter(Boolean).join("|") || "variant";
    const estimatedValue = firstKnownVaultNumber(
      record.marketPrice,
      record.market_price,
      record.marketValue,
      record.market_value,
      record.estimatedValue,
      record.estimated_value,
      record.targetPrice,
      record.target_price,
    );

    if (!groups.has(key)) {
      groups.set(key, {
        id: key,
        name,
        setName,
        setCode,
        cardNumber,
        franchise: "tcg",
        category: "card",
        imageUrl: vaultItemDisplayImage(record),
        rarity: record.rarity || "",
        artist: record.artist || "",
        ownedTotal: 0,
        wanted: false,
        completionStatus: "missing",
        records: [],
        variantsByKey: new Map(),
      });
    }

    const group = groups.get(key);
    group.ownedTotal += ownedCount;
    group.wanted = group.wanted || Boolean(isWishlist || wantedCount > 0);
    group.imageUrl = group.imageUrl || vaultItemDisplayImage(record);
    group.rarity = group.rarity || record.rarity || "";
    group.records.push(record);

    if (!group.variantsByKey.has(variantKey)) {
      group.variantsByKey.set(variantKey, {
        id: `${key}|${variantKey}`,
        masterCardId: key,
        variantType,
        label: variantLabel,
        condition: condition || undefined,
        gradingCompany: gradingCompany || undefined,
        grade: grade || undefined,
        ownedCount: 0,
        wantedCount: 0,
        estimatedValue: estimatedValue ?? undefined,
        imageUrl: vaultItemDisplayImage(record),
        notes: record.notes || record.actionNotes || record.action_notes || "",
        tags: [],
        records: [],
      });
    }

    const variant = group.variantsByKey.get(variantKey);
    variant.ownedCount += ownedCount;
    variant.wantedCount += wantedCount;
    variant.estimatedValue = variant.estimatedValue ?? estimatedValue ?? undefined;
    variant.imageUrl = variant.imageUrl || vaultItemDisplayImage(record);
    variant.records.push(record);
  });

  return [...groups.values()].map((group) => {
    const variants = [...group.variantsByKey.values()]
      .sort((a, b) => b.ownedCount - a.ownedCount || b.wantedCount - a.wantedCount || a.label.localeCompare(b.label));
    const completionStatus = group.ownedTotal > 0 && group.wanted
      ? "partial"
      : group.ownedTotal > 0
        ? "owned"
        : "missing";
    return {
      ...group,
      completionStatus,
      variants,
      variantCount: variants.length,
      variantOwnedCount: variants.filter((variant) => variant.ownedCount > 0).length,
      variantWantedCount: variants.filter((variant) => variant.wantedCount > 0).length,
      totalEstimatedValue: variants.reduce((sum, variant) => sum + Number(variant.estimatedValue || 0) * Math.max(1, Number(variant.ownedCount || 0)), 0),
      variantsByKey: undefined,
    };
  }).sort((a, b) =>
    b.ownedTotal - a.ownedTotal ||
    Number(b.wanted) - Number(a.wanted) ||
    a.name.localeCompare(b.name)
  );
}

function buildMasterCardItemIndex(masterCards = []) {
  const index = new Map();
  masterCards.forEach((masterCard) => {
    (masterCard.records || []).forEach((record) => {
      if (record?.id) index.set(String(record.id), masterCard);
      if (record?.groupId) index.set(String(record.groupId), masterCard);
    });
    (masterCard.variants || []).forEach((variant) => {
      (variant.records || []).forEach((record) => {
        if (record?.id) index.set(String(record.id), masterCard);
        if (record?.groupId) index.set(String(record.groupId), masterCard);
      });
    });
  });
  return index;
}

function findMasterCardForInventoryItem(item = {}, index = new Map()) {
  if (!item) return null;
  if (item.id && index.has(String(item.id))) return index.get(String(item.id));
  if (item.groupId && index.has(String(item.groupId))) return index.get(String(item.groupId));
  const entry = inventoryGroupEntries(item).find((record) => record?.id && index.has(String(record.id)));
  return entry ? index.get(String(entry.id)) : null;
}

function PremiumCardImage({ image, title, subtitle, variantType = "normal", className = "" }) {
  const tone = MASTER_CARD_VARIANT_LABELS[variantType] ? variantType : "other";
  return (
    <div className={`premium-card-image premium-card-image--${tone} ${image ? "has-image" : "is-placeholder"} ${className}`.trim()} aria-label={`${title || "Card"} visual`}>
      {image ? <img src={image} alt="" loading="lazy" /> : (
        <div className="premium-card-placeholder-art" aria-hidden="true">
          <span className="premium-card-crest" />
          <strong>{title || "Card"}</strong>
          <small>{subtitle || "Ember & Tide"}</small>
        </div>
      )}
    </div>
  );
}

function MasterVariantRail({ masterCard, compact = false }) {
  if (!masterCard?.variants?.length) return null;
  return (
    <div className={`master-variant-rail${compact ? " master-variant-rail--compact" : ""}`} aria-label={`${masterCard.name} variants and copies`}>
      {masterCard.variants.slice(0, compact ? 4 : 8).map((variant) => {
        const countLabel = variant.ownedCount > 0
          ? `${variant.ownedCount} owned`
          : variant.wantedCount > 0
            ? `${variant.wantedCount} wanted`
            : "Tracked";
        const conditionLabel = variant.condition ? MASTER_CARD_CONDITION_LABELS[variant.condition] || "" : "";
        return (
          <span className={`master-variant-pill master-variant-pill--${variant.variantType}`} key={variant.id}>
            <b>{variant.label}</b>
            <small>{[countLabel, conditionLabel].filter(Boolean).join(" / ")}</small>
          </span>
        );
      })}
      {masterCard.variants.length > (compact ? 4 : 8) ? (
        <span className="master-variant-pill master-variant-pill--more">
          <b>+{masterCard.variants.length - (compact ? 4 : 8)}</b>
          <small>more</small>
        </span>
      ) : null}
    </div>
  );
}

function MasterCardGroupPreview({ masterCard, onOpenRecord, onOpenMarket, compact = false }) {
  if (!masterCard) return null;
  const primaryRecord = masterCard.records?.find((record) => Number(record.quantity || 0) > 0) || masterCard.records?.[0] || masterCard.variants?.flatMap((variant) => variant.records || [])[0] || null;
  const subtitle = [masterCard.setName, masterCard.cardNumber ? `#${masterCard.cardNumber}` : "", masterCard.rarity].filter(Boolean).join(" - ");
  const ownedLabel = masterCard.ownedTotal > 0 ? `${masterCard.ownedTotal} owned` : masterCard.wanted ? "Wishlist" : "Tracked";
  return (
    <article className={`master-card-group-preview${compact ? " master-card-group-preview--compact" : ""}`}>
      <PremiumCardImage
        image={masterCard.imageUrl}
        title={masterCard.name}
        subtitle={masterCard.setName}
        variantType={masterCard.variants?.[0]?.variantType || "normal"}
      />
      <div className="master-card-group-body">
        <div className="compact-card-header">
          <div>
            <span className={`trust-badge master-card-status master-card-status--${masterCard.completionStatus || "partial"}`}>{ownedLabel}</span>
            <h3>{masterCard.name}</h3>
            <p>{subtitle || "Master card identity"}</p>
          </div>
          <strong>{masterCard.variantCount || masterCard.variants?.length || 0} variants</strong>
        </div>
        <MasterVariantRail masterCard={masterCard} compact={compact} />
        <div className="master-card-summary-row">
          <span>{masterCard.variantOwnedCount || 0} owned variant{masterCard.variantOwnedCount === 1 ? "" : "s"}</span>
          <span>{masterCard.variantWantedCount || 0} wanted</span>
          {masterCard.totalEstimatedValue ? <span>{money(masterCard.totalEstimatedValue)} est.</span> : <span>Value review needed</span>}
        </div>
        {masterCard.isPreview ? (
          <p className="master-card-preview-note">Preview model only. Saved cards will group here once added.</p>
        ) : null}
        <div className="compact-actions master-card-actions">
          {primaryRecord && onOpenRecord ? <button type="button" className="secondary-button" onClick={() => onOpenRecord(primaryRecord)}>View copies</button> : null}
          {primaryRecord && onOpenMarket ? <button type="button" className="secondary-button" onClick={() => onOpenMarket(primaryRecord)}>Market</button> : null}
        </div>
      </div>
    </article>
  );
}

function MasterCardFamilyNote({ masterCard }) {
  if (!masterCard) return null;
  return (
    <section className="master-card-family-note" aria-label="Master card grouping">
      <div>
        <span className="trust-badge trust-badge--secure">Master card</span>
        <h4>{masterCard.name}</h4>
        <p>{[masterCard.setName, masterCard.cardNumber ? `#${masterCard.cardNumber}` : ""].filter(Boolean).join(" - ") || "Grouped card identity"}</p>
      </div>
      <MasterVariantRail masterCard={masterCard} compact />
    </section>
  );
}

function vaultItemTypeLabel(item = {}) {
  if (item.graded || item.grade || item.gradingCompany || item.grading_company) return "Graded card";
  if (isInventorySealedProduct(item)) return item.productType || item.product_type || "Sealed product";
  if (isInventoryCardProduct(item)) return item.productType || item.product_type || "Single card";
  return item.productType || item.product_type || item.category || "Other";
}

function vaultItemSetLabel(item = {}) {
  return String(item.setName || item.set_name || item.expansion || item.productLine || item.product_line || "").trim();
}

function vaultCardNumberLabel(value = {}) {
  return getSetMasteryCardNumber(value);
}

function vaultVariantLabel(value = {}) {
  return getSetMasteryVariantLabel(value);
}

function vaultVariantMatches(value = {}, filter = "all") {
  return setMasteryVariantMatches(value, filter);
}

function compareVaultSetRows(a = {}, b = {}, sortMode = "cardNumber") {
  return compareSetMasteryRows(a, b, sortMode);
}

function vaultItemLocationLabel(item = {}) {
  return friendlyInventoryLabel(item.storageLocation || item.storage_location || item.locationSummary || item.physicalLocation || item.physical_location || item.location, "");
}

function firstKnownVaultNumber(...values) {
  for (const value of values) {
    if (hasKnownPriceValue(value)) return Number(value);
  }
  return null;
}

function vaultItemTotalMarketValue(item = {}) {
  const marketPrice = firstKnownVaultNumber(
    item.marketPrice,
    item.market_price,
    item.marketValue,
    item.market_value,
    item.referenceMarketPrice,
    item.catalogMarketPrice
  );
  return marketPrice === null ? 0 : Number(item.quantity || 0) * marketPrice;
}

function vaultItemLastUpdatedLabel(item = {}) {
  const raw = item.updatedAt || item.updated_at || item.lastPriceChecked || item.marketLastUpdated || item.createdAt || item.created_at || "";
  return raw ? shortDate(raw) : "Not updated";
}

function catalogReferenceName(product = {}) {
  return String(product.name || product.productName || product.product_name || product.cardName || product.card_name || "").trim();
}

function catalogReferenceSet(product = {}) {
  return String(product.setName || product.set_name || product.expansion || product.productLine || product.product_line || product.series || "").trim();
}

function catalogReferenceType(product = {}) {
  return String(product.productType || product.product_type || product.catalogType || product.catalog_type || product.category || "").trim();
}

function catalogLookupToken(value = "") {
  return String(value || "").toLowerCase().replace(/[^a-z0-9]+/g, "").trim();
}

function catalogLookupKey(prefix, value = "") {
  const token = catalogLookupToken(value);
  return token ? `${prefix}:${token}` : "";
}

function catalogProductLookupKeys(product = {}) {
  const keys = [
    catalogLookupKey("id", product.id),
    catalogLookupKey("catalog", product.catalogProductId || product.catalog_product_id),
    catalogLookupKey("external", product.externalProductId || product.external_product_id),
    catalogLookupKey("tcgplayer", product.tcgplayerProductId || product.tcgplayer_product_id),
    catalogLookupKey("sku", product.sku),
    catalogLookupKey("upc", product.upc || product.barcode),
  ].filter(Boolean);
  const name = normalizeSearchText(catalogReferenceName(product));
  const setName = normalizeSearchText(catalogReferenceSet(product));
  const type = normalizeSearchText(catalogReferenceType(product));
  if (name && setName) keys.push(`name-set:${name}:${setName}`);
  if (name && setName && type) keys.push(`name-set-type:${name}:${setName}:${type}`);
  return [...new Set(keys)];
}

function inventoryCatalogLookupKeys(item = {}) {
  const keys = [
    catalogLookupKey("id", item.catalogProductId || item.catalog_product_id),
    catalogLookupKey("catalog", item.catalogProductId || item.catalog_product_id),
    catalogLookupKey("external", item.externalProductId || item.external_product_id || item.tideTradrProductId || item.tide_tradr_product_id),
    catalogLookupKey("tcgplayer", item.tcgplayerProductId || item.tcgplayer_product_id),
    catalogLookupKey("sku", item.sku),
    catalogLookupKey("upc", item.upc || item.barcode),
  ].filter(Boolean);
  const name = normalizeSearchText(item.name || item.itemName || item.catalogProductName || item.catalog_product_name);
  const setName = normalizeSearchText(item.setName || item.set_name || item.expansion || item.productLine || item.product_line);
  const type = normalizeSearchText(item.productType || item.product_type || item.category);
  if (name && setName) keys.push(`name-set:${name}:${setName}`);
  if (name && setName && type) keys.push(`name-set-type:${name}:${setName}:${type}`);
  return [...new Set(keys)];
}

function buildCatalogProductLookup(products = []) {
  const lookup = new Map();
  products.forEach((product) => {
    catalogProductLookupKeys(product).forEach((key) => {
      if (!lookup.has(key)) lookup.set(key, product);
    });
  });
  return lookup;
}

function resolveCatalogProductForItem(item = {}, lookup = new Map()) {
  for (const key of inventoryCatalogLookupKeys(item)) {
    const product = lookup.get(key);
    if (product) return product;
  }
  return null;
}

function enrichVaultItemWithCatalogData(item = {}, catalogProduct = null) {
  if (!catalogProduct) {
    const displayName = item.name || item.itemName || item.catalogProductName || "Vault item";
    return { ...item, name: displayName, displayName };
  }
  const catalogName = catalogReferenceName(catalogProduct);
  const catalogSet = catalogReferenceSet(catalogProduct);
  const catalogType = catalogReferenceType(catalogProduct);
  const catalogImageUrl = getCatalogImage(catalogProduct);
  const itemMarket = firstKnownVaultNumber(item.marketPrice, item.market_price, item.marketValue, item.market_value);
  const catalogMarket = firstKnownVaultNumber(
    catalogProduct.marketPrice,
    catalogProduct.market_price,
    catalogProduct.marketValue,
    catalogProduct.market_value,
    catalogProduct.marketValueNearMint,
    catalogProduct.market_value_near_mint
  );
  const itemMsrp = firstKnownVaultNumber(item.msrpPrice, item.msrp_price, item.msrp);
  const catalogMsrp = firstKnownVaultNumber(catalogProduct.msrpPrice, catalogProduct.msrp_price, catalogProduct.msrp);
  const resolvedMarket = itemMarket ?? catalogMarket;
  const resolvedMsrp = itemMsrp ?? catalogMsrp;
  const displayName = item.name || item.itemName || item.catalogProductName || catalogName || "Vault item";
  const displayImage = vaultItemDisplayImage(item) || catalogImageUrl;
  return {
    ...item,
    name: displayName,
    displayName,
    catalogProductId: item.catalogProductId || item.catalog_product_id || catalogProduct.id || "",
    catalogProductName: item.catalogProductName || item.catalog_product_name || catalogName,
    setName: item.setName || item.set_name || item.expansion || catalogSet,
    expansion: item.expansion || item.setName || item.set_name || catalogSet,
    productType: item.productType || item.product_type || catalogType,
    catalogImageUrl,
    displayImage,
    referenceMarketPrice: catalogMarket || 0,
    catalogMarketPrice: catalogMarket || 0,
    marketPrice: resolvedMarket ?? Number(item.marketPrice || item.market_price || 0),
    marketValue: resolvedMarket ?? Number(item.marketValue || item.market_value || 0),
    marketPriceSource: item.marketPriceSource || item.market_price_source || item.marketValueSource || item.market_value_source || (catalogMarket ? "catalog" : ""),
    marketValueSource: item.marketValueSource || item.market_value_source || item.marketPriceSource || item.market_price_source || (catalogMarket ? "catalog" : ""),
    marketPriceConfidence: item.marketPriceConfidence || item.market_price_confidence || (catalogMarket ? "Estimated" : ""),
    msrpPrice: resolvedMsrp ?? Number(item.msrpPrice || item.msrp_price || 0),
    msrp: resolvedMsrp ?? Number(item.msrp || 0),
    msrpSource: item.msrpSource || item.msrp_source || (catalogMsrp ? "msrp" : ""),
  };
}

function uniqueSortedLabels(values = []) {
  return [...new Set(values.map((value) => String(value || "").trim()).filter(Boolean))]
    .sort((a, b) => a.localeCompare(b));
}

function catalogHasStrongCardIndicators(value = {}) {
  const source = value || {};
  const details = catalogCardDetailsForClassification(source);
  const printedTotal = source.printedTotal || source.printed_total || details.printedTotal || details.printed_total;
  const rarity = source.rarity || details.rarity;
  const supertype = source.supertype || details.supertype;
  const cardNumber = source.cardNumber || source.card_number || details.cardNumber || details.card_number || (
    catalogHasAnyValue(printedTotal, rarity, supertype) ? source.number : ""
  );
  const cardTypeText = normalizeSearchText([
    supertype,
    source.cardSubtype,
    source.card_subtype,
    details.stage,
    (details.subtypes || []).join(" "),
    (details.types || []).join(" "),
    source.productType,
    source.product_type,
    source.catalogItemType,
    source.catalog_item_type,
  ].filter(Boolean).join(" "));
  const numberPatternText = normalizeSearchText([
    cardNumber,
    source.displayNumber,
    source.display_number,
    source.collectorNumber,
    source.collector_number,
    source.name,
    source.cardName,
    source.card_name,
  ].filter(Boolean).join(" "));
  const hasCardNumberPattern = /\b[a-z]{0,3}\d{1,4}[a-z]?\/[a-z]{0,3}\d{1,4}[a-z]?\b/.test(numberPatternText);
  const hasCardSpecificArrays = [
    details.subtypes,
    details.types,
    details.attacks,
    details.abilities,
    details.weaknesses,
    details.resistances,
    details.retreatCost,
    details.retreat_cost,
  ].some((entry) => Array.isArray(entry) ? entry.length > 0 : catalogHasAnyValue(entry));
  const hasCardSpecificScalar = catalogHasAnyValue(
    cardNumber,
    printedTotal,
    rarity,
    supertype,
    source.hp,
    details.hp,
    source.artist,
    details.artist,
    source.regulationMark,
    source.regulation_mark,
    details.regulationMark,
    details.regulation_mark,
    source.evolvesFrom,
    source.evolves_from,
    details.evolvesFrom,
    details.evolves_from
  );
  const explicitCardType =
    /\b(pokemon|pok[eé]mon|trainer|item|supporter|stadium|tool|energy)\b/.test(cardTypeText) &&
    !/\bsealed\b|\bbooster\b|\bbox\b|\bbundle\b|\btin\b|\bcollection\b|\bpack\b|\bblister\b|\bdeck\b|\belite\s+trainer\s+box\b|\btrainer'?s?\s+toolkit\b|\bleague\s+battle\s+deck\b|\btheme\s+deck\b|\bstarter\s+deck\b/.test(cardTypeText);
  const explicitKindText = normalizeSearchText([
    source.catalogType,
    source.catalog_type,
    source.catalogGroup,
    source.catalog_group,
    source.productKind,
    source.product_kind,
    source.catalogItemType,
    source.catalog_item_type,
    source.productType,
    source.product_type,
  ].filter(Boolean).join(" "));
  const sourceSaysCard =
    !catalogNameSuggestsSealedProduct(source) && (
      source.catalogType === "card" ||
      source.catalog_type === "card" ||
      /\bsingle[_\s-]?card\b|\bindividual\s+card\b|\bpromo\s+card\b/.test(explicitKindText) ||
      (/\bcard\b/.test(explicitKindText) && !catalogSourceSuggestsSealed(source) && catalogHasAnyValue(cardNumber, printedTotal, rarity, supertype))
    );
  const cardVariantWithMetadata =
    catalogHasAnyValue(source.finish, source.printing, source.variant, source.variantNames, source.variant_names, source.priceSubtype, source.price_subtype) &&
    catalogHasAnyValue(cardNumber, printedTotal, rarity, supertype, source.setName, source.set_name, source.expansion);

  return Boolean(
    sourceSaysCard ||
    hasCardNumberPattern ||
    hasCardSpecificScalar ||
    hasCardSpecificArrays ||
    explicitCardType ||
    cardVariantWithMetadata
  );
}

function classifyCatalogItem(value = {}) {
  if (!value) return "other";
  if (isCatalogCodeCardLike(value)) return "code_card";
  if (catalogSourceSuggestsSealed(value)) return "sealed";
  if (catalogHasStrongCardIndicators(value)) return "card";
  return "other";
}

function getCatalogDisplayKind(value = {}) {
  if (!value) return "other";
  const recomputedKind = classifyCatalogItem(value);
  const storedKind = value.catalogDisplayKind || value.displayKind;
  if (storedKind === "sealed" && (recomputedKind === "card" || recomputedKind === "code_card")) return recomputedKind;
  if ((storedKind === "card" || storedKind === "code_card") && recomputedKind === "sealed") return recomputedKind;
  return storedKind || recomputedKind;
}

function catalogHasClassificationConflict(value = {}) {
  const displayKind = getCatalogDisplayKind(value);
  return catalogSourceSuggestsSealed(value) && (displayKind === "card" || displayKind === "code_card");
}

// Classifier regression cases: Dratini, Dratini / Energy Symbol Pattern,
// Fighting Gong, Iris's Fighting Spirit, Iron Bundle, Secret Box, and Ting-Lu
// should resolve as card when card metadata is present; code-card terms resolve
// as code_card; ETB/Booster Bundle/Mini Tin/Collection Box resolve as sealed.

function aliasEntriesFromMap(map, type) {
  return Object.entries(map).flatMap(([canonical, aliases]) => [
    { canonical, alias: canonical, type },
    ...aliases.map((alias) => ({ canonical, alias, type })),
  ]);
}

const SEARCH_ALIAS_ENTRIES = [
  ...Object.entries(SET_SEARCH_METADATA).flatMap(([setName, metadata]) => [
    { canonical: setName, alias: setName, type: "set" },
    { canonical: setName, alias: metadata.setCode, type: "setCode" },
    ...(metadata.setAliases || []).map((alias) => ({ canonical: setName, alias, type: "set" })),
  ]),
  ...aliasEntriesFromMap(PRODUCT_TYPE_ALIASES, "productType"),
  ...aliasEntriesFromMap(POKEMON_ALIASES, "pokemon"),
  ...aliasEntriesFromMap(RARITY_VARIANT_ALIASES, "rarity"),
  ...aliasEntriesFromMap(STORE_ALIASES, "store"),
].filter((entry) => entry.alias);

function expandSearchQuery(query) {
  const normalized = normalizeSearchText(query);
  const tokens = searchTokens(query);
  const phrases = new Set([normalized, ...tokens]);
  SEARCH_ALIAS_ENTRIES.forEach((entry) => {
    const alias = normalizeSearchText(entry.alias);
    if (!alias) return;
    const aliasTokens = searchTokens(alias);
    const exactPhrase = normalized === alias || normalized.includes(alias);
    const exactToken = aliasTokens.length === 1 && tokens.includes(alias);
    if (exactPhrase || exactToken) {
      phrases.add(normalizeSearchText(entry.canonical));
      searchTokens(entry.canonical).forEach((token) => phrases.add(token));
      if (entry.type === "setCode") phrases.add(alias);
    }
  });
  return { normalized, tokens, phrases: [...phrases].filter(Boolean) };
}

function searchableText(parts) {
  return normalizeSearchText(parts.flatMap((part) => Array.isArray(part) ? part : [part]).filter(Boolean).join(" "));
}

function scoreSearchCandidate(queryInfo, candidate) {
  const text = searchableText(candidate.fields);
  const exactIds = (candidate.exactIds || []).map(normalizeSearchText).filter(Boolean);
  const cardNumbers = (candidate.cardNumbers || []).map(normalizeSearchText).filter(Boolean);
  const setCodes = (candidate.setCodes || []).map(normalizeSearchText).filter(Boolean);
  const aliases = (candidate.aliases || []).map(normalizeSearchText).filter(Boolean);
  const names = (candidate.names || []).map(normalizeSearchText).filter(Boolean);
  const { normalized, tokens, phrases } = queryInfo;
  let score = 0;
  let reason = "";

  if (exactIds.some((id) => id && id === normalized)) return { score: 1000, reason: "Exact UPC/SKU/barcode match" };
  if (cardNumbers.some((number) => number && number === normalized)) return { score: 940, reason: "Exact card number match" };
  if (setCodes.some((code) => code && code === normalized)) {
    score += 880;
    reason = "Exact set code match";
  }
  if (names.some((name) => name === normalized)) {
    score += 820;
    reason = "Exact name match";
  }
  if (aliases.some((alias) => alias === normalized || (alias.includes(" ") && normalized.includes(alias)))) {
    score += 760;
    reason = "Exact alias match";
  }
  if (normalized.length > 3 && text.includes(normalized)) {
    score += 900;
    reason = reason || "Exact name match";
  }

  const phraseHits = phrases.filter((phrase) => phrase.length > 1 && text.includes(phrase)).length;
  const tokenHits = tokens.filter((token) => text.includes(token) || aliases.some((alias) => alias.includes(token))).length;
  score += phraseHits * 80 + tokenHits * 38;

  const setHit = setCodes.some((code) => tokens.includes(code)) || aliases.some((alias) => tokens.includes(alias));
  const typeHit = (candidate.productTypeAliases || []).map(normalizeSearchText).some((alias) => normalized.includes(alias) || tokens.includes(alias));
  const pokemonHit = (candidate.pokemonAliases || []).map(normalizeSearchText).some((alias) => normalized.includes(alias) || tokens.includes(alias));
  const rarityHit = (candidate.rarityAliases || []).map(normalizeSearchText).some((alias) => normalized.includes(alias) || tokens.includes(alias));
  if (setHit && typeHit) {
    score += 240;
    reason = reason || "Set + product type match";
  }
  if (pokemonHit && rarityHit) {
    score += 220;
    reason = reason || "Pokemon + rarity/variant match";
  }
  if (tokenHits > 0 && !reason) reason = "Partial/fuzzy match";
  return { score, reason };
}

function toNumber(value, fallback = 0) {
  const number = Number.parseFloat(value);
  return Number.isFinite(number) ? number : fallback;
}

function makeTidepoolPost(overrides = {}) {
  const username = normalizePublicUsername(overrides.username || overrides.publicUsername || overrides.displayName || "local_scout");
  return buildTidepoolPost({
    ...overrides,
    postId: overrides.postId || makeId("tidepool-post"),
    username,
    publicUsername: username,
  });
}

function createDefaultTidepoolData() {
  return emptyTidepoolData();
}

function getCatalogImage(product = {}) {
  return getProductImageUrl(product);
}

function shouldPersistLocalCatalogProduct(product = {}) {
  const sourceType = String(product.sourceType || product.source_type || product.source || "").toLowerCase();
  if (!sourceType) return false;
  if (sourceType === "supabase" || sourceType === LOCAL_CATALOG_SEED_SOURCE || sourceType === "local_catalog_seed") return false;
  if (/tcgcsv|generated|recovery|official_release|pokemon_tcg_api/.test(sourceType)) return false;
  return /manual|user|admin|custom|suggest|approved|phase2|smoke/.test(sourceType);
}

function getImageSourceLabel(item = {}) {
  const source = item.imageSource || item.itemImageSource || "";
  const status = item.imageStatus || item.itemImageStatus || "";
  const value = status || source || (getCatalogImage(item) || item.itemImage ? "manual" : "placeholder");
  const labels = {
    pokemon_tcg_api: "Pokemon TCG API",
    tcgdex: "TCGdex",
    best_buy: "Best Buy",
    ebay: "Marketplace",
    tcgcsv: "TCGCSV",
    user: "User photo",
    manual: "Manual image",
    mock: "Image needs review",
    placeholder: "Image needed",
    official: "Official/API",
    api: "API",
    retailer: "Retailer",
    marketplace: "Marketplace",
    unknown: "Unknown image",
  };
  return labels[value] || labels[source] || labels[status] || String(value).replaceAll("_", " ");
}

function getDefaultImageSource(item = {}) {
  if (item.catalogType === "card") {
    if (item.images?.small || item.images?.large || item.imageSmall || item.imageLarge) return "pokemon_tcg_api";
    if (item.imageUrl) return item.imageSource || "manual";
    return "placeholder";
  }
  if (item.imageUrl) return item.imageSource || "manual";
  return "placeholder";
}

function getDefaultImageStatus(item = {}) {
  if (item.imageStatus) return item.imageStatus;
  const source = getDefaultImageSource(item);
  if (source === "pokemon_tcg_api" || source === "tcgdex") return "api";
  if (["best_buy", "tcgcsv"].includes(source)) return "retailer";
  if (source === "ebay") return "marketplace";
  return source;
}

function shortDate(value) {
  if (!value) return "No date";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "No date";
  return date.toLocaleDateString(undefined, { month: "short", day: "numeric" });
}

function makeId(prefix) {
  return `${prefix}-${Date.now()}-${Math.random().toString(36).slice(2)}`;
}

function workspaceTypeLabel(type = "personal") {
  return WORKSPACE_TYPES.find((option) => option.value === type)?.label || "Workspace";
}

function workspaceRoleLabel(role = "viewer") {
  const normalizedRole = role === "editor" ? "contributor" : role;
  return WORKSPACE_ROLES.find((option) => option.value === normalizedRole)?.label || "Viewer";
}

function normalizeWorkspaceDisplayName(value = "") {
  return String(value || "").trim().replace(/\s+/g, " ").slice(0, WORKSPACE_NAME_MAX_LENGTH);
}

function workspaceArchivedAt(workspace = {}) {
  return workspace.archivedAt || workspace.archived_at || "";
}

function isWorkspaceArchived(workspace = {}) {
  return Boolean(workspaceArchivedAt(workspace)) || workspace.active === false || String(workspace.status || "").toLowerCase() === "archived";
}

function workspaceTypeValue(value = "personal", fallback = "personal") {
  const normalized = String(value || "").trim();
  if (WORKSPACE_TYPES.some((option) => option.value === normalized)) return normalized;
  return WORKSPACE_TYPES.some((option) => option.value === fallback) ? fallback : "personal";
}

function normalizeForgeModeSettings(value = {}) {
  const forgeIdentityMode = normalizeForgeIdentityMode(
    value.forgeIdentityMode ||
    (value.lockToEmberTide || value.alwaysUseEmberTideForge || value.lockForgeToEmberTide || value.useEmberTideBranding ? "ember_tide" : value.defaultForgeWorkspaceId ? "business" : "personal")
  );
  const keepPersonalForgeSeparate = value.keepPersonalForgeSeparate !== undefined
    ? Boolean(value.keepPersonalForgeSeparate)
    : value.personalForgeEnabled !== false;
  return {
    ...DEFAULT_FORGE_MODE_SETTINGS,
    personalForgeEnabled: value.personalForgeEnabled !== false,
    defaultForgeWorkspaceId: String(value.defaultForgeWorkspaceId || value.defaultForgeWorkspace || "").trim(),
    lockToEmberTide: Boolean(value.lockToEmberTide || value.alwaysUseEmberTideForge || value.lockForgeToEmberTide),
    forgeIdentityMode,
    useEmberTideBranding: Boolean(value.useEmberTideBranding || value.lockToEmberTide || value.alwaysUseEmberTideForge || value.lockForgeToEmberTide || forgeIdentityMode === "ember_tide"),
    keepPersonalForgeSeparate,
    businessName: String(value.businessName || value.business_name || "").trim().replace(/\s+/g, " ").slice(0, 80),
    shopName: String(value.shopName || value.shop_name || "").trim().replace(/\s+/g, " ").slice(0, 80),
    publicDisplayName: String(value.publicDisplayName || value.public_display_name || "").trim().replace(/\s+/g, " ").slice(0, 80),
    updatedAt: value.updatedAt || "",
  };
}

function loadForgeModeSettings(fallback = {}) {
  if (typeof localStorage === "undefined") return normalizeForgeModeSettings(fallback);
  try {
    return normalizeForgeModeSettings({
      ...fallback,
      ...JSON.parse(localStorage.getItem(FORGE_MODE_SETTINGS_STORAGE_KEY) || "{}"),
    });
  } catch {
    return normalizeForgeModeSettings(fallback);
  }
}

function isPersonalForgeWorkspace(workspace = {}) {
  return workspace.id === DEFAULT_PERSONAL_WORKSPACE_ID || workspace.type === "personal";
}

function isEmberTideForgeWorkspace(workspace = {}) {
  const name = String(workspace.name || "").toLowerCase().replace(/\s+/g, " ").trim();
  return /\bember\s*(?:&|and)\s*tide\b/.test(name);
}

function normalizeForgePhysicalLocation(value = "", fallback = "") {
  const trimmed = String(value || "").trim();
  if (!trimmed) return fallback;
  return FORGE_PHYSICAL_LOCATION_OPTIONS.includes(trimmed) ? trimmed : "Other";
}

function forgePhysicalLocationLabel(item = {}) {
  return friendlyInventoryLabel(item.physicalLocation || item.physical_location, "");
}

function normalizeWorkspaceRoleValue(role = "viewer", fallback = "viewer") {
  const normalizedRole = role === "editor" ? "contributor" : role;
  const normalizedFallback = fallback === "editor" ? "contributor" : fallback;
  return ["owner", "admin", "contributor", "viewer"].includes(normalizedRole)
    ? normalizedRole
    : (["owner", "admin", "contributor", "viewer"].includes(normalizedFallback) ? normalizedFallback : "viewer");
}

function createDefaultWorkspaceBundle(user = {}) {
  const now = new Date().toISOString();
  const userId = user?.id || "local-beta";
  return {
    activeWorkspaceId: DEFAULT_PERSONAL_WORKSPACE_ID,
    workspaces: [
      {
        id: DEFAULT_PERSONAL_WORKSPACE_ID,
        name: "My Personal Space",
        type: "personal",
        ownerUserId: userId,
        owner_user_id: userId,
        createdBy: userId,
        created_by: userId,
        createdAt: now,
        updatedAt: now,
        archivedAt: "",
        archived_at: null,
      },
    ],
    members: [
      {
        workspaceId: DEFAULT_PERSONAL_WORKSPACE_ID,
        workspace_id: DEFAULT_PERSONAL_WORKSPACE_ID,
        userId,
        user_id: userId,
        role: "owner",
        status: "active",
        invitedBy: userId,
        invited_by: userId,
        createdAt: now,
        acceptedAt: now,
      },
    ],
    invites: [],
  };
}

function normalizeWorkspace(record = {}, fallback = {}) {
  const id = record.id || record.workspaceId || record.workspace_id || fallback.id || makeId("workspace");
  const now = new Date().toISOString();
  const archivedAtValue = record.archivedAt !== undefined
    ? record.archivedAt
    : record.archived_at !== undefined
      ? record.archived_at
      : fallback.archivedAt !== undefined
        ? fallback.archivedAt
        : fallback.archived_at || "";
  const archivedByValue = record.archivedBy !== undefined
    ? record.archivedBy
    : record.archived_by !== undefined
      ? record.archived_by
      : fallback.archivedBy !== undefined
        ? fallback.archivedBy
        : fallback.archived_by || "";
  return {
    id,
    name: String(record.name || fallback.name || "My Personal Space").trim() || "My Personal Space",
    type: workspaceTypeValue(record.type, fallback.type || "personal"),
    ownerUserId: record.ownerUserId || record.owner_user_id || fallback.ownerUserId || fallback.owner_user_id || "local-beta",
    owner_user_id: record.owner_user_id || record.ownerUserId || fallback.owner_user_id || fallback.ownerUserId || "local-beta",
    createdBy: record.createdBy || record.created_by || record.ownerUserId || record.owner_user_id || fallback.createdBy || fallback.created_by || fallback.ownerUserId || fallback.owner_user_id || "local-beta",
    created_by: record.created_by || record.createdBy || record.owner_user_id || record.ownerUserId || fallback.created_by || fallback.createdBy || fallback.owner_user_id || fallback.ownerUserId || "local-beta",
    createdAt: record.createdAt || record.created_at || fallback.createdAt || now,
    updatedAt: record.updatedAt || record.updated_at || fallback.updatedAt || now,
    archivedAt: archivedAtValue || "",
    archived_at: archivedAtValue || null,
    archivedBy: archivedByValue || "",
    archived_by: archivedByValue || null,
    active: record.active !== undefined ? Boolean(record.active) : fallback.active !== undefined ? Boolean(fallback.active) : !archivedAtValue,
    status: record.status || fallback.status || (archivedAtValue ? "archived" : "active"),
    businessName: String(record.businessName || record.business_name || fallback.businessName || fallback.business_name || "").trim().replace(/\s+/g, " ").slice(0, 80),
    business_name: String(record.business_name || record.businessName || fallback.business_name || fallback.businessName || "").trim().replace(/\s+/g, " ").slice(0, 80),
    shopName: String(record.shopName || record.shop_name || fallback.shopName || fallback.shop_name || "").trim().replace(/\s+/g, " ").slice(0, 80),
    shop_name: String(record.shop_name || record.shopName || fallback.shop_name || fallback.shopName || "").trim().replace(/\s+/g, " ").slice(0, 80),
    displayLabel: String(record.displayLabel || record.display_label || fallback.displayLabel || fallback.display_label || "").trim().replace(/\s+/g, " ").slice(0, 80),
    display_label: String(record.display_label || record.displayLabel || fallback.display_label || fallback.displayLabel || "").trim().replace(/\s+/g, " ").slice(0, 80),
    notes: String(record.notes || record.workspaceNotes || record.workspace_notes || fallback.notes || fallback.workspaceNotes || fallback.workspace_notes || "").trim().slice(0, 240),
    workspaceNotes: String(record.workspaceNotes || record.workspace_notes || record.notes || fallback.workspaceNotes || fallback.workspace_notes || fallback.notes || "").trim().slice(0, 240),
    workspace_notes: String(record.workspace_notes || record.workspaceNotes || record.notes || fallback.workspace_notes || fallback.workspaceNotes || fallback.notes || "").trim().slice(0, 240),
    defaultForgeMode: normalizeForgeIdentityMode(record.defaultForgeMode || record.default_forge_mode || fallback.defaultForgeMode || fallback.default_forge_mode || "personal"),
    default_forge_mode: normalizeForgeIdentityMode(record.default_forge_mode || record.defaultForgeMode || fallback.default_forge_mode || fallback.defaultForgeMode || "personal"),
    useEmberTideBranding: Boolean(record.useEmberTideBranding || record.use_ember_tide_branding || fallback.useEmberTideBranding || fallback.use_ember_tide_branding),
    use_ember_tide_branding: Boolean(record.use_ember_tide_branding || record.useEmberTideBranding || fallback.use_ember_tide_branding || fallback.useEmberTideBranding),
  };
}

function normalizeWorkspaceMember(member = {}, fallback = {}) {
  const workspaceId = member.workspaceId || member.workspace_id || fallback.workspaceId || fallback.workspace_id || DEFAULT_PERSONAL_WORKSPACE_ID;
  const userId = member.userId || member.user_id || fallback.userId || fallback.user_id || "local-beta";
  const role = normalizeWorkspaceRoleValue(member.role, fallback.role);
  const status = ["invited", "active", "removed"].includes(member.status) ? member.status : fallback.status || "active";
  const now = new Date().toISOString();
  return {
    workspaceId,
    workspace_id: workspaceId,
    userId,
    user_id: userId,
    email: member.email || fallback.email || "",
    role,
    status,
    invitedBy: member.invitedBy || member.invited_by || fallback.invitedBy || fallback.invited_by || "",
    invited_by: member.invited_by || member.invitedBy || fallback.invited_by || fallback.invitedBy || "",
    createdAt: member.createdAt || member.created_at || fallback.createdAt || now,
    acceptedAt: member.acceptedAt || member.accepted_at || fallback.acceptedAt || (status === "active" ? now : ""),
  };
}

function normalizeWorkspaceInvite(invite = {}) {
  const now = new Date().toISOString();
  const workspaceId = invite.workspaceId || invite.workspace_id || invite.workspaceID || DEFAULT_PERSONAL_WORKSPACE_ID;
  const email = String(invite.email || invite.inviteEmail || invite.invite_email || "").trim().toLowerCase();
  const role = normalizeWorkspaceRoleValue(invite.role, "viewer");
  const invitePath = invite.invitePath || invite.invite_path || (invite.id ? `/workspace-invite/${encodeURIComponent(String(invite.id))}` : "");
  const emailSent = Boolean(invite.emailSent ?? invite.email_sent ?? false);
  const deliveryMethod = invite.deliveryMethod || invite.delivery_method || (emailSent ? "email" : "copy_link");
  return {
    id: invite.id || invite.inviteId || invite.invite_id || makeId("invite"),
    workspaceId,
    workspace_id: workspaceId,
    email,
    role: role === "owner" ? "viewer" : role,
    status: ["invited", "active", "removed"].includes(invite.status) ? invite.status : "invited",
    note: invite.note || "",
    invitedBy: invite.invitedBy || invite.invited_by || "",
    invited_by: invite.invited_by || invite.invitedBy || "",
    createdAt: invite.createdAt || invite.created_at || now,
    acceptedAt: invite.acceptedAt || invite.accepted_at || "",
    expiresAt: invite.expiresAt || invite.expires_at || "",
    expires_at: invite.expires_at || invite.expiresAt || "",
    emailSent,
    email_sent: emailSent,
    deliveryMethod,
    delivery_method: deliveryMethod,
    invitePath,
    invite_path: invitePath,
    inviteUrl: invite.inviteUrl || invite.invite_url || "",
    invite_url: invite.invite_url || invite.inviteUrl || "",
    duplicatePending: Boolean(invite.duplicatePending ?? invite.duplicate_pending ?? false),
    duplicate_pending: Boolean(invite.duplicate_pending ?? invite.duplicatePending ?? false),
  };
}

function normalizeWorkspaceState(saved = {}, user = {}) {
  const defaults = createDefaultWorkspaceBundle(user);
  const savedWorkspaces = Array.isArray(saved.workspaces) ? saved.workspaces : [];
  const byId = new Map();
  [...defaults.workspaces, ...savedWorkspaces.map((workspace) => normalizeWorkspace(workspace, defaults.workspaces[0]))]
    .forEach((workspace) => {
      if (workspace.id) byId.set(workspace.id, workspace);
    });
  const workspaces = [...byId.values()];

  const savedMembers = Array.isArray(saved.workspaceMembers) ? saved.workspaceMembers : [];
  const memberKey = (member) => `${member.workspaceId || member.workspace_id}:${member.userId || member.user_id || member.email || ""}`;
  const memberMap = new Map();
  [...defaults.members, ...savedMembers.map(normalizeWorkspaceMember)].forEach((member) => {
    memberMap.set(memberKey(member), member);
  });

  const unarchivedWorkspaces = workspaces.filter((workspace) => !isWorkspaceArchived(workspace));
  const activeWorkspaceId = unarchivedWorkspaces.some((workspace) => workspace.id === saved.activeWorkspaceId)
    ? saved.activeWorkspaceId
    : unarchivedWorkspaces[0]?.id || workspaces[0]?.id || DEFAULT_PERSONAL_WORKSPACE_ID;

  return {
    activeWorkspaceId,
    workspaces,
    workspaceMembers: [...memberMap.values()],
    workspaceInvites: Array.isArray(saved.workspaceInvites) ? saved.workspaceInvites.map(normalizeWorkspaceInvite).filter((invite) => invite.email) : [],
  };
}

function workspaceIdForRecord(record = {}) {
  return record.workspaceId || record.workspace_id || record.workspace || DEFAULT_PERSONAL_WORKSPACE_ID;
}

function recordBelongsToWorkspace(record = {}, workspaceId = DEFAULT_PERSONAL_WORKSPACE_ID) {
  return String(workspaceIdForRecord(record) || DEFAULT_PERSONAL_WORKSPACE_ID) === String(workspaceId || DEFAULT_PERSONAL_WORKSPACE_ID);
}

function applyWorkspaceToRecord(record = {}, workspace = {}) {
  const workspaceId = workspace.id || DEFAULT_PERSONAL_WORKSPACE_ID;
  return {
    ...record,
    workspaceId,
    workspace_id: workspaceId,
    workspaceName: workspace.name || "My Personal Space",
    workspaceType: workspace.type || "personal",
    workspaceScope: "workspace",
  };
}

function defaultVisibilityForWorkspace(workspace = {}) {
  return workspace?.type === "personal" ? "private" : "shared_workspace";
}

function migrateRecordsToWorkspace(records = [], workspaceId = DEFAULT_PERSONAL_WORKSPACE_ID, workspaces = []) {
  const workspace = workspaces.find((entry) => String(entry.id) === String(workspaceId)) || { id: workspaceId, name: "My Personal Space", type: "personal" };
  return Array.isArray(records)
    ? records.map((record) => record?.workspaceId || record?.workspace_id ? record : applyWorkspaceToRecord(record, workspace))
    : [];
}

function workspaceCanEdit(role = "viewer") {
  const normalizedRole = normalizeWorkspaceRoleValue(role);
  return ["owner", "admin", "contributor"].includes(normalizedRole);
}

function workspaceCanManage(role = "viewer") {
  const normalizedRole = normalizeWorkspaceRoleValue(role);
  return ["owner", "admin"].includes(normalizedRole);
}

function createDefaultPurchasers() {
  return [];
}

const PERSON_TYPE_OPTIONS = ["Family", "Seller", "Helper", "Partner", "Business", "Other"];
const PAYOUT_ASSIST_DISCLAIMER = "Payout Assist is an estimate for planning. It is not payroll, tax, or legal advice.";
const FORGE_BUSINESS_LEDGER_DISCLAIMER = "Planning tool only. Ember & Tide does not provide tax, payroll, accounting, or legal advice.";
const INFO_TOOLTIP_COPY = {
  whoPaid: "The person or account that originally paid for this item or expense.",
  ownerPerson: "The person this record belongs to for family, collection, or business tracking.",
  costBasis: "What this item cost before profit is calculated.",
  plannedSalePrice: "The price you expect to sell this item for later.",
  profit: "Estimated money left after the known costs in this record.",
  netProfit: "Estimated profit after known costs, expenses, fees, and reimbursements.",
  mileage: "Business miles can help estimate travel cost and records for later review.",
  reimbursement: "Money someone may need back for expenses or mileage they covered.",
  payoutEstimate: "Estimated amount available to pay after costs, expenses, and reimbursements.",
  vehicle: "A reusable vehicle profile for mileage logs and business records.",
  smartSetup: "Smart Setup shapes the app around your collecting, family, Scout, or seller needs. You can change this anytime.",
  customizeMyApp: "Choose which sections each page shows first. This changes visibility only, not your saved data or permissions.",
  smartRecommendations: "Ember & Tide can suggest layout changes based on app use, but it will not change your layout without confirmation.",
  resetRecommended: "Restore the recommended layout for your current setup mode.",
  sellerTools: "Seller tools unlock Forge, receipts, mileage, expenses, sales, and planning summaries when you choose to use them.",
  adminTools: "Admin tools are protected by account permissions. Visibility settings cannot grant admin access.",
  lockedTools: "Locked tools stay unavailable until your role, setup, or beta access allows them.",
};

function normalizePersonType(value = "") {
  const text = String(value || "").trim();
  if (!text) return "Family";
  return PERSON_TYPE_OPTIONS.find((option) => option.toLowerCase() === text.toLowerCase()) || text;
}

function purchaserWorkspaceId(purchaser = {}) {
  return purchaser.workspaceId || purchaser.workspace_id || DEFAULT_PERSONAL_WORKSPACE_ID;
}

function normalizePurchasers(savedPurchasers = []) {
  const normalized = Array.isArray(savedPurchasers)
    ? savedPurchasers
        .filter((purchaser) => !String(purchaser?.id || "").startsWith("purchaser-default-"))
        .map((purchaser) => {
          const now = new Date().toISOString();
          const workspaceId = purchaserWorkspaceId(purchaser);
          return {
            id: purchaser.id || makeId("purchaser"),
            name: String(purchaser.name || "").trim(),
            note: String(purchaser.note || purchaser.label || purchaser.description || "").trim(),
            type: normalizePersonType(purchaser.type || purchaser.role || purchaser.personType || purchaser.person_type),
            role: purchaser.role || purchaser.type || purchaser.personType || purchaser.person_type || "Family",
            active: purchaser.active !== false && purchaser.is_active !== false,
            defaultWorkspaceId: purchaser.defaultWorkspaceId || purchaser.default_workspace_id || workspaceId,
            default_workspace_id: purchaser.default_workspace_id || purchaser.defaultWorkspaceId || workspaceId,
            workspaceId,
            workspace_id: workspaceId,
            createdAt: purchaser.createdAt || purchaser.created_at || now,
            updatedAt: purchaser.updatedAt || purchaser.updated_at || now,
          };
        })
        .filter((purchaser) => purchaser.name)
    : [];

  const byName = new Map();
  normalized.forEach((purchaser) => {
    const key = `${purchaserWorkspaceId(purchaser)}:${purchaser.name.toLowerCase()}`;
    if (!byName.has(key)) byName.set(key, purchaser);
  });

  return [...byName.values()];
}

function friendlyInventoryLabel(value, fallback = "Not assigned") {
  const text = String(value ?? "").trim();
  if (!text) return fallback;
  if (/^(?:-?\d+|null|undefined|n\/a)$/i.test(text)) return fallback;
  if (/^unknown$/i.test(text)) return fallback === "No purchaser assigned" ? fallback : "Unknown";
  if (/unassigned\s+purchaser(?:\s*-?\d+)?/i.test(text)) return "No purchaser assigned";
  if (/no\s+purchaser\s+assigned(?:\s*-\s*\d+)?/i.test(text)) return "No purchaser assigned";
  return text.replace(/\s+-1$/i, "");
}

function itemPurchaserName(item) {
  return friendlyInventoryLabel(item.purchaserName || item.purchaser_name || item.buyer, "No purchaser assigned");
}

function itemPurchaserKey(item = {}) {
  const purchaserId = String(item.purchaserId || item.purchaser_id || "").trim();
  if (purchaserId) return `id:${purchaserId}`;
  const name = itemPurchaserName(item);
  if (name && name !== "No purchaser assigned") return `name:${normalizeSearchText(name)}`;
  return "__unassigned_purchaser__";
}

function inventoryProductGroupKey(item = {}, context = "inventory") {
  if (context === "vault" && classifyVaultSetItem(item) === "single") {
    const canonicalKey = getCanonicalCardKey(item);
    if (canonicalKey) return `${context}:${canonicalKey}`;
  }
  return inventoryProductIdentityGroupKey(item, context);
}

function summarizeBreakdownRows(rows = [], options = {}) {
  const { type = "purchaser", moneyFn = money } = options;
  const groups = new Map();
  rows.forEach((row) => {
    const quantity = Math.max(0, Number(row.quantity || 0));
    if (quantity <= 0) return;
    const key = type === "location"
      ? normalizeSearchText(forgePhysicalLocationLabel(row) || "No location assigned")
      : itemPurchaserKey(row);
    const name = type === "location"
      ? (forgePhysicalLocationLabel(row) || "No location assigned")
      : itemPurchaserName(row);
    if (!groups.has(key)) {
      groups.set(key, {
        key,
        name,
        quantity: 0,
        totalCost: 0,
        entries: [],
      });
    }
    const group = groups.get(key);
    group.quantity += quantity;
    group.totalCost += quantity * Number(row.unitCost || row.unit_cost || 0);
    group.entries.push(row);
  });
  return [...groups.values()]
    .map((group) => ({
      ...group,
      averageCost: group.quantity > 0 ? group.totalCost / group.quantity : 0,
      summary: `${group.name} ${group.quantity}`,
      costSummary: group.totalCost > 0 ? moneyFn(group.totalCost) : "",
    }))
    .sort((a, b) => b.quantity - a.quantity || a.name.localeCompare(b.name));
}

function buildGroupedInventoryItems(rows = [], context = "inventory", options = {}) {
  const { sales = [] } = options;
  const groups = new Map();
  rows.forEach((row) => {
    const key = inventoryProductGroupKey(row, context);
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key).push(row);
  });

  return [...groups.entries()].map(([groupId, groupRows]) => {
    const primary = groupRows[0] || {};
    const totalQuantity = groupRows.reduce((sum, row) => sum + Number(row.quantity || 0), 0);
    const safeQuantity = Math.max(0, totalQuantity);
    const weighted = (field) => {
      if (safeQuantity <= 0) return Number(primary[field] || 0);
      return groupRows.reduce((sum, row) => sum + Number(row.quantity || 0) * Number(row[field] || 0), 0) / safeQuantity;
    };
    const saleHistory = context === "forge" ? buildForgeGroupSaleHistory(groupRows, sales) : [];
    const statusSummary = context === "forge" ? summarizeForgeGroupedInventoryStatus(groupRows, saleHistory) : null;
    const latestUpdatedAt = [
      ...groupRows
      .map((row) => row.updatedAt || row.updated_at || row.createdAt || row.created_at || "")
        .filter(Boolean),
      ...saleHistory.map((sale) => sale.activityDate || sale.saleDate || sale.createdAt || ""),
    ].filter(Boolean).sort();
    const latestTimestamp = latestUpdatedAt[latestUpdatedAt.length - 1] || primary.updatedAt || primary.createdAt || "";
    const purchaserBreakdown = summarizeBreakdownRows(groupRows, { type: "purchaser" });
    const locationBreakdown = summarizeBreakdownRows(groupRows, { type: "location" });
    const purchaserSummary = purchaserBreakdown.length <= 2
      ? purchaserBreakdown.map((entry) => `${entry.name} - ${entry.quantity}`).join(" / ")
      : `${purchaserBreakdown.length} purchasers`;
    const locationSummary = locationBreakdown.length <= 1
      ? locationBreakdown[0]?.name || forgePhysicalLocationLabel(primary) || ""
      : `${locationBreakdown.length} locations`;

    return {
      ...primary,
      id: primary.id,
      groupId,
      isGroupedInventory: groupRows.length > 1,
      rawItems: groupRows,
      groupedEntryCount: groupRows.length,
      quantity: safeQuantity,
      unitCost: weighted("unitCost"),
      marketPrice: weighted("marketPrice"),
      salePrice: weighted("salePrice"),
      msrpPrice: weighted("msrpPrice"),
      valuationSummary: buildGroupedInventoryValuation({ ...primary, rawItems: groupRows, quantity: safeQuantity }, { context }),
      saleHistory,
      statusSummary,
      soldQuantity: statusSummary?.soldQuantity || 0,
      listedQuantity: statusSummary?.listedQuantity || 0,
      totalActivityQuantity: statusSummary?.totalQuantity || safeQuantity,
      purchaserBreakdown,
      locationBreakdown,
      purchaserSummary,
      locationSummary,
      updatedAt: latestTimestamp,
    };
  });
}

function inventoryGroupEntries(item = {}) {
  return Array.isArray(item.rawItems) && item.rawItems.length ? item.rawItems : item ? [item] : [];
}

function inventoryEntryLabel(item = {}) {
  const pieces = [
    itemPurchaserName(item),
    `Qty ${Number(item.quantity || 0)}`,
    forgePhysicalLocationLabel(item),
    hasValue(item.unitCost) ? `Cost ${money(item.unitCost)}` : "",
  ].filter(Boolean);
  return pieces.join(" - ");
}

function mileageTripDateValue(trip = {}) {
  return trip.date || trip.tripDate || trip.createdAt || trip.created_at || "";
}

function vehicleGroupKeyForTrip(trip = {}, vehicle = {}) {
  const vehicleId = String(trip.vehicleId || trip.vehicle_id || vehicle.id || "").trim();
  if (vehicleId) return `vehicle:${vehicleId}`;
  const name = normalizeSearchText(trip.vehicleName || trip.vehicle_name || vehicle.name || "");
  return name ? `name:${name}` : "__unassigned_vehicle__";
}

function buildMileageVehicleGroups(trips = [], vehicles = []) {
  const vehicleById = new Map(vehicles.map((vehicle) => [String(vehicle.id), vehicle]));
  const currentYear = String(new Date().getFullYear());
  const groups = new Map();
  trips.forEach((trip) => {
    const vehicle = vehicleById.get(String(trip.vehicleId || trip.vehicle_id || ""));
    const key = vehicleGroupKeyForTrip(trip, vehicle);
    const vehicleName = trip.vehicleName || trip.vehicle_name || vehicle?.name || "No vehicle";
    if (!groups.has(key)) {
      groups.set(key, {
        key,
        vehicleId: trip.vehicleId || trip.vehicle_id || vehicle?.id || "",
        vehicleName,
        vehicle,
        trips: [],
        totalMiles: 0,
        ytdMiles: 0,
        businessMiles: 0,
        personalMiles: 0,
        totalVehicleCost: 0,
        totalMileageValue: 0,
        totalFuelCost: 0,
        totalWearCost: 0,
        purposeTotals: {},
        lastTripDate: "",
      });
    }
    const group = groups.get(key);
    group.trips.push(trip);
    const tripMiles = Number(trip.businessMiles || trip.business_miles || trip.miles || 0);
    const personalMiles = Number(trip.personalMiles || trip.personal_miles || 0);
    const tripDate = mileageTripDateValue(trip);
    const purpose = normalizeMileagePurpose(trip.purpose || trip.category || "");
    group.totalMiles += tripMiles;
    group.businessMiles += tripMiles;
    group.personalMiles += personalMiles;
    if (String(tripDate).slice(0, 4) === currentYear) group.ytdMiles += tripMiles;
    group.totalVehicleCost += Number(trip.totalVehicleCost || trip.total_vehicle_cost || 0);
    group.totalMileageValue += Number(trip.mileageValue || trip.mileage_value || 0);
    group.totalFuelCost += Number(trip.fuelCost || trip.fuel_cost || 0);
    group.totalWearCost += Number(trip.wearCost || trip.wear_cost || 0);
    group.purposeTotals[purpose] = (group.purposeTotals[purpose] || 0) + tripMiles;
    if (!group.lastTripDate || (tripDate && tripDate > group.lastTripDate)) group.lastTripDate = tripDate;
  });
  return [...groups.values()].map((group) => ({
    ...group,
    tripCount: group.trips.length,
    topPurposes: Object.entries(group.purposeTotals)
      .sort((a, b) => Number(b[1] || 0) - Number(a[1] || 0) || a[0].localeCompare(b[0]))
      .map(([purpose, miles]) => ({ purpose, miles })),
    trips: [...group.trips].sort((a, b) => String(mileageTripDateValue(b)).localeCompare(String(mileageTripDateValue(a)))),
  })).sort((a, b) => String(b.lastTripDate).localeCompare(String(a.lastTripDate)) || a.vehicleName.localeCompare(b.vehicleName));
}

function normalizeUserType(userType) {
  if (userType === "parent") return "budget";
  if (userType === "advanced") return "all_in_one";
  return USER_TYPES.includes(userType) ? userType : "collector";
}

function getDefaultHomeStatsForUserType(userType = "collector") {
  const enabledKeys = HOME_STAT_DEFAULTS[normalizeUserType(userType)] || HOME_STAT_DEFAULTS.collector;
  return HOME_STATS.reduce((settings, stat) => ({ ...settings, [stat.key]: enabledKeys.includes(stat.key) }), {});
}

function normalizeHomeStatsEnabled(savedStats, userType = "collector") {
  const defaults = getDefaultHomeStatsForUserType(userType);
  if (!savedStats || typeof savedStats !== "object") return defaults;
  return HOME_STATS.reduce(
    (settings, stat) => ({ ...settings, [stat.key]: savedStats[stat.key] ?? defaults[stat.key] }),
    {}
  );
}
function isHomeStatEnabled(profile, statKey) {
  const userType = normalizeUserType(profile?.userType || profile?.user_type);
  const enabled = normalizeHomeStatsEnabled(profile?.homeStatsEnabled || profile?.home_stats_enabled, userType);
  return enabled[statKey] !== false;
}

function normalizeDashboardPreset(preset) {
  const aliases = {
    parent: "budget_parent",
    budget: "budget_parent",
    scout: "restock_scout",
    advanced: "full_business",
    all_in_one: "full_business",
  };
  const normalized = aliases[preset] || preset;
  return DASHBOARD_PRESETS.includes(normalized) ? normalized : "simple";
}

function normalizeDashboardCardStyle(style) {
  return DASHBOARD_CARD_STYLES.includes(style) ? style : "comfortable";
}

function dashboardPresetLabel(preset) {
  const normalized = normalizeDashboardPreset(preset);
  return DASHBOARD_PRESET_OPTIONS.find((option) => option.key === normalized)?.label || normalized.charAt(0).toUpperCase() + normalized.slice(1);
}

function getDashboardPresetForUserType(userType = "collector") {
  const map = { collector: "collector", seller: "seller", scout: "restock_scout", budget: "budget_parent", all_in_one: "full_business" };
  return map[normalizeUserType(userType)] || "simple";
}

function getDefaultDashboardLayoutForPreset(preset = "simple") {
  const normalized = normalizeDashboardPreset(preset);
  const enabledKeys = DASHBOARD_PRESET_SECTIONS[normalized] || DASHBOARD_PRESET_SECTIONS.simple;
  return {
    sections: DASHBOARD_SECTIONS.map((section, index) => ({
      key: section.key,
      enabled: section.locked ? true : enabledKeys.includes(section.key),
      order: enabledKeys.includes(section.key) ? enabledKeys.indexOf(section.key) + 1 : index + 100,
      collapsed: false,
    })).sort((a, b) => a.order - b.order),
  };
}

function normalizeDashboardLayout(layout, preset = "simple") {
  const defaults = getDefaultDashboardLayoutForPreset(preset);
  const savedSections = Array.isArray(layout?.sections) ? layout.sections : [];
  return {
    sections: DASHBOARD_SECTIONS.map((section) => {
      const saved = savedSections.find((candidate) => candidate.key === section.key);
      const fallback = defaults.sections.find((candidate) => candidate.key === section.key);
      return {
        key: section.key,
        enabled: section.locked ? true : saved?.enabled ?? fallback?.enabled ?? false,
        order: Number(saved?.order ?? fallback?.order ?? 100),
        collapsed: Boolean(saved?.collapsed ?? fallback?.collapsed ?? false),
      };
    }).sort((a, b) => a.order - b.order),
  };
}

function normalizeLocalSubscriptionProfile(savedProfile = {}) {
  return {
    subscriptionPlan: savedProfile.subscriptionPlan || savedProfile.subscription_plan || PLAN_TYPES.FREE,
    featureTier: savedProfile.featureTier || savedProfile.feature_tier || savedProfile.tier || PLAN_TYPES.FREE,
    tier: savedProfile.tier || savedProfile.featureTier || savedProfile.feature_tier || PLAN_TYPES.FREE,
    appRole: normalizeAppRole(savedProfile.appRole || savedProfile.app_role || savedProfile.userRole || savedProfile.user_role),
    app_role: normalizeAppRole(savedProfile.app_role || savedProfile.appRole || savedProfile.userRole || savedProfile.user_role),
    userRole: savedProfile.userRole || savedProfile.user_role || USER_ROLES.USER,
    isAdmin: Boolean(savedProfile.isAdmin || savedProfile.is_admin),
    subscriptionStatus: savedProfile.subscriptionStatus || savedProfile.subscription_status || "active",
    subscriptionStartedAt: savedProfile.subscriptionStartedAt || savedProfile.subscription_started_at || "",
    subscriptionExpiresAt: savedProfile.subscriptionExpiresAt || savedProfile.subscription_expires_at || "",
    lifetimeAccess: Boolean(savedProfile.lifetimeAccess || savedProfile.lifetime_access),
  };
}

function isDashboardSectionEnabled(profile, sectionKey) {
  const preset = normalizeDashboardPreset(profile?.dashboardPreset || profile?.dashboard_preset);
  const layout = normalizeDashboardLayout(profile?.dashboardLayout || profile?.dashboard_layout, preset);
  return layout.sections.find((section) => section.key === sectionKey)?.enabled !== false;
}

function statusClass(status) {
  return `status-badge ${String(status || "In Stock")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-|-$/g, "")}`;
}

function InfoTooltip({ label = "More information", children }) {
  const [open, setOpen] = useState(false);
  if (!children) return null;
  return (
    <span className="info-tooltip">
      <button
        type="button"
        className="info-tooltip-trigger"
        aria-label={label}
        aria-expanded={open}
        onClick={(event) => {
          event.preventDefault();
          event.stopPropagation();
          setOpen((current) => !current);
        }}
      >
        &#9432;
      </button>
      {open ? (
        <span className="info-tooltip-bubble" role="tooltip">
          {children}
        </span>
      ) : null}
    </span>
  );
}

function Field({ label, children, error = "", fieldId = "", className = "", help = "" }) {
  const classes = [className, error ? "has-error" : ""].filter(Boolean).join(" ");
  if (help) {
    return (
      <div className={["field-help-wrapper", classes].filter(Boolean).join(" ")}>
        <div className="field-help-heading">
          <span>{label}</span>
          <InfoTooltip label="Field information">{help}</InfoTooltip>
        </div>
        <label className="field-control-label" data-validation-field={fieldId || undefined}>
          <span className="sr-only">{label}</span>
          {children}
          {error ? <span className="field-error" role="alert">{error}</span> : null}
        </label>
      </div>
    );
  }
  return (
    <label className={classes || undefined} data-validation-field={fieldId || undefined}>
      <span className="field-label-row">
        <span>{label}</span>
      </span>
      {children}
      {error ? <span className="field-error" role="alert">{error}</span> : null}
    </label>
  );
}

function PurchaserSelect({
  label = "Who paid?",
  purchasers = [],
  valueId = "",
  valueName = "",
  onSelect,
  onCreatePurchaser,
  onManagePurchasers,
  help = "",
  emptyCopy = "No purchasers yet. Add one to track who paid. People you add here are reusable across Vault, Forge, receipts, mileage, sales, and Payout Assist.",
  addLabel = "Add person",
  manageLabel = "Manage People",
}) {
  const [showNewPurchaser, setShowNewPurchaser] = useState(false);
  const [newPurchaserName, setNewPurchaserName] = useState("");
  const [newPurchaserNote, setNewPurchaserNote] = useState("");
  const [newPurchaserType, setNewPurchaserType] = useState("Family");
  const currentActive = purchasers.find((purchaser) => String(purchaser.id) === String(valueId));
  const currentByName = purchasers.find((purchaser) => purchaser.name === valueName);
  const historicalName = valueName && !currentActive && !currentByName ? valueName : "";
  const currentValue = currentActive?.id || currentByName?.id || (historicalName ? "__historical__" : "");

  function handleChange(event) {
    const nextValue = event.target.value;
    if (nextValue === "__add__") {
      setShowNewPurchaser(true);
      return;
    }
    if (nextValue === "__manage__") {
      onManagePurchasers?.();
      return;
    }
    const purchaser = purchasers.find((candidate) => String(candidate.id) === String(nextValue));
    onSelect?.(purchaser || null);
  }

  function saveInlinePurchaser() {
    const created = onCreatePurchaser?.(newPurchaserName, newPurchaserNote, newPurchaserType);
    if (!created) return;
    onSelect?.(created);
    setNewPurchaserName("");
    setNewPurchaserNote("");
    setNewPurchaserType("Family");
    setShowNewPurchaser(false);
  }

  return (
    <div className="purchaser-select-field">
      <Field label={label} help={help || INFO_TOOLTIP_COPY.whoPaid}>
        <select value={currentValue} onChange={handleChange}>
          <option value="">No person selected</option>
          {historicalName ? <option value="__historical__" disabled>{historicalName} (historical)</option> : null}
          {purchasers.map((purchaser) => (
            <option key={purchaser.id} value={purchaser.id}>
              {purchaser.name}{purchaser.type ? ` - ${purchaser.type}` : ""}{purchaser.note ? ` - ${purchaser.note}` : ""}
            </option>
          ))}
          <option value="__add__">Add new person...</option>
          <option value="__manage__">{manageLabel}...</option>
        </select>
      </Field>
      {!purchasers.length ? (
        <div className="small-empty-state purchaser-empty-state">
          <p>{emptyCopy}</p>
          <button type="button" className="secondary-button" onClick={() => setShowNewPurchaser(true)}>
            {addLabel}
          </button>
        </div>
      ) : null}
      {showNewPurchaser ? (
        <div className="inline-form purchaser-inline-form">
          <input
            value={newPurchaserName}
            maxLength={PURCHASER_NAME_MAX_LENGTH}
            onChange={(event) => setNewPurchaserName(event.target.value)}
            placeholder="Display name"
          />
          <select value={newPurchaserType} onChange={(event) => setNewPurchaserType(event.target.value)}>
            {PERSON_TYPE_OPTIONS.map((type) => <option key={type} value={type}>{type}</option>)}
          </select>
          <input
            value={newPurchaserNote}
            onChange={(event) => setNewPurchaserNote(event.target.value)}
            placeholder="Optional note, card, partner..."
          />
          <button type="button" onClick={saveInlinePurchaser}>Save Person</button>
          <button type="button" className="secondary-button" onClick={() => setShowNewPurchaser(false)}>Cancel</button>
        </div>
      ) : null}
    </div>
  );
}

function VehicleSelect({
  label = "Vehicle",
  vehicles = [],
  valueId = "",
  onSelect,
  onCreateVehicle,
  help = INFO_TOOLTIP_COPY.vehicle,
}) {
  const [showNewVehicle, setShowNewVehicle] = useState(false);
  const [draft, setDraft] = useState({ name: "", owner: "", averageMpg: "", wearCostPerMile: "", notes: "" });
  const currentValue = vehicles.some((vehicle) => String(vehicle.id) === String(valueId)) ? valueId : "";

  function updateDraft(field, value) {
    setDraft((current) => ({ ...current, [field]: value }));
  }

  async function saveInlineVehicle() {
    const created = await onCreateVehicle?.(draft);
    if (!created) return;
    onSelect?.(created);
    setDraft({ name: "", owner: "", averageMpg: "", wearCostPerMile: "", notes: "" });
    setShowNewVehicle(false);
  }

  return (
    <div className="vehicle-select-field">
      <Field label={label} help={help}>
        <select
          value={currentValue}
          onChange={(event) => {
            const vehicle = vehicles.find((candidate) => String(candidate.id) === String(event.target.value));
            onSelect?.(vehicle || null);
          }}
        >
          <option value="">No vehicle selected</option>
          {vehicles.filter((vehicle) => vehicle.active !== false).map((vehicle) => (
            <option key={vehicle.id} value={vehicle.id}>
              {vehicle.name}{vehicle.owner ? ` - ${vehicle.owner}` : ""}{vehicle.averageMpg ? ` - ${vehicle.averageMpg} MPG` : ""}
            </option>
          ))}
        </select>
      </Field>
      {!vehicles.length ? (
        <div className="small-empty-state vehicle-empty-state">
          <p>No vehicles yet. Add one once, then reuse it for mileage and business records.</p>
          <button type="button" className="secondary-button" onClick={() => setShowNewVehicle(true)}>Add vehicle</button>
        </div>
      ) : (
        <button type="button" className="text-link-button add-inline-link" onClick={() => setShowNewVehicle(true)}>
          Add another vehicle
        </button>
      )}
      {showNewVehicle ? (
        <div className="inline-form vehicle-inline-form">
          <input value={draft.name} onChange={(event) => updateDraft("name", event.target.value)} placeholder="Vehicle name" />
          <input value={draft.owner} onChange={(event) => updateDraft("owner", event.target.value)} placeholder="Owner or driver" />
          <input type="number" step="0.1" value={draft.averageMpg} onChange={(event) => updateDraft("averageMpg", event.target.value)} placeholder="Average MPG optional" />
          <input type="number" step="0.01" value={draft.wearCostPerMile} onChange={(event) => updateDraft("wearCostPerMile", event.target.value)} placeholder="Cost per mile optional" />
          <input value={draft.notes} onChange={(event) => updateDraft("notes", event.target.value)} placeholder="Optional notes" />
          <button type="button" onClick={() => void saveInlineVehicle()}>Save Vehicle</button>
          <button type="button" className="secondary-button" onClick={() => setShowNewVehicle(false)}>Cancel</button>
        </div>
      ) : null}
    </div>
  );
}

function DetailItem({ label, value }) {
  return (
    <div className="detail-item">
      <span>{label}</span>
      <strong>{value || "Not listed"}</strong>
    </div>
  );
}

function maskEmail(value = "") {
  const [name = "", domain = ""] = String(value || "").split("@");
  if (!name || !domain) return value || "Email unavailable";
  const visible = name.length <= 2 ? `${name.slice(0, 1)}*` : `${name.slice(0, 2)}***`;
  return `${visible}@${domain}`;
}

function clampPageSize(value, fallback = 24) {
  const size = Number(value || fallback);
  return CATALOG_PAGE_SIZE_OPTIONS.includes(size) ? size : fallback;
}

function getDefaultCatalogPageSize() {
  if (typeof window === "undefined") return 24;
  const saved = clampPageSize(localStorage.getItem(CATALOG_PAGE_SIZE_STORAGE_KEY), 0);
  if (saved) return saved;
  return window.innerWidth >= 900 ? 48 : 24;
}

function clampPage(page, pageCount) {
  return Math.min(Math.max(1, Number(page || 1)), Math.max(1, Number(pageCount || 1)));
}

function getPageCount(totalCount, pageSize = LONG_LIST_PAGE_SIZE) {
  return Math.max(1, Math.ceil(Number(totalCount || 0) / Math.max(1, Number(pageSize || LONG_LIST_PAGE_SIZE))));
}

function getPagedItems(items = [], page = 1, pageSize = LONG_LIST_PAGE_SIZE) {
  const pageCount = getPageCount(items.length, pageSize);
  const currentPage = clampPage(page, pageCount);
  const startIndex = (currentPage - 1) * pageSize;
  return {
    items: items.slice(startIndex, startIndex + pageSize),
    page: currentPage,
    pageCount,
    start: items.length ? startIndex + 1 : 0,
    end: Math.min(startIndex + pageSize, items.length),
    total: items.length,
  };
}

function pageNumberItems(page = 1, pageCount = 1, maxVisible = 7) {
  const currentPage = clampPage(page, pageCount);
  const totalPages = Math.max(1, Number(pageCount || 1));
  if (totalPages <= maxVisible) return Array.from({ length: totalPages }, (_, index) => index + 1);

  const siblings = maxVisible <= 5 ? 1 : 2;
  const pages = new Set([1, totalPages, currentPage]);
  for (let offset = 1; offset <= siblings; offset += 1) {
    if (currentPage - offset > 1) pages.add(currentPage - offset);
    if (currentPage + offset < totalPages) pages.add(currentPage + offset);
  }

  const sorted = [...pages].sort((a, b) => a - b);
  const result = [];
  sorted.forEach((value, index) => {
    if (index > 0 && value - sorted[index - 1] > 1) result.push(`gap-${sorted[index - 1]}-${value}`);
    result.push(value);
  });
  return result;
}

function PaginationControls({
  label = "Results",
  page = 1,
  pageCount = 1,
  totalCount = 0,
  pageSize = LONG_LIST_PAGE_SIZE,
  pageSizeOptions = null,
  onPageChange,
  onPageSizeChange,
  disabled = false,
  compact = false,
}) {
  const safePageCount = Math.max(1, Number(pageCount || 1));
  const safePage = clampPage(page, safePageCount);
  const safeTotal = Number(totalCount || 0);
  const start = safeTotal ? (safePage - 1) * pageSize + 1 : 0;
  const end = safeTotal ? Math.min(safePage * pageSize, safeTotal) : 0;
  const visiblePages = pageNumberItems(safePage, safePageCount, compact ? 5 : 7);

  if (safeTotal <= pageSize && !pageSizeOptions) return null;

  return (
    <nav className={`pagination-controls ${compact ? "pagination-controls--compact" : ""}`.trim()} aria-label={`${label} pagination`}>
      <div className="pagination-count">
        {safeTotal ? `Showing ${start}-${end} of ${safeTotal} ${label.toLowerCase()}` : `No ${label.toLowerCase()}`}
      </div>
      <div className="pagination-actions">
        <button type="button" className="secondary-button" disabled={disabled || safePage <= 1} onClick={() => onPageChange?.(safePage - 1)}>
          Previous
        </button>
        <div className="pagination-page-list" aria-label="Page numbers">
          {visiblePages.map((item) =>
            typeof item === "number" ? (
              <button
                type="button"
                key={item}
                className={item === safePage ? "active" : ""}
                aria-current={item === safePage ? "page" : undefined}
                disabled={disabled || item === safePage}
                onClick={() => onPageChange?.(item)}
              >
                {item}
              </button>
            ) : (
              <span key={item} aria-hidden="true">...</span>
            )
          )}
        </div>
        <span className="pagination-mobile-current">Page {safePage} of {safePageCount}</span>
        <button type="button" className="secondary-button" disabled={disabled || safePage >= safePageCount} onClick={() => onPageChange?.(safePage + 1)}>
          Next
        </button>
      </div>
      {pageSizeOptions?.length ? (
        <label className="pagination-size-control">
          <span>Per page</span>
          <select value={pageSize} disabled={disabled} onChange={(event) => onPageSizeChange?.(Number(event.target.value))}>
            {pageSizeOptions.map((option) => <option key={option} value={option}>{option}</option>)}
          </select>
        </label>
      ) : null}
    </nav>
  );
}

function QuickActionGrid({ actions = [], className = "", ariaLabel = "Quick actions" }) {
  const visibleActions = actions.filter(Boolean);
  if (!visibleActions.length) return null;

  return (
    <div className={`quick-action-card-grid ${className}`.trim()} aria-label={ariaLabel}>
      {visibleActions.map((action) => {
        const title = action.title || action.label || "Action";
        const iconKey = action.icon || action.key || title;
        return (
          <button
            key={action.key || title}
            type="button"
            className={`quick-action-card icon-action-tile ${action.primary ? "primary" : "secondary-button"} ${action.className || ""}`.trim()}
            onClick={action.onClick}
            disabled={action.disabled}
            aria-label={action.ariaLabel || title}
          >
            <span className="command-icon" aria-hidden="true"><CommandGlyphIcon seed={iconKey} /></span>
            <span className="quick-action-copy">
              <span>{title}</span>
              {action.subtitle ? <small>{action.subtitle}</small> : null}
            </span>
          </button>
        );
      })}
    </div>
  );
}

function commandIconKind(seed = "") {
  const key = String(seed).toLowerCase();
  if (/home|hearth/.test(key)) return "home";
  if (/newstuff|announcement|update/.test(key)) return "clipboard";
  if (/scan|camera|barcode/.test(key)) return "scan";
  if (/search|find/.test(key)) return "search";
  if (/import|bulk|receipt|clipboard/.test(key)) return "clipboard";
  if (/kid|spark|family|giveaway/.test(key)) return "spark";
  if (/tidepool|post|community|comment|pool/.test(key)) return "pool";
  if (/scout|signal|report|map|store/.test(key)) return "scout";
  if (/vault|card|collection|sealed|wishlist/.test(key)) return "vault";
  if (/market|trade|deal|listing|watch|exchange/.test(key)) return "market";
  if (/forge|inventory|sale|expense|mileage|product|workshop/.test(key)) return "forge";
  if (/daily|calendar/.test(key)) return "calendar";
  return "plus";
}

function CommandGlyphIcon({ seed = "" }) {
  return <AppNavIcon kind={commandIconKind(seed)} />;
}

function commandGlyph(seed = "") {
  const key = String(seed).toLowerCase();
  if (/scout|signal|report|map|store/.test(key)) return "⌁";
  if (/vault|card|collection|sealed|wishlist/.test(key)) return "▣";
  if (/market|trade|deal|listing|watch/.test(key)) return "⇄";
  if (/forge|inventory|sale|expense|receipt|mileage|product/.test(key)) return "⚒";
  if (/tidepool|post|community|comment/.test(key)) return "◌";
  if (/kid|spark|family|giveaway/.test(key)) return "✦";
  if (/scan|camera|barcode/.test(key)) return "⌗";
  if (/import|bulk/.test(key)) return "⇥";
  if (/search|find/.test(key)) return "⌕";
  if (/scout|signal|report|map|store/.test(key)) return "⌁";
  if (/vault|card|collection|sealed|wishlist/.test(key)) return "▣";
  if (/market|trade|deal|listing|watch/.test(key)) return "⇄";
  if (/forge|inventory|sale|expense|receipt|mileage|product/.test(key)) return "⚒";
  if (/tidepool|post|community|comment/.test(key)) return "◌";
  if (/kid|spark|family|giveaway/.test(key)) return "✦";
  if (/scan|camera|barcode/.test(key)) return "⌗";
  if (/import|bulk/.test(key)) return "⇥";
  if (/search|find/.test(key)) return "⌕";
  return "+";
}

function sectionHeroKind(title = "", className = "") {
  const value = `${title} ${className}`.toLowerCase();
  if (/new stuff|announcement|washed|what'?s new|known limitations|partner|links|trust/.test(value)) return "newstuff";
  if (/admin|operations|moderation|review|readiness/.test(value)) return "admin";
  if (/settings|menu|support|profile|suggestions/.test(value)) return "settings";
  if (/ember watch|monthly|calendar|drops?/.test(value)) return "watch";
  if (/tide forecast|forecast|planner|guess|prediction|window/.test(value)) return "forecast";
  if (/\bstores?\b|store map|map/.test(value)) return "stores";
  if (/wishlist|wanted|watchlist/.test(value)) return "wishlist";
  if (/daily|today/.test(value)) return "daily";
  if (/kids|spark|family/.test(value)) return "spark";
  if (/tidepool|community/.test(value)) return "tidepool";
  if (/forge|workshop|inventory|business/.test(value)) return "forge";
  if (/market|exchange|tidetradr|deal|listing/.test(value)) return "market";
  if (/vault|deep|collection|sets?/.test(value)) return "vault";
  if (/scout|signal|report/.test(value)) return "scout";
  return "hearth";
}

