  useEffect(() => {
    if (!catalogSearchHasRun) {
      setSupabaseCatalogStatus((current) => ({ ...current, page: 1, pageSize: catalogPageSize }));
      return undefined;
    }
    const query = submittedCatalogSearch || catalogSearch;
    const barcode = submittedCatalogBarcodeSearch || catalogBarcodeSearch;
    if (!canRunCatalogSearch(query, barcode)) return undefined;
    const timer = window.setTimeout(() => {
      loadImportedPokemonCatalog(query, {
        page: 1,
        pageSize: catalogPageSize,
        mode: barcode ? "barcode" : "general",
        barcode,
      }).then(() => scrollToResultsTop(catalogResultsRef));
    }, 80);
    return () => window.clearTimeout(timer);
  }, [catalogKindFilter, catalogDataFilter, catalogSetFilter, catalogTypeFilter, catalogRarityFilter, catalogSort, catalogPageSize]);

  useEffect(() => {
    if (typeof window === "undefined") return undefined;

    let frameId = 0;
    const updateBackToTop = () => {
      frameId = 0;
      setShowBackToTop((window.scrollY || document.documentElement.scrollTop || 0) > 500);
    };
    const handleScroll = () => {
      if (!frameId) frameId = window.requestAnimationFrame(updateBackToTop);
    };

    updateBackToTop();
    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => {
      window.removeEventListener("scroll", handleScroll);
      if (frameId) window.cancelAnimationFrame(frameId);
    };
  }, []);

  const updateItemForm = (field, value) => setItemForm((old) => ({ ...old, [field]: value }));
  const updateCatalogForm = (field, value) => setCatalogForm((old) => ({ ...old, [field]: value }));

  function useSmartCatalogProduct(product) {
  setCatalogForm((old) => ({
    ...old,
    name: product.name,
    category: "Pokemon",
    setName: product.expansion || "",
    productType: product.itemType || "",
    barcode: product.upcs?.[0] || "",
    marketPrice: product.marketPrice || "",
    lowPrice: "",
    midPrice: product.marketPrice || "",
    highPrice: "",
    msrpPrice: product.msrpPrice || "",
    setCode: product.setCode || "",
    expansion: product.expansion || "",
    productLine: product.productLine || "",
    packCount: product.packCount || "",
    notes: [
      product.conditionDefault ? `Condition: ${product.conditionDefault}` : "",
      product.languageDefault ? `Language: ${product.languageDefault}` : "",
      product.upcs?.length ? `UPC(s): ${product.upcs.join(", ")}` : "",
    ]
      .filter(Boolean)
      .join(" | "),
  }));
}

  const updateExpenseForm = (field, value) => setExpenseForm((old) => ({ ...old, [field]: value }));
  const updateVehicleForm = (field, value) => setVehicleForm((old) => ({ ...old, [field]: value }));
  const updateTripForm = (field, value) => setTripForm((old) => ({ ...old, [field]: value }));
  const updateSaleForm = (field, value) => setSaleForm((old) => ({ ...old, [field]: value }));
  const updateDealForm = (field, value) => setDealForm((old) => ({ ...old, [field]: value }));
  const updateKidProjectForm = (field, value) => setKidProjectForm((old) => ({ ...old, [field]: value }));
  const phase2Context = (overrides = {}) => ({
    supabase,
    isSupabaseConfigured,
    user,
    workspaceId: overrides.workspaceId || activeWorkspaceId,
    requireSupabase: !BETA_LOCAL_MODE,
  });
  const forgePhase2Context = () => phase2Context({ workspaceId: activeForgeWorkspace?.id || activeWorkspaceId });
  const phase2RecentDeals = phase2Data.dealFinderSessions || [];
  const phase2RecentScannerIntakes = phase2Data.scannerIntakeSessions || [];
  const phase2RecentReceipts = phase2Data.receiptRecords || [];
  const phase2RecentAiAssistEvents = phase2Data.aiAssistEvents || [];
  const forgeReceiptRecords = commandDeskSellerAccess && activeForgeWorkspace
    ? (forgePhase2Data.receiptRecords || []).filter((receipt) => recordBelongsToWorkspace(receipt, activeForgeWorkspace.id))
    : [];
  const forgeReceiptIds = new Set(forgeReceiptRecords.map((receipt) => String(receipt.id || "")).filter(Boolean));
  const forgeReceiptLineItems = commandDeskSellerAccess && activeForgeWorkspace
    ? (forgePhase2Data.receiptLineItems || []).filter((line) => !forgeReceiptIds.size || forgeReceiptIds.has(String(line.receiptId || line.receipt_id || "")))
    : [];
  const visibleReceiptRecords = useMemo(() => {
    const seen = new Set();
    return [
      quickAddWizard.receiptSaved,
      ...forgeReceiptRecords,
      ...phase2RecentReceipts,
    ]
      .filter(Boolean)
      .filter((receipt) => {
        const id = String(receipt.id || receipt.receiptId || "");
        if (!id || seen.has(id)) return false;
        seen.add(id);
        return true;
      })
      .sort((a, b) => String(b.purchasedAt || b.purchaseDate || b.createdAt || "").localeCompare(String(a.purchasedAt || a.purchaseDate || a.createdAt || "")));
  }, [forgeReceiptRecords, phase2RecentReceipts, quickAddWizard.receiptSaved]);
  const phase2WorkflowSyncLabel = phase2SyncStatus.source === "supabase"
    ? "Cloud synced"
    : phase2SyncStatus.label || "Local only mode";
  const phase2ReceiptLineItemCounts = (phase2Data.receiptLineItems || []).reduce((acc, item) => {
    if (item.receiptId) acc[item.receiptId] = (acc[item.receiptId] || 0) + 1;
    return acc;
  }, {});
  const phase2ReceiptDestinationSummaries = (phase2Data.receiptLineItems || []).reduce((acc, item) => {
    if (!item.receiptId) return acc;
    const destination = normalizeReceiptDestination(item.destination);
    const label = RECEIPT_DESTINATION_LABELS[destination] || "Expense only";
    acc[item.receiptId] = acc[item.receiptId] || {};
    acc[item.receiptId][label] = (acc[item.receiptId][label] || 0) + 1;
    return acc;
  }, {});
  const phase2ReceiptDestinationSummaryText = (receiptId) => {
    const counts = phase2ReceiptDestinationSummaries[receiptId] || {};
    const summary = Object.entries(counts).map(([label, count]) => `${label} ${count}`).join(", ");
    return summary || "No destinations";
  };
  const receiptRecordId = (receipt = {}) => String(receipt.id || receipt.receiptId || receipt.receipt_id || "");
  const receiptMerchantLabel = (receipt = {}) => receipt.merchant || receipt.storeName || receipt.store_name || receipt.vendor || "Saved receipt";
  const receiptDateLabel = (receipt = {}) => {
    const value = receipt.purchaseDate || receipt.purchase_date || receipt.purchasedAt || receipt.purchased_at || receipt.createdAt || receipt.created_at || "";
    return value ? shortDate(value) : "Date not set";
  };
  const receiptDateInputValue = (receipt = {}) => {
    const value = receipt.purchaseDate || receipt.purchase_date || receipt.purchasedAt || receipt.purchased_at || "";
    return value ? String(value).slice(0, 10) : new Date().toISOString().slice(0, 10);
  };
  const receiptImageUrl = (receipt = {}) => receipt.receiptImageUrl || receipt.receipt_image_url || receipt.receiptImage || receipt.receipt_image || receipt.imageUrl || receipt.image_url || "";
  const findReceiptRecord = (receiptOrId) => {
    const id = typeof receiptOrId === "object" ? receiptRecordId(receiptOrId) : String(receiptOrId || "");
    return visibleReceiptRecords.find((receipt) => receiptRecordId(receipt) === id) || (typeof receiptOrId === "object" ? receiptOrId : null);
  };
  const allReceiptLineItems = () => {
    const seen = new Set();
    return [...(phase2Data.receiptLineItems || []), ...(forgePhase2Data.receiptLineItems || [])].filter((line) => {
      const key = String(line.id || `${line.receiptId || line.receipt_id}-${line.createdInventoryItemId || line.created_inventory_item_id}-${line.itemName || line.item_name || line.productName || line.product_name}`);
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  };
  const receiptLinesFor = (receipt = {}) => {
    const id = receiptRecordId(receipt);
    if (!id) return [];
    return allReceiptLineItems().filter((line) => String(line.receiptId || line.receipt_id || "") === id);
  };
  const receiptLinkedItems = (receipt = {}) => {
    const id = receiptRecordId(receipt);
    const image = receiptImageUrl(receipt);
    if (!id && !image) return [];
    return items.filter((item) => (
      String(item.receiptId || item.receipt_id || item.linkedReceiptId || item.linked_receipt_id || "") === id ||
      (image && String(item.receiptImage || item.receipt_image || item.receiptImageUrl || item.receipt_image_url || "") === String(image)) ||
      (id && String(item.actionNotes || item.notes || "").includes(id))
    ));
  };
  const receiptLinkedExpenses = (receipt = {}) => {
    const id = receiptRecordId(receipt);
    const image = receiptImageUrl(receipt);
    if (!id && !image) return [];
    return expenses.filter((expense) => (
      String(expense.receiptId || expense.receipt_id || "") === id ||
      (image && String(expense.receiptImage || expense.receipt_image || expense.receiptPhoto || expense.receipt_photo || "") === String(image)) ||
      (id && String(expense.notes || "").includes(id))
    ));
  };
  const receiptLinkedSales = (receipt = {}) => {
    const id = receiptRecordId(receipt);
    const image = receiptImageUrl(receipt);
    if (!id && !image) return [];
    return workspaceSales.filter((sale) => (
      String(sale.receiptId || sale.receipt_id || "") === id ||
      String(sale.referenceId || "").includes(id) ||
      (image && String(sale.receiptImage || sale.receiptImageUrl || "") === String(image))
    ));
  };
  const receiptTotalLabel = (receipt = {}) => Number(receipt.total ?? receipt.receiptTotal ?? receipt.receipt_total ?? 0)
    ? money(receipt.total ?? receipt.receiptTotal ?? receipt.receipt_total ?? 0)
    : "Total optional";
  const selectedReceiptRecord = selectedReceiptId ? findReceiptRecord(selectedReceiptId) : null;
  const phase2RecentKidProjects = phase2Data.kidCommunityProjects || [];
  const phase2KidProjectItemCounts = (phase2Data.kidCommunityProjectItems || []).reduce((acc, item) => {
    if (item.projectId) acc[item.projectId] = (acc[item.projectId] || 0) + 1;
    return acc;
  }, {});
  const phase2MarketplaceDraftListings = Object.values(
    (phase2Data.marketplaceListingChannels || []).reduce((acc, channel) => {
      const key = channel.sourceInventoryId || channel.id;
      if (!acc[key]) {
        acc[key] = {
          id: key,
          title: channel.listingTitle || "Marketplace channel draft",
          listingType: "Cross-listing",
          status: channel.listingStatus || "Draft",
          askingPrice: Number(channel.listedPrice || 0),
          condition: "Channel draft",
          locationState: "VA",
          sourceType: "phase2-channel",
          sourceItemId: channel.sourceInventoryId || "",
          catalogItemId: channel.catalogItemId || "",
          channels: [],
          createdAt: channel.createdAt,
          updatedAt: channel.updatedAt,
        };
      }
      acc[key].channels.push(channel);
      return acc;
    }, {})
  );
  const updatePhase2Status = (result, fallbackMessage = "Phase 2 workflow saved.") => {
    const source = result?.source || "local";
    const error = result?.error;
    if (source === "supabase") {
      setPhase2SyncStatus({ source, kind: "connected", label: "Supabase connected", message: "Supabase connected. Saved to Supabase Phase 2 tables." });
      return;
    }
    const classified = classifyPhase2SyncError(error);
    setPhase2SyncStatus({
      source,
      kind: classified.kind,
      label: classified.label,
      message: error ? classified.message : `Local only mode. ${fallbackMessage}`,
    });
  };
  async function logAiAssistEvent(featureArea, payload = {}) {
    const sanitizeAiLogText = (value = "") => String(value || "")
      .replace(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi, "[email redacted]")
      .replace(/\b(?:\d[ -]*?){13,19}\b/g, "[number redacted]")
      .replace(/\b(?:password|token|secret|authorization)\s*[:=]\s*\S+/gi, "[sensitive redacted]")
      .replace(/\s+/g, " ")
      .trim()
      .slice(0, 360);
    const event = {
      id: makeId("ai-assist"),
      featureArea,
      inputSummary: sanitizeAiLogText(payload.inputSummary || ""),
      outputSummary: sanitizeAiLogText(payload.outputSummary || ""),
      confidenceScore: payload.confidenceScore == null ? null : Number(payload.confidenceScore),
      status: payload.status || "suggested",
      accepted: payload.accepted ?? null,
      relatedEntityType: payload.relatedEntityType || "",
      relatedEntityId: payload.relatedEntityId || "",
      createdAt: new Date().toISOString(),
    };
    setPhase2Data((current) => ({
      ...current,
      aiAssistEvents: [event, ...(current.aiAssistEvents || [])].slice(0, 50),
    }));
    const result = await saveAiAssistEvent(phase2Context(), event);
    updatePhase2Status(result, "Guided suggestion logged locally.");
    return result;
  }
  function getLocalFeedbackRecords() {
    if (typeof localStorage === "undefined") return [];
    try {
      const rows = JSON.parse(localStorage.getItem(FEEDBACK_STORAGE_KEY) || "[]");
      return Array.isArray(rows) ? rows : [];
    } catch {
      return [];
    }
  }
  async function showAiSuggestion(featureArea, suggestion, fallbackMessage = "") {
    const output = suggestion?.outputSummary || fallbackMessage || AI_REVIEW_DISCLAIMER;
    const reviewId = makeId("ai-review");
    setAiAssistReview({
      id: reviewId,
      featureArea,
      title: suggestion?.title || "Guided suggestion",
      inputSummary: suggestion?.inputSummary || "",
      outputSummary: output,
      editableOutput: output,
      confidenceScore: suggestion?.confidenceScore == null ? null : Number(suggestion.confidenceScore),
      relatedEntityType: suggestion?.relatedEntityType || "",
      relatedEntityId: suggestion?.relatedEntityId || "",
      status: "suggested",
      createdAt: new Date().toISOString(),
    });
    setVaultToast(output);
    await logAiAssistEvent(featureArea, {
      inputSummary: suggestion?.inputSummary || "",
      outputSummary: output,
      confidenceScore: suggestion?.confidenceScore,
      relatedEntityType: suggestion?.relatedEntityType,
      relatedEntityId: suggestion?.relatedEntityId,
    });
    return output;
  }

  async function resolveAiAssistReview(status = "accepted") {
    if (!aiAssistReview) return;
    const edited = String(aiAssistReview.editableOutput || "") !== String(aiAssistReview.outputSummary || "");
    await logAiAssistEvent(aiAssistReview.featureArea, {
      inputSummary: aiAssistReview.inputSummary,
      outputSummary: aiAssistReview.editableOutput || aiAssistReview.outputSummary,
      confidenceScore: aiAssistReview.confidenceScore,
      relatedEntityType: aiAssistReview.relatedEntityType,
      relatedEntityId: aiAssistReview.relatedEntityId,
      status: status === "accepted" && edited ? "edited" : status,
      accepted: status === "accepted",
    });
    setVaultToast(status === "accepted" ? "Guided suggestion marked reviewed. Make any final form changes before saving." : "Guided suggestion dismissed.");
    setAiAssistReview(null);
  }

  function renderAiAssistActions(actions = [], { label = "Guided suggestions", compact = true } = {}) {
    const visibleActions = actions.filter(Boolean).slice(0, 6);
    if (!visibleActions.length) return null;
    return (
      <details className={`ai-assist-menu ${compact ? "ai-assist-menu--compact" : ""}`}>
        <summary>{label}</summary>
        <div className="ai-assist-menu-actions">
          {visibleActions.map((action) => (
            <button
              key={action.label}
              type="button"
              className="secondary-button"
              onClick={(event) => {
                event.currentTarget.closest("details")?.removeAttribute("open");
                action.onClick?.();
              }}
            >
              {action.label}
            </button>
          ))}
        </div>
        <p>{AI_REVIEW_DISCLAIMER}</p>
      </details>
    );
  }
  function aiEventCountFor(featureArea) {
    return phase2RecentAiAssistEvents.filter((event) => event.featureArea === featureArea || event.feature_area === featureArea).length;
  }
  const retryPhase2Sync = async () => {
    const { data, status } = await loadPhase2Data(phase2Context());
    setPhase2Data(data);
    setPhase2SyncStatus(status);
    setVaultToast(status.source === "supabase" ? "Supabase sync is available." : `${status.label || "Supabase sync unavailable"}. Saved locally.`);
  };
  const updateVaultForm = (field, value) => setVaultForm((old) => {
    if (field === "vaultStatus") {
      return { ...old, vaultStatus: value, status: vaultStatusLabel(value) };
    }
    return { ...old, [field]: value };
  });
  function closeQuickAddMenu(returnFocus = true) {
    setQuickAddMenuOpen(false);
    if (returnFocus) setTimeout(() => quickAddButtonRef.current?.focus?.(), 0);
  }

  const resetMultiDestinationForm = (overrides = {}) => {
    const {
      destinations,
      vault,
      wishlist,
      forge,
      tidetradr,
      catalogSearchQuery,
      initialStep,
      ...rest
    } = overrides;

    setMultiDestinationCatalogQuery(catalogSearchQuery || "");
    setMultiDestinationMatchSearchOpen(!rest.catalogProductId);
    const normalizedSeedDestinations = Object.entries(destinations || {}).reduce((acc, [key, enabled]) => {
      const normalizedKey = normalizeAddDestinationValue(key, "", { allowIgnore: false });
      if (normalizedKey && Object.prototype.hasOwnProperty.call(BLANK_MULTI_DESTINATION_FORM.destinations, normalizedKey)) {
        acc[normalizedKey] = Boolean(enabled);
      }
      return acc;
    }, {});
    const nextDestinations = { ...BLANK_MULTI_DESTINATION_FORM.destinations, ...normalizedSeedDestinations };
    const nextVault = {
      ...BLANK_MULTI_DESTINATION_FORM.vault,
      workspaceId: defaultWorkspaceIdForDestination("vault"),
      ...(vault || {}),
    };
    const nextWishlist = {
      ...BLANK_MULTI_DESTINATION_FORM.wishlist,
      workspaceId: defaultWorkspaceIdForDestination("wishlist"),
      ...(wishlist || {}),
    };
    const seededForgeWorkspaceId = forge?.workspaceId || forge?.workspace_id || "";
    const validForgeWorkspaceId = forgeWorkspaceOptions.some((workspace) => String(workspace.id) === String(seededForgeWorkspaceId))
      ? seededForgeWorkspaceId
      : defaultWorkspaceIdForDestination("forge");
    const nextForge = {
      ...BLANK_MULTI_DESTINATION_FORM.forge,
      ...(forge || {}),
      workspaceId: validForgeWorkspaceId,
    };

    const nextForm = {
      ...BLANK_MULTI_DESTINATION_FORM,
      ...rest,
      destinations: nextDestinations,
      vault: nextVault,
      wishlist: nextWishlist,
      forge: nextForge,
      tidetradr: { ...BLANK_MULTI_DESTINATION_FORM.tidetradr, ...(tidetradr || {}) },
    };
    flowModalBaselineRef.current.multiDestinationAdd = nextForm;
    setMultiDestinationMessage("");
    setMultiDestinationSuccess(null);
    setMultiDestinationValidationAttempted(false);
    setMultiDestinationSaving(false);
    setMultiDestinationStep(MULTI_DESTINATION_STEPS.includes(initialStep) ? initialStep : "item");
    setMultiDestinationForm(nextForm);
  };
  const updateMultiDestinationField = (field, value) => {
    setMultiDestinationMessage("");
    setMultiDestinationForm((current) => ({ ...current, [field]: value }));
  };
  const updateMultiDestinationSection = (section, field, value) => {
    setMultiDestinationMessage("");
    setMultiDestinationForm((current) => ({
      ...current,
      [section]: {
        ...current[section],
        [field]: value,
      },
    }));
  };
  const updateMultiDestinationToggle = (destination, checked) => setMultiDestinationForm((current) => {
    setMultiDestinationMessage("");
    const normalizedDestination = normalizeAddDestinationValue(destination, "", { allowIgnore: false });
    if (!normalizedDestination || !Object.prototype.hasOwnProperty.call(current.destinations, normalizedDestination)) return current;
    if (checked && normalizedDestination === "forge" && !activeForgeWorkspace) {
      setMultiDestinationMessage(forgeWorkspaceUnavailableMessage);
      setVaultToast("Forge workspace is unavailable.");
      return current;
    }
    const next = {
      ...current,
      destinations: {
        ...current.destinations,
        [normalizedDestination]: checked,
      },
    };
    if (checked && ["vault", "wishlist", "forge"].includes(normalizedDestination)) {
      next[normalizedDestination] = {
        ...next[normalizedDestination],
        workspaceId: normalizedDestination === "forge"
          ? defaultWorkspaceIdForDestination("forge")
          : next[normalizedDestination]?.workspaceId || defaultWorkspaceIdForDestination(normalizedDestination),
      };
    }
    return next;
  });

  const selectedMultiDestinationKeys = (form = multiDestinationForm) =>
    Object.entries(form.destinations || {})
      .filter(([, enabled]) => Boolean(enabled))
      .map(([key]) => key);

  const multiDestinationDestinationLabel = (destination) => ({
    vault: "Vault",
    wishlist: "Wishlist",
    forge: "Forge",
    tidetradr: "Market",
  }[destination] || destination);

  function multiDestinationValidationError({ id, step, label, message }) {
    return {
      id,
      field: id,
      step,
      label,
      message,
      stepLabel: MULTI_DESTINATION_STEP_LABELS[step] || "Review",
    };
  }

  function requiredQuantityError(id, label, value) {
    const rawValue = String(value ?? "").trim();
    if (!rawValue) {
      return multiDestinationValidationError({
        id,
        step: "details",
        label,
        message: "Enter a quantity.",
      });
    }
    const quantity = Number(rawValue);
    if (!Number.isFinite(quantity) || quantity < 1) {
      return multiDestinationValidationError({
        id,
        step: "details",
        label,
        message: "Quantity must be at least 1.",
      });
    }
    if (!Number.isInteger(quantity)) {
      return multiDestinationValidationError({
        id,
        step: "details",
        label,
        message: "Quantity must be a whole number.",
      });
    }
    return null;
  }

  function optionalMoneyError(id, label, value) {
    if (value === "" || value === null || value === undefined) return null;
    const amount = Number(value);
    if (!Number.isFinite(amount) || amount < 0) {
      return multiDestinationValidationError({
        id,
        step: "details",
        label,
        message: "Enter a valid price.",
      });
    }
    return null;
  }

  function getMultiDestinationValidationErrors(step = multiDestinationStep, form = multiDestinationForm) {
    const scopeIndex = MULTI_DESTINATION_STEP_INDEX[step] ?? MULTI_DESTINATION_STEP_INDEX.review;
    const includesStep = (targetStep) => (MULTI_DESTINATION_STEP_INDEX[targetStep] ?? 0) <= scopeIndex;
    const itemName = String(form.itemName || "").trim();
    const selectedDestinations = selectedMultiDestinationKeys(form);
    const errors = [];
    const push = (error) => {
      if (error) errors.push(error);
    };

    if (includesStep("item") && !itemName) {
      push(multiDestinationValidationError({
        id: "item-name",
        step: "item",
        label: "Item",
        message: "Choose an item or add one manually.",
      }));
    }

    if (includesStep("destination") && !selectedDestinations.length) {
      push(multiDestinationValidationError({
        id: "destination",
        step: "destination",
        label: "Destination",
        message: "Choose where this should go.",
      }));
    }

    if (includesStep("details")) {
      if (form.destinations?.forge) {
        if (!activeForgeWorkspace) {
          push(multiDestinationValidationError({
            id: "forge-workspace",
            step: "destination",
            label: "Forge workspace",
            message: forgeWorkspaceUnavailableMessage,
          }));
        }
        push(requiredQuantityError("forge-quantity", "Forge quantity", form.forge?.quantity));
        push(optionalMoneyError("forge-unit-cost", "Paid cost", form.forge?.unitCost));
        push(optionalMoneyError("forge-planned-sell-price", "Planned sell price", form.forge?.plannedSellPrice));
        if (!String(form.forge?.physicalLocation || DEFAULT_FORGE_PHYSICAL_LOCATION || "").trim()) {
          push(multiDestinationValidationError({
            id: "forge-physical-location",
            step: "details",
            label: "Forge location",
            message: "Choose where this inventory is located.",
          }));
        }
      }
      if (form.destinations?.vault) {
        push(requiredQuantityError("vault-quantity", "Vault quantity", form.vault?.quantity));
        push(optionalMoneyError("vault-unit-cost", "Vault cost basis", form.vault?.unitCost));
      }
      if (form.destinations?.wishlist) {
        push(requiredQuantityError("wishlist-quantity", "Wishlist quantity", form.wishlist?.quantity));
        push(optionalMoneyError("wishlist-target-price", "Wishlist target price", form.wishlist?.targetPrice));
      }
      if (form.destinations?.tidetradr) {
        push(optionalMoneyError("tidetradr-msrp", "Market MSRP", form.tidetradr?.msrpPrice || form.msrpPrice));
      }
    }

    return errors;
  }

  function focusMultiDestinationValidationError(error) {
    if (!error) return;
    const targetStep = MULTI_DESTINATION_STEPS.includes(error.step) ? error.step : "item";
    setMultiDestinationStep(targetStep);
    window.setTimeout(() => {
      const modal = flowModalRef.current;
      const target = modal?.querySelector?.(`[data-validation-field="${error.field}"]`);
      target?.scrollIntoView?.({ block: "center", behavior: "smooth" });
      const focusable = target?.querySelector?.("input, select, textarea, button");
      focusable?.focus?.({ preventScroll: true });
    }, 80);
  }

  function advanceMultiDestinationStep(event) {
    event?.preventDefault?.();
    event?.stopPropagation?.();
    setMultiDestinationValidationAttempted(true);
    const validationErrors = getMultiDestinationValidationErrors(multiDestinationStep, multiDestinationForm);
    if (validationErrors.length) {
      setMultiDestinationMessage("Fix missing fields to continue.");
      focusMultiDestinationValidationError(validationErrors[0]);
      return;
    }
    const currentIndex = MULTI_DESTINATION_STEPS.indexOf(multiDestinationStep);
    setMultiDestinationMessage("");
    setMultiDestinationStep(MULTI_DESTINATION_STEPS[Math.min(MULTI_DESTINATION_STEPS.length - 1, currentIndex + 1)] || "review");
  }

  function goBackMultiDestinationStep(event) {
    event?.preventDefault?.();
    event?.stopPropagation?.();
    const currentIndex = MULTI_DESTINATION_STEPS.indexOf(multiDestinationStep);
    setMultiDestinationMessage("");
    setMultiDestinationStep(MULTI_DESTINATION_STEPS[Math.max(0, currentIndex - 1)] || "item");
  }

  function multiDestinationFailureMessage(failures = []) {
    const firstFailure = String(failures[0] || "").trim();
    if (!firstFailure) return "Could not save item.";
    const compactFailure = firstFailure
      .replace(/\s*\|\s*/g, " ")
      .replace(/\s+/g, " ")
      .slice(0, 180);
    return `Could not save item: ${compactFailure}`;
  }

  function findCatalogAutofillCompanion(product = {}, known = {}) {
    const selectedId = String(product.id || "");
    const title = normalizeSearchText(known.itemName || catalogTitle(product));
    const setName = normalizeSearchText(known.setName || catalogExpansionName(product));
    const productType = normalizeSearchText(known.productType || catalogProductTypeLabel(product));
    if (!title && !productType) return {};
    let fallbackKnown = {};
    const searchPool = mergeCatalogProductLists(catalogProducts, localCatalogSeedProducts);
    for (const candidate of searchPool) {
      if (selectedId && String(candidate.id || "") === selectedId) continue;
      const candidateKnown = buildCatalogAutofillDetails(candidate);
      const hasNeededMsrp = !known.msrpPrice && candidateKnown.msrpPrice;
      const hasNeededMarket = !known.marketPrice && candidateKnown.marketPrice;
      if (!hasNeededMsrp && !hasNeededMarket) continue;
      const candidateTitle = normalizeSearchText(candidateKnown.itemName || catalogTitle(candidate));
      const candidateSet = normalizeSearchText(candidateKnown.setName || catalogExpansionName(candidate));
      const candidateType = normalizeSearchText(candidateKnown.productType || catalogProductTypeLabel(candidate));
      const sameTitle = title && candidateTitle === title;
      const sameSetType = productType && candidateType === productType && setName && candidateSet && (candidateSet.includes(setName) || setName.includes(candidateSet));
      if (!sameTitle && !sameSetType) continue;
      if (hasNeededMsrp) return candidateKnown;
      if (!fallbackKnown.marketPrice && hasNeededMarket) fallbackKnown = candidateKnown;
    }
    return fallbackKnown;
  }

  function selectMultiDestinationCatalogProduct(productOrId) {
    const product = typeof productOrId === "object"
      ? productOrId
      : catalogProducts.find((entry) => String(entry.id) === String(productOrId));
    const productId = product?.id || (typeof productOrId === "object" ? "" : productOrId);
    const defaultVariant = product
      ? (getCatalogVariantOptions(product).find((variant) => variant.isDefault) || getCatalogVariantOptions(product)[0] || null)
      : null;
    const directKnown = product ? buildCatalogAutofillDetails(product) : {};
    const companionKnown = product ? findCatalogAutofillCompanion(product, directKnown) : {};
    const known = {
      ...directKnown,
      msrpPrice: directKnown.msrpPrice || companionKnown.msrpPrice || "",
      marketPrice: directKnown.marketPrice || companionKnown.marketPrice || "",
    };

    if (product) {
      setCatalogProducts((current) => [
        product,
        ...current.filter((entry) => String(entry.id) !== String(product.id)),
      ]);
      setMultiDestinationCatalogQuery(catalogTitle(product));
      setMultiDestinationMatchSearchOpen(false);
      void logAiAssistEvent(AI_FEATURE_AREAS.CATALOG_MATCH, {
        inputSummary: multiDestinationCatalogQuery || catalogTitle(product),
        outputSummary: `User selected catalog match for review: ${catalogTitle(product)}.`,
        confidenceScore: 90,
        status: "accepted",
        accepted: true,
        relatedEntityType: "catalog_item",
        relatedEntityId: product.masterCatalogItemId || product.id,
      });
    }

    setMultiDestinationForm((current) => ({
      ...current,
      catalogProductId: productId,
      itemName: known.itemName || current.itemName,
      productType: known.productType || normalizedInventoryProductType(product || current),
      category: known.category || current.category,
      setName: known.setName || current.setName,
      variant: defaultVariant?.variantName || current.variant,
      upcSku: known.upc || known.sku || current.upcSku,
      msrpPrice: known.msrpPrice || current.msrpPrice,
      marketPrice: known.marketPrice || current.marketPrice,
      forge: {
        ...current.forge,
        unitCost: isBlankCatalogField(current.forge?.unitCost) && known.msrpPrice ? known.msrpPrice : current.forge?.unitCost,
        plannedSellPrice: isBlankCatalogField(current.forge?.plannedSellPrice) && known.marketPrice ? known.marketPrice : current.forge?.plannedSellPrice,
        businessCategory: known.category || current.forge?.businessCategory || "Pokemon",
        conditionName: current.forge?.conditionName || (isCatalogCardProduct(product || {}) ? "Near Mint" : "Sealed"),
      },
      tidetradr: {
        ...current.tidetradr,
        existingProductId: productId,
        msrpPrice: known.msrpPrice || current.tidetradr.msrpPrice,
        upc: known.upc || current.tidetradr.upc,
        sku: known.sku || current.tidetradr.sku,
        setName: known.setName || current.tidetradr.setName,
        productType: known.productType || normalizedInventoryProductType(product || current.tidetradr),
        releaseDate: product?.releaseDate || product?.releaseYear || current.tidetradr.releaseDate,
      },
    }));
  }

  function clearMultiDestinationCatalogProduct() {
    setMultiDestinationCatalogQuery("");
    setMultiDestinationMatchSearchOpen(true);
    setMultiDestinationForm((current) => ({
      ...current,
      catalogProductId: "",
      tidetradr: {
        ...current.tidetradr,
        existingProductId: "",
      },
    }));
  }

  function runMultiDestinationCatalogSearch(value, options = {}) {
    const lookup = String(value || "").trim();
    setMultiDestinationCatalogQuery(lookup);
    setMultiDestinationMatchSearchOpen(true);
    if (!lookup) return;
    const normalizedLookupCode = normalizeBarcodeValue(lookup);
    const exactIdentifier = isLikelyBarcodeValue(lookup) || /^\d{6,}$/.test(normalizedLookupCode);
    void loadImportedPokemonCatalog(lookup, {
      page: 1,
      pageSize: Math.min(24, catalogPageSize || 24),
      mode: exactIdentifier ? "barcode" : "general",
      barcode: exactIdentifier ? normalizedLookupCode || lookup : "",
      forceSearch: true,
      ...options,
    });
  }

  function startMultiDestinationManualEntry(seed = {}) {
    const fallbackSeed = buildManualFallbackItemSeed({
      rawValue: seed.catalogSearchQuery || seed.itemName || multiDestinationCatalogQuery,
      itemName: seed.itemName,
      productType: seed.productType,
      setName: seed.setName,
      upcSku: seed.upcSku,
      msrpPrice: seed.msrpPrice,
      marketPrice: seed.marketPrice,
      destinations: seed.destinations || {},
    });
    setMultiDestinationMatchSearchOpen(false);
    setMultiDestinationMessage("Manual item mode. Enter an item name, then continue to choose where it belongs.");
    setMultiDestinationForm((current) => ({
      ...current,
      ...seed,
      itemName: fallbackSeed.itemName || current.itemName || multiDestinationCatalogQuery,
      productType: fallbackSeed.productType || current.productType,
      setName: fallbackSeed.setName || current.setName,
      upcSku: fallbackSeed.upcSku || current.upcSku,
      msrpPrice: fallbackSeed.msrpPrice || current.msrpPrice,
      marketPrice: fallbackSeed.marketPrice || current.marketPrice,
      catalogProductId: "",
      catalogVariantId: "",
      tidetradr: {
        ...current.tidetradr,
        existingProductId: "",
      },
    }));
  }

  function selectRecentMultiDestinationItem(item = {}) {
    const name = item.name || item.itemName || item.catalogProductName || "";
    if (!name) return;
    setMultiDestinationCatalogQuery(name);
    setMultiDestinationMatchSearchOpen(false);
    setMultiDestinationMessage("Recent item copied. Review the details, then continue.");
    setMultiDestinationForm((current) => ({
      ...current,
      itemName: name,
      productType: item.productType || item.product_type || current.productType,
      setName: item.setName || item.set_name || item.expansion || current.setName,
      variant: item.variant || current.variant,
      upcSku: item.barcode || item.upc || item.sku || current.upcSku,
      msrpPrice: item.msrpPrice || item.msrp_price || current.msrpPrice,
      marketPrice: item.marketPrice || item.market_price || item.marketValue || item.market_value || current.marketPrice,
      notes: current.notes || item.notes || "",
      catalogProductId: item.catalogProductId || item.catalog_product_id || current.catalogProductId,
      catalogVariantId: item.catalogVariantId || item.catalog_variant_id || current.catalogVariantId,
    }));
  }

  function markMultiDestinationMissingCatalog() {
    const query = String(multiDestinationCatalogQuery || "").trim();
    const prefill = buildMissingProductPrefill({
      query: query || multiDestinationForm.itemName,
      detectedText: query || multiDestinationForm.itemName,
      productType: multiDestinationForm.productType,
      setName: multiDestinationForm.setName,
      upc: multiDestinationForm.upcSku,
    });
    setMultiDestinationForm((current) => ({
      ...current,
      itemName: current.itemName || prefill.productName || query,
      productType: current.productType || prefill.productType,
      setName: current.setName || prefill.setName,
      upcSku: current.upcSku || prefill.upc,
      notes: [current.notes, prefill.notes].filter(Boolean).join("\n"),
      destinations: {
        ...current.destinations,
        tidetradr: true,
      },
      tidetradr: {
        ...current.tidetradr,
        action: "suggest",
        productType: current.tidetradr.productType || current.productType || prefill.productType,
        upc: current.tidetradr.upc || current.upcSku || prefill.upc,
        msrpPrice: current.tidetradr.msrpPrice || current.msrpPrice,
      },
    }));
    void logAiAssistEvent(AI_FEATURE_AREAS.MISSING_PRODUCT, {
      inputSummary: prefill.inputSummary || query,
      outputSummary: prefill.outputSummary,
      confidenceScore: prefill.confidenceScore,
      relatedEntityType: "missing_catalog_product",
    });
    setVaultToast(`${prefill.outputSummary} It will still go to Admin Review before any catalog item is created.`);
  }

  function normalizeDestinationScopes(value) {
    const raw = Array.isArray(value)
      ? value
      : typeof value === "string"
        ? value.split(/[,|/]+/)
        : value && typeof value === "object"
          ? Object.entries(value).filter(([, enabled]) => Boolean(enabled)).map(([key]) => key)
          : [];
    return [...new Set(raw
      .map((entry) => String(entry || "").trim().toLowerCase())
      .map((entry) => entry.replace(/[\s-]+/g, "_"))
      .map((entry) => (
        entry === "forge_inventory" || entry === "business_inventory" ? "forge" :
        entry === "vault_item" || entry === "vault_items" ? "vault" :
        entry === "wishlist_item" || entry === "wishlist_items" ? "wishlist" :
        entry === "personal_collection" || entry === "vault_collection" ? "vault" :
        entry === "expenseonly" || entry === "expense_only" || entry === "ignore" || entry === "ignored" ? "expense_only" :
        entry === "tidetradr_suggestion" || entry === "catalog_suggestion" ? "tidetradr" :
        entry
      ))
      .filter(Boolean))];
  }

  function itemDestinationScopes(item = {}) {
    return normalizeDestinationScopes(
      item.destinationScope ||
      item.destination_scope ||
      item.destinations ||
      item.destination ||
      item.itemScope ||
      item.item_scope ||
      item.recordType ||
      item.record_type
    );
  }

  function itemHasDestination(item = {}, destination) {
    return itemDestinationScopes(item).includes(destination);
  }

  function normalizeInventoryDestination(item = {}) {
    const scopes = itemDestinationScopes(item);
    const recordType = String(item.recordType || item.record_type || "").trim().toLowerCase().replace(/[\s-]+/g, "_");
    const status = String(item.status || "").trim().toLowerCase();
    const actionNotes = String(item.actionNotes || item.action_notes || item.notes || "").trim().toLowerCase();
    const vaultStatusRaw = item.vaultStatus ?? item.vault_status;
    const hasVaultStatus = !isBlankLike(vaultStatusRaw);
    const normalizedVault = hasVaultStatus ? normalizeVaultStatus({ vaultStatus: vaultStatusRaw, status: item.status, actionNotes: item.actionNotes }) : "";
    const explicitForgeDestination = /\bdestination\s*:\s*forge\b|\bsave(?:d)?\s+to\s+forge\b|\bopen\s+in\s+forge\b|\bforge\s+draft\b/.test(actionNotes);
    const explicitVaultDestination = /\bdestination\s*:\s*vault\b|\bsave(?:d)?\s+to\s+vault\b|\bopen\s+in\s+vault\b|\bvault\s+draft\b/.test(actionNotes);

    if (scopes.includes("expense_only") || recordType === "expense_only" || status.includes("expense only")) return "expense_only";
    if (scopes.includes("wishlist") || recordType === "wishlist_item" || item.isWishlist || item.is_wishlist || normalizedVault === "wishlist" || status === "wishlist") return "wishlist";
    if (scopes.includes("market") || recordType === "market_listing" || recordType === "market_draft" || status.includes("market listing")) return "market";
    if (hasVaultStatus && normalizedVault === "moved_to_forge") return "vault_archive";
    if (scopes.includes("vault") && !scopes.includes("forge")) return "vault";
    if (scopes.includes("forge") && !scopes.includes("vault")) return "forge";
    if (explicitForgeDestination && !explicitVaultDestination) return "forge";
    if (explicitVaultDestination && !explicitForgeDestination) return "vault";
    if (recordType === "vault_item") return "vault";
    if (recordType === "forge_inventory") return "forge";
    if (item.businessInventory || item.business_inventory || Number(item.forgeQuantity || item.forge_quantity || 0) > 0) return "forge";
    if (hasVaultStatus && normalizedVault !== "moved_to_forge") return "vault";
    if (["personal collection", "held", "sealed", "sealed / holding", "ripped / opened", "traded"].includes(status)) return "vault";
    if (["in stock", "ready to list", "listed", "needs photos", "needs market check", "sold"].includes(status)) return "forge";
    if (actionNotes.includes("wishlist")) return "wishlist";
    if (actionNotes.includes("personal collection") || actionNotes.includes("vault")) return "vault";
    return "forge";
  }

  function isWishlistItemRecord(item = {}) {
    return normalizeInventoryDestination(item) === "wishlist";
  }

  function isBlankLike(value) {
    return value === undefined || value === null || String(value).trim() === "";
  }

  function isNumericDraft(value) {
    return isBlankLike(value) || Number.isFinite(Number(value));
  }

  function isVaultDraftReady(form) {
    return Boolean(
      String(form.name || "").trim() &&
      Number(form.quantity) >= 1 &&
      String(form.vaultStatus || "").trim() &&
      isNumericDraft(form.marketPrice) &&
      isNumericDraft(form.msrpPrice) &&
      isNumericDraft(form.unitCost) &&
      isNumericDraft(form.salePrice)
    );
  }

  function validateVaultDraft(form) {
    if (!String(form.name || "").trim()) return "Item name is required.";
    if (!Number.isFinite(Number(form.quantity)) || Number(form.quantity) < 1) return "Quantity must be at least 1.";
    if (!String(form.vaultStatus || "").trim()) return "Vault status is required.";
    if (!isNumericDraft(form.marketPrice)) return "Market value must be a number.";
    if (!isNumericDraft(form.msrpPrice)) return "MSRP must be a number.";
    if (!isNumericDraft(form.unitCost)) return "Cost paid must be a number.";
    if (!isNumericDraft(form.salePrice)) return "Planned sale price must be a number.";
    return "";
  }

  function normalizeVaultDuplicateText(value) {
    return String(value || "").trim().toLowerCase().replace(/\s+/g, " ");
  }

  function isVaultItemRecord(item) {
    return normalizeInventoryDestination(item) === "vault" && normalizeVaultStatus(item) !== "moved_to_forge";
  }

  function isForgeInventoryItem(item = {}) {
    return normalizeInventoryDestination(item) === "forge";
  }

  function findVaultDuplicate(candidate, collection = items) {
    const candidateName = normalizeVaultDuplicateText(candidate.itemName || candidate.name);
    const candidateUpc = normalizeVaultDuplicateText(candidate.upc || candidate.barcode);
    const candidateSku = normalizeVaultDuplicateText(candidate.sku);
    const candidateCatalogId = normalizeVaultDuplicateText(candidate.catalogProductId || candidate.tideTradrProductId || candidate.externalProductId);
    return collection.find((item) => {
      if (!isVaultItemRecord(item) || item.id === candidate.id) return false;
      const itemName = normalizeVaultDuplicateText(item.itemName || item.name);
      const itemUpc = normalizeVaultDuplicateText(item.upc || item.barcode);
      const itemSku = normalizeVaultDuplicateText(item.sku);
      const itemCatalogId = normalizeVaultDuplicateText(item.catalogProductId || item.tideTradrProductId || item.externalProductId);
      return Boolean(
        (candidateCatalogId && itemCatalogId && candidateCatalogId === itemCatalogId) ||
        (candidateUpc && itemUpc && candidateUpc === itemUpc) ||
        (candidateSku && itemSku && candidateSku === itemSku) ||
        (candidateName && itemName && candidateName === itemName)
      );
    });
  }

  function filterVaultItems(collection, status = "all") {
    return collection.filter((item) => {
      if (status === "all") return isActiveVaultItem(item);
      if (status === "sealed") return isInventorySealedProduct(item) || ["sealed", "held"].includes(normalizeVaultStatus(item));
      if (status === "wishlist") return ["wishlist", "held"].includes(normalizeVaultStatus(item));
      if (status === "sold_archived") {
        const normalizedStatus = normalizeVaultStatus(item);
        return normalizedStatus === "archived" || String(item.status || "").toLowerCase() === "sold";
      }
      return normalizeVaultStatus(item) === status;
    });
  }

  function searchVaultItems(collection, query = "") {
    const normalizedQuery = query.trim().toLowerCase();
    if (!normalizedQuery) return collection;
    return collection.filter((item) =>
      [
        item.itemName,
        item.name,
        item.expansion,
        item.setName,
        item.setCode,
        item.barcode,
        item.upc,
        item.sku,
        item.notes,
        item.productType,
        item.storageLocation,
        item.storage_location,
        item.location,
        item.sourceLocation,
        item.buyer,
        item.purchaserName,
        item.purchaser_name,
        item.conditionName,
        item.condition,
        item.sourceType,
      ]
        .filter(Boolean)
        .some((value) => String(value).toLowerCase().includes(normalizedQuery))
    );
  }

  function resetVaultForm() {
    setVaultForm({ ...BLANK_VAULT_FORM });
    setVaultFormSections({ basic: true, pricing: false, status: false, extra: false });
    setVaultAddMode("manual");
    setVaultSaving(false);
  }

  function vaultFormHasDraft() {
    const comparableFields = [
      "name",
      "unitCost",
      "msrpPrice",
      "marketPrice",
      "salePrice",
      "packCount",
      "setName",
      "productType",
      "store",
      "storageLocation",
      "condition",
      "conditionName",
      "language",
      "finish",
      "printing",
      "sealedCondition",
      "conditionNotes",
      "upc",
      "sku",
      "catalogVariantId",
      "purchaseDate",
      "receiptImage",
      "itemImage",
      "notes",
    ];
    return comparableFields.some((field) => !isBlankLike(vaultForm[field])) || Number(vaultForm.quantity) !== Number(BLANK_VAULT_FORM.quantity);
  }

  function closeVaultAddModal(force = false) {
    if (!force && vaultFormHasDraft()) {
      const leave = window.confirm("You have unsaved changes. Leave without saving?");
      if (!leave) return false;
    }
    setShowVaultAddForm(false);
    setVaultPotentialDuplicate(null);
    resetVaultForm();
    return true;
  }

  function isEditingVaultItem() {
    return Boolean(editingItemId && items.some((item) => item.id === editingItemId && isVaultItemRecord(item)));
  }

  function cancelVaultEdit(force = false) {
    if (!force && isEditingVaultItem()) {
      const leave = window.confirm("You have unsaved changes. Leave without saving?");
      if (!leave) return false;
    }
    setEditingItemId(null);
    setItemForm(blankItem);
    return true;
  }

  function confirmLeaveVaultWork() {
    if (activeTab !== "vault") return true;
    if (showVaultAddForm && vaultFormHasDraft()) return closeVaultAddModal();
    if (isEditingVaultItem()) return cancelVaultEdit();
    return true;
  }

  function purchaserBelongsToWorkspace(purchaser, workspaceId = activeWorkspace?.id) {
    return String(purchaserWorkspaceId(purchaser)) === String(workspaceId || DEFAULT_PERSONAL_WORKSPACE_ID);
  }

  function purchasersForWorkspace(workspaceId = activeWorkspace?.id, options = {}) {
    const includeArchived = Boolean(options.includeArchived);
    return purchasers
      .filter((purchaser) => purchaserBelongsToWorkspace(purchaser, workspaceId))
      .filter((purchaser) => includeArchived || purchaser.active !== false)
      .sort((a, b) => String(a.name || "").localeCompare(String(b.name || "")));
  }

  const purchaserOptions = purchasersForWorkspace(activeWorkspace?.id);
  const forgePurchaserOptions = activeForgeWorkspace
    ? purchasersForWorkspace(activeForgeWorkspace.id)
    : purchaserOptions;
  function mergePurchaserLists(...lists) {
    const byKey = new Map();
    for (const list of lists) {
      for (const purchaser of list || []) {
        if (!purchaser || purchaser.active === false) continue;
        const key = String(purchaser.id || purchaser.name || "").trim().toLowerCase();
        if (!key || byKey.has(key)) continue;
        byKey.set(key, purchaser);
      }
    }
    return [...byKey.values()].sort((a, b) => String(a.name || "").localeCompare(String(b.name || "")));
  }
  const sharedPeopleOptions = mergePurchaserLists(purchaserOptions, forgePurchaserOptions, purchasers);
  const peopleOptions = sharedPeopleOptions.map((purchaser) => purchaser.name);
  const purchaserManagerWorkspace = visibleWorkspaceOptions.find((workspace) => String(workspace.id) === String(purchaserManagerWorkspaceId)) || activeWorkspace;
  const purchaserManagerList = purchasersForWorkspace(purchaserManagerWorkspace?.id, { includeArchived: true });

  function openPurchaserManager(workspaceId = activeWorkspace?.id) {
    setPurchaserManagerWorkspaceId(workspaceId || activeWorkspace?.id || DEFAULT_PERSONAL_WORKSPACE_ID);
    setPurchaserDraft("");
    setPurchaserNoteDraft("");
    setPurchaserTypeDraft("Family");
    setEditingPurchaserId(null);
    setPurchaserMessage("");
    setPurchaserManagerOpen(true);
  }

  function closePurchaserManager() {
    setPurchaserManagerOpen(false);
    setEditingPurchaserId(null);
    setPurchaserDraft("");
    setPurchaserNoteDraft("");
    setPurchaserTypeDraft("Family");
    setPurchaserMessage("");
  }

  function resolvePurchaser(form = itemForm, workspaceId = activeWorkspace?.id) {
    const workspacePurchasers = purchasersForWorkspace(workspaceId, { includeArchived: true });
    const selected =
      workspacePurchasers.find((purchaser) => purchaser.id === form.purchaserId) ||
      workspacePurchasers.find((purchaser) => purchaser.name === form.purchaserName) ||
      workspacePurchasers.find((purchaser) => purchaser.name === form.buyer) ||
      purchasers.find((purchaser) => purchaser.id === form.purchaserId);

    return {
      purchaserId: selected?.id || form.purchaserId || "",
      purchaserName: selected?.name || form.purchaserName || form.buyer || "",
    };
  }

  function validatePurchaserName(name, workspaceId = activeWorkspace?.id, existingId = "") {
    const trimmed = String(name || "").trim();
    if (!trimmed) return { error: "Person name cannot be blank." };
    if (trimmed.length > PURCHASER_NAME_MAX_LENGTH) {
      return { error: `Person name must be ${PURCHASER_NAME_MAX_LENGTH} characters or fewer.` };
    }
    const duplicate = purchasers.find((purchaser) =>
      String(purchaser.id) !== String(existingId) &&
      purchaserBelongsToWorkspace(purchaser, workspaceId) &&
      String(purchaser.name || "").trim().toLowerCase() === trimmed.toLowerCase()
    );
    if (duplicate) return { error: "That person already exists for this collection.", duplicate };
    return { name: trimmed };
  }

  function addPurchaserName(name, options = {}) {
    const workspaceId = options.workspaceId || purchaserManagerWorkspace?.id || activeWorkspace?.id || DEFAULT_PERSONAL_WORKSPACE_ID;
    const result = validatePurchaserName(name, workspaceId);
    if (result.error) {
      if (result.duplicate && result.duplicate.active === false) {
        setPurchasers((current) =>
          current.map((purchaser) =>
            purchaser.id === result.duplicate.id
              ? { ...purchaser, active: true, note: String(options.note || purchaser.note || "").trim(), type: normalizePersonType(options.type || purchaser.type), role: options.type || purchaser.role || purchaser.type || "Family", updatedAt: new Date().toISOString() }
              : purchaser
          )
        );
        const restored = { ...result.duplicate, active: true };
        setPurchaserMessage(`${restored.name} is active again.`);
        showAppMessage(`${restored.name} is active again.`);
        return restored;
      }
      setPurchaserMessage(result.error);
      return null;
    }

    const now = new Date().toISOString();
    const purchaser = {
      id: makeId("purchaser"),
      name: result.name,
      note: String(options.note || "").trim(),
      type: normalizePersonType(options.type || "Family"),
      role: options.type || "Family",
      active: true,
      defaultWorkspaceId: workspaceId,
      default_workspace_id: workspaceId,
      workspaceId,
      workspace_id: workspaceId,
      createdAt: now,
      updatedAt: now,
    };
    setPurchasers((current) => [...current, purchaser]);
    setPurchaserMessage(`Added ${purchaser.name}.`);
    showAppMessage(`Added person: ${purchaser.name}.`);
    return purchaser;
  }

  function savePurchaserName(id, name, note = purchaserNoteDraft, type = purchaserTypeDraft) {
    const purchaser = purchasers.find((candidate) => candidate.id === id);
    if (!purchaser) return;
    const workspaceId = purchaserWorkspaceId(purchaser);
    const result = validatePurchaserName(name, workspaceId, id);
    if (result.error) {
      setPurchaserMessage(result.error);
      return;
    }
    const trimmedNote = String(note || "").trim();
    const normalizedType = normalizePersonType(type || purchaser.type || "Family");

    setPurchasers((current) =>
      current.map((purchaser) =>
        purchaser.id === id ? { ...purchaser, name: result.name, note: trimmedNote, type: normalizedType, role: normalizedType, updatedAt: new Date().toISOString() } : purchaser
      )
    );
    setItems((currentItems) =>
      currentItems.map((item) =>
        item.purchaserId === id ? { ...item, purchaserName: result.name, buyer: result.name } : item
      )
    );
    setEditingPurchaserId(null);
    setPurchaserDraft("");
    setPurchaserNoteDraft("");
    setPurchaserTypeDraft("Family");
    setPurchaserMessage(`Updated person: ${result.name}.`);
  }

  function archiveOrDeletePurchaser(id) {
    const purchaser = purchasers.find((candidate) => candidate.id === id);
    if (!purchaser) return;

    const inUse =
      items.some((item) => item.purchaserId === id || itemPurchaserName(item) === purchaser.name) ||
      expenses.some((expense) => expense.buyer === purchaser.name) ||
      mileageTrips.some((trip) => trip.driver === purchaser.name);

    if (inUse) {
      setPurchasers((current) =>
        current.map((candidate) =>
          candidate.id === id ? { ...candidate, active: false, updatedAt: new Date().toISOString() } : candidate
        )
      );
      return;
    }

    setPurchasers((current) => current.filter((candidate) => candidate.id !== id));
  }

  function restorePurchaser(id) {
    setPurchasers((current) =>
      current.map((purchaser) =>
        purchaser.id === id ? { ...purchaser, active: true, updatedAt: new Date().toISOString() } : purchaser
      )
    );
    const purchaser = purchasers.find((candidate) => candidate.id === id);
    if (purchaser) setPurchaserMessage(`${purchaser.name} is active again.`);
  }

  function updateHomeStatsEnabled(updates) {
    setHomeStatsEnabled((current) => normalizeHomeStatsEnabled({ ...current, ...updates }, userType));
  }

  function resetHomeStatsForUserType(nextUserType = userType) {
    setHomeStatsEnabled(getDefaultHomeStatsForUserType(nextUserType));
  }

  function setAllHomeStats(enabled) {
    setHomeStatsEnabled(HOME_STATS.reduce((settings, stat) => ({ ...settings, [stat.key]: enabled }), {}));
  }

  function updateUserType(nextUserType) {
    const normalized = normalizeUserType(nextUserType);
    setUserType(normalized);
    setHomeStatsEnabled((current) => normalizeHomeStatsEnabled(current, normalized));
  }

  function applyHomeViewPreset(presetKey) {
    const preset = HOME_VIEW_PRESETS[presetKey];
    if (!preset) return;
    setUserType(preset.userType);
    setDashboardPreset(preset.dashboardPreset);
    setDashboardLayout(getDefaultDashboardLayoutForPreset(preset.dashboardPreset));
    setHomeStatsEnabled(HOME_STATS.reduce((settings, stat) => ({ ...settings, [stat.key]: preset.stats.includes(stat.key) }), {}));
  }

  function setDashboardSectionsEnabled(sectionKeys, enabled) {
    setDashboardLayout((current) => {
      const normalized = normalizeDashboardLayout(current, dashboardPreset);
      return {
        ...normalized,
        sections: normalized.sections.map((section) => sectionKeys.includes(section.key) ? { ...section, enabled } : section),
      };
    });
  }

  function updateDashboardPreset(nextPreset) {
    const normalized = normalizeDashboardPreset(nextPreset);
    setDashboardPreset(normalized);
    setDashboardLayout(getDefaultDashboardLayoutForPreset(normalized));
  }

  function updateDashboardLayout(updater) {
    setDashboardLayout((current) => normalizeDashboardLayout(typeof updater === "function" ? updater(current) : updater, dashboardPreset));
  }

  function updateDashboardCardStyle(nextStyle) {
    setDashboardCardStyle(normalizeDashboardCardStyle(nextStyle));
  }

  function resetDashboardLayoutForPreset(preset = dashboardPreset) {
    setDashboardLayout(getDefaultDashboardLayoutForPreset(preset));
  }

  function updateDashboardSection(key, updates) {
    updateDashboardLayout((current) => ({
      sections: normalizeDashboardLayout(current, dashboardPreset).sections.map((section) =>
        section.key === key ? { ...section, ...updates } : section
      ),
    }));
  }

  function moveDashboardSection(key, direction) {
    updateDashboardLayout((current) => {
      const sections = normalizeDashboardLayout(current, dashboardPreset).sections;
      const index = sections.findIndex((section) => section.key === key);
      const nextIndex = index + direction;
      if (index < 0 || nextIndex < 0 || nextIndex >= sections.length) return current;
      const next = [...sections];
      [next[index], next[nextIndex]] = [next[nextIndex], next[index]];
      return { sections: next.map((section, orderIndex) => ({ ...section, order: orderIndex + 1 })) };
    });
  }

  function toggleFeatureSection(key) {
    setFeatureSectionsOpen((current) => ({ ...current, [key]: !current[key] }));
  }

  function isFeatureSectionOpen(key) {
    return Boolean(featureSectionsOpen[key]);
  }

  function updateLocationSettings(updates) {
    if (blockGuestSave()) return;
    setLocationSettings((current) => ({ ...current, ...updates, lastUpdated: new Date().toISOString() }));
  }

  function saveManualLocation() {
    if (blockGuestSave()) return;
    const value = String(locationSettings.manualLocation || "").trim();
    if (!value) return;
    setLocationSettings((current) => ({
      ...current,
      mode: "saved",
      selectedSavedLocation: value,
      savedLocations: [...new Set([...(current.savedLocations || []), value])],
      lastUpdated: new Date().toISOString(),
    }));
  }

  const hasScoutLocation = Boolean(
    String(locationSettings.manualLocation || "").trim() ||
    String(locationSettings.selectedSavedLocation || "").trim() ||
    locationSettings.trackingEnabled
  );

  function requestScoutLocation(reason = "") {
    if (reason === "route-planner" && !featureAllowed("scout_route_planner")) {
      openLockedFeatureNotice("scout_route_planner");
      return false;
    }
    if (hasScoutLocation) return true;
    setLocationPromptOpen(true);
    return false;
  }

  function savePromptLocation(event) {
    event?.preventDefault?.();
    if (blockGuestSave()) return;
    const value = String(locationPromptZip || "").trim();
    if (!value) return;
    setLocationSettings((current) => ({
      ...current,
      mode: "manual",
      manualLocation: value,
      selectedSavedLocation: value,
      savedLocations: [...new Set([...(current.savedLocations || []), value])],
      trackingEnabled: false,
      lastUpdated: new Date().toISOString(),
    }));
    setLocationPromptOpen(false);
    setLocationPromptZip("");
  }

  function openLocationSettingsFromPrompt() {
    setLocationPromptOpen(false);
    openUtilityPage("settings");
  }

  function openInventoryImportAssistant(context = "Vault", options = {}) {
    const mode = options.mode || (options.sourceType?.startsWith?.("bulk_") ? BATCH_INTAKE_MODES.BULK_ADD : BATCH_INTAKE_MODES.TRANSFER);
    const sourceType = options.sourceType || (mode === BATCH_INTAKE_MODES.BULK_ADD ? "bulk_paste" : "spreadsheet_csv");
    setImportAssistantContext(context);
    setBatchIntakeMode(mode);
    setImportSourceType(sourceType);
    setImportAssistantOpen(true);
    setImportBatchMessage("");
    setImportLastBatchResult(null);
    setImportBulkApply((current) => ({
      ...current,
      destination: context === "Forge" ? "Forge" : context === "Wishlist" ? "Wishlist" : context === "Mixed" ? "" : "Vault",
    }));
    if (options.resetRows) {
      setImportRows([]);
      setImportText("");
      setImportFileName("");
      setImportColumnHeaders([]);
      setImportColumnMapping({});
    }
    if (context === "Forge") {
      setFeatureSectionsOpen((current) => ({ ...current, forge_inventory: true }));
    }
    if (context === "Vault" || context === "Wishlist") {
      setFeatureSectionsOpen((current) => ({ ...current, vault_add: true }));
      setActiveTab("vault");
    }
    openFlowModal("batchIntake", { size: "large", source: options.source || "batch-intake" });
  }

  function parseCsvLine(line) {
    const cells = [];
    let current = "";
    let inQuotes = false;
    for (let index = 0; index < line.length; index += 1) {
      const char = line[index];
      if (char === '"') {
        inQuotes = !inQuotes;
      } else if (char === "," && !inQuotes) {
        cells.push(current.trim());
        current = "";
      } else {
        current += char;
      }
    }
    cells.push(current.trim());
    return cells.map((cell) => cell.replace(/^"|"$/g, ""));
  }

  function getImportSourceGuide(sourceType = importSourceType) {
    return IMPORT_SOURCE_GUIDES.find((guide) => guide.value === sourceType) || IMPORT_SOURCE_GUIDES[0];
  }

  function defaultImportDestination(context = importAssistantContext) {
    if (context === "Forge") return "Forge";
    if (context === "Wishlist") return "Wishlist";
    return "Vault";
  }

  function inferImportColumnMapping(headers = []) {
    return headers.reduce((mapping, header, index) => {
      const normalizedHeader = String(header || "").toLowerCase().trim();
      const match = IMPORT_FIELD_OPTIONS.find((field) => field.aliases.some((alias) => normalizedHeader.includes(alias)));
      if (match && !Object.values(mapping).includes(match.value)) {
        return { ...mapping, [index]: match.value };
      }
      return mapping;
    }, {});
  }

  function readImportCell(row, headers, aliases, fallbackIndex = -1, mapping = importColumnMapping, fieldKey = "") {
    if (fieldKey && mapping) {
      const mappedIndex = Object.entries(mapping).find(([, value]) => value === fieldKey)?.[0];
      if (mappedIndex !== undefined && row[Number(mappedIndex)] !== undefined) return row[Number(mappedIndex)] || "";
    }
    const match = headers.findIndex((header) => aliases.some((alias) => header.includes(alias)));
    if (match >= 0) return row[match] || "";
    if (fallbackIndex >= 0) return row[fallbackIndex] || "";
    return "";
  }

  function normalizeImportNumber(value) {
    const clean = String(value || "").replace(/[$,%]/g, "").trim();
    const number = Number(clean);
    return Number.isFinite(number) ? number : "";
  }

  function normalizeImportQuantity(value) {
    const number = Number(String(value || "").replace(/[^\d.]/g, ""));
    return Number.isFinite(number) && number > 0 ? Math.max(1, Math.floor(number)) : 1;
  }

  function normalizeImportIdentifier(value) {
    return normalizeBarcodeValue(value).toLowerCase();
  }

  function importConfidenceLabel(score) {
    if (Number(score || 0) >= 85) return "High";
    if (Number(score || 0) >= 60) return "Medium";
    return "Low";
  }

  function findCatalogMatchForImport(name, setName = "", identifiers = {}) {
    const cleanName = String(name || "").trim().toLowerCase();
    const cleanSet = String(setName || "").trim().toLowerCase();
    const identifier = normalizeImportIdentifier(identifiers.upcSku || identifiers.barcode || identifiers.sku || identifiers.externalId || identifiers.cardNumber);
    if (!cleanName && !identifier) return { match: null, confidenceScore: 20, needsReview: true, alternateMatches: [] };

    if (identifier) {
      const exactIdentifier = catalogProducts.find((product) => {
        const values = catalogIdentifiersForProduct(product).map(normalizeImportIdentifier).filter(Boolean);
        return values.includes(identifier);
      });
      if (exactIdentifier) {
        return { match: exactIdentifier, confidenceScore: 98, needsReview: false, alternateMatches: [exactIdentifier] };
      }
    }

    const exact = catalogProducts.find((product) => {
      const productName = String(product.name || product.productName || product.cardName || "").trim().toLowerCase();
      const productSet = String(product.setName || product.expansion || "").trim().toLowerCase();
      return productName === cleanName && (!cleanSet || productSet === cleanSet);
    });
    if (exact) return { match: exact, confidenceScore: 94, needsReview: false, alternateMatches: [exact] };

    const alternateMatches = getBestCatalogMatches([cleanName, cleanSet, identifiers.cardNumber, identifiers.productType].filter(Boolean).join(" "), catalogProducts)
      .slice(0, 3)
      .map((candidate) => candidate.product || candidate);
    if (alternateMatches.length) {
      const best = alternateMatches[0];
      const bestTitle = String(best.name || best.productName || best.cardName || "").trim().toLowerCase();
      const titleHit = cleanName && (bestTitle.includes(cleanName) || cleanName.includes(bestTitle));
      return {
        match: best,
        confidenceScore: titleHit ? 78 : 62,
        needsReview: true,
        alternateMatches,
      };
    }

    const tokens = cleanName.split(/\s+/).filter((token) => token.length > 2);
    const fuzzy = catalogProducts.find((product) => {
      const productName = String(product.name || product.productName || product.cardName || "").trim().toLowerCase();
      const productSet = String(product.setName || product.expansion || "").trim().toLowerCase();
      const tokenHits = tokens.filter((token) => productName.includes(token)).length;
      return tokenHits >= Math.min(3, Math.max(1, tokens.length - 1)) && (!cleanSet || productSet.includes(cleanSet) || cleanSet.includes(productSet));
    });
    if (fuzzy) return { match: fuzzy, confidenceScore: 70, needsReview: true, alternateMatches: [fuzzy] };

    return { match: null, confidenceScore: 35, needsReview: true, alternateMatches: [] };
  }

  function makeImportRow(raw, sourceType, index) {
    const normalizedRaw = normalizeBulkImportRow(raw, {
      destination: importBulkApply.destination || defaultImportDestination(),
      store: importBulkApply.store,
      purchaseDate: importBulkApply.purchaseDate,
    });
    const itemName = normalizedRaw.itemName || raw.itemName || raw.name || raw.productName || raw.originalText || `Imported item ${index + 1}`;
    const matchResult = findCatalogMatchForImport(itemName, raw.setName, { ...raw, upcSku: normalizedRaw.upcSku || raw.upcSku });
    const matched = matchResult.match;
    const marketInfo = matched ? getTideTradrMarketInfo(matched) : {};
    const catalogType = raw.catalogType || matched?.catalogType || (raw.condition || raw.grade ? "card" : matched?.catalog_type || "unknown");
    const destination = normalizedRaw.destination || raw.destination || importBulkApply.destination || defaultImportDestination();
    return {
      importedItemId: makeId("import-row"),
      originalText: raw.originalText || itemName,
      matchedCatalogItemId: matched?.id || "",
      possibleMatchName: matched?.name || matched?.productName || matched?.cardName || "",
      alternateMatches: matchResult.alternateMatches || [],
      itemName,
      catalogType,
      productType: raw.productType || matched?.productType || "",
      setName: raw.setName || matched?.setName || matched?.expansion || "",
      cardNumber: raw.cardNumber || matched?.cardNumber || "",
      quantity: normalizedRaw.quantity || normalizeImportQuantity(raw.quantity),
      costPaid: normalizeImportNumber(raw.costPaid || normalizedRaw.unitCost),
      msrp: normalizeImportNumber(raw.msrp || matched?.msrpPrice || matched?.msrp || ""),
      marketValue: normalizeImportNumber(raw.marketValue || marketInfo.currentMarketValue || ""),
      condition: raw.condition || matched?.condition || "Unknown",
      variant: raw.variant || matched?.variant || "",
      language: raw.language || matched?.language || "",
      graded: Boolean(raw.graded || matched?.graded),
      grade: raw.grade || matched?.grade || "",
      location: raw.location || raw.store || raw.source || "",
      store: normalizedRaw.store || raw.store || raw.location || raw.source || "",
      purchaseDate: normalizedRaw.purchaseDate || raw.purchaseDate || "",
      purchaserName: normalizedRaw.purchaserName || raw.purchaserName || raw.purchaser || raw.buyer || "",
      upcSku: normalizedRaw.upcSku || raw.upcSku || raw.barcode || raw.sku || "",
      notes: raw.notes || "",
      confidenceScore: matchResult.confidenceScore,
      confidenceLabel: importConfidenceLabel(matchResult.confidenceScore),
      needsReview: matchResult.needsReview,
      importStatus: "pending",
      duplicateAction: importOptions.duplicateAction || "add_separate",
      destination,
      sourceType,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };
  }

  function parseImportText(text, sourceType = importSourceType) {
    const lines = String(text || "").split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
    if (lines.length === 0) return [];
    const firstLineCells = parseCsvLine(lines[0]);
    const headerCellPattern = /^(name|item|item name|product|product name|card|title|quantity|qty|count|destination|purchaser|buyer|cost|cost paid|paid|purchase price|price|market|market value|value|msrp|retail|set|set name|collection|expansion|condition|variant|finish|printing|upc|sku|barcode|external id|note|notes|date|purchase date|purchased|store|source|vendor|card number|card #|card no)$/i;
    const hasHeaders = firstLineCells.length > 1
      ? firstLineCells.some((cell) => headerCellPattern.test(cell.trim()))
      : headerCellPattern.test(firstLineCells[0]?.trim() || "");
    const headers = hasHeaders ? firstLineCells.map((cell) => cell.toLowerCase().trim()) : [];
    const dataLines = hasHeaders ? lines.slice(1) : lines;
    const mapping = hasHeaders ? (Object.keys(importColumnMapping || {}).length ? importColumnMapping : inferImportColumnMapping(headers)) : {};

    return dataLines.map((line, index) => {
      const cells = line.includes(",") ? parseCsvLine(line) : line.split(/\t|\|/).map((cell) => cell.trim());
      if (headers.length) {
        return makeImportRow({
          originalText: line,
          itemName: readImportCell(cells, headers, ["name", "item", "product", "card", "title"], 0, mapping, "itemName"),
          quantity: readImportCell(cells, headers, ["quantity", "qty", "count"], 1, mapping, "quantity"),
          costPaid: readImportCell(cells, headers, ["cost", "paid", "purchase", "price"], 2, mapping, "costPaid"),
          marketValue: readImportCell(cells, headers, ["market", "value"], 3, mapping, "marketValue"),
          msrp: readImportCell(cells, headers, ["msrp", "retail"], 4, mapping, "msrp"),
          productType: readImportCell(cells, headers, ["type", "category"], 5, mapping, "productType"),
          setName: readImportCell(cells, headers, ["set", "collection", "expansion"], 6, mapping, "setName"),
          condition: readImportCell(cells, headers, ["condition"], 7, mapping, "condition"),
          destination: readImportCell(cells, headers, ["destination"], -1, mapping, "destination"),
          purchaserName: readImportCell(cells, headers, ["purchaser", "buyer"], -1, mapping, "purchaserName"),
          variant: readImportCell(cells, headers, ["variant", "finish", "printing"], -1, mapping, "variant"),
          notes: readImportCell(cells, headers, ["note"], 8, mapping, "notes"),
          purchaseDate: readImportCell(cells, headers, ["date", "purchase date", "purchased"], -1, mapping, "purchaseDate"),
          upcSku: readImportCell(cells, headers, ["upc", "sku", "barcode", "external"], -1, mapping, "upcSku"),
          cardNumber: readImportCell(cells, headers, ["number", "card #", "card no"], -1, mapping, "cardNumber"),
          store: readImportCell(cells, headers, ["store", "source", "vendor"], -1, mapping, "store"),
        }, sourceType, index);
      }

      const quantityMatch =
        line.match(/\b(?:qty|quantity)\s*[:#-]?\s*(\d+)\b/i) ||
        line.match(/\bx\s*[:#-]?\s*(\d+)\b/i) ||
        line.match(/\b(\d+)\s*x\b/i) ||
        line.match(/^\s*(\d+)\s+(?=\S)/i);
      const lineWithoutQuantity = line
        .replace(/\b(?:qty|quantity|x)\s*[:#-]?\s*\d+\b/gi, "")
        .replace(/\b\d+\s*x\b/gi, "")
        .replace(/^\s*\d+\s+(?=\S)/i, "")
        .trim();
      const prices = [...lineWithoutQuantity.matchAll(/\$\s*(\d+(?:\.\d{1,2})?)\b|\b(\d+\.\d{2})\b/g)].map((match) => match[1] || match[2]);
      const cleanedName = lineWithoutQuantity
        .replace(/\$?\b\d+(?:\.\d{1,2})?\b/g, "")
        .replace(/[,|-]+/g, " ")
        .trim();
      return makeImportRow({
        originalText: line,
        itemName: cleanedName || cells[0] || line,
        quantity: quantityMatch?.[1] || 1,
        costPaid: prices[0] || "",
        marketValue: prices[1] || "",
      }, sourceType, index);
    });
  }

  function runImportParse() {
    if (importSourceType === "no_tracker") {
      setImportBatchMessage("No tracker selected. Use Bulk Add search, paste list, scanner, or manual add to build your first batch.");
      setBatchIntakeMode(BATCH_INTAKE_MODES.BULK_ADD);
      setImportSourceType("bulk_paste");
      return;
    }
    if (importSourceType === "link") {
      const row = makeImportRow({
        originalText: importLink,
        itemName: "Saved inventory source link",
        notes: "Automatic link import is coming soon. You can paste the list or upload a CSV for now.",
        source: importLink,
      }, "link", 0);
      setImportRows([row]);
      return;
    }
    const lines = String(importText || "").split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
    if (lines.length) {
      const headers = parseCsvLine(lines[0]);
      if (headers.some((cell) => /name|item|product|quantity|qty|cost|market|msrp|set|condition|upc|sku|barcode|note|date/i.test(cell))) {
        setImportColumnHeaders(headers);
        setImportColumnMapping((current) => Object.keys(current || {}).length ? current : inferImportColumnMapping(headers));
      }
    }
    const nextRows = parseImportText(importText, importSourceType);
    setImportRows(nextRows);
    setImportBatchMessage(nextRows.length ? `${nextRows.length} row${nextRows.length === 1 ? "" : "s"} staged for review. Nothing has been saved.` : "No rows found to review.");
  }

  function handleImportFileUpload(event) {
    const file = event.target.files?.[0];
    if (!file) return;
    setImportFileName(file.name);
    const extension = file.name.split(".").pop()?.toLowerCase();
    if (["png", "jpg", "jpeg", "webp", "gif"].includes(extension || "")) {
      setImportSourceType("photo_reference");
      setImportRows([
        makeImportRow({
          originalText: file.name,
          itemName: "Image reference upload",
          notes: "Image/OCR import is coming later. Type the visible text into the paste box for beta matching.",
        }, "photo_reference", 0),
      ]);
      setImportBatchMessage("Image uploaded as a reference only. Type visible text into the paste box, then review matches before saving.");
      return;
    }
    if (["xlsx", "xls", "pdf"].includes(extension || "")) {
      setImportSourceType("spreadsheet_csv");
      setImportRows([
        makeImportRow({
          originalText: file.name,
          itemName: `${extension?.toUpperCase()} import preview`,
          notes: "Spreadsheet/PDF parsing is limited in this beta build. Export as CSV or paste the list for automatic preview.",
        }, extension === "pdf" ? "pdf_reference" : "spreadsheet_reference", 0),
      ]);
      setImportBatchMessage(`${extension?.toUpperCase()} selected for reference. Export to CSV or paste visible rows for beta parsing.`);
      return;
    }
    const reader = new FileReader();
    reader.onload = () => {
      const content = String(reader.result || "");
      setImportText(content);
      const sourceType = extension === "csv" ? "spreadsheet_csv" : "notes_list";
      const lines = content.split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
      const headers = lines.length ? parseCsvLine(lines[0]) : [];
      const hasHeaders = headers.some((cell) => /name|item|product|quantity|qty|cost|market|msrp|set|condition|upc|sku|barcode|note|date/i.test(cell));
      setImportSourceType(sourceType);
      setImportColumnHeaders(hasHeaders ? headers : []);
      setImportColumnMapping(hasHeaders ? inferImportColumnMapping(headers) : {});
      const rows = parseImportText(content, sourceType);
      setImportRows(rows);
      setImportBatchMessage(`${rows.length} row${rows.length === 1 ? "" : "s"} staged from ${file.name}. Review before saving.`);
    };
    reader.readAsText(file);
  }

  function handleForgeImportFileUpload(event) {
    const file = event.target.files?.[0];
    if (!file) return;
    const extension = file.name.split(".").pop()?.toLowerCase() || "";
    setForgeImportForm((current) => ({
      ...current,
      fileName: file.name,
      detectedColumns: [],
      previewRows: [],
      mappingNotes: "",
    }));

    if (["xlsx", "xls"].includes(extension)) {
      setForgeImportForm((current) => ({
        ...current,
        fileName: file.name,
        detectedColumns: ["Spreadsheet file selected"],
        mappingNotes: "XLSX uploads are accepted for beta planning. Export to CSV for automatic column preview in this build.",
      }));
      return;
    }

    const reader = new FileReader();
    reader.onload = () => {
      const content = String(reader.result || "");
      try {
        if (extension === "json") {
          const parsed = JSON.parse(content);
          const rows = Array.isArray(parsed) ? parsed : Array.isArray(parsed.items) ? parsed.items : [parsed];
          const detectedColumns = [...new Set(rows.flatMap((row) => Object.keys(row || {})))].slice(0, 16);
          const csvLike = [
            detectedColumns.join(","),
            ...rows.map((row) => detectedColumns.map((column) => String(row?.[column] ?? "").replaceAll(",", " ")).join(",")),
          ].join("\n");
          setForgeImportForm((current) => ({
            ...current,
            fileName: file.name,
            detectedColumns,
            previewRows: parseImportText(csvLike, "json"),
            mappingNotes: rows.length ? "" : "No rows were found in this JSON file.",
          }));
          return;
        }

        const lines = content.split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
        const detectedColumns = lines.length ? parseCsvLine(lines[0]).filter(Boolean).slice(0, 16) : [];
        const sourceType = extension === "csv" ? "spreadsheet_csv" : "seller_list";
        setForgeImportForm((current) => ({
          ...current,
          fileName: file.name,
          detectedColumns,
          previewRows: parseImportText(content, sourceType),
          mappingNotes: lines.length ? "" : "No rows were found in this file.",
        }));
      } catch (error) {
        setForgeImportForm((current) => ({
          ...current,
          fileName: file.name,
          detectedColumns: [],
          previewRows: [],
          mappingNotes: `Could not preview this file yet: ${error.message || "unknown parsing error"}`,
        }));
      }
    };
    reader.readAsText(file);
  }

  function confirmForgeImportFile(event) {
    event?.preventDefault?.();
    const previewRows = forgeImportForm.previewRows || [];
    if (!forgeImportForm.fileName) {
      showAppMessage("Choose a file to import first.");
      return;
    }
    if (forgeImportForm.importType === "Sales") {
      setForgeImportForm((current) => ({
        ...current,
        mappingNotes: "Sales import mapping is coming soon. Manual sale entry is available now; this file was previewed but no sale records were saved.",
      }));
      setVaultToast("Sales import preview is staged for mapping only. No sale records were saved.");
      return;
    }
    if (!previewRows.length) {
      setVaultToast(`${forgeImportForm.fileName} saved for beta import mapping.`);
      closeFlowModal({ force: true, reset: false });
      setForgeImportForm(FORGE_IMPORT_BLANK);
      return;
    }

    setImportAssistantContext("Forge");
    setBatchIntakeMode(BATCH_INTAKE_MODES.TRANSFER);
    setImportSourceType(forgeImportForm.sourceApp ? "seller_list" : "spreadsheet_csv");
    setImportRows(previewRows.map((row) => ({ ...row, destination: "Forge", importStatus: "pending" })));
    setImportBatchMessage(`${forgeImportForm.fileName} is staged for review. Nothing has been saved yet.`);
    setVaultToast(`${forgeImportForm.fileName} staged for review before saving.`);
    closeFlowModal({ force: true, reset: false });
    setForgeImportForm(FORGE_IMPORT_BLANK);
    setImportAssistantOpen(true);
    openFlowModal("batchIntake", { size: "large", source: "forge-import-review" });
  }

  function updateImportRow(rowId, updates) {
    setImportRows((current) => current.map((row) => {
      if (row.importedItemId !== rowId) return row;
      const next = { ...row, ...updates, updatedAt: new Date().toISOString() };
      if (Object.prototype.hasOwnProperty.call(updates, "itemName") || Object.prototype.hasOwnProperty.call(updates, "setName") || Object.prototype.hasOwnProperty.call(updates, "upcSku") || Object.prototype.hasOwnProperty.call(updates, "cardNumber")) {
        const matchResult = findCatalogMatchForImport(next.itemName, next.setName, next);
        next.matchedCatalogItemId = matchResult.match?.id || "";
        next.possibleMatchName = matchResult.match?.name || matchResult.match?.productName || matchResult.match?.cardName || "";
        next.alternateMatches = matchResult.alternateMatches || [];
        next.confidenceScore = matchResult.confidenceScore;
        next.confidenceLabel = importConfidenceLabel(matchResult.confidenceScore);
        next.needsReview = matchResult.needsReview;
      }
      return next;
    }));
  }

  function selectImportRowCatalogMatch(rowId, productId) {
    setImportRows((current) => current.map((row) => {
      if (row.importedItemId !== rowId) return row;
      if (!productId) {
        return {
          ...row,
          matchedCatalogItemId: "",
          possibleMatchName: "",
          confidenceScore: 35,
          confidenceLabel: "Low",
          needsReview: true,
          importStatus: "reviewed",
          updatedAt: new Date().toISOString(),
        };
      }
      const product = catalogProducts.find((candidate) => String(candidate.id) === String(productId));
      return {
        ...row,
        matchedCatalogItemId: productId,
        possibleMatchName: product ? catalogTitle(product) : row.possibleMatchName,
        productType: row.productType || product?.productType || "",
        setName: row.setName || product?.setName || product?.expansion || "",
        confidenceScore: Math.max(Number(row.confidenceScore || 0), 88),
        confidenceLabel: "High",
        needsReview: false,
        importStatus: "reviewed",
        updatedAt: new Date().toISOString(),
      };
    }));
  }

  function createManualCatalogItemFromImport(row) {
    const now = new Date().toISOString();
    const product = {
      id: makeId("catalog"),
      catalogType: row.catalogType === "card" ? "card" : "sealed",
      name: row.itemName,
      productName: row.catalogType === "card" ? "" : row.itemName,
      cardName: row.catalogType === "card" ? row.itemName : "",
      pokemonName: "",
      category: "Pokemon",
      setName: row.setName,
      productType: row.productType,
      barcode: "",
      sku: "",
      marketPrice: Number(row.marketValue || 0),
      marketSource: "Manual",
      marketLastUpdated: now,
      marketConfidenceLevel: "Manual",
      sourceType: "manual",
      imageUrl: "",
      imageSource: "placeholder",
      imageStatus: "placeholder",
      imageLastUpdated: now,
      imageNeedsReview: true,
      msrpPrice: Number(row.msrp || 0),
      condition: row.condition || "",
      language: row.language || "English",
      graded: Boolean(row.graded),
      grade: row.grade || "",
      notes: row.notes || "Created from Inventory Import Assistant.",
      createdAt: now,
      updatedAt: now,
    };
    setCatalogProducts((current) => [product, ...current]);
    updateImportRow(row.importedItemId, {
      matchedCatalogItemId: product.id,
      possibleMatchName: product.name,
      confidenceScore: 88,
      needsReview: false,
    });
  }

  function importedRowToItem(row, destination) {
    const matched = catalogProducts.find((product) => String(product.id) === String(row.matchedCatalogItemId));
    const normalizedDestination = normalizeAddDestinationValue(destination, "forge");
    const defaultPurchaser = (normalizedDestination === "forge" ? forgePurchaserOptions[0] : purchaserOptions[0]) || { id: "", name: "" };
    const rowPurchaserName = String(row.purchaserName || row.purchaser || row.buyer || "").trim();
    const isVaultDestination = normalizedDestination === "vault";
    const isWishlistDestination = normalizedDestination === "wishlist";
    const isForgeDestination = normalizedDestination === "forge";
    const status = isVaultDestination ? "Personal Collection" : isWishlistDestination ? "Wishlist" : "In Stock";
    return {
      ...blankItem,
      id: makeId(isVaultDestination ? "vault-import" : isWishlistDestination ? "wishlist-import" : "import"),
      name: row.itemName,
      destinationScope: [normalizedDestination],
      recordType: isVaultDestination ? "vault_item" : isWishlistDestination ? "wishlist_item" : "forge_inventory",
      businessInventory: isForgeDestination,
      isWishlist: isWishlistDestination,
      buyer: rowPurchaserName || defaultPurchaser.name,
      purchaserId: rowPurchaserName ? "" : defaultPurchaser.id,
      purchaserName: rowPurchaserName || defaultPurchaser.name,
      category: "Pokemon",
      store: row.store || row.location || "",
      quantity: Number(row.quantity || 1),
      unitCost: Number(row.costPaid || 0),
      salePrice: "",
      barcode: matched?.barcode || matched?.upc || row.upcSku || "",
      catalogProductId: matched?.id || "",
      catalogProductName: matched?.name || "",
      externalProductId: matched?.externalProductId || "",
      tideTradrUrl: matched?.marketUrl || "",
      itemImage: getCatalogImage(matched) || "",
      itemImageSource: matched?.imageSource || getDefaultImageSource(matched || {}),
      itemImageStatus: matched?.imageStatus || getDefaultImageStatus(matched || {}),
      itemImageSourceUrl: matched?.imageSourceUrl || "",
      itemImageLastUpdated: matched?.imageLastUpdated || "",
      itemImageNeedsReview: Boolean(matched?.imageNeedsReview),
      marketPrice: Number(row.marketValue || matched?.marketPrice || 0),
      lowPrice: Number(matched?.lowPrice || 0),
      midPrice: Number(matched?.midPrice || row.marketValue || 0),
      highPrice: Number(matched?.highPrice || 0),
      msrpPrice: Number(row.msrp || matched?.msrpPrice || 0),
      expansion: row.setName || matched?.setName || "",
      productType: row.productType || matched?.productType || "",
      variant: row.variant || "",
      purchaseDate: row.purchaseDate || "",
      status,
      vaultStatus: isVaultDestination ? "personal_collection" : isWishlistDestination ? "wishlist" : "",
      physicalLocation: isForgeDestination ? DEFAULT_FORGE_PHYSICAL_LOCATION : "",
      physicalLocationNotes: "",
      actionNotes: isVaultDestination ? "Imported collection item" : isWishlistDestination ? "Imported wishlist item" : "Imported Forge item",
      notes: [row.notes, `Imported from ${row.sourceType}. Original: ${row.originalText}`].filter(Boolean).join(" | "),
      createdAt: new Date().toISOString(),
      importStatus: "imported",
      importSourceType: row.sourceType,
    };
  }

  function uuidOrNull(value) {
    return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(String(value || "")) ? value : null;
  }

  function sanitizeInventorySupabaseRow(row = {}) {
    const metadata = [];
    INVENTORY_ITEMS_METADATA_FIELDS.forEach(([key, label]) => {
      const value = row[key];
      if (value === null || value === undefined || value === "" || value === 0) return;
      metadata.push(`${label}: ${value}`);
    });
    const next = {};
    Object.entries(row).forEach(([key, value]) => {
      if (!INVENTORY_ITEMS_SUPABASE_COLUMNS.has(key) || value === undefined) return;
      next[key] = value;
    });
    if (!next.buyer && row.purchaser_name) next.buyer = row.purchaser_name;
    if (metadata.length) {
      next.action_notes = [next.action_notes, `Catalog/details: ${metadata.join("; ")}`].filter(Boolean).join(" | ");
    }
    return next;
  }

  function inventoryRecordToSupabaseRow(record = {}) {
    const marketValue = Number(record.marketValue ?? record.market_value ?? record.marketPrice ?? record.market_price ?? 0);
    const unitCost = Number(record.unitCost ?? record.unit_cost ?? record.purchasePrice ?? record.purchase_price ?? 0);
    return sanitizeInventorySupabaseRow({
      user_id: user?.id,
      workspace_id: uuidOrNull(record.workspaceId || record.workspace_id || activeWorkspace?.id),
      owner_user_id: uuidOrNull(record.ownerUserId || record.owner_user_id || user?.id),
      visibility: record.visibility || defaultVisibilityForWorkspace(activeWorkspace),
      name: record.name || record.itemName || "",
      sku: record.sku || "",
      buyer: record.buyer || record.purchaserName || "",
      purchaser_id: uuidOrNull(record.purchaserId || record.purchaser_id),
      purchaser_name: record.purchaserName || record.purchaser_name || record.buyer || "",
      category: record.category || "Pokemon",
      store: record.store || record.location || "",
      quantity: Number(record.quantity || 1),
      unit_cost: unitCost,
      purchase_price: Number(record.purchasePrice ?? record.purchase_price ?? unitCost ?? 0),
      sale_price: Number(record.salePrice || record.plannedSalePrice || record.sale_price || 0),
      receipt_image: record.receiptImage || record.receipt_image || "",
      item_image: record.itemImage || record.item_image || "",
      item_image_source: record.itemImageSource || record.item_image_source || (record.itemImage || record.item_image ? "user" : "placeholder"),
      item_image_status: record.itemImageStatus || record.item_image_status || (record.itemImage || record.item_image ? "user" : "placeholder"),
      item_image_source_url: record.itemImageSourceUrl || record.item_image_source_url || "",
      item_image_last_updated: record.itemImageLastUpdated || record.item_image_last_updated || null,
      item_image_needs_review: Boolean(record.itemImageNeedsReview || record.item_image_needs_review),
      barcode: record.barcode || record.upc || "",
      catalog_product_id: uuidOrNull(record.catalogProductId || record.catalog_product_id),
      catalog_variant_id: uuidOrNull(record.catalogVariantId || record.catalog_variant_id),
      catalog_product_name: record.catalogProductName || record.catalog_product_name || "",
      external_product_source: record.externalProductSource || record.external_product_source || "TideTradr",
      external_product_id: record.externalProductId || record.external_product_id || "",
      tcgplayer_product_id: record.tcgplayerProductId || record.tcgplayer_product_id || record.externalProductId || record.external_product_id || "",
      tcgplayer_url: record.tideTradrUrl || record.tcgplayer_url || "",
      market_price: Number(record.marketPrice || record.marketValue || 0),
      market_value: marketValue,
      market_value_source: record.marketValueSource || record.market_value_source || record.marketPriceSource || record.market_price_source || record.externalProductSource || record.external_product_source || "TideTradr",
      market_value_updated_at: record.marketPrice || record.marketValue ? new Date().toISOString() : null,
      low_price: Number(record.lowPrice || 0),
      mid_price: Number(record.midPrice || 0),
      high_price: Number(record.highPrice || 0),
      msrp_price: Number(record.msrpPrice || record.msrp || 0),
      set_code: record.setCode || "",
      set_name: record.setName || record.expansion || "",
      product_line: record.productLine || "",
      product_type: normalizedInventoryProductType(record),
      pack_count: Number(record.packCount || 0),
      last_price_checked: record.marketPrice || record.marketValue ? new Date().toISOString() : null,
      status: record.status || "In Stock",
      listing_platform: record.listingPlatform || "",
      listing_url: record.listingUrl || "",
      listed_price: Number(record.listedPrice || 0),
      physical_location: record.physicalLocation || record.physical_location || "",
      physical_location_notes: record.physicalLocationNotes || record.physical_location_notes || "",
      action_notes: record.actionNotes || record.notes || "",
      condition_name: record.conditionName || record.condition || "Near Mint",
      language: record.language || "English",
      finish: record.finish || "",
      printing: record.printing || "",
    });
  }

  async function saveInventoryRecords(records = []) {
    if (blockGuestSave()) {
      return {
        saved: [],
        failures: records.map((record) => ({
          rowId: record?.id || record?.itemId || record?.name || "inventory-save",
          itemName: record?.name || record?.itemName || "Inventory item",
          error: "Create a free account to save this.",
        })),
      };
    }
    if (!records.length) return { saved: [], failures: [] };
    if (BETA_LOCAL_MODE || !supabase || !user?.id) {
      return { saved: records, failures: [] };
    }
    const saved = [];
    const failures = [];
    for (const record of records) {
      const { data, error } = await supabase
        .from("inventory_items")
        .insert(inventoryRecordToSupabaseRow(record))
        .select()
        .single();
      if (error) {
        failures.push({ rowId: record.id || record.itemId || record.name || "inventory-save", itemName: record.name || record.itemName || "Inventory item", error: error.message || "Could not save item" });
      } else {
        saved.push(mapItem(data));
      }
    }
    return { saved, failures };
  }

  function importDestinationScope(destination) {
    return normalizeAddDestinationValue(destination, "forge");
  }

  function findImportDuplicate(row, destination) {
    const scope = importDestinationScope(destination);
    const normalizedName = normalizeSearchText(row.itemName);
    const rowCatalogId = String(row.matchedCatalogItemId || "");
    return items.find((item) => {
      const scopeMatch =
        scope === "wishlist" ? isWishlistItemRecord(item) :
        scope === "vault" ? isVaultItemRecord(item) :
        isForgeInventoryItem(item);
      if (!scopeMatch) return false;
      if (rowCatalogId && String(item.catalogProductId || "") === rowCatalogId) return true;
      return normalizedName && normalizeSearchText(item.name) === normalizedName;
    }) || null;
  }

  function applyImportedQuantityIncrease(duplicate, row) {
    setItems((current) => current.map((item) => {
      if (item.id !== duplicate.id) return item;
      return {
        ...item,
        quantity: Number(item.quantity || 0) + Number(row.quantity || 1),
        notes: [item.notes, `Quantity increased from batch intake: ${row.originalText}`].filter(Boolean).join(" | "),
        updatedAt: new Date().toISOString(),
      };
    }));
  }

  async function confirmInventoryImport() {
    const rowsToImport = importRows.filter((row) => row.importStatus !== "skipped" && row.destination !== "Skip");
    if (rowsToImport.length === 0) return showAppMessage("No import rows selected.");
    const unreviewedRows = rowsToImport.filter((row) => row.needsReview && row.importStatus !== "reviewed");
    if (unreviewedRows.length) {
      setImportBatchMessage(`${unreviewedRows.length} low-confidence or unmatched row${unreviewedRows.length === 1 ? "" : "s"} still need review before saving.`);
      return;
    }
    const nextItems = [];
    const failures = [];
    let skippedDuplicates = 0;
    let quantityIncreases = 0;
    rowsToImport.forEach((row) => {
      const destinations = row.destination === "Both" ? ["Forge", "Vault"] : [row.destination || defaultImportDestination()];
      destinations.forEach((destination) => {
        if (destination === "Skip") return;
        try {
          const duplicate = findImportDuplicate(row, destination);
          const duplicateAction = row.duplicateAction || importOptions.duplicateAction || "add_separate";
          if (duplicate && duplicateAction === "skip_duplicate") {
            skippedDuplicates += 1;
            return;
          }
          if (duplicate && duplicateAction === "increase_quantity") {
            applyImportedQuantityIncrease(duplicate, row);
            quantityIncreases += 1;
            return;
          }
          nextItems.push(importedRowToItem(row, destination));
        } catch (error) {
          failures.push({ rowId: row.importedItemId, itemName: row.itemName, error: error.message || "Unknown import failure" });
        }
      });
    });
    let savedItems = nextItems;
    if (nextItems.length) {
      const saveResult = await saveInventoryRecords(nextItems);
      savedItems = saveResult.saved;
      failures.push(...saveResult.failures);
      if (savedItems.length) setItems((current) => [...savedItems, ...current]);
    }
    if (importOptions.addToWatchlist || importOptions.pinHighValue) {
      rowsToImport.forEach((row) => {
        const marketValue = Number(row.marketValue || 0);
        if (row.matchedCatalogItemId && (importOptions.addToWatchlist || marketValue >= 50)) {
          addProductToTideTradrWatchlist(row.matchedCatalogItemId);
        }
      });
    }
    setImportRows((current) => current.map((row) => row.importStatus === "skipped" || row.destination === "Skip" ? row : { ...row, importStatus: failures.some((failure) => failure.rowId === row.importedItemId) ? "failed" : "imported", updatedAt: new Date().toISOString() }));
    const result = {
      batchId: makeId("batch-intake"),
      saved: savedItems.length,
      skippedDuplicates,
      quantityIncreases,
      failures,
      completedAt: new Date().toISOString(),
    };
    setImportLastBatchResult(result);
    setImportBatchMessage(`${savedItems.length} item${savedItems.length === 1 ? "" : "s"} saved, ${quantityIncreases} duplicate quantit${quantityIncreases === 1 ? "y" : "ies"} increased, ${skippedDuplicates} duplicate${skippedDuplicates === 1 ? "" : "s"} skipped${failures.length ? `, ${failures.length} failed` : ""}.`);
    if (!failures.length) {
      const savedScopes = new Set(savedItems.map(normalizeInventoryDestination));
      setImportAssistantOpen(false);
      closeFlowModal({ force: true, reset: false });
      setActiveTab(savedScopes.has("forge") ? "inventory" : "vault");
    }
  }

  function addManualImportRow(event) {
    event?.preventDefault?.();
    if (!String(importManualRow.itemName || "").trim()) {
      setImportBatchMessage("Enter an item name before adding a manual row.");
      return;
    }
    const row = makeImportRow({
      ...importManualRow,
      originalText: importManualRow.itemName,
      source: importManualRow.store,
    }, importSourceType || "bulk_manual", importRows.length);
    setImportRows((current) => [...current, { ...row, importStatus: row.needsReview ? "pending" : "reviewed" }]);
    setImportManualRow((current) => ({
      ...current,
      itemName: "",
      quantity: "1",
      costPaid: "",
      notes: "",
    }));
    setImportBatchMessage("Manual row added to review. Nothing has been saved.");
  }

  function addCatalogProductToImportBatch(product, destination = importBulkApply.destination || defaultImportDestination()) {
    if (!product) return;
    const row = makeImportRow({
      itemName: catalogTitle(product),
      originalText: catalogTitle(product),
      productType: catalogProductTypeLabel(product),
      setName: catalogExpansionName(product),
      marketValue: getTideTradrMarketInfo(product).currentMarketValue || "",
      msrp: product.msrpPrice || product.msrp || "",
      upcSku: product.barcode || product.upc || "",
      destination,
    }, "bulk_search", importRows.length);
    setImportRows((current) => [
      ...current,
      {
        ...row,
        matchedCatalogItemId: product.id,
        possibleMatchName: catalogTitle(product),
        alternateMatches: [product],
        confidenceScore: 98,
        confidenceLabel: "High",
        needsReview: false,
        importStatus: "reviewed",
      },
    ]);
    setImportBatchMessage(`${catalogTitle(product)} added to the review batch.`);
  }

  function applyImportBulkUpdates() {
    const updates = {};
    if (importBulkApply.destination) updates.destination = importBulkApply.destination;
    if (importBulkApply.condition) updates.condition = importBulkApply.condition;
    if (importBulkApply.store) {
      updates.store = importBulkApply.store;
      updates.location = importBulkApply.store;
    }
    if (importBulkApply.purchaseDate) updates.purchaseDate = importBulkApply.purchaseDate;
    if (!Object.keys(updates).length) {
      setImportBatchMessage("Choose a bulk value to apply first.");
      return;
    }
    setImportRows((current) => current.map((row) => row.importStatus === "skipped" ? row : {
      ...row,
      ...updates,
      importStatus: row.needsReview ? "reviewed" : row.importStatus,
      updatedAt: new Date().toISOString(),
    }));
    setImportBatchMessage("Bulk values applied to review rows. Nothing has been saved yet.");
  }

  function removeImportRow(rowId) {
    setImportRows((current) => current.filter((row) => row.importedItemId !== rowId));
  }

  const importCatalogSearchResults = useMemo(() => {
    const query = String(deferredImportCatalogSearch || "").trim();
    if (query.length < 2) return [];
    return getBestCatalogMatches(query, catalogProducts)
      .slice(0, 8)
      .map((candidate) => candidate.product || candidate.item || candidate);
  }, [deferredImportCatalogSearch, catalogProducts]);

  function renderInventoryImportAssistant() {
    if (!importAssistantOpen) return null;
    const currentGuide = getImportSourceGuide();
    const sourceOptions = IMPORT_SOURCE_GUIDES.filter((guide) => guide.mode === batchIntakeMode || guide.value === importSourceType);
    const reviewableRows = importRows.filter((row) => row.importStatus !== "skipped" && row.destination !== "Skip");
    const unresolvedRows = reviewableRows.filter((row) => row.needsReview && row.importStatus !== "reviewed");
    const duplicateCount = reviewableRows.reduce((count, row) => {
      const destinations = row.destination === "Both" ? ["Forge", "Vault"] : [row.destination || defaultImportDestination()];
      return count + (destinations.some((destination) => destination !== "Skip" && findImportDuplicate(row, destination)) ? 1 : 0);
    }, 0);
    return (
      <section className="panel import-assistant-panel batch-intake-panel">
        <div className="compact-card-header">
          <div>
            <h2>{batchIntakeMode === BATCH_INTAKE_MODES.BULK_ADD ? "Bulk Add Review" : "Import / Transfer Collection"}</h2>
            <p>Input, parse, match, review, choose destination, then confirm. Nothing is saved until you approve the batch.</p>
          </div>
          <button type="button" className="secondary-button" onClick={() => closeFlowModal()}>Close</button>
        </div>

        <div className="quick-action-rail">
          <button
            type="button"
            className={batchIntakeMode === BATCH_INTAKE_MODES.TRANSFER ? "primary" : "secondary-button"}
            onClick={() => {
              setBatchIntakeMode(BATCH_INTAKE_MODES.TRANSFER);
              if (importSourceType.startsWith("bulk_")) setImportSourceType("spreadsheet_csv");
            }}
          >
            Transfer Collection
          </button>
          <button
            type="button"
            className={batchIntakeMode === BATCH_INTAKE_MODES.BULK_ADD ? "primary" : "secondary-button"}
            onClick={() => {
              setBatchIntakeMode(BATCH_INTAKE_MODES.BULK_ADD);
              if (!importSourceType.startsWith("bulk_")) setImportSourceType("bulk_paste");
            }}
          >
            Bulk Add
          </button>
        </div>

        <div className="cards mini-cards">
          <div className="card"><p>Source</p><h2>{currentGuide.label}</h2></div>
          <div className="card"><p>Review Rows</p><h2>{importRows.length}</h2></div>
          <div className="card"><p>Needs Review</p><h2>{unresolvedRows.length}</h2></div>
          <div className="card"><p>Duplicate Warnings</p><h2>{duplicateCount}</h2></div>
        </div>

        <div className="form">
          <Field label="Import Source">
            <select value={importSourceType} onChange={(event) => setImportSourceType(event.target.value)}>
              {sourceOptions.map((guide) => (
                <option key={guide.value} value={guide.value}>{guide.label}</option>
              ))}
            </select>
          </Field>
          <div className="drawer-info-card">
            <strong>{currentGuide.instructions}</strong>
            <p className="compact-subtitle">Best format: {currentGuide.bestFormat}</p>
          </div>
          {batchIntakeMode === BATCH_INTAKE_MODES.BULK_ADD ? (
            <div className="small-empty-state">
              <strong>Bulk import mapping is coming soon.</strong>
              <span>You can paste rows or add multiple manual items now; each row still gets reviewed before anything saves.</span>
            </div>
          ) : null}
          {importSourceType !== "no_tracker" ? (
            <Field label="Upload File">
              <input type="file" accept=".csv,.txt,.tsv,.xlsx,.xls,.pdf,image/*" onChange={handleImportFileUpload} />
            </Field>
          ) : null}
          {importFileName ? <p className="compact-subtitle">Selected file: {importFileName}</p> : null}
          {importColumnHeaders.length ? (
            <details className="forge-import-mapping" open>
              <summary>Column mapping</summary>
              <div className="forge-import-columns">
                {importColumnHeaders.map((header, index) => (
                  <label key={`${header}-${index}`} className="mapping-column-row">
                    <span>{header || `Column ${index + 1}`}</span>
                    <select
                      value={importColumnMapping[index] || ""}
                      onChange={(event) => setImportColumnMapping((current) => ({ ...current, [index]: event.target.value }))}
                    >
                      <option value="">Ignore</option>
                      {IMPORT_FIELD_OPTIONS.map((field) => <option key={field.value} value={field.value}>{field.label}</option>)}
                    </select>
                  </label>
                ))}
              </div>
            </details>
          ) : null}
          <Field label={importSourceType === "photo_reference" ? "Type visible text from photo/screenshot" : "Paste Text / List"}>
            <textarea
              value={importText}
              onChange={(event) => setImportText(event.target.value)}
              placeholder={"Example:\nName,Quantity,Cost Paid,Market Value,MSRP,Product Type,Set,Condition,Notes\nPrismatic Evolutions ETB,2,59.99,90,49.99,Elite Trainer Box,Prismatic Evolutions,Sealed,Keep one\n2x Surging Sparks Booster Bundle"}
            />
          </Field>
          {batchIntakeMode === BATCH_INTAKE_MODES.TRANSFER ? (
          <Field label="Paste inventory/collection link">
            <input value={importLink} onChange={(event) => setImportLink(event.target.value)} placeholder="Google Sheets, Excel/OneDrive, TCGPlayer, PriceCharting, Collectr, eBay, Whatnot export link" />
          </Field>
          ) : null}
          {importSourceType === "link" ? (
            <div className="empty-state">
              <h3>Link import beta</h3>
              <p>Save source link, then attempt import if supported. Automatic link import is coming soon. You can paste the list or upload a CSV for now.</p>
              <p className="compact-subtitle">Later examples: Google Sheets, Excel/OneDrive, TCGPlayer collection/export, PriceCharting collection/export, Collectr export, eBay inventory/drafts export, and Whatnot inventory/export if available.</p>
            </div>
          ) : null}
        </div>

        <div className="quick-actions">
          <button type="button" onClick={runImportParse}>Parse and Review Matches</button>
          <button type="button" className="secondary-button" onClick={() => setImportRows([])}>Clear Review</button>
        </div>

        <details className="forge-form-step forge-optional-details" open={batchIntakeMode === BATCH_INTAKE_MODES.BULK_ADD}>
          <summary>Bulk Add: search and manual rows</summary>
          <div className="form">
            <Field label="Search catalog and add to batch">
              <input value={importCatalogSearch} onChange={(event) => setImportCatalogSearch(event.target.value)} placeholder="Search Market Watch catalog..." />
            </Field>
            {importCatalogSearchResults.length ? (
              <div className="catalog-picker-grid">
                {importCatalogSearchResults.map((product) => (
                  <button key={product.id || catalogTitle(product)} type="button" className="catalog-picker-card" onClick={() => addCatalogProductToImportBatch(product)}>
                    <div className="catalog-thumb">
                      {catalogImage(product) ? (
                        <>
                          <img
                            src={catalogImage(product)}
                            alt=""
                            onError={(event) => {
                              event.currentTarget.style.display = "none";
                              event.currentTarget.nextElementSibling?.removeAttribute("hidden");
                            }}
                          />
                          {renderProductImageFallback(product, { hidden: true })}
                        </>
                      ) : (
                        renderProductImageFallback(product)
                      )}
                    </div>
                    <span className="catalog-picker-copy">
                      <strong>{catalogTitle(product)}</strong>
                      <small>{catalogProductTypeLabel(product)}{catalogExpansionName(product) ? ` | ${catalogExpansionName(product)}` : ""}</small>
                    </span>
                  </button>
                ))}
              </div>
            ) : null}
            <form className="form flow-form-grid" onSubmit={addManualImportRow}>
              <Field label="Manual row item">
                <input value={importManualRow.itemName} onChange={(event) => setImportManualRow((current) => ({ ...current, itemName: event.target.value }))} placeholder="Charizard ex or Prismatic Evolutions ETB" />
              </Field>
              <Field label="Quantity">
                <input type="number" min="1" value={importManualRow.quantity} onChange={(event) => setImportManualRow((current) => ({ ...current, quantity: event.target.value }))} />
              </Field>
              <Field label="Destination">
                <select value={importManualRow.destination} onChange={(event) => setImportManualRow((current) => ({ ...current, destination: event.target.value }))}>
                  {IMPORT_DESTINATION_OPTIONS.filter((option) => option.value !== "Both").map((option) => <option key={option.value} value={option.value}>{option.label}</option>)}
                </select>
              </Field>
              <Field label="Purchaser">
                <input value={importManualRow.purchaserName} onChange={(event) => setImportManualRow((current) => ({ ...current, purchaserName: event.target.value }))} placeholder="Zena, Dillon, or buyer name" />
              </Field>
              <Field label="Condition">
                <select value={importManualRow.condition} onChange={(event) => setImportManualRow((current) => ({ ...current, condition: event.target.value }))}>
                  {IMPORT_CONDITION_OPTIONS.map((condition) => <option key={condition}>{condition}</option>)}
                </select>
              </Field>
              <Field label="Cost">
                <input type="number" step="0.01" value={importManualRow.costPaid} onChange={(event) => setImportManualRow((current) => ({ ...current, costPaid: event.target.value }))} />
              </Field>
              <Field label="Store/source">
                <input value={importManualRow.store} onChange={(event) => setImportManualRow((current) => ({ ...current, store: event.target.value }))} />
              </Field>
              <Field label="Purchase date">
                <input type="date" value={importManualRow.purchaseDate} onChange={(event) => setImportManualRow((current) => ({ ...current, purchaseDate: event.target.value }))} />
              </Field>
              <Field label="UPC / barcode">
                <input value={importManualRow.upcSku} onChange={(event) => setImportManualRow((current) => ({ ...current, upcSku: event.target.value }))} placeholder="Typed or scanned code" />
              </Field>
              <Field label="Notes">
                <input value={importManualRow.notes} onChange={(event) => setImportManualRow((current) => ({ ...current, notes: event.target.value }))} />
              </Field>
              <div className="flow-form-footer">
                <button type="submit">Add Manual Row</button>
              </div>
            </form>
          </div>
        </details>

        <div className="settings-subsection">
          <h3>Review Controls</h3>
          <div className="form import-review-grid">
            <Field label="Apply destination to all">
              <select value={importBulkApply.destination} onChange={(event) => setImportBulkApply((current) => ({ ...current, destination: event.target.value }))}>
                <option value="">No bulk destination</option>
                {IMPORT_DESTINATION_OPTIONS.map((option) => <option key={option.value} value={option.value}>{option.label}</option>)}
              </select>
            </Field>
            <Field label="Apply condition to all">
              <select value={importBulkApply.condition} onChange={(event) => setImportBulkApply((current) => ({ ...current, condition: event.target.value }))}>
                <option value="">No bulk condition</option>
                {IMPORT_CONDITION_OPTIONS.map((condition) => <option key={condition}>{condition}</option>)}
              </select>
            </Field>
            <Field label="Apply store/source to all">
              <input value={importBulkApply.store} onChange={(event) => setImportBulkApply((current) => ({ ...current, store: event.target.value }))} placeholder="Target, Walmart, collection app..." />
            </Field>
            <Field label="Apply purchase date to all">
              <input type="date" value={importBulkApply.purchaseDate} onChange={(event) => setImportBulkApply((current) => ({ ...current, purchaseDate: event.target.value }))} />
            </Field>
          </div>
          <div className="quick-actions">
            <button type="button" className="secondary-button" onClick={applyImportBulkUpdates}>Apply to Review Rows</button>
          </div>
          <div className="toggle-list">
            <label className="toggle-row">
              <span>Pin imported high-value items to Home Market Watch</span>
              <input type="checkbox" checked={importOptions.pinHighValue} onChange={(event) => setImportOptions((current) => ({ ...current, pinHighValue: event.target.checked }))} />
            </label>
            <label className="toggle-row">
              <span>Add imported matched items to Watchlist</span>
              <input type="checkbox" checked={importOptions.addToWatchlist} onChange={(event) => setImportOptions((current) => ({ ...current, addToWatchlist: event.target.checked }))} />
            </label>
            <label className="toggle-row">
              <span>Update market values after import if possible</span>
              <input type="checkbox" checked={importOptions.updateMarketValues} onChange={(event) => setImportOptions((current) => ({ ...current, updateMarketValues: event.target.checked }))} />
            </label>
            <label className="toggle-row">
              <span>Default duplicate action</span>
              <select value={importOptions.duplicateAction} onChange={(event) => setImportOptions((current) => ({ ...current, duplicateAction: event.target.value }))}>
                {IMPORT_DUPLICATE_ACTIONS.map((action) => <option key={action.value} value={action.value}>{action.label}</option>)}
              </select>
            </label>
          </div>
        </div>

        {importBatchMessage ? <p className="compact-subtitle">{importBatchMessage}</p> : null}
        {importLastBatchResult?.failures?.length ? (
          <div className="empty-state small-empty-state">
            <h3>Partial save issue</h3>
            {importLastBatchResult.failures.map((failure) => <p key={failure.rowId}>{failure.itemName}: {failure.error}</p>)}
          </div>
        ) : null}

        {importRows.length ? (
          <div className="inventory-list compact-inventory-list">
            {importRows.map((row) => {
              const rowDestinations = row.destination === "Both" ? ["Forge", "Vault"] : [row.destination || defaultImportDestination()];
              const duplicate = rowDestinations.map((destination) => findImportDuplicate(row, destination)).find(Boolean);
              return (
              <div className={`inventory-card compact-card ${row.importStatus === "skipped" ? "is-muted" : ""}`} key={row.importedItemId}>
                <div className="compact-card-header">
                  <div>
                    <h3>{row.itemName}</h3>
                    <p>{row.possibleMatchName ? `Match: ${row.possibleMatchName}` : "No catalog match yet"}</p>
                    <small>{row.confidenceLabel || importConfidenceLabel(row.confidenceScore)} confidence ({row.confidenceScore}%) | {row.needsReview ? "Needs Review" : "Good Match"} | {row.sourceType}</small>
                    <small>Original: {row.originalText}</small>
                    {duplicate ? <small className="danger-text">Duplicate possible: {duplicate.name}</small> : null}
                  </div>
                  <span className="status-badge">{row.importStatus}</span>
                </div>
                <div className="form import-review-grid">
                  <Field label="Item Name">
                    <input value={row.itemName} onChange={(event) => updateImportRow(row.importedItemId, { itemName: event.target.value, importStatus: "reviewed" })} />
                  </Field>
                  <Field label="Destination">
                    <select value={row.destination} onChange={(event) => updateImportRow(row.importedItemId, { destination: event.target.value, importStatus: "reviewed" })}>
                      {IMPORT_DESTINATION_OPTIONS.map((option) => <option key={option.value} value={option.value}>{option.label}</option>)}
                    </select>
                  </Field>
                  <Field label="Catalog Match">
                    <select value={row.matchedCatalogItemId || ""} onChange={(event) => selectImportRowCatalogMatch(row.importedItemId, event.target.value)}>
                      <option value="">No match / add manually</option>
                      {(row.alternateMatches || []).map((product) => <option key={product.id} value={product.id}>{catalogTitle(product)}</option>)}
                    </select>
                  </Field>
                  <Field label="Quantity">
                    <input type="number" min="1" value={row.quantity} onChange={(event) => updateImportRow(row.importedItemId, { quantity: event.target.value, importStatus: "reviewed" })} />
                  </Field>
                  <Field label="Purchaser">
                    <input value={row.purchaserName || ""} onChange={(event) => updateImportRow(row.importedItemId, { purchaserName: event.target.value, importStatus: "reviewed" })} />
                  </Field>
                  <Field label="Cost Paid">
                    <input type="number" step="0.01" value={row.costPaid} onChange={(event) => updateImportRow(row.importedItemId, { costPaid: event.target.value, importStatus: "reviewed" })} />
                  </Field>
                  <Field label="Market Value">
                    <input type="number" step="0.01" value={row.marketValue} onChange={(event) => updateImportRow(row.importedItemId, { marketValue: event.target.value, importStatus: "reviewed" })} />
                  </Field>
                  <Field label="Product Type">
                    <input value={row.productType} onChange={(event) => updateImportRow(row.importedItemId, { productType: event.target.value, importStatus: "reviewed" })} />
                  </Field>
                  <Field label="Set Name">
                    <input value={row.setName} onChange={(event) => updateImportRow(row.importedItemId, { setName: event.target.value, importStatus: "reviewed" })} />
                  </Field>
                  <Field label="Condition">
                    <select value={row.condition || "Unknown"} onChange={(event) => updateImportRow(row.importedItemId, { condition: event.target.value, importStatus: "reviewed" })}>
                      {IMPORT_CONDITION_OPTIONS.map((condition) => <option key={condition}>{condition}</option>)}
                    </select>
                  </Field>
                  <Field label="Variant">
                    <input value={row.variant || ""} onChange={(event) => updateImportRow(row.importedItemId, { variant: event.target.value, importStatus: "reviewed" })} />
                  </Field>
                  <Field label="Store/source">
                    <input value={row.store || row.location || ""} onChange={(event) => updateImportRow(row.importedItemId, { store: event.target.value, location: event.target.value, importStatus: "reviewed" })} />
                  </Field>
                  <Field label="Purchase date">
                    <input type="date" value={row.purchaseDate || ""} onChange={(event) => updateImportRow(row.importedItemId, { purchaseDate: event.target.value, importStatus: "reviewed" })} />
                  </Field>
                  <Field label="UPC/SKU">
                    <input value={row.upcSku || ""} onChange={(event) => updateImportRow(row.importedItemId, { upcSku: event.target.value, importStatus: "reviewed" })} />
                  </Field>
                  <Field label="Duplicate action">
                    <select value={row.duplicateAction || importOptions.duplicateAction} onChange={(event) => updateImportRow(row.importedItemId, { duplicateAction: event.target.value, importStatus: "reviewed" })}>
                      {IMPORT_DUPLICATE_ACTIONS.map((action) => <option key={action.value} value={action.value}>{action.label}</option>)}
                    </select>
                  </Field>
                  <Field label="Notes">
                    <input value={row.notes} onChange={(event) => updateImportRow(row.importedItemId, { notes: event.target.value, importStatus: "reviewed" })} />
                  </Field>
                </div>
                <div className="quick-actions">
                  <button type="button" onClick={() => updateImportRow(row.importedItemId, { importStatus: "reviewed", needsReview: false })}>Mark Reviewed</button>
                  <button type="button" className="secondary-button" onClick={() => updateImportRow(row.importedItemId, { importStatus: "skipped" })}>Skip</button>
                  <button type="button" className="secondary-button" onClick={() => removeImportRow(row.importedItemId)}>Remove</button>
                  <button type="button" className="secondary-button" onClick={() => createManualCatalogItemFromImport(row)}>Create Manual Catalog Item</button>
                </div>
              </div>
            );})}
          </div>
        ) : (
          <div className="empty-state">
            <h3>Start a batch</h3>
            <p>Upload CSV, paste a list, search catalog items, or add manual rows. The batch stays temporary until you confirm.</p>
          </div>
        )}

        <div className="quick-actions">
          <button type="button" disabled={!importRows.length} onClick={confirmInventoryImport}>Confirm Import</button>
          <button type="button" className="secondary-button" onClick={() => closeFlowModal()}>Cancel</button>
        </div>
      </section>
    );
  }

  function enableLocationTracking() {
    if (!navigator.geolocation) {
      showAppMessage("Location is not available in this browser.");
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        setLocationSettings((current) => ({
          ...current,
          mode: "device",
          trackingEnabled: true,
          manualLocation: `${position.coords.latitude.toFixed(4)}, ${position.coords.longitude.toFixed(4)}`,
          lastUpdated: new Date().toISOString(),
        }));
      },
      () => showAppMessage("Location permission was not granted.")
    );
  }

  function disableLocationTracking() {
    updateLocationSettings({ trackingEnabled: false, mode: "manual" });
  }

  function updateScoutAlertPreference(key, value) {
    const nextAlertSettings = { ...(scoutSnapshot.alertSettings || {}), [key]: value };
    setScoutSnapshot((current) => ({ ...current, alertSettings: nextAlertSettings }));
    setPhase2Data((current) => ({
      ...current,
      notificationPreferences: {
        ...(current.notificationPreferences || {}),
        [key]: {
          key,
          enabled: Boolean(value),
          channels: { inApp: true },
          filters: {},
          quietHours: {},
          updatedAt: new Date().toISOString(),
        },
      },
    }));
    void saveNotificationPreference(phase2Context(), {
      key,
      enabled: Boolean(value),
      channels: { inApp: true },
      filters: {},
    }).then((result) => {
      updatePhase2Status(result, "Alert preference saved locally.");
      setVaultToast(result.source === "supabase" ? "Scout alert preference synced." : "Scout alert preference saved locally.");
    });
    try {
      const saved = JSON.parse(localStorage.getItem(SCOUT_STORAGE_KEY) || "{}");
      localStorage.setItem(SCOUT_STORAGE_KEY, JSON.stringify({ ...saved, alertSettings: nextAlertSettings }));
    } catch (error) {
      console.warn("Unable to save Scout alert preference", error);
      setVaultToast("Could not save preference right now.");
    }
  }

  function loadScoutSnapshot() {
    const saved = sanitizeScoutLocalData(JSON.parse(localStorage.getItem(SCOUT_STORAGE_KEY) || "{}"));
    const restockIntel = saved.restockIntel?.length ? saved.restockIntel : [];
    setScoutSnapshot({
      stores: saved.stores || [],
      reports: saved.reports || [],
      tidepoolReports: saved.tidepoolReports || [],
      bestBuyAlerts: saved.bestBuyAlerts || [],
      restockIntel,
      restockPatterns: saved.restockPatterns || buildScoutRestockPatterns(restockIntel),
      manualRestockTraining: saved.manualRestockTraining || [],
      dropRadarPredictionCache: saved.dropRadarPredictionCache || [],
      dropRadarPredictions: saved.dropRadarPredictions || [],
      dropRadarSeedDisabled: Boolean(saved.dropRadarSeedDisabled),
      dropRadarLastResetAt: saved.dropRadarLastResetAt || "",
      dropRadarBackups: saved.dropRadarBackups || [],
      storeGuesses: saved.storeGuesses || saved.guesses || [],
      forecastWindows: saved.forecastWindows || [],
      intelImportReviews: saved.intelImportReviews || [],
      scoutProfile: saved.scoutProfile || {},
      alertSettings: saved.alertSettings || {},
    });
  }

  function scoutBackendSyncReady() {
    return Boolean(
      !BETA_LOCAL_MODE &&
      !guestPreviewActive &&
      signedInWithSupabase &&
      isSupabaseConfigured &&
      supabase &&
      protectedAppDataAccessReady()
    );
  }

  function isScoutBackendOptionalError(error) {
    const message = String(error?.message || error?.details || error || "").toLowerCase();
    return Boolean(
      /does not exist|schema cache|column|relation|table|permission denied|row-level security|rls/.test(message) ||
      error?.code === "42P01" ||
      error?.code === "42703" ||
      error?.code === "42501"
    );
  }

  function scoutBackendKey(value = "") {
    return String(value || "").toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
  }

  function scoutBackendStoreMergeKey(store = {}, index = 0) {
    const nameKey = [
      getScoutQuickRetailer(store),
      getScoutQuickStoreName(store),
      store.city,
      store.address,
    ].map(scoutBackendKey).join("|");
    if (nameKey.replace(/\|/g, "")) return `store:${nameKey}`;
    return `store-id:${getScoutQuickStoreId(store) || index}`;
  }

  function scoutBackendReportMergeKey(report = {}, index = 0) {
    const store = getScoutReportStore(report);
    const fingerprint = [
      report.storeId || report.store_id || store.id || store.storeId,
      report.storeName || report.store_name || store.name || store.nickname,
      report.productName || report.product_name || report.itemName || report.productType || report.product_type,
      report.observedAt || report.observed_at || report.reportedAt || report.reported_at || report.reportTime || report.report_time || report.createdAt || report.created_at,
      report.userId || report.user_id || report.reportedBy || report.reported_by,
    ].map(scoutBackendKey).join("|");
    if (fingerprint.replace(/\|/g, "")) return `report:${fingerprint}`;
    return `report-id:${getScoutReportId(report) || index}`;
  }

  function scoutBackendGuessMergeKey(guess = {}, index = 0) {
    return [
      guess.id || "",
      guess.storeId || guess.store_id || guess.storeName || guess.store_name,
      guess.guessedDay || guess.guessed_day,
      guess.guessedTimeWindow || guess.guessed_time_window,
      guess.userId || guess.user_id,
    ].map(scoutBackendKey).join("|") || `guess-${index}`;
  }

  function scoutBackendForecastMergeKey(forecast = {}, index = 0) {
    return [
      forecast.id || "",
      forecast.storeId || forecast.store_id || forecast.storeName || forecast.store_name,
      forecast.forecastDay || forecast.forecast_day || forecast.days?.[0],
      forecast.forecastTimeWindow || forecast.forecast_time_window || forecast.windowLabel,
    ].map(scoutBackendKey).join("|") || `forecast-${index}`;
  }

  function mergeScoutRows(currentRows = [], incomingRows = [], keyFn = (row, index) => row?.id || `row-${index}`) {
    const map = new Map();
    [...currentRows, ...incomingRows].filter(Boolean).forEach((row, index) => {
      const key = keyFn(row, index);
      const previous = map.get(key);
      map.set(key, previous ? { ...previous, ...row } : row);
    });
    return [...map.values()];
  }

  function mergeScoutStores(currentRows = [], incomingRows = []) {
    const map = new Map();
    [...currentRows, ...incomingRows].filter(Boolean).forEach((store, index) => {
      const key = scoutBackendStoreMergeKey(store, index);
      const previous = map.get(key);
      map.set(key, previous ? {
        ...previous,
        ...store,
        favorite: Boolean(previous.favorite || store.favorite),
        watchlisted: Boolean(previous.watchlisted || store.watchlisted),
        watchlist: Boolean(previous.watchlist || store.watchlist),
        priority: Boolean(previous.priority || store.priority),
      } : store);
    });
    return [...map.values()];
  }

  function mapSupabaseStore(row = {}, watchlist = {}) {
    const active = row.active !== false && row.is_active !== false;
    const reportable = active && row.sells_pokemon !== false && row.reportable !== false && row.is_reportable !== false;
    const watched = Boolean(watchlist.favorite || watchlist.watched);
    return {
      id: row.id || "",
      storeId: row.id || "",
      store_id: row.id || "",
      name: row.nickname || row.store_name || row.name || row.retailer_store_id || "Store location",
      storeName: row.store_name || row.name || row.nickname || "Store location",
      store_name: row.store_name || row.name || row.nickname || "Store location",
      nickname: row.nickname || row.store_name || row.name || "",
      retailer: row.retailer || row.chain || "",
      chain: row.chain || row.retailer || "",
      storeType: row.store_type || row.type || "",
      store_type: row.store_type || row.type || "",
      address: row.address || "",
      city: row.city || "",
      state: row.state || "",
      zip: row.zip || row.zip_code || "",
      zipCode: row.zip_code || row.zip || "",
      region: row.region || "",
      county: row.county || "",
      phone: row.phone || "",
      website: row.website || "",
      latitude: row.latitude,
      longitude: row.longitude,
      active,
      isActive: active,
      is_active: active,
      reportable,
      isReportable: reportable,
      is_reportable: reportable,
      pokemonStockLikelihood: row.pokemon_stock_likelihood || row.confidence || "unknown",
      pokemon_stock_likelihood: row.pokemon_stock_likelihood || row.confidence || "unknown",
      source: row.source || "supabase-store-directory",
      sourceType: "supabase_store_directory",
      source_type: "supabase_store_directory",
      sourceUrl: row.source_url || "",
      lastVerifiedAt: row.last_verified_at || "",
      notes: row.notes || "",
      favorite: watched,
      watchlisted: watched,
      watchlist: watched,
      priority: Boolean(watchlist.favorite),
      watchlistNotes: watchlist.notes || "",
      updatedAt: row.updated_at || row.created_at || watchlist.updated_at || "",
      createdAt: row.created_at || "",
    };
  }

  function mapSupabaseScoutReport(row = {}, stores = []) {
    const matchedStore = stores.find((store) => String(getScoutQuickStoreId(store)) === String(row.store_id)) || {};
    const observedAt = row.observed_at || row.report_time || row.reported_at || row.created_at || row.updated_at || "";
    const reportedAt = observedAt;
    const status = row.status || row.verification_status || "unverified";
    const statusText = scoutBackendKey(status);
    const rejected = /rejected|stale|duplicate|deleted|archived/.test(statusText);
    const confirmed = !rejected && /confirmed|verified/.test(statusText);
    const confidenceScore = Number(row.confidence_score ?? 0);
    const likely = !confirmed && !rejected && confidenceScore >= 60;
    const reportedDate = reportedAt ? new Date(reportedAt) : null;
    const reportDate = reportedDate && !Number.isNaN(reportedDate.getTime()) ? getLocalDateInputKey(reportedDate) : String(reportedAt || "").slice(0, 10);
    const reportTime = reportedDate && !Number.isNaN(reportedDate.getTime()) ? getLocalTimeKey(reportedDate) : String(reportedAt || "").slice(11, 16);
    const storeName = row.store_name || getScoutQuickStoreName(matchedStore) || "Store location";
    const retailer = getScoutQuickRetailer(matchedStore) || row.retailer || "";
    const sourceType = row.source_type || (confirmed ? "verified_user_report" : "user_report");
    const confidence = row.confidence || (confirmed ? "confirmed" : likely ? "likely" : "unconfirmed");
    const importedByAdmin = Boolean(row.imported_by_admin);
    const reportStatus = row.report_status || "";
    const historicalImport = sourceType === "historical_import" || importedByAdmin || Boolean(row.imported_batch);
    const historicalStockPositive = historicalImport && ["stock_seen", "vendor_seen", "leftover_stock"].includes(reportStatus);
    return {
      id: row.id || makeId("store-report"),
      reportId: row.id || "",
      userId: row.user_id || "",
      user_id: row.user_id || "",
      workspaceId: row.workspace_id || "",
      workspace_id: row.workspace_id || "",
      storeId: row.store_id || "",
      store_id: row.store_id || "",
      selectedStoreId: row.store_id || "",
      storeName,
      store_name: storeName,
      retailer,
      chain: retailer,
      city: matchedStore.city || "",
      region: matchedStore.region || "",
      address: matchedStore.address || "",
      productId: row.product_id || "",
      product_id: row.product_id || "",
      productName: row.product_name || "",
      product_name: row.product_name || "",
      productType: row.product_type || row.report_type || "",
      product_type: row.product_type || row.report_type || "",
      productSetName: row.set_name || "",
      setName: row.set_name || "",
      quantity: row.quantity_estimate || row.quantity_seen || "",
      quantityEstimate: row.quantity_estimate || row.quantity_seen || "",
      quantity_seen: row.quantity_seen,
      price: row.price_seen || "",
      price_seen: row.price_seen,
      photoUrl: row.photo_url || "",
      photo_url: row.photo_url || "",
      proofType: row.photo_url ? "stock_photo" : "manual",
      proofText: row.notes || "",
      notes: row.notes || "",
      note: row.notes || "",
      reportType: row.report_type || (confirmed ? "stock_on_shelf" : "other"),
      report_type: row.report_type || (confirmed ? "restock" : "other"),
      reportStatus,
      report_status: reportStatus,
      stockStatus: reportStatus || (confirmed ? "confirmed_restock" : row.report_type || "reported"),
      visibility: normalizeScoutReportVisibility(row.visibility || "public"),
      status,
      verificationStatus: status,
      verification_status: status,
      verified: confirmed,
      confidence,
      confidenceScore: confidenceScore || scoutConfidenceScore(confidence),
      confidence_score: confidenceScore || scoutConfidenceScore(confidence),
      sourceType,
      source_type: sourceType,
      sourceLabel: row.source_label || "",
      source_label: row.source_label || "",
      submittedByDisplay: row.submitted_by_display || "",
      submitted_by_display: row.submitted_by_display || "",
      importedBatch: row.imported_batch || "",
      imported_batch: row.imported_batch || "",
      importedByAdmin,
      imported_by_admin: importedByAdmin,
      scoutPointsAwarded: row.scout_points_awarded !== false,
      scout_points_awarded: row.scout_points_awarded !== false,
      importKey: row.import_key || "",
      import_key: row.import_key || "",
      sourceStatus: "supabase",
      shouldTrainPredictions: confirmed || historicalStockPositive,
      trainingEligible: confirmed || historicalStockPositive,
      observedAt,
      observed_at: observedAt,
      reportedAt,
      reported_at: reportedAt,
      submittedAt: row.created_at || reportedAt,
      submitted_at: row.created_at || reportedAt,
      reportDate,
      reportTime,
      createdAt: row.created_at || reportedAt,
      created_at: row.created_at || reportedAt,
      updatedAt: row.updated_at || reportedAt,
      updated_at: row.updated_at || reportedAt,
    };
  }

  function mapSupabaseScoutGuess(row = {}, stores = []) {
    const matchedStore = stores.find((store) => String(getScoutQuickStoreId(store)) === String(row.store_id)) || {};
    return {
      id: row.id || makeId("store-guess"),
      recordType: "guess",
      recordKind: "community_guess",
      eventType: "Community Guess",
      shouldTrainPredictions: false,
      trainingEligible: false,
      userId: row.user_id || "",
      user_id: row.user_id || "",
      workspaceId: row.workspace_id || "",
      workspace_id: row.workspace_id || "",
      storeId: row.store_id || "",
      store_id: row.store_id || "",
      storeName: row.store_name || getScoutQuickStoreName(matchedStore) || "Store location",
      store_name: row.store_name || getScoutQuickStoreName(matchedStore) || "Store location",
      retailer: getScoutQuickRetailer(matchedStore) || "",
      city: matchedStore.city || "",
      guessedDay: row.guessed_day || "Unknown",
      guessed_day: row.guessed_day || "Unknown",
      guessedTimeWindow: row.guessed_time_window || "",
      guessed_time_window: row.guessed_time_window || "",
      restockPatternNotes: row.restock_pattern_notes || "User pattern note; not confirmed stock.",
      restock_pattern_notes: row.restock_pattern_notes || "User pattern note; not confirmed stock.",
      productType: row.product_type || "",
      product_type: row.product_type || "",
      confidenceSelfRating: Number(row.confidence_self_rating || 0),
      confidence_self_rating: Number(row.confidence_self_rating || 0),
      confidence: "guess",
      confidenceLabel: "Community Guess",
      status: row.status || "pending",
      verificationStatus: row.status || "pending",
      moderationStatus: row.status || "pending",
      sourceType: "community_guess",
      source_type: "community_guess",
      sourceStatus: "supabase",
      visibility: normalizeScoutGuessVisibility(row.visibility || "private"),
      createdAt: row.created_at || row.updated_at || "",
      created_at: row.created_at || row.updated_at || "",
      updatedAt: row.updated_at || row.created_at || "",
      updated_at: row.updated_at || row.created_at || "",
    };
  }

  function mapSupabaseForecastWindow(row = {}, stores = []) {
    const matchedStore = stores.find((store) => String(getScoutQuickStoreId(store)) === String(row.store_id)) || {};
    const confidenceScore = Number(row.confidence_score || 0);
    const confidenceKey = String(row.confidence_label || "low").toLowerCase();
    const supportingReportCount = Number(row.supporting_report_count || 0);
    const supportingGuessCount = Number(row.supporting_guess_count || 0);
    const needsMoreData = supportingReportCount < 2;
    return {
      id: row.id || makeId("forecast-window"),
      recordKind: "predicted_window",
      eventType: "Predicted Drop Window",
      storeId: row.store_id || "",
      store_id: row.store_id || "",
      storeName: row.store_name || getScoutQuickStoreName(matchedStore) || "Store location",
      store_name: row.store_name || getScoutQuickStoreName(matchedStore) || "Store location",
      retailer: getScoutQuickRetailer(matchedStore) || "",
      city: matchedStore.city || "",
      forecastDay: row.forecast_day || "",
      forecast_day: row.forecast_day || "",
      forecastTimeWindow: row.forecast_time_window || "",
      forecast_time_window: row.forecast_time_window || "",
      confidenceScore,
      confidence_score: confidenceScore,
      confidence: needsMoreData ? "needs-data" : confidenceKey,
      confidenceKey: needsMoreData ? "needs-data" : confidenceKey,
      confidenceLabel: needsMoreData ? "Needs more data" : confidenceKey === "high" ? "High" : confidenceKey === "medium" ? "Medium" : "Low",
      sourceType: "prediction_cache",
      source_type: "prediction_cache",
      sourceLabel: "Saved Drop Radar prediction cache",
      badges: ["Predicted", needsMoreData ? "Needs Data" : "Cached"],
      days: [row.forecast_day].filter(Boolean),
      groupLabel: row.forecast_day || "Needs more data",
      windowLabel: row.forecast_time_window || "Unknown time",
      reason: row.basis_summary || (needsMoreData ? "Needs more confirmed restocks before predictions are reliable." : "Based on saved forecast history."),
      basisSummary: row.basis_summary || "",
      lastConfirmedReportLabel: row.last_confirmed_report_at ? scoutReportDateTimeLabel({ observedAt: row.last_confirmed_report_at }) : "",
      supportingReportCount,
      supportingGuessCount,
      dataNeededMessage: needsMoreData ? `Low confidence: needs ${2 - supportingReportCount} more confirmed restock${2 - supportingReportCount === 1 ? "" : "s"} before predictions are reliable.` : "",
      sortRank: needsMoreData ? 5 : 1,
      dayDistance: row.forecast_day ? scoutForecastDayDistance(row.forecast_day) : 99,
      createdAt: row.created_at || "",
      updatedAt: row.updated_at || "",
    };
  }

  async function loadScoutBackendData(options = {}) {
    if (!scoutBackendSyncReady()) return false;
    if (!options.force && (scoutBackendSync.loading || scoutBackendSync.loaded)) return false;

    setScoutBackendSync((current) => ({ ...current, loading: true, error: "" }));
    try {
      const watchlistByStoreId = new Map();
      let watchlistRows = [];
      const watchlistResult = await supabase
        .from("store_user_watchlist")
        .select("store_id,favorite,watched,notes,updated_at")
        .eq("user_id", user.id)
        .limit(500);
      if (watchlistResult.error && !isScoutBackendOptionalError(watchlistResult.error)) throw watchlistResult.error;
      watchlistRows = watchlistResult.error ? [] : watchlistResult.data || [];
      watchlistRows.forEach((row) => watchlistByStoreId.set(String(row.store_id), row));

      const baseStoreSelect = "id,name,chain,nickname,address,city,state,zip,region,county,phone,website,sells_pokemon,store_type,notes,created_at,updated_at";
      const wideStoreSelect = `${baseStoreSelect},latitude,longitude,retailer,store_name,zip_code,store_number,retailer_store_id,active,pokemon_stock_likelihood,source,source_url,last_verified_at,confidence`;
      let storesQuery = supabase.from("stores").select(wideStoreSelect).order("updated_at", { ascending: false, nullsFirst: false }).limit(500);
      if (!adminEditModeActive) storesQuery = storesQuery.eq("active", true);
      let storesResult = await storesQuery;
      if (storesResult.error && isScoutBackendOptionalError(storesResult.error)) {
        storesResult = await supabase.from("stores").select(baseStoreSelect).order("updated_at", { ascending: false, nullsFirst: false }).limit(500);
      }
      if (storesResult.error && isExpectedShorelineAccessDenial(storesResult.error) && !protectedAppDataAccessReady()) return false;
      if (storesResult.error && !isScoutBackendOptionalError(storesResult.error)) throw storesResult.error;
      const cloudStores = (storesResult.error ? [] : storesResult.data || [])
        .map((row) => mapSupabaseStore(row, watchlistByStoreId.get(String(row.id)) || {}))
        .filter((store) => adminEditModeActive || store.active !== false);

      const reportSelect = "id,store_id,user_id,product_id,report_type,quantity_seen,price_seen,photo_url,notes,observed_at,reported_at,verification_status,workspace_id,store_name,product_name,product_type,set_name,quantity_estimate,report_time,visibility,status,confidence_score,source_type,source_label,submitted_by_display,confidence,imported_batch,imported_by_admin,scout_points_awarded,import_key,report_status,created_at,updated_at";
      const reportFallbackSelect = "id,store_id,user_id,product_id,report_type,quantity_seen,price_seen,photo_url,notes,reported_at,verification_status";
      let reportsResult = await supabase
        .from("store_reports")
        .select(reportSelect)
        .order("observed_at", { ascending: false, nullsFirst: false })
        .limit(200);
      if (reportsResult.error && isScoutBackendOptionalError(reportsResult.error)) {
        reportsResult = await supabase.from("store_reports").select(reportFallbackSelect).order("reported_at", { ascending: false, nullsFirst: false }).limit(200);
      }
      if (reportsResult.error && isExpectedShorelineAccessDenial(reportsResult.error) && !protectedAppDataAccessReady()) return false;
      if (reportsResult.error && !isScoutBackendOptionalError(reportsResult.error)) throw reportsResult.error;
      const cloudReports = (reportsResult.error ? [] : reportsResult.data || []).map((row) => mapSupabaseScoutReport(row, cloudStores));

      let guessesResult = await supabase
        .from("store_guesses")
        .select("id,user_id,workspace_id,store_id,store_name,guessed_day,guessed_time_window,restock_pattern_notes,product_type,confidence_self_rating,visibility,created_at,updated_at")
        .order("updated_at", { ascending: false, nullsFirst: false })
        .limit(150);
      if (guessesResult.error && isExpectedShorelineAccessDenial(guessesResult.error) && !protectedAppDataAccessReady()) guessesResult = { data: [], error: null };
      if (guessesResult.error && !isScoutBackendOptionalError(guessesResult.error)) throw guessesResult.error;
      const cloudGuesses = (guessesResult.error ? [] : guessesResult.data || []).map((row) => mapSupabaseScoutGuess(row, cloudStores));

      let forecastsResult = await supabase
        .from("forecast_windows")
        .select("id,store_id,store_name,forecast_day,forecast_time_window,confidence_score,confidence_label,basis_summary,last_confirmed_report_at,supporting_report_count,supporting_guess_count,created_at,updated_at")
        .order("updated_at", { ascending: false, nullsFirst: false })
        .limit(150);
      if (forecastsResult.error && !isScoutBackendOptionalError(forecastsResult.error)) throw forecastsResult.error;
      const cloudForecasts = (forecastsResult.error ? [] : forecastsResult.data || []).map((row) => mapSupabaseForecastWindow(row, cloudStores));

      setScoutSnapshot((current) => ({
        ...current,
        stores: mergeScoutStores(current.stores || [], cloudStores),
        reports: mergeScoutRows(current.reports || [], cloudReports, scoutBackendReportMergeKey),
        storeGuesses: mergeScoutRows(current.storeGuesses || [], cloudGuesses, scoutBackendGuessMergeKey),
        forecastWindows: mergeScoutRows(current.forecastWindows || [], cloudForecasts, scoutBackendForecastMergeKey),
      }));
      setScoutBackendSync({
        loaded: true,
        loading: false,
        error: "",
        loadedAt: new Date().toISOString(),
      });
      return true;
    } catch (error) {
      logAppError("scout_backend_load", error, { userId: user?.id }, "normal");
      setScoutBackendSync({
        loaded: false,
        loading: false,
        error: "Scout and Drop Radar cloud data is unavailable right now. Local/manual fallback remains available.",
        loadedAt: "",
      });
      return false;
    }
  }

  function scoutBackendNumberOrNull(value) {
    if (value === "" || value === null || value === undefined) return null;
    const number = Number(value);
    return Number.isFinite(number) ? number : null;
  }

  function scoutReportTimeForBackend(report = {}) {
    const raw = report.observedAt || report.observed_at || report.report_time || report.reportedAt || report.reported_at || "";
    if (raw) return raw;
    const date = report.reportDate || report.report_date || getLocalDateInputKey();
    const time = report.reportTime || report.report_time || getLocalTimeKey();
    return `${date}T${time || "00:00"}:00.000Z`;
  }

  async function persistScoutReportToSupabase(report = {}) {
    if (!scoutBackendSyncReady()) {
      return { ok: false, skipped: true, reason: "backend_unavailable" };
    }
    const rawStoreId = report.storeId || report.store_id || report.selectedStoreId || report.selected_store_id || "";
    const storeId = uuidOrNull(rawStoreId);
    const observedAt = scoutReportTimeForBackend(report);
    const confidenceScore = Number(report.confidenceScore || report.confidence_score || scoutConfidenceScore(report.confidence || ""));
    const confirmed = Boolean(report.verified || /confirmed|verified/i.test(`${report.status || ""} ${report.verificationStatus || report.verification_status || ""}`));
    const verificationStatus = report.verification_status || report.verificationStatus || (confirmed ? "verified" : report.needsReview || report.needs_review ? "needs_review" : "new_report");
    const publicStatus = report.status || (confirmed ? "confirmed" : report.hidden ? "hidden" : "active");
    const payload = {
      store_id: storeId,
      user_id: user.id,
      product_id: uuidOrNull(report.productId || report.product_id || report.catalogProductId || report.catalog_product_id),
      report_type: report.report_type || report.reportType || "restock",
      quantity_seen: scoutBackendNumberOrNull(report.quantity || report.quantitySeen || report.quantity_seen),
      price_seen: scoutBackendNumberOrNull(report.price || report.priceSeen || report.price_seen),
      photo_url: report.photoUrl || report.photo_url || "",
      notes: report.notes || report.note || report.proofText || "",
      observed_at: observedAt,
      reported_at: observedAt,
      verification_status: verificationStatus,
      workspace_id: uuidOrNull(report.workspaceId || report.workspace_id || activeWorkspaceId),
      store_name: report.storeName || report.store_name || "",
      product_name: report.productName || report.product_name || report.itemName || "",
      product_type: report.productType || report.product_type || report.productCategory || "",
      set_name: report.setName || report.set_name || report.productSetName || "",
      quantity_estimate: String(report.quantity || report.quantityEstimate || report.quantity_estimate || ""),
      report_time: observedAt,
      visibility: normalizeScoutReportVisibility(report.visibility || "public"),
      status: publicStatus,
      confidence_score: confidenceScore,
      source_type: report.sourceType || report.source_type || (confirmed ? "verified_user_report" : "user_report"),
      source_label: report.sourceLabel || report.source_label || report.confidenceLabel || report.confidence_label || "",
      submitted_by_display: report.submittedByDisplay || report.submitted_by_display || "",
      confidence: report.confidence || (confirmed ? "confirmed" : "new-report"),
      imported_batch: report.importedBatch || report.imported_batch || null,
      imported_by_admin: Boolean(report.importedByAdmin || report.imported_by_admin),
      scout_points_awarded: report.scoutPointsAwarded ?? report.scout_points_awarded ?? true,
      import_key: report.importKey || report.import_key || null,
      report_status: report.reportStatus || report.report_status || null,
    };
    let result = await supabase.from("store_reports").insert(payload).select("id,store_id,user_id,product_id,report_type,quantity_seen,price_seen,photo_url,notes,observed_at,reported_at,verification_status,workspace_id,store_name,product_name,product_type,set_name,quantity_estimate,report_time,visibility,status,confidence_score,source_type,source_label,submitted_by_display,confidence,imported_batch,imported_by_admin,scout_points_awarded,import_key,report_status,created_at,updated_at").single();
    if (result.error && isScoutBackendOptionalError(result.error)) {
      const fallbackPayload = {
        store_id: storeId,
        user_id: user.id,
        product_id: payload.product_id,
        report_type: payload.report_type,
        quantity_seen: payload.quantity_seen,
        price_seen: payload.price_seen,
        photo_url: payload.photo_url,
        notes: payload.notes,
        reported_at: observedAt,
        verification_status: payload.verification_status,
      };
      result = await supabase.from("store_reports").insert(fallbackPayload).select("id,store_id,user_id,product_id,report_type,quantity_seen,price_seen,photo_url,notes,reported_at,verification_status").single();
    }
    if (result.error) {
      logAppError("scout_report_backend_save", result.error, { storeId: rawStoreId || storeId, storeName: payload.store_name }, "normal");
      return { ok: false, error: result.error, reason: "backend_save_failed" };
    }
    return {
      ok: true,
      report: mapSupabaseScoutReport(result.data, getScoutQuickStores({ admin: adminEditModeActive })),
      source: "supabase",
      usedDirectoryStoreFallback: Boolean(rawStoreId && !storeId),
    };
  }

  async function persistScoutGuessToSupabase(guess = {}) {
    if (!scoutBackendSyncReady()) return null;
    const payload = {
      user_id: user.id,
      workspace_id: uuidOrNull(guess.workspaceId || guess.workspace_id || activeWorkspaceId),
      store_id: uuidOrNull(guess.storeId || guess.store_id || guess.selectedStoreId || guess.selected_store_id),
      store_name: guess.storeName || guess.store_name || "Store location",
      guessed_day: guess.guessedDay || guess.guessed_day || "Unknown",
      guessed_time_window: guess.guessedTimeWindow || guess.guessed_time_window || "",
      restock_pattern_notes: guess.restockPatternNotes || guess.restock_pattern_notes || guess.notes || "",
      product_type: guess.productType || guess.product_type || "",
      confidence_self_rating: scoutBackendNumberOrNull(guess.confidenceSelfRating || guess.confidence_self_rating),
      visibility: normalizeScoutGuessVisibility(guess.visibility || "private"),
    };
    const { data, error } = await supabase
      .from("store_guesses")
      .insert(payload)
      .select("id,user_id,workspace_id,store_id,store_name,guessed_day,guessed_time_window,restock_pattern_notes,product_type,confidence_self_rating,visibility,created_at,updated_at")
      .single();
    if (error) {
      logAppError("scout_guess_backend_save", error, { storeName: payload.store_name }, "normal");
      return null;
    }
    return mapSupabaseScoutGuess(data, getScoutQuickStores({ admin: adminEditModeActive }));
  }

  async function persistScoutStoreWatchToSupabase(store = {}, favorite = true) {
    if (!scoutBackendSyncReady()) return false;
    const storeId = uuidOrNull(getScoutQuickStoreId(store));
    if (!storeId) return false;
    const { error } = await supabase.from("store_user_watchlist").upsert(
      {
        user_id: user.id,
        store_id: storeId,
        favorite: Boolean(favorite),
        watched: Boolean(favorite),
        updated_at: new Date().toISOString(),
      },
      { onConflict: "user_id,store_id" }
    );
    if (error) {
      logAppError("scout_store_watch_save", error, { storeId }, "normal");
      return false;
    }
    return true;
  }

  function saveTidepoolCommunity(next) {
    const payload = {
      posts: next.posts ?? tidepoolPosts,
      comments: next.comments ?? tidepoolComments,
      reactions: next.reactions ?? tidepoolReactions,
    };
    localStorage.setItem(TIDEPOOL_STORAGE_KEY, JSON.stringify(payload));
    setTidepoolPosts(payload.posts);
    setTidepoolComments(payload.comments);
    setTidepoolReactions(payload.reactions);
  }

  function submitTidepoolPost(event) {
    event?.preventDefault?.();
    if (blockGuestSave()) return false;
    if (!canUserCreateTidepoolPost({
      betaAccessAllowed: betaAccessAllowed(),
      guestPreviewActive,
      activeTabLocked,
    })) {
      setVaultToast("Tidepool posting is available after beta access is approved.");
      return false;
    }
    const identity = publicIdentityForProfile(currentUserProfile);
    const validationError = validateTidepoolPostDraft(tidepoolPostForm, {
      isOfficialAdmin: identity.isOfficialAdminIdentity,
      allowSafetyReview: true,
    });
    if (validationError) {
      setVaultToast(validationError);
      return false;
    }
    const post = makeTidepoolPost({
      ...tidepoolPostForm,
      displayName: publicProfileLabel(),
      username: currentPublicUsername(),
      publicUsername: currentPublicUsername(),
      userId: currentUserProfile.userId || "local-beta",
      status: "Pending Review",
      moderationStatus: "Pending Review",
      visibility: "author_admin",
      verificationStatus: "pending_review",
      sourceType: "user",
    });
    saveTidepoolCommunity({ posts: [post, ...tidepoolPosts] });
    setTidepoolPostForm(BLANK_TIDEPOOL_POST_FORM);
    setTidepoolFilter("Feed");
    if (activeFlowModal?.type === "tidepoolCreatePost") {
      closeFlowModal({ force: true, reset: false });
    }
    setVaultToast("Post saved for admin review before it appears publicly.");
    return true;
  }

  function updateTidepoolPost(postId, updates) {
    saveTidepoolCommunity({
      posts: tidepoolPosts.map((post) =>
        post.postId === postId ? buildTidepoolPost({ ...post, ...updates, updatedAt: new Date().toISOString() }) : post
      ),
    });
  }

  function openTidepoolFlagFlow(post = {}) {
    setTidepoolFlagTarget(post);
    setTidepoolFlagReason(TIDEPOOL_FLAG_REASONS[0]);
    setTidepoolFlagDetails("");
  }

  function submitTidepoolFlag() {
    if (!tidepoolFlagTarget?.postId) return;
    const updated = flagTidepoolPost(tidepoolFlagTarget, {
      reason: tidepoolFlagReason,
      details: tidepoolFlagDetails,
      userId: currentUserProfile.userId || "local-beta",
    });
    updateTidepoolPost(tidepoolFlagTarget.postId, updated);
    setTidepoolFlagTarget(null);
    setTidepoolFlagDetails("");
    setVaultToast("Thanks — admins will review this.");
  }

  function hideOwnTidepoolPost(post = {}) {
    const currentUserId = currentUserProfile.userId || "local-beta";
    if (post.userId !== currentUserId && !adminToolsVisible) {
      setVaultToast("Only the author or an admin can hide this post.");
      return;
    }
    updateTidepoolPost(post.postId, moderateTidepoolPost(post, "Archived", {
      reviewer: currentUserId,
      reason: "Hidden by author or admin.",
    }));
    setVaultToast("Post hidden from the public feed.");
  }

  function requestAdminActionConfirmation({
    title,
    message,
    details = "",
    targetName = "",
    confirmLabel = "Confirm",
    danger = false,
    onConfirm,
    successMessage = "",
    errorMessage = "",
  }) {
    setAdminConfirmAction({
      id: makeId("admin-confirm"),
      title,
      message,
      details,
      targetName,
      confirmLabel,
      danger,
      onConfirm,
      successMessage,
      errorMessage,
      loading: false,
      error: "",
      success: "",
    });
  }

  async function runAdminConfirmedAction() {
    const action = adminConfirmAction;
    if (!action || action.loading) return;
    setAdminConfirmAction((current) =>
      current?.id === action.id ? { ...current, loading: true, error: "", success: "" } : current
    );
    try {
      await action.onConfirm?.();
      const success = action.successMessage || "Admin action complete.";
      setAdminConfirmAction((current) =>
        current?.id === action.id ? { ...current, loading: false, success } : current
      );
      setVaultToast(success);
      window.setTimeout(() => {
        setAdminConfirmAction((current) => (current?.id === action.id ? null : current));
      }, 650);
    } catch (error) {
      const message = error?.message || action.errorMessage || "Admin action failed. Try again.";
      setAdminConfirmAction((current) =>
        current?.id === action.id ? { ...current, loading: false, error: message } : current
      );
      setVaultToast(message, { type: "error" });
    }
  }

  function runTidepoolAdminPostAction(post, label, updates, options = {}) {
    if (!adminEditModeActive) {
      setVaultToast("Turn on Admin Edit Mode to moderate Tidepool posts.");
      return;
    }
    const execute = () => {
      const requestedStatus = updates.status || updates.moderationStatus || updates.verificationStatus || post.status;
      const moderated = moderateTidepoolPost({ ...post, ...updates }, requestedStatus, {
        reviewer: currentPublicUsername(),
        reason: updates.moderationReason || updates.reason || "",
      });
      updateTidepoolPost(post.postId, moderated);
      setVaultToast(`${label} applied to Tidepool post.`);
    };
    if (options.confirm) {
      requestAdminActionConfirmation({
        title: `${label} Tidepool post?`,
        message: options.message || "This changes the post moderation state for beta users.",
        targetName: post.title || post.topic || post.body?.slice?.(0, 64) || "Tidepool post",
        confirmLabel: label,
        danger: Boolean(options.danger),
        onConfirm: execute,
      });
      return;
    }
    execute();
  }

  function addTidepoolReaction(postId, reactionType) {
    const reaction = {
      reactionId: makeId("reaction"),
      postId,
      commentId: "",
      userId: currentUserProfile.userId || "local-beta",
      reactionType,
      createdAt: new Date().toISOString(),
    };
    saveTidepoolCommunity({
      reactions: [reaction, ...tidepoolReactions],
      posts: tidepoolPosts.map((post) =>
        post.postId === postId ? { ...post, reactionCount: Number(post.reactionCount || 0) + 1 } : post
      ),
    });
  }

  function addTidepoolComment(postId, parentCommentId = "") {
    const targetPost = tidepoolPosts.find((post) => post.postId === postId);
    const targetStatus = normalizeTidepoolPostStatus(targetPost || {});
    if (targetPost?.commentsLocked || ["Rejected", "Archived"].includes(targetStatus)) {
      setVaultToast("Comments are closed for this post.");
      return;
    }
    const key = parentCommentId || postId;
    const body = String(tidepoolCommentDrafts[key] || "").trim();
    const identity = publicIdentityForProfile(currentUserProfile);
    const validationError = validateTidepoolCommentDraft(body, {
      isOfficialAdmin: identity.isOfficialAdminIdentity,
    });
    if (validationError) {
      setVaultToast(validationError);
      return;
    }
    const comment = {
      commentId: makeId("comment"),
      postId,
      userId: currentUserProfile.userId || "local-beta",
      displayName: publicProfileLabel(),
      username: currentPublicUsername(),
      publicUsername: currentPublicUsername(),
      body,
      parentCommentId,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      status: "active",
    };
    saveTidepoolCommunity({
      comments: [...tidepoolComments, comment],
      posts: tidepoolPosts.map((post) =>
        post.postId === postId ? { ...post, commentCount: Number(post.commentCount || 0) + 1 } : post
      ),
    });
    setTidepoolCommentDrafts((current) => ({ ...current, [key]: "" }));
  }

