  async function sendPasswordResetEmail(email) {
    if (!isSupabaseConfigured || !supabase) {
      throw new Error("Supabase auth is not configured yet.");
    }
    const { error } = await supabase.auth.resetPasswordForEmail(String(email || "").trim(), {
      redirectTo: getPasswordResetRedirectTo(),
    });
    if (error) throw error;
  }

  async function handlePasswordResetRequest(event, emailOverride = "") {
    event?.preventDefault?.();
    const email = String(emailOverride || passwordResetEmail || authEmail || user?.email || currentUserProfile?.email || "").trim();
    setPasswordResetError("");
    setPasswordResetMessage("");
    if (!email) {
      setPasswordResetError("Enter your account email.");
      return;
    }
    setPasswordResetLoading(true);
    try {
      await sendPasswordResetEmail(email);
      setPasswordResetMessage("If an account exists for that email, a reset link has been sent.");
      setVaultToast("If an account exists for that email, a reset link has been sent.");
    } catch (error) {
      setPasswordResetError(error.message || "Could not send a reset link. Try again.");
    } finally {
      setPasswordResetLoading(false);
    }
  }

  async function handleSignedInPasswordReset() {
    const email = String(user?.email || currentUserProfile?.email || "").trim();
    if (!email) {
      setPasswordResetError("Your signed-in account does not have an email address available.");
      setVaultToast("Your signed-in account does not have an email address available.");
      return;
    }
    setPasswordResetEmail(email);
    await handlePasswordResetRequest(null, email);
  }

  async function handleUpdatePassword(event) {
    event.preventDefault();
    const password = String(newPasswordForm.password || "");
    const confirm = String(newPasswordForm.confirm || "");
    setNewPasswordError("");
    setNewPasswordMessage("");
    if (!password) {
      setNewPasswordError("Enter a new password.");
      return;
    }
    if (password.length < 8) {
      setNewPasswordError("Password must be at least 8 characters.");
      return;
    }
    if (password !== confirm) {
      setNewPasswordError("Passwords do not match.");
      return;
    }
    if (!isSupabaseConfigured || !supabase) {
      setNewPasswordError("Supabase auth is not configured yet.");
      return;
    }
    setNewPasswordLoading(true);
    try {
      const { error } = await supabase.auth.updateUser({ password });
      if (error) {
        setNewPasswordError(error.message || "Could not update password.");
        return;
      }
      setNewPasswordForm({ password: "", confirm: "" });
      const message = "Password updated. Please log in with your new password.";
      setNewPasswordMessage(message);
      setVaultToast(message);
      await goToSignInAfterPasswordReset(message);
    } finally {
      setNewPasswordLoading(false);
    }
  }

  async function goToSignInAfterPasswordReset(successMessage = "") {
    const nextAuthMessage = typeof successMessage === "string" ? successMessage : "";
    setAuthMode("login");
    setAuthPassword("");
    setNewPasswordForm({ password: "", confirm: "" });
    setNewPasswordError("");
    setNewPasswordMessage("");
    setAuthError("");
    setAuthMessage(nextAuthMessage);
    if (isSupabaseConfigured && supabase) {
      await supabase.auth.signOut();
    }
    if (BETA_LOCAL_MODE) {
      setUser({ id: "local-beta", email: "local beta mode" });
      setActiveTab("menu");
      setMenuOpen(true);
      setMenuSectionsOpen((current) => ({ ...current, account: true }));
    } else {
      setUser(null);
      setActiveTab("dashboard");
    }
  }

  async function checkUser() {
    if (!isSupabaseConfigured || !supabase) return;
    const { data, error } = await supabase.auth.getUser();
    if (!error) setUser(data.user);
  }

  async function handleAuth(event) {
    event.preventDefault();
    if (!isSupabaseConfigured || !supabase) {
      const message = "Supabase login is not configured yet. Private beta mode is still available.";
      setAuthError(message);
      setVaultToast(message);
      return;
    }
    const email = String(authEmail || "").trim();
    const password = String(authPassword || "");
    setAuthError("");
    setAuthMessage("");
    if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      setAuthError("Enter a valid email address.");
      return;
    }
    if (!password) {
      setAuthError("Enter your password.");
      return;
    }
    if (authMode === "signup" && password.length < 6) {
      setAuthError("Password must be at least 6 characters.");
      return;
    }
    const signupFirstName = normalizePersonName(authFirstName);
    const signupLastName = normalizePersonName(authLastName);
    const signupFullName = [signupFirstName, signupLastName].filter(Boolean).join(" ");
    const signupPublicUsername = normalizePublicUsername(authPublicUsername);
    if (authMode === "signup") {
      const nameError = validateSignupFullName(signupFirstName, signupLastName);
      if (nameError) {
        setAuthError(nameError);
        return;
      }
      const usernameError = validatePublicUsername(
        signupPublicUsername,
        { firstName: signupFirstName, first_name: signupFirstName, fullName: signupFullName, full_name: signupFullName, displayName: signupFullName, display_name: signupFullName, email },
        takenPublicUsernames("")
      );
      if (usernameError) {
        setAuthError(usernameError);
        return;
      }
      if (!authTermsAccepted) {
        setAuthError("You must agree to the Terms of Use and Privacy Policy before creating an account.");
        return;
      }
    }
    const consentTimestamp = new Date().toISOString();
    setAuthLoading(true);
    try {
      if (authMode === "signup") {
        const { data, error } = await supabase.auth.signUp({
          email,
          password,
          options: {
            emailRedirectTo: getAuthEmailRedirectTo(),
            data: {
              first_name: signupFirstName,
              last_name: signupLastName,
              full_name: signupFullName,
              display_name: signupFullName,
              username: signupPublicUsername,
              public_username: signupPublicUsername,
              publicUsername: signupPublicUsername,
              terms_accepted_at: consentTimestamp,
              privacy_accepted_at: consentTimestamp,
              beta_acknowledged_at: authBetaAcknowledged ? consentTimestamp : null,
              consent_text: {
                terms: SIGNUP_TERMS_TEXT,
                beta: authBetaAcknowledged ? SIGNUP_BETA_ACK_TEXT : "",
              },
            },
          },
        });
        if (error) {
          const message = normalizeAuthErrorMessage(error.message);
          setAuthError(message);
          setVaultToast(message);
          return;
        }
        if (!data.session) {
          const message = "Check your email to confirm your account. After confirming, return here to log in.";
          setAuthMessage(message);
          setVaultToast(message);
          setAuthMode("login");
          setAuthPassword("");
          return;
        }
        if (data.user?.id) {
          const { error: profileError } = await supabase.from("profiles").upsert(
            {
              id: data.user.id,
              email,
              first_name: signupFirstName,
              last_name: signupLastName,
              full_name: signupFullName,
              display_name: signupFullName,
              terms_accepted_at: consentTimestamp,
              privacy_accepted_at: consentTimestamp,
              beta_acknowledged_at: authBetaAcknowledged ? consentTimestamp : null,
              consent_text: {
                terms: SIGNUP_TERMS_TEXT,
                beta: authBetaAcknowledged ? SIGNUP_BETA_ACK_TEXT : "",
              },
              beta_status: "not_requested",
              beta_access_status: "not_requested",
              little_sparks_status: "not_applied",
              app_access: false,
              updated_at: new Date().toISOString(),
            },
            { onConflict: "id" }
          );
          if (profileError) {
            console.warn("Unable to sync signup profile names", profileError);
          }
        }
        const { data: currentUserData, error: currentUserError } = await supabase.auth.getUser();
        setUser(currentUserError ? data.user : currentUserData.user);
      } else {
        const { data, error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) {
          const message = normalizeAuthErrorMessage(error.message);
          setAuthError(message);
          setVaultToast(message);
          return;
        }
        const { data: currentUserData, error: currentUserError } = await supabase.auth.getUser();
        setUser(currentUserError ? data.user : currentUserData.user);
      }
      setAuthPassword("");
      if (authMode === "signup") {
        setAuthFirstName("");
        setAuthLastName("");
        setAuthPublicUsername("");
        setAuthTermsAccepted(false);
        setAuthBetaAcknowledged(false);
      }
      setAuthMessage(authMode === "signup" ? "Account created. Request beta access from the welcome screen." : "Signed in.");
      setVaultToast(authMode === "signup" ? "Account created. Request beta access from the welcome screen." : "Signed in.");
    } catch (error) {
      const message = normalizeAuthErrorMessage(error.message);
      setAuthError(message);
      setVaultToast(message);
    } finally {
      setAuthLoading(false);
    }
  }

  async function signOut() {
    if (isSupabaseConfigured && supabase && user?.id !== "local-beta") {
      await supabase.auth.signOut();
    }
    if (BETA_LOCAL_MODE) {
      setUser({ id: "local-beta", email: "local beta mode" });
      setAuthPassword("");
      setVaultToast("Signed out. Private beta data is still available on this device.");
      return;
    }

    if (isSupabaseConfigured && supabase) await supabase.auth.signOut();
    setUser(null);
  }

  function changeActiveWorkspace(workspaceId) {
    const workspace = workspaces.find((entry) => String(entry.id) === String(workspaceId));
    if (!workspace) return;
    if (isWorkspaceArchived(workspace)) {
      setWorkspaceMessage("Restore that collection before switching to it.");
      return;
    }
    setActiveWorkspaceId(workspaceId);
    setWorkspaceInviteForm((current) => ({ ...current, workspaceId }));
    setWorkspaceMessage(`Switched to ${workspace?.name || "collection"}.`);
    setVaultPage(1);
    setForgeInventoryPage(1);
    setMarketWatchPage(1);
  }

  async function createWorkspace(event) {
    event?.preventDefault?.();
    const name = normalizeWorkspaceDisplayName(workspaceForm.name || "");
    if (!name) {
      setWorkspaceMessage("Enter a collection name first.");
      return;
    }
    if (collectionNameExists(name)) {
      setWorkspaceMessage("A collection with that name already exists.");
      return;
    }
    const now = new Date().toISOString();
    const ownerId = user?.id || "local-beta";
    const workspace = {
      id: makeId("workspace"),
      name,
      type: workspaceTypeValue(workspaceForm.type || "business", "business"),
      ownerUserId: ownerId,
      owner_user_id: ownerId,
      createdAt: now,
      updatedAt: now,
      archivedAt: "",
      archived_at: null,
    };
    const ownerMember = normalizeWorkspaceMember({
      workspaceId: workspace.id,
      userId: ownerId,
      email: user?.email || "",
      role: "owner",
      status: "active",
      invitedBy: ownerId,
      createdAt: now,
      acceptedAt: now,
    });

    if (!BETA_LOCAL_MODE && user?.id !== "local-beta" && isSupabaseConfigured && supabase) {
      const { data: createdWorkspace, error: workspaceError } = await supabase
        .from("workspaces")
        .insert({ name: workspace.name, type: workspace.type, owner_user_id: user.id })
        .select()
        .single();
      if (workspaceError) {
        setWorkspaceMessage(`Could not create collection: ${workspaceError.message}`);
        setVaultToast("Collection was not created.");
        return;
      }
      const { data: createdMember, error: memberError } = await supabase
        .from("workspace_memberships")
        .insert({
          workspace_id: createdWorkspace.id,
          user_id: user.id,
          email: user.email || null,
          role: "owner",
          status: "active",
          accepted_at: now,
        })
        .select()
        .single();
      if (memberError) {
        setWorkspaceMessage(`Collection created, but owner role could not be saved: ${memberError.message}`);
        setVaultToast("Collection owner role needs admin review.");
      }
      const mappedWorkspace = normalizeWorkspace(createdWorkspace, workspace);
      const mappedMember = createdMember ? normalizeWorkspaceMember(createdMember) : normalizeWorkspaceMember({ ...ownerMember, workspaceId: createdWorkspace.id });
      setWorkspaces((current) => [mappedWorkspace, ...current.filter((entry) => String(entry.id) !== String(mappedWorkspace.id))]);
      setWorkspaceMembers((current) => [mappedMember, ...current.filter((entry) => !(String(entry.workspaceId || entry.workspace_id) === String(mappedWorkspace.id) && String(entry.userId || entry.user_id) === String(user.id)))]);
      setWorkspaceForm({ name: "", type: "business" });
      setActiveWorkspaceId(mappedWorkspace.id);
      setWorkspaceInviteForm((current) => ({ ...current, workspaceId: mappedWorkspace.id }));
      setWorkspaceMessage(`${mappedWorkspace.name} created. Personal data was not moved or shared.`);
      setVaultToast("Workspace created.");
      return;
    }

    setWorkspaces((current) => [workspace, ...current]);
    setWorkspaceMembers((current) => [ownerMember, ...current]);
    setWorkspaceForm({ name: "", type: "business" });
    setActiveWorkspaceId(workspace.id);
    setWorkspaceInviteForm((current) => ({ ...current, workspaceId: workspace.id }));
    setWorkspaceMessage(`${workspace.name} created. Personal data was not moved or shared.`);
    setVaultToast("Workspace created.");
  }

  function openWorkspaceRename(workspace = activeWorkspace) {
    if (!workspace?.id) return;
    if (!canEditWorkspaceId(workspace.id)) {
      setWorkspaceMessage("You do not have permission to edit this collection.");
      return;
    }
    setWorkspaceRenameTarget(workspace);
    setWorkspaceRenameName(workspace.name || "");
    setWorkspaceRenameType(workspaceTypeValue(workspace.type, "personal"));
    setWorkspaceMessage("");
  }

  function closeWorkspaceRename() {
    if (workspaceRenameSaving) return;
    setWorkspaceRenameTarget(null);
    setWorkspaceRenameName("");
    setWorkspaceRenameType("personal");
  }

  async function submitWorkspaceRename(event) {
    event?.preventDefault?.();
    if (!workspaceRenameTarget?.id || workspaceRenameSaving) return;
    const rawName = String(workspaceRenameName || "");
    const name = normalizeWorkspaceDisplayName(rawName);
    if (!name) {
      setWorkspaceMessage("Collection name cannot be blank.");
      return;
    }
    if (rawName.trim().replace(/\s+/g, " ").length > WORKSPACE_NAME_MAX_LENGTH) {
      setWorkspaceMessage(`Collection name must be ${WORKSPACE_NAME_MAX_LENGTH} characters or fewer.`);
      return;
    }
    if (collectionNameExists(name, workspaceRenameTarget.id)) {
      setWorkspaceMessage("A collection with that name already exists.");
      return;
    }
    if (!canEditWorkspaceId(workspaceRenameTarget.id)) {
      setWorkspaceMessage("You do not have permission to edit this collection.");
      return;
    }

    setWorkspaceRenameSaving(true);
    const now = new Date().toISOString();
    const nextType = workspaceTypeValue(workspaceRenameType || workspaceRenameTarget.type, workspaceRenameTarget.type || "personal");
    const applyRenamedWorkspace = (updatedWorkspace) => {
      setWorkspaces((current) => current.map((workspace) =>
        String(workspace.id) === String(updatedWorkspace.id) ? normalizeWorkspace(updatedWorkspace, workspace) : workspace
      ));
      setItems((current) => current.map((item) =>
        String(item.workspaceId || item.workspace_id) === String(updatedWorkspace.id)
          ? { ...item, workspaceName: name }
          : item
      ));
      setWorkspaceMessage(`Saved ${name}.`);
      setVaultToast("Collection saved.");
    };

    try {
      if (!BETA_LOCAL_MODE && user?.id !== "local-beta" && isSupabaseConfigured && supabase) {
        const { data, error } = await supabase
          .from("workspaces")
          .update({ name, type: nextType, updated_at: now })
          .eq("id", workspaceRenameTarget.id)
          .select()
          .single();
        if (error) throw error;
        applyRenamedWorkspace(data || { ...workspaceRenameTarget, name, type: nextType, updatedAt: now });
      } else {
        applyRenamedWorkspace({ ...workspaceRenameTarget, name, type: nextType, updatedAt: now, updated_at: now });
      }
      setWorkspaceRenameTarget(null);
      setWorkspaceRenameName("");
      setWorkspaceRenameType("personal");
    } catch (error) {
      console.error("Could not rename collection", error);
      setWorkspaceMessage(`Could not rename collection: ${error.message || "Try again."}`);
      setVaultToast("Could not rename collection.");
    } finally {
      setWorkspaceRenameSaving(false);
    }
  }

  function openWorkspaceArchive(workspace = activeWorkspace) {
    if (!workspace?.id) return;
    if (isProtectedWorkspace(workspace, { defaultWorkspaceId: DEFAULT_PERSONAL_WORKSPACE_ID })) {
      setWorkspaceMessage(workspace.id === DEFAULT_PERSONAL_WORKSPACE_ID
        ? "The default personal workspace cannot be archived. Hide Personal Forge or archive another workspace instead."
        : "Protected system or Ember & Tide workspaces cannot be archived from normal settings.");
      return;
    }
    if (!canManageWorkspaceId(workspace.id)) {
      setWorkspaceMessage("You need owner or admin access to archive this collection.");
      return;
    }
    if (!isWorkspaceArchived(workspace) && workspaceSelectorOptions.length <= 1) {
      setWorkspaceMessage("Create another active collection before archiving this one.");
      return;
    }
    setWorkspaceArchiveTarget(workspace);
    setWorkspaceMessage("");
  }

  function closeWorkspaceArchive() {
    if (workspaceArchiveSavingId) return;
    setWorkspaceArchiveTarget(null);
  }

  async function archiveWorkspace(workspace = workspaceArchiveTarget) {
    if (!workspace?.id || workspaceArchiveSavingId) return;
    if (isProtectedWorkspace(workspace, { defaultWorkspaceId: DEFAULT_PERSONAL_WORKSPACE_ID })) {
      setWorkspaceMessage(workspace.id === DEFAULT_PERSONAL_WORKSPACE_ID
        ? "The default personal workspace cannot be archived."
        : "Protected system or Ember & Tide workspaces cannot be archived from normal settings.");
      return;
    }
    if (!canManageWorkspaceId(workspace.id)) {
      setWorkspaceMessage("You need owner or admin access to archive this collection.");
      return;
    }
    if (!isWorkspaceArchived(workspace) && workspaceSelectorOptions.length <= 1) {
      setWorkspaceMessage("Create another active collection before archiving this one.");
      return;
    }
    const now = new Date().toISOString();
    const nextWorkspace = {
      ...workspace,
      archivedAt: now,
      archived_at: now,
      archivedBy: user?.id || "local-beta",
      archived_by: user?.id || "local-beta",
      active: false,
      status: "archived",
      updatedAt: now,
      updated_at: now,
    };
    const fallbackWorkspace = workspaceSelectorOptions.find((option) => String(option.id) !== String(workspace.id));
    setWorkspaceArchiveSavingId(workspace.id);
    try {
      if (!BETA_LOCAL_MODE && user?.id !== "local-beta" && isSupabaseConfigured && supabase) {
        const { data, error } = await supabase
          .from("workspaces")
          .update({
            archived_at: now,
            archived_by: user.id,
            updated_at: now,
          })
          .eq("id", workspace.id)
          .select()
          .single();
        if (error) throw error;
        setWorkspaces((current) => current.map((entry) => String(entry.id) === String(workspace.id) ? normalizeWorkspace(data || nextWorkspace, entry) : entry));
      } else {
        setWorkspaces((current) => current.map((entry) => String(entry.id) === String(workspace.id) ? normalizeWorkspace(nextWorkspace, entry) : entry));
      }
      if (String(activeWorkspaceId) === String(workspace.id) && fallbackWorkspace?.id) {
        setActiveWorkspaceId(fallbackWorkspace.id);
        setWorkspaceInviteForm((current) => ({ ...current, workspaceId: fallbackWorkspace.id }));
      }
      setWorkspaceArchiveTarget(null);
      setShowArchivedCollections(true);
      setWorkspaceMessage(`${workspace.name || "Collection"} archived. Its records are hidden from normal collection switching, not deleted.`);
      setVaultToast("Collection archived.");
    } catch (error) {
      console.error("Could not archive collection", error);
      setWorkspaceMessage(`Could not archive collection: ${error.message || "Try again."}`);
      setVaultToast("Could not archive collection.");
    } finally {
      setWorkspaceArchiveSavingId("");
    }
  }

  async function restoreWorkspace(workspace) {
    if (!workspace?.id || workspaceArchiveSavingId) return;
    if (!canManageWorkspaceId(workspace.id)) {
      setWorkspaceMessage("You need owner or admin access to restore this collection.");
      return;
    }
    const now = new Date().toISOString();
    setWorkspaceArchiveSavingId(workspace.id);
    try {
      if (!BETA_LOCAL_MODE && user?.id !== "local-beta" && isSupabaseConfigured && supabase) {
        const { data, error } = await supabase
          .from("workspaces")
          .update({ archived_at: null, archived_by: null, updated_at: now })
          .eq("id", workspace.id)
          .select()
          .single();
        if (error) throw error;
        setWorkspaces((current) => current.map((entry) => String(entry.id) === String(workspace.id)
          ? normalizeWorkspace(data || { ...workspace, archivedAt: "", archived_at: null, active: true, status: "active", updatedAt: now, updated_at: now }, { ...entry, active: true, status: "active" })
          : entry
        ));
      } else {
        setWorkspaces((current) => current.map((entry) => String(entry.id) === String(workspace.id)
          ? normalizeWorkspace({ ...entry, archivedAt: "", archived_at: null, archivedBy: "", archived_by: null, active: true, status: "active", updatedAt: now, updated_at: now }, entry)
          : entry
        ));
      }
      setWorkspaceMessage(`${workspace.name || "Collection"} restored.`);
      setVaultToast("Collection restored.");
    } catch (error) {
      console.error("Could not restore collection", error);
      setWorkspaceMessage(`Could not restore collection: ${error.message || "Try again."}`);
      setVaultToast("Could not restore collection.");
    } finally {
      setWorkspaceArchiveSavingId("");
    }
  }

  function openWorkspaceDelete(workspace) {
    if (!workspace?.id) return;
    if (!canManageWorkspaceId(workspace.id)) {
      setWorkspaceMessage("You need owner or admin access to delete this collection.");
      return;
    }
    setWorkspaceDeleteTarget(workspace);
    setWorkspaceDeleteConfirmText("");
    setWorkspaceMessage("");
  }

  function closeWorkspaceDelete() {
    if (workspaceDeleteSaving) return;
    setWorkspaceDeleteTarget(null);
    setWorkspaceDeleteConfirmText("");
  }

  async function deleteWorkspace() {
    const workspace = workspaceDeleteTarget;
    if (!workspace?.id || workspaceDeleteSaving) return;
    const counts = workspaceRecordCountsFor(workspace.id);
    const deleteBlockReason = workspaceDeleteBlockReason(workspace, counts, {
      activeWorkspaceId,
      activeWorkspaceCount: workspaceSelectorOptions.length,
      canManage: canManageWorkspaceId(workspace.id),
      confirmed: String(workspaceDeleteConfirmText || "").trim().toUpperCase() === "DELETE",
      defaultWorkspaceId: DEFAULT_PERSONAL_WORKSPACE_ID,
    });
    if (deleteBlockReason) {
      setWorkspaceMessage(deleteBlockReason);
      return;
    }
    const fallbackWorkspace = workspaceSelectorOptions.find((option) => String(option.id) !== String(workspace.id))
      || accessibleWorkspaceOptions.find((option) => String(option.id) !== String(workspace.id) && !isWorkspaceArchived(option));
    setWorkspaceDeleteSaving(true);
    try {
      if (!BETA_LOCAL_MODE && user?.id !== "local-beta" && isSupabaseConfigured && supabase) {
        const { error } = await supabase
          .from("workspaces")
          .delete()
          .eq("id", workspace.id);
        if (error) throw error;
      }
      setWorkspaces((current) => current.filter((entry) => String(entry.id) !== String(workspace.id)));
      setWorkspaceMembers((current) => current.filter((member) => String(member.workspaceId || member.workspace_id) !== String(workspace.id)));
      setWorkspaceInvites((current) => current.filter((invite) => String(invite.workspaceId || invite.workspace_id) !== String(workspace.id)));
      if (String(activeWorkspaceId) === String(workspace.id) && fallbackWorkspace?.id) {
        setActiveWorkspaceId(fallbackWorkspace.id);
        setWorkspaceInviteForm((current) => ({ ...current, workspaceId: fallbackWorkspace.id }));
      }
      setWorkspaceDeleteTarget(null);
      setWorkspaceDeleteConfirmText("");
      setWorkspaceMessage(`${workspace.name || "Collection"} deleted.`);
      setVaultToast("Empty collection deleted.");
    } catch (error) {
      console.error("Could not delete collection", error);
      setWorkspaceMessage(`Could not delete collection: ${error.message || "Try again."}`);
      setVaultToast("Could not delete collection.");
    } finally {
      setWorkspaceDeleteSaving(false);
    }
  }

  async function sendWorkspaceInvite(event) {
    event?.preventDefault?.();
    const email = String(workspaceInviteForm.email || "").trim().toLowerCase();
    const workspace = workspaces.find((entry) => String(entry.id) === String(workspaceInviteForm.workspaceId));
    if (!email || !workspace) {
      setWorkspaceMessage("Choose a workspace and enter an email address.");
      return;
    }
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      setWorkspaceMessage("Enter a valid email address for the invite.");
      return;
    }
    if (!canManageWorkspaceId(workspace.id)) {
      setWorkspaceMessage("You do not have permission to invite members to this workspace.");
      return;
    }
    const role = normalizeWorkspaceRoleValue(workspaceInviteForm.role, "viewer") === "owner"
      ? "viewer"
      : normalizeWorkspaceRoleValue(workspaceInviteForm.role, "viewer");
    const now = new Date().toISOString();
    setWorkspaceInviteSending(true);
    setWorkspaceInviteDelivery(null);
    setWorkspaceMessage("");
    const invite = normalizeWorkspaceInvite({
      id: makeId("invite"),
      workspaceId: workspace.id,
      email,
      role,
      note: workspaceInviteForm.note,
      status: "invited",
      invitedBy: user?.id || "local-beta",
      createdAt: now,
      expiresAt: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString(),
      emailSent: false,
      deliveryMethod: "copy_link",
    });

    try {
      if (!BETA_LOCAL_MODE && user?.id !== "local-beta" && isSupabaseConfigured && supabase) {
        const { data: createdInvite, error: inviteError } = await supabase.rpc("create_workspace_invite", {
          target_workspace_id: workspace.id,
          invite_email: email,
          invite_role: role,
          invite_note: workspaceInviteForm.note || null,
        });
        if (inviteError) throw inviteError;
        const payload = Array.isArray(createdInvite) ? createdInvite[0] : createdInvite || {};
        const mappedInvite = normalizeWorkspaceInvite({
          ...payload,
          id: payload.invite_id || payload.id,
          email: payload.invite_email || payload.email,
          workspaceId: payload.workspace_id || workspace.id,
          emailSent: payload.email_sent,
          deliveryMethod: payload.delivery_method,
          invitePath: payload.invite_path,
          duplicatePending: payload.duplicate_pending,
        });
        const inviteLink = workspaceInviteLinkForInvite(mappedInvite);
        const delivery = { ...mappedInvite, inviteUrl: inviteLink, invite_url: inviteLink };
        setWorkspaceInvites((current) => [delivery, ...current.filter((entry) => !(
          String(entry.email || "").toLowerCase() === email &&
          String(entry.workspaceId || entry.workspace_id) === String(workspace.id) &&
          entry.status === "invited"
        ))]);
        setWorkspaceInviteForm((current) => ({ ...current, email: "", note: "" }));
        setWorkspaceInviteDelivery(delivery);
        setWorkspaceMessage(
          delivery.emailSent
            ? `Email sent to ${email}.`
            : `Invite created for ${email}. Email is not configured - copy and send this invite link.`
        );
        setVaultToast(delivery.emailSent ? "Workspace invite email sent." : "Workspace invite created. Copy the invite link.");
        return;
      }

      const localInviteLink = workspaceInviteLinkForInvite(invite);
      const localInvite = { ...invite, inviteUrl: localInviteLink, invite_url: localInviteLink };
      setWorkspaceInvites((current) => [localInvite, ...current.filter((entry) => !(entry.email === email && entry.workspaceId === workspace.id && entry.status === "invited"))]);
      setWorkspaceMembers((current) => {
        const existingIndex = current.findIndex((entry) =>
          String(entry.workspaceId || entry.workspace_id) === String(workspace.id) &&
          String(entry.email || "").toLowerCase() === email
        );
        const pendingMember = normalizeWorkspaceMember({
          workspaceId: workspace.id,
          email,
          userId: "",
          role,
          status: "invited",
          invitedBy: user?.id || "local-beta",
          createdAt: now,
        });
        if (existingIndex >= 0) {
          return current.map((entry, index) => index === existingIndex ? pendingMember : entry);
        }
        return [pendingMember, ...current];
      });
      setWorkspaceInviteForm((current) => ({ ...current, email: "", note: "" }));
      setWorkspaceInviteDelivery(localInvite);
      setWorkspaceMessage(`Invite created for ${email}. Email is not configured - copy and send this invite link.`);
      setVaultToast("Workspace invite created. Copy the invite link.");
    } catch (error) {
      console.error("Could not create workspace invite", error);
      const missingRpc = error?.code === "42883" || error?.code === "PGRST202" || /create_workspace_invite|function.*does not exist|could not find/i.test(error?.message || "");
      setWorkspaceMessage(
        missingRpc
          ? "Workspace invite backend is not up to date. Apply the workspace invite delivery migration, then try again."
          : `Could not create invite: ${error.message || "Try again."}`
      );
      setVaultToast("Workspace invite was not created.");
    } finally {
      setWorkspaceInviteSending(false);
    }
  }

  function acceptWorkspaceInvite(inviteId) {
    const invite = workspaceInvites.find((entry) => entry.id === inviteId);
    if (!invite) return;
    const now = new Date().toISOString();
    const userId = user?.id || "local-beta";
    setWorkspaceInvites((current) => current.map((entry) => entry.id === inviteId ? { ...entry, status: "active", acceptedAt: now } : entry));
    setWorkspaceMembers((current) => {
      const activeMember = normalizeWorkspaceMember({
        workspaceId: invite.workspaceId,
        email: invite.email,
        userId,
        role: invite.role,
        status: "active",
        invitedBy: invite.invitedBy,
        createdAt: invite.createdAt,
        acceptedAt: now,
      });
      return [activeMember, ...current.filter((entry) =>
        !(String(entry.workspaceId || entry.workspace_id) === String(invite.workspaceId) && String(entry.email || "").toLowerCase() === String(invite.email || "").toLowerCase())
      )];
    });
    setActiveWorkspaceId(invite.workspaceId);
    setWorkspaceMessage(`Invite accepted. You are now viewing ${workspaces.find((workspace) => workspace.id === invite.workspaceId)?.name || "that workspace"}.`);
  }

  async function claimCloudWorkspaceInvite(inviteId) {
    const normalizedInviteId = String(inviteId || "").trim();
    if (!normalizedInviteId) throw new Error("This workspace invite link is not valid.");
    if (!isSupabaseConfigured || !supabase || BETA_LOCAL_MODE || user?.id === "local-beta") {
      acceptWorkspaceInvite(normalizedInviteId);
      return { invite_id: normalizedInviteId, status: "active" };
    }
    const { data, error } = await supabase.rpc("accept_workspace_invite", {
      target_invite_id: normalizedInviteId,
    });
    if (error) throw error;
    const payload = Array.isArray(data) ? data[0] : data || {};
    const workspaceId = payload.workspace_id || payload.workspaceId || "";
    const acceptedAt = payload.accepted_at || new Date().toISOString();
    const role = normalizeWorkspaceRoleValue(payload.role, "viewer");
    const email = String(payload.email || user?.email || "").trim().toLowerCase();

    setWorkspaceInvites((current) => current.map((entry) => (
      String(entry.id) === normalizedInviteId
        ? { ...entry, status: "active", acceptedAt, accepted_at: acceptedAt }
        : entry
    )));

    if (workspaceId) {
      setActiveWorkspaceId(workspaceId);
      setWorkspaceMembers((current) => {
        const activeMember = normalizeWorkspaceMember({
          workspaceId,
          email,
          userId: user?.id || "",
          role,
          status: "active",
          acceptedAt,
        });
        return [activeMember, ...current.filter((entry) => !(
          String(entry.workspaceId || entry.workspace_id) === String(workspaceId) &&
          (String(entry.userId || entry.user_id) === String(user?.id || "") || String(entry.email || "").toLowerCase() === email)
        ))];
      });

      try {
        const { data: workspaceRow } = await supabase
          .from("workspaces")
          .select("*")
          .eq("id", workspaceId)
          .maybeSingle();
        if (workspaceRow) {
          const normalizedWorkspace = normalizeWorkspace(workspaceRow, createDefaultWorkspaceBundle(user || { id: "local-beta" }).workspaces[0]);
          setWorkspaces((current) => [normalizedWorkspace, ...current.filter((workspace) => String(workspace.id) !== String(workspaceId))]);
        }
      } catch {
        // The accepted membership is enough for the app; workspace metadata can reload later.
      }
    }

    return payload;
  }

