  function parseReceiptDraftLines(rawText = "") {
    const lines = String(rawText || "")
      .split(/\r?\n/)
      .map((line) => line.trim())
      .filter(Boolean);
    return lines
      .filter((line) => !/^(subtotal|tax|total|visa|mastercard|cash|change|thank|auth|transaction|receipt)\b/i.test(line))
      .map((line) => {
        const priceMatch = line.match(/(.+?)\s+\$?(-?\d+(?:\.\d{2})?)$/);
        const quantityMatch = line.match(/\b(?:qty|quantity)\s*[:x]?\s*(\d+(?:\.\d+)?)\b/i);
        const rawName = priceMatch ? priceMatch[1] : line;
        const quantity = quantityMatch ? Number(quantityMatch[1]) : 1;
        const totalCost = priceMatch ? Number(priceMatch[2]) : 0;
        return {
          rawText: line,
          name: rawName.replace(/\b(?:qty|quantity)\s*[:x]?\s*\d+(?:\.\d+)?\b/ig, "").trim(),
          quantity: Math.max(1, quantity || 1),
          unitCost: quantity ? totalCost / quantity : totalCost,
          totalCost,
        };
      })
      .filter((line) => line.name);
  }

  function makeReceiptEntityId(prefix = "receipt") {
    if (typeof crypto !== "undefined" && typeof crypto.randomUUID === "function") return crypto.randomUUID();
    return makeId(prefix);
  }

  async function findReceiptLineCatalogMatches(line = {}) {
    const query = String(line.rawText || line.name || "").trim();
    if (!query || query.length < 2) return [];
    if (isSupabaseConfigured && supabase) {
      try {
        const result = await searchPokemonCatalogOnDemand({
          supabase,
          query,
          mode: detectCatalogSearchMode(query),
          page: 1,
          pageSize: 5,
          force: true,
        });
        const normalizedLineName = normalizeSearchText(line.name || line.rawText);
        return (result.rows || []).map((row, index) => {
          const item = mapCatalog(row);
          const normalizedTitle = normalizeSearchText(catalogTitle(item));
          const exactTitle = normalizedTitle && normalizedTitle === normalizedLineName;
          return {
            item,
            score: exactTitle ? 1000 : Math.max(350, 850 - index * 55),
            confidencePercent: exactTitle ? 96 : Math.max(58, 88 - index * 7),
            explanation: result.searchPhase === "rpc" ? "Fast catalog match" : "Catalog search match",
            reason: result.searchPhase || result.sourceName || "catalog search",
          };
        });
      } catch {
        return getBestCatalogMatches(query, catalogProducts).slice(0, 5);
      }
    }
    return getBestCatalogMatches(query, catalogProducts).slice(0, 5);
  }

  async function buildReceiptReviewDraft() {
    setReceiptScanStatus("reading_receipt");
    setReceiptScanStatus("matching_products");
    const rawText = receiptScanForm.rawText || "";
    const parsedReceiptLines = parseReceiptDraftLines(rawText);
    const fallbackLines = parsedReceiptLines.length ? parsedReceiptLines : [{ rawText: "Unmatched receipt item", name: "Unmatched receipt item", quantity: 1, unitCost: 0, totalCost: 0 }];
    const items = await Promise.all(fallbackLines.map(async (line) => {
      const lineClassification = classifyReceiptLineForEntry(line);
      const matches = await findReceiptLineCatalogMatches(line);
      const best = matches[0];
      const confidence = best?.confidencePercent || 0;
      const autoAccept = confidence >= 92 && best?.item;
      const needsReview = !autoAccept;
      return {
        id: makeReceiptEntityId("receipt-line"),
        rawText: line.rawText,
        itemName: line.name || "",
        matchedCatalogId: autoAccept ? best?.item?.id || "" : "",
        matchedCatalogItemId: autoAccept ? best?.item?.masterCatalogItemId || best?.item?.id || "" : "",
        suggestedMatchName: best?.item ? catalogTitle(best.item) : line.name || "",
        matchConfidence: confidence,
        quantity: line.quantity || 1,
        unitCost: Number(line.unitCost || 0).toFixed(2),
        totalCost: Number(line.totalCost || 0).toFixed(2),
        destination: "expense_only",
        entryType: lineClassification.entryType,
        entryTypeLabel: lineClassification.label,
        suggestedCategory: lineClassification.category,
        category: lineClassification.category,
        classificationReason: lineClassification.reason,
        condition: /box|etb|tin|booster|pack|sealed/i.test(line.name) ? "Sealed" : "Unknown",
        ownerUserId: user?.id && user.id !== "local-beta" ? user.id : "",
        notes: "",
        status: needsReview ? "needs_review" : "draft_extracted",
        verified: false,
        possibleMatches: matches.slice(0, 5),
      };
    }));
    const itemTotal = items.reduce((sum, item) => sum + Number(item.totalCost || 0), 0);
    const discountTotal = Number(receiptScanForm.discounts || 0);
    const total = Number(receiptScanForm.total || itemTotal + Number(receiptScanForm.tax || 0) - discountTotal || 0);
    const receiptHash = [receiptScanForm.storeName, receiptScanForm.purchaseDate, total, receiptScanForm.transactionNumber].join("|").toLowerCase();
    const duplicatePossible = phase2Data.receiptRecords.some((receipt) =>
      String(receipt.merchant || "").toLowerCase() === String(receiptScanForm.storeName || "").toLowerCase() &&
      Math.abs(Number(receipt.total || 0) - total) < 0.01 &&
      String(receipt.purchasedAt || "").slice(0, 10) === String(receiptScanForm.purchaseDate || "").slice(0, 10)
    );
    const aiSummary = buildAiReceiptDraftSummary({
      storeName: receiptScanForm.storeName || "Unknown store",
      rawText,
      lineCount: items.length,
      total: total ? money(total) : "",
    });
    setReceiptScanDraft({
      id: makeReceiptEntityId("receipt-draft"),
      storeName: receiptScanForm.storeName || "Unknown store",
      storeLocation: receiptScanForm.storeLocation || "",
      purchaseDate: receiptScanForm.purchaseDate || new Date().toISOString().slice(0, 10),
      subtotal: Number(receiptScanForm.subtotal || itemTotal || Math.max(0, total - Number(receiptScanForm.tax || 0) + discountTotal) || 0),
      tax: Number(receiptScanForm.tax || 0),
      discounts: discountTotal,
      total,
      paymentMethod: receiptScanForm.paymentMethod || "",
      receiptImageUrl: receiptScanForm.receiptImageUrl || receiptScanForm.filePreviewUrl || "",
      source: receiptScanForm.source || (receiptScanForm.receiptImageUrl || receiptScanForm.filePreviewUrl ? "upload" : "manual"),
      receiptHash,
      transactionNumber: receiptScanForm.transactionNumber || "",
      status: duplicatePossible ? "duplicate_possible" : "draft_extracted",
      items,
      warnings: [],
      aiSummary: aiSummary.outputSummary,
      createdAt: new Date().toISOString(),
    });
    setReceiptScanStatus("ready_for_review");
    setReceiptScanMessage(`${aiSummary.outputSummary} ${AI_REVIEW_DISCLAIMER}`);
    void logAiAssistEvent(AI_FEATURE_AREAS.RECEIPT_EXTRACTION, {
      ...aiSummary,
      relatedEntityType: "receipt_draft",
    });
  }

  function updateReceiptDraft(field, value) {
    setReceiptScanDraft((current) => current ? { ...current, [field]: value } : current);
  }

  function updateReceiptDraftItem(itemId, field, value) {
    const nextValue = field === "destination" ? normalizeReceiptDestination(value) : value;
    setReceiptScanDraft((current) => current ? {
      ...current,
      items: current.items.map((item) => {
        if (item.id !== itemId) return item;
        const nextItem = {
          ...item,
          [field]: nextValue,
          status: field === "verified" && nextValue ? "verified" : field === "verified" ? "needs_review" : item.status,
        };
        if (["quantity", "unitCost"].includes(field)) {
          const quantity = Math.max(0, Number(field === "quantity" ? nextValue : nextItem.quantity || 0));
          const unitCost = Math.max(0, Number(field === "unitCost" ? nextValue : nextItem.unitCost || 0));
          nextItem.totalCost = (quantity * unitCost).toFixed(2);
          if (field !== "verified") nextItem.verified = false;
        }
        if (field === "totalCost") {
          const quantity = Math.max(1, Number(nextItem.quantity || 1));
          nextItem.unitCost = (Number(nextValue || 0) / quantity).toFixed(2);
          nextItem.verified = false;
        }
        if (field !== "verified" && !["quantity", "unitCost", "totalCost"].includes(field)) {
          nextItem.verified = false;
        }
        return nextItem;
      }),
    } : current);
  }

  function markReceiptDraftItemUse(itemId, entryType, destination = "expense_only") {
    const category =
      entryType === RECEIPT_LINE_ENTRY_TYPES.INVENTORY ? "Inventory/Product Cost" :
      entryType === RECEIPT_LINE_ENTRY_TYPES.SUPPLIES ? "Packaging Supplies" :
      entryType === RECEIPT_LINE_ENTRY_TYPES.MILEAGE_REFERENCE ? "Mileage/Vehicle" :
      entryType === RECEIPT_LINE_ENTRY_TYPES.IGNORED ? "Ignored" :
      "Supplies";
    setReceiptScanDraft((current) => current ? {
      ...current,
      items: current.items.map((item) => item.id === itemId ? {
        ...item,
        entryType,
        entryTypeLabel: RECEIPT_LINE_ENTRY_LABELS[entryType] || "Expense-only record",
        suggestedCategory: category,
        category,
        destination: normalizeReceiptDestination(destination),
        status: entryType === RECEIPT_LINE_ENTRY_TYPES.IGNORED ? "ignored" : "needs_review",
        verified: entryType === RECEIPT_LINE_ENTRY_TYPES.IGNORED ? true : item.verified,
        notes: [
          item.notes,
          entryType === RECEIPT_LINE_ENTRY_TYPES.IGNORED ? "Ignored during receipt review." : "",
        ].filter(Boolean).join(" "),
      } : item),
    } : current);
  }

  function selectReceiptItemCatalogMatch(itemId, productId) {
    const draftItem = receiptScanDraft?.items?.find((item) => item.id === itemId);
    const product =
      catalogProducts.find((candidate) => String(candidate.id) === String(productId)) ||
      draftItem?.possibleMatches?.find((match) => String(match.item?.id) === String(productId))?.item;
    if (product?.id) rememberCatalogProduct(product);
    setReceiptScanDraft((current) => current ? {
      ...current,
      items: current.items.map((item) => item.id === itemId ? {
        ...item,
        matchedCatalogId: product?.id || "",
        matchedCatalogItemId: product?.masterCatalogItemId || product?.id || "",
        suggestedMatchName: product ? catalogTitle(product) : "",
        matchConfidence: product ? Math.max(Number(item.matchConfidence || 0), 90) : 0,
        status: product ? "needs_review" : item.status,
        verified: false,
      } : item),
    } : current);
  }

  async function searchReceiptItemCatalogMatch(itemId) {
    const line = receiptScanDraft?.items?.find((item) => item.id === itemId);
    if (!line) return;
    setReceiptScanStatus("matching_products");
    const matches = await findReceiptLineCatalogMatches({
      rawText: line.rawText || line.suggestedMatchName,
      name: line.suggestedMatchName || line.itemName || line.rawText,
    });
    const aiSummary = buildAiCatalogMatchSummary({ query: line.rawText || line.suggestedMatchName, matches });
    setReceiptScanDraft((current) => current ? {
      ...current,
      items: current.items.map((item) => item.id === itemId ? {
        ...item,
        possibleMatches: matches,
        matchConfidence: matches[0]?.confidencePercent || item.matchConfidence || 0,
        suggestedMatchName: matches[0]?.item ? catalogTitle(matches[0].item) : item.suggestedMatchName,
        verified: false,
        status: "needs_review",
      } : item),
    } : current);
    setReceiptScanStatus("ready_for_review");
    setReceiptScanMessage(`${aiSummary.outputSummary} ${AI_REVIEW_DISCLAIMER}`);
    void logAiAssistEvent(AI_FEATURE_AREAS.CATALOG_MATCH, {
      ...aiSummary,
      relatedEntityType: "receipt_line_item",
    });
  }

  function addReceiptCustomItem(itemId) {
    setReceiptScanDraft((current) => current ? {
      ...current,
      items: current.items.map((item) => item.id === itemId ? {
        ...item,
        matchedCatalogId: "",
        matchedCatalogItemId: "",
        possibleMatches: [],
        matchConfidence: 0,
        suggestedMatchName: item.suggestedMatchName || item.itemName || item.rawText,
        status: "needs_review",
        verified: false,
      } : item),
    } : current);
  }

  function removeReceiptDraftItem(itemId) {
    setReceiptScanDraft((current) => current ? {
      ...current,
      items: current.items.filter((item) => item.id !== itemId),
    } : current);
  }

  function splitReceiptDraftItem(itemId) {
    setReceiptScanDraft((current) => {
      if (!current) return current;
      const source = current.items.find((item) => item.id === itemId);
      if (!source) return current;
      const quantity = Math.max(1, Number(source.quantity || 1));
      const splitQuantity = quantity > 1 ? 1 : 1;
      const remainingQuantity = quantity > 1 ? quantity - splitQuantity : quantity;
      const unitCost = Number(source.unitCost || 0);
      const nextSource = {
        ...source,
        quantity: remainingQuantity,
        totalCost: (remainingQuantity * unitCost).toFixed(2),
        verified: false,
        status: "needs_review",
      };
      const splitLine = {
        ...source,
        id: makeReceiptEntityId("receipt-line"),
        quantity: splitQuantity,
        totalCost: (splitQuantity * unitCost).toFixed(2),
        destination: "expense_only",
        verified: false,
        status: "needs_review",
        notes: [source.notes, "Split from receipt line."].filter(Boolean).join(" "),
      };
      return {
        ...current,
        items: current.items.flatMap((item) => item.id === itemId ? [nextSource, splitLine] : [item]),
      };
    });
  }

  function mergeReceiptDuplicateLines() {
    setReceiptScanDraft((current) => {
      if (!current) return current;
      const merged = [];
      const byKey = new Map();
      current.items.forEach((item) => {
        const key = [
          normalizeSearchText(item.matchedCatalogId || item.suggestedMatchName || item.itemName || item.rawText),
          normalizeReceiptDestination(item.destination),
          Number(item.unitCost || 0).toFixed(2),
        ].join("|");
        if (!byKey.has(key)) {
          const clone = { ...item };
          byKey.set(key, clone);
          merged.push(clone);
          return;
        }
        const existing = byKey.get(key);
        const quantity = Number(existing.quantity || 0) + Number(item.quantity || 0);
        existing.quantity = quantity;
        existing.totalCost = (Number(existing.totalCost || 0) + Number(item.totalCost || 0)).toFixed(2);
        existing.rawText = [existing.rawText, item.rawText].filter(Boolean).join(" | ");
        existing.verified = false;
        existing.status = "needs_review";
      });
      return { ...current, items: merged };
    });
  }

  function bulkVerifyHighConfidenceReceiptItems() {
    setReceiptScanDraft((current) => current ? {
      ...current,
      items: current.items.map((item) =>
        item.matchConfidence >= 85 && item.quantity && item.unitCost && (normalizeReceiptDestination(item.destination) === "expense_only" || item.matchedCatalogId)
          ? { ...item, verified: true, status: "verified" }
          : item
      ),
    } : current);
  }

  function receiptReviewWarnings(draft = receiptScanDraft) {
    if (!draft) return [];
    const warnings = [];
    if (draft.status === "duplicate_possible") warnings.push("Duplicate receipt already uploaded may exist.");
    const itemTotal = draft.items.reduce((sum, item) => sum + Number(item.totalCost || 0), 0);
    if (Math.abs((itemTotal + Number(draft.tax || 0) - Number(draft.discounts || 0)) - Number(draft.total || 0)) > 1) warnings.push("Receipt total does not match item totals plus tax/discounts.");
    draft.items.forEach((item, index) => {
      if (item.status === "ignored" || item.entryType === RECEIPT_LINE_ENTRY_TYPES.IGNORED) return;
      const destination = normalizeReceiptDestination(item.destination);
      const createsInventory = ["vault", "forge", "wishlist"].includes(destination);
      if (!item.verified) warnings.push(`Item ${index + 1} must be verified before submit.`);
      if (createsInventory && !item.matchedCatalogId) warnings.push(`Item ${index + 1} will save as a custom ${RECEIPT_DESTINATION_LABELS[destination] || "inventory"} item because no catalog match is selected.`);
      if (Number(item.matchConfidence || 0) < 50 && createsInventory && item.matchedCatalogId) warnings.push(`Item ${index + 1} has a very low confidence match.`);
      if (!Number(item.quantity || 0) || !Number(item.unitCost || 0)) warnings.push(`Item ${index + 1} is missing quantity or cost.`);
    });
    return [...new Set(warnings)];
  }

  function receiptItemDbDestination(item = {}) {
    return normalizeReceiptDestination(item.destination);
  }

  function receiptItemShouldCreateInventory(item = {}) {
    if (item.status === "ignored" || item.entryType === RECEIPT_LINE_ENTRY_TYPES.IGNORED) return false;
    const destination = receiptItemDbDestination(item);
    return ["forge", "vault", "wishlist"].includes(destination);
  }

  function receiptItemToInventoryRecord(item, receipt, destination) {
    const product = catalogProducts.find((candidate) =>
      String(candidate.id) === String(item.matchedCatalogId) ||
      String(candidate.masterCatalogItemId || "") === String(item.matchedCatalogItemId || "")
    ) || item.possibleMatches?.find((match) =>
      String(match.item?.id || "") === String(item.matchedCatalogId || "") ||
      String(match.item?.masterCatalogItemId || "") === String(item.matchedCatalogItemId || "")
    )?.item;
    const normalizedDestination = normalizeReceiptDestination(destination);
    const workspace = workspaces.find((entry) => String(entry.id) === String(defaultWorkspaceIdForDestination(normalizedDestination))) || activeWorkspace;
    const isWishlist = normalizedDestination === "wishlist";
    const isVault = normalizedDestination === "vault" || isWishlist;
    return applyWorkspaceToRecord({
      ...blankItem,
      id: makeId(isWishlist ? "receipt-wishlist" : isVault ? "receipt-vault" : "receipt-forge"),
      name: product ? catalogTitle(product) : item.suggestedMatchName || item.itemName || item.rawText,
      itemName: product ? catalogTitle(product) : item.suggestedMatchName || item.itemName || item.rawText,
      destinationScope: [isWishlist ? "wishlist" : isVault ? "vault" : "forge"],
      recordType: isWishlist ? "wishlist_item" : isVault ? "vault_item" : "forge_inventory",
      businessInventory: !isVault,
      isWishlist,
      quantity: Number(item.quantity || 1),
      ownedQuantity: isVault && !isWishlist ? Number(item.quantity || 1) : 0,
      forgeQuantity: isVault ? 0 : Number(item.quantity || 1),
      unitCost: Number(item.unitCost || 0),
      salePrice: Number(product?.marketPrice || 0),
      plannedSalePrice: Number(product?.marketPrice || 0),
      category: product?.category || "Pokemon",
      productType: normalizedInventoryProductType(product || item),
      setName: product?.setName || product?.expansion || "",
      expansion: product?.setName || product?.expansion || "",
      barcode: product?.barcode || product?.upc || "",
      catalogProductId: product?.id || item.matchedCatalogId || "",
      masterCatalogItemId: product?.masterCatalogItemId || item.matchedCatalogItemId || "",
      catalogProductName: product ? catalogTitle(product) : item.suggestedMatchName || item.itemName || "",
      marketPrice: Number(product?.marketPrice || 0),
      msrpPrice: Number(product?.msrpPrice || 0),
      condition: item.condition,
      conditionName: item.condition === "Sealed" ? "Sealed" : item.condition || "Unknown",
      sealedCondition: item.condition === "Sealed" ? "Sealed" : "",
      status: isWishlist ? "Wishlist" : isVault ? "Personal Collection" : "In Stock",
      vaultStatus: isWishlist ? "wishlist" : isVault ? "personal_collection" : "",
      receiptImage: receipt.receiptImageUrl || "",
      receiptId: receipt.id,
      sourceType: "Receipt scan",
      notes: [item.notes, `Receipt ${receipt.transactionNumber || receipt.id}`, `Raw line: ${item.rawText}`].filter(Boolean).join(" | "),
      purchaseDate: receipt.purchaseDate,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    }, workspace);
  }

  function upsertReceiptWorkflowData(current = createEmptyPhase2Data(), receipt = {}, lines = []) {
    const receiptId = receipt.id || receipt.receiptId || "";
    const normalizedReceipt = {
      ...receipt,
      workspaceId: receipt.workspaceId || receipt.workspace_id || activeForgeWorkspace?.id || activeWorkspace?.id || DEFAULT_PERSONAL_WORKSPACE_ID,
      workspace_id: receipt.workspace_id || receipt.workspaceId || activeForgeWorkspace?.id || activeWorkspace?.id || DEFAULT_PERSONAL_WORKSPACE_ID,
      workspaceName: receipt.workspaceName || activeForgeWorkspace?.name || activeWorkspace?.name || "Forge",
    };
    const normalizedLines = (lines || []).map((line) => ({ ...line, receiptId: line.receiptId || line.receipt_id || receiptId }));
    return {
      ...current,
      receiptRecords: [
        normalizedReceipt,
        ...(current.receiptRecords || []).filter((entry) => String(entry.id || "") !== String(receiptId)),
      ],
      receiptLineItems: [
        ...normalizedLines,
        ...(current.receiptLineItems || []).filter((line) => String(line.receiptId || line.receipt_id || "") !== String(receiptId)),
      ],
    };
  }

  function syncForgeReceiptWorkflowState(receipt = {}, lines = []) {
    setForgePhase2Data((current) => upsertReceiptWorkflowData(current, receipt, lines));
    const targetWorkspaceId = receipt.workspaceId || receipt.workspace_id || activeForgeWorkspace?.id || activeWorkspace?.id || DEFAULT_PERSONAL_WORKSPACE_ID;
    if (String(targetWorkspaceId) === String(activeWorkspaceId)) {
      setPhase2Data((current) => upsertReceiptWorkflowData(current, receipt, lines));
    }
  }

  function appendUniqueText(current = "", addition = "") {
    const next = String(addition || "").trim();
    if (!next) return current || "";
    const existing = String(current || "").trim();
    if (existing.includes(next)) return existing;
    return [existing, next].filter(Boolean).join(" | ");
  }

  function receiptLinkNote(receipt = {}) {
    return `Receipt ${receiptRecordId(receipt)}: ${receiptMerchantLabel(receipt)} ${receiptDateLabel(receipt)}`;
  }

  function buildReceiptLineForInventoryItem(receipt = {}, item = {}) {
    const destination =
      isForgeInventoryItem(item) ? "forge" :
      isWishlistItemRecord(item) ? "wishlist" :
      "vault";
    return {
      id: makeReceiptEntityId("receipt-line-link"),
      receiptId: receiptRecordId(receipt),
      rawText: `Linked existing item: ${item.name || item.itemName || "Inventory item"}`,
      itemName: item.name || item.itemName || "Inventory item",
      productName: item.catalogProductName || item.name || item.itemName || "Inventory item",
      quantity: Number(item.quantity || 1),
      unitCost: Number(item.unitCost || item.purchasePrice || 0),
      totalCost: Number(item.unitCost || item.purchasePrice || 0) * Number(item.quantity || 1),
      destination,
      matchedConfidence: "linked_existing",
      verified: true,
      createdInventoryItemId: item.id,
      notes: "Linked after receipt save.",
      createdAt: new Date().toISOString(),
    };
  }

  function syncReceiptItemLinkLine(receipt = {}, item = {}, action = "link") {
    const receiptId = receiptRecordId(receipt);
    if (!receiptId || !item?.id) return;
    const existingLines = receiptLinesFor(receipt).filter((line) =>
      String(line.createdInventoryItemId || line.created_inventory_item_id || "") !== String(item.id)
    );
    const nextLines = action === "unlink" ? existingLines : [...existingLines, buildReceiptLineForInventoryItem(receipt, item)];
    syncForgeReceiptWorkflowState(receipt, nextLines);
  }

  async function updateInventoryReceiptProof(item = {}, patch = {}) {
    if (!item?.id) return;
    if (BETA_LOCAL_MODE || user?.id === "local-beta" || !supabase) return;
    const row = {};
    if (Object.prototype.hasOwnProperty.call(patch, "receiptImage")) row.receipt_image = patch.receiptImage || "";
    if (Object.prototype.hasOwnProperty.call(patch, "actionNotes")) row.action_notes = patch.actionNotes || "";
    if (!Object.keys(row).length) return;
    row.updated_at = new Date().toISOString();
    const { error } = await supabase.from("inventory_items").update(row).eq("id", item.id);
    if (error) throw new Error(`Could not update item receipt link: ${error.message}`);
  }

  async function linkReceiptToItem(receiptInput = {}, itemInput = {}, options = {}) {
    const receipt = findReceiptRecord(receiptInput);
    const item = items.find((entry) => String(entry.id) === String(itemInput?.id || itemInput)) || itemInput;
    if (!receipt || !item?.id) return;
    if (!ensureWorkspaceEditor(item.workspaceId || item.workspace_id || activeWorkspace?.id)) return;
    const image = receiptImageUrl(receipt);
    const note = receiptLinkNote(receipt);
    const updatedItem = {
      ...item,
      receiptId: receiptRecordId(receipt),
      linkedReceiptId: receiptRecordId(receipt),
      receiptImage: item.receiptImage || image || "",
      actionNotes: appendUniqueText(item.actionNotes || item.notes || "", note),
      updatedAt: new Date().toISOString(),
    };
    setItems((current) => current.map((entry) => String(entry.id) === String(item.id) ? { ...entry, ...updatedItem } : entry));
    syncReceiptItemLinkLine(receipt, updatedItem, "link");
    try {
      await updateInventoryReceiptProof(item, {
        receiptImage: updatedItem.receiptImage,
        actionNotes: updatedItem.actionNotes,
      });
      if (!options.silent) setReceiptActionMessage(`${item.name || item.itemName || "Item"} is linked to this receipt.`);
    } catch (error) {
      if (!options.silent) setReceiptActionMessage(error?.message || "Receipt linked locally, but cloud sync failed.");
    }
  }

  async function unlinkReceiptFromItem(receiptInput = {}, itemInput = {}) {
    const receipt = findReceiptRecord(receiptInput);
    const item = items.find((entry) => String(entry.id) === String(itemInput?.id || itemInput)) || itemInput;
    if (!receipt || !item?.id) return;
    if (!ensureWorkspaceEditor(item.workspaceId || item.workspace_id || activeWorkspace?.id)) return;
    const image = receiptImageUrl(receipt);
    const note = receiptLinkNote(receipt);
    const cleanedActionNotes = String(item.actionNotes || item.notes || "")
      .split(" | ")
      .map((part) => part.trim())
      .filter((part) => part && part !== note && !part.includes(receiptRecordId(receipt)))
      .join(" | ");
    const updatedItem = {
      ...item,
      receiptId: String(item.receiptId || item.linkedReceiptId || "") === receiptRecordId(receipt) ? "" : item.receiptId,
      linkedReceiptId: String(item.linkedReceiptId || item.receiptId || "") === receiptRecordId(receipt) ? "" : item.linkedReceiptId,
      receiptImage: image && String(item.receiptImage || "") === String(image) ? "" : item.receiptImage,
      actionNotes: cleanedActionNotes,
      updatedAt: new Date().toISOString(),
    };
    setItems((current) => current.map((entry) => String(entry.id) === String(item.id) ? { ...entry, ...updatedItem } : entry));
    syncReceiptItemLinkLine(receipt, item, "unlink");
    try {
      await updateInventoryReceiptProof(item, {
        receiptImage: updatedItem.receiptImage,
        actionNotes: updatedItem.actionNotes || item.actionNotes || "",
      });
      setReceiptActionMessage(`${item.name || item.itemName || "Item"} was unlinked from this receipt.`);
    } catch (error) {
      setReceiptActionMessage(error?.message || "Receipt unlinked locally, but cloud sync failed.");
    }
  }

  async function linkReceiptToSale(receiptInput = {}, saleInput = {}, options = {}) {
    const receipt = findReceiptRecord(receiptInput);
    const sale = sales.find((entry) => String(entry.id) === String(saleInput?.id || saleInput)) || saleInput;
    if (!receipt || !sale?.id) return;
    if (!ensureWorkspaceEditor(sale.workspaceId || sale.workspace_id || activeForgeWorkspace?.id || activeWorkspace?.id)) return;
    const image = receiptImageUrl(receipt);
    const note = receiptLinkNote(receipt);
    const nextSale = {
      ...sale,
      receiptId: receiptRecordId(receipt),
      receiptImage: sale.receiptImage || image || "",
      receiptImageUrl: sale.receiptImageUrl || image || "",
      referenceId: sale.referenceId || receiptRecordId(receipt),
      notes: appendUniqueText(sale.notes || "", note),
      updatedAt: new Date().toISOString(),
    };
    setSales((current) => current.map((entry) => String(entry.id) === String(sale.id) ? nextSale : entry));
    if (!BETA_LOCAL_MODE && supabase && uuidOrNull(sale.id)) {
      const { error } = await supabase.from("sales_records").update({
        notes: nextSale.notes,
        updated_at: new Date().toISOString(),
      }).eq("id", sale.id);
      if (error && !options.silent) setReceiptActionMessage(`Sale linked locally, but cloud sync failed: ${error.message}`);
    }
    if (!options.silent) setReceiptActionMessage(`${sale.itemName || "Sale"} is linked to this receipt.`);
  }

  function openReceiptDetail(receiptInput = {}, options = {}) {
    const receipt = findReceiptRecord(receiptInput) || receiptInput;
    const id = receiptRecordId(receipt);
    if (!id) return;
    if (options.closeReceiptScan) setReceiptScanOpen(false);
    if (options.closeFlowModal) closeFlowModal({ force: true, reset: false });
    setReceiptActionMessage("");
    setReceiptLinkQuery("");
    setSelectedReceiptId(id);
  }

  function openBasicReceiptFlow(source = "receipt", seed = {}) {
    setQuickAddWizard(createQuickAddWizardState({
      screen: "receipt",
      path: "receipt",
      ...seed,
    }));
    openFlowModal("addActionSheet", { size: "medium", source });
  }

  function openReceiptForItem(item = {}, context = "item") {
    if (!item?.id) return;
    setSelectedReceiptId("");
    openBasicReceiptFlow(`${context}-attach-receipt`, {
      receiptMerchant: item.store || item.sourceLocation || "",
      receiptTotal: item.unitCost ? String(item.unitCost) : "",
      receiptNote: `Proof for ${item.name || item.itemName || "item"}.`,
      receiptLinkTargetType: "item",
      receiptLinkTargetId: item.id,
      receiptLinkTargetName: item.name || item.itemName || "Inventory item",
    });
  }

  function openReceiptForSale(sale = {}) {
    if (!sale?.id) return;
    setSelectedReceiptId("");
    openBasicReceiptFlow("sale-attach-receipt", {
      receiptMerchant: sale.platform || "",
      receiptDate: sale.saleDate || String(sale.createdAt || "").slice(0, 10) || new Date().toISOString().slice(0, 10),
      receiptTotal: sale.grossSale ? String(sale.grossSale) : "",
      receiptNote: `Sale proof for ${sale.itemName || "sale"}.`,
      receiptLinkTargetType: "sale",
      receiptLinkTargetId: sale.id,
      receiptLinkTargetName: sale.itemName || "Sale",
    });
  }

  function openReceiptAddItemFlow(receiptInput = {}, seed = {}) {
    const receipt = findReceiptRecord(receiptInput) || receiptInput;
    if (!receiptRecordId(receipt)) return;
    setSelectedReceiptId("");
    const receiptDate = receiptDateInputValue(receipt);
    const receiptPersonName = receipt.buyer || receipt.purchaserName || receipt.purchaser_name || receipt.paidBy || receipt.paid_by || "";
    const receiptPerson = purchasers.find((purchaser) => purchaser.name === receiptPersonName);
    openProductAddFlow({
      source: "receipt-add-item",
      seed: {
        initialStep: "item",
        destinations: destinationDefaults({ vault: true }),
        receiptId: receiptRecordId(receipt),
        receiptImage: receiptImageUrl(receipt),
        receiptMerchant: receiptMerchantLabel(receipt),
        receiptDate,
        notes: `Added from receipt ${receiptMerchantLabel(receipt)} ${receiptDateLabel(receipt)}.`,
        vault: { purchaseDate: receiptDate, unitCost: "", purchaserId: receiptPerson?.id || "", purchaserName: receiptPersonName },
        forge: { source: receiptMerchantLabel(receipt), unitCost: "", purchaserId: receiptPerson?.id || "", purchaserName: receiptPersonName },
        ...seed,
      },
    });
  }

  function openReceiptCreateExpense(receiptInput = {}) {
    const receipt = findReceiptRecord(receiptInput) || receiptInput;
    if (!receiptRecordId(receipt)) return;
    setSelectedReceiptId("");
    setEditingExpenseId(null);
    setExpenseForm({
      ...blankExpense,
      date: receiptDateInputValue(receipt),
      vendor: receiptMerchantLabel(receipt),
      amount: Number(receipt.total ?? receipt.receiptTotal ?? receipt.receipt_total ?? 0) ? String(receipt.total ?? receipt.receiptTotal ?? receipt.receipt_total) : "",
      buyer: receipt.buyer || receipt.purchaserName || receipt.purchaser_name || receipt.paidBy || receipt.paid_by || "",
      receiptImage: receiptImageUrl(receipt),
      receiptId: receiptRecordId(receipt),
      notes: appendUniqueText(receipt.notes || "", `Expense linked from receipt ${receiptRecordId(receipt)}.`),
      receiptSplitMode: "expense_only",
    });
    openAddExpenseFlow({ preserveForm: true, source: "receipt-link-expense" });
  }

  function openReceiptEditFlow(receiptInput = {}) {
    const receipt = findReceiptRecord(receiptInput) || receiptInput;
    const receiptId = receiptRecordId(receipt);
    if (!receiptId) return;
    setSelectedReceiptId("");
    openBasicReceiptFlow("receipt-edit", {
      receiptEditingId: receiptId,
      receiptMerchant: receiptMerchantLabel(receipt),
      receiptDate: receiptDateInputValue(receipt),
      receiptTotal: Number(receipt.total ?? receipt.receiptTotal ?? receipt.receipt_total ?? 0)
        ? String(receipt.total ?? receipt.receiptTotal ?? receipt.receipt_total)
        : "",
      receiptPhotoUrl: receiptImageUrl(receipt),
      receiptFileName: receiptImageUrl(receipt) ? "Saved receipt proof" : "",
      receiptNote: receipt.notes || "",
      receiptPayerName: receipt.buyer || receipt.purchaserName || receipt.purchaser_name || receipt.paidBy || receipt.paid_by || "",
      receiptSaved: receipt,
    });
  }

  function deleteReceiptRecord(receiptInput = {}) {
    const receipt = findReceiptRecord(receiptInput) || receiptInput;
    const receiptId = receiptRecordId(receipt);
    if (!receiptId) return;
    const workspaceId = receipt.workspaceId || receipt.workspace_id || activeForgeWorkspace?.id || activeWorkspace?.id;
    if (!ensureWorkspaceEditor(workspaceId)) return;
    requestAdminActionConfirmation({
      title: "Delete this receipt?",
      message: `This removes ${receiptMerchantLabel(receipt)} from saved receipts. Linked item, sale, or expense records stay, but the receipt record and receipt line review will be removed.`,
      confirmLabel: "Delete receipt",
      danger: true,
      successMessage: "Receipt deleted.",
      errorMessage: "Could not delete receipt.",
      onConfirm: async () => {
        setForgePhase2Data((current) => ({
          ...current,
          receiptRecords: (current.receiptRecords || []).filter((entry) => receiptRecordId(entry) !== receiptId),
          receiptLineItems: (current.receiptLineItems || []).filter((line) => String(line.receiptId || line.receipt_id || "") !== receiptId),
        }));
        setPhase2Data((current) => ({
          ...current,
          receiptRecords: (current.receiptRecords || []).filter((entry) => receiptRecordId(entry) !== receiptId),
          receiptLineItems: (current.receiptLineItems || []).filter((line) => String(line.receiptId || line.receipt_id || "") !== receiptId),
        }));
        saveLocalPhase2Data((current) => ({
          ...current,
          receiptRecords: (current.receiptRecords || []).filter((entry) => receiptRecordId(entry) !== receiptId),
          receiptLineItems: (current.receiptLineItems || []).filter((line) => String(line.receiptId || line.receipt_id || "") !== receiptId),
        }));
        setSelectedReceiptId("");
        if (!BETA_LOCAL_MODE && supabase && uuidOrNull(receiptId)) {
          const { error: lineError } = await supabase.from("receipt_line_items").delete().eq("receipt_id", receiptId);
          if (lineError) throw new Error(lineError.message);
          const { error } = await supabase.from("receipt_records").delete().eq("id", receiptId);
          if (error) throw new Error(error.message);
        }
      },
    });
  }

  async function submitReceiptReview() {
    if (!receiptScanDraft) return;
    const warnings = receiptReviewWarnings();
    if (guestPreviewActive) {
      setReceiptScanMessage("Create a free account to save receipts and inventory.");
      setReceiptScanDraft((current) => current ? { ...current, warnings: ["Create a free account to save receipts and inventory."] } : current);
      return;
    }
    if (warnings.some((warning) => /must be verified|missing quantity/i.test(warning))) {
      setReceiptScanDraft((current) => ({ ...current, warnings }));
      setReceiptScanMessage("Resolve required warnings before submitting.");
      return;
    }
    setReceiptScanStatus("ready_for_review");
    setReceiptScanMessage("Submitting verified receipt to Supabase.");
    const importableItems = receiptScanDraft.items.filter(receiptItemShouldCreateInventory);
    const expenseOnlyItems = receiptScanDraft.items.filter((item) =>
      receiptItemDbDestination(item) === "expense_only" &&
      item.status !== "ignored" &&
      item.entryType !== RECEIPT_LINE_ENTRY_TYPES.IGNORED
    );
    const receipt = {
      id: receiptScanDraft.id,
      merchant: receiptScanDraft.storeName,
      storeName: receiptScanDraft.storeName,
      purchasedAt: `${receiptScanDraft.purchaseDate}T12:00:00.000Z`,
      purchaseDate: receiptScanDraft.purchaseDate,
      total: receiptScanDraft.total,
      receiptTotal: receiptScanDraft.total,
      subtotal: receiptScanDraft.subtotal,
      tax: receiptScanDraft.tax,
      discounts: receiptScanDraft.discounts || 0,
      paymentMethod: receiptScanDraft.paymentMethod || "",
      category: "Receipt Scan",
      imageUrl: receiptScanDraft.receiptImageUrl,
      receiptImageUrl: receiptScanDraft.receiptImageUrl,
      receiptImage: receiptScanDraft.receiptImageUrl,
      status: "submitted",
      source: receiptScanDraft.source || "manual",
      splitMode: "expense_only",
      businessTotal: importableItems.filter((item) => receiptItemDbDestination(item) === "forge").reduce((sum, item) => sum + Number(item.totalCost || 0), 0),
      personalTotal: importableItems.filter((item) => receiptItemDbDestination(item) === "vault").reduce((sum, item) => sum + Number(item.totalCost || 0), 0),
      workspaceId: activeForgeWorkspace?.id || activeWorkspace?.id || DEFAULT_PERSONAL_WORKSPACE_ID,
      workspace_id: activeForgeWorkspace?.id || activeWorkspace?.id || DEFAULT_PERSONAL_WORKSPACE_ID,
      workspaceName: activeForgeWorkspace?.name || activeWorkspace?.name || "Forge",
      notes: `Receipt scan report. Store location: ${receiptScanDraft.storeLocation || "not visible"}. Transaction: ${receiptScanDraft.transactionNumber || "not visible"}.`,
      rawOcrText: receiptScanForm.rawText,
      lines: receiptScanDraft.items.map((item) => ({
        id: item.id,
        catalogItemId: item.matchedCatalogItemId || item.matchedCatalogId,
        matchedCatalogItemId: item.matchedCatalogItemId || item.matchedCatalogId,
        rawText: item.rawText,
        itemName: item.itemName || item.suggestedMatchName || item.rawText,
        productName: item.suggestedMatchName || item.itemName || item.rawText,
        quantity: Number(item.quantity || 1),
        unitPrice: Number(item.unitCost || 0),
        unitCost: Number(item.unitCost || 0),
        lineTotal: Number(item.totalCost || 0),
        totalCost: Number(item.totalCost || 0),
        destination: receiptItemDbDestination(item),
        confidenceScore: Number(item.matchConfidence || 0),
        matchedConfidence: item.verified ? "confirmed" : "needs_review",
        verified: Boolean(item.verified),
        notes: [item.notes, item.entryTypeLabel ? `Suggested use: ${item.entryTypeLabel}` : "", item.suggestedCategory ? `Category: ${item.suggestedCategory}` : "", item.status === "ignored" ? "Ignored during receipt review." : ""].filter(Boolean).join(" | "),
      })),
      createdAt: receiptScanDraft.createdAt,
    };
    const result = await saveReceiptRecord(forgePhase2Context(), { ...receipt });
    updatePhase2Status(result, "Receipt scan saved locally.");
    if (!BETA_LOCAL_MODE && result.source !== "supabase") {
      setReceiptScanDraft((current) => current ? { ...current, warnings: [...warnings, "Receipt did not sync to Supabase. Review remains unsubmitted."] } : current);
      setReceiptScanMessage(result.error?.message ? `Receipt sync failed: ${result.error.message}` : "Receipt sync failed. Review remains unsubmitted.");
      return;
    }

    const savedReceiptId = result.data?.id || receipt.id;
    const savedReceipt = {
      ...receipt,
      ...(result.data || {}),
      id: savedReceiptId,
      workspaceId: activeForgeWorkspace?.id || activeWorkspace?.id || DEFAULT_PERSONAL_WORKSPACE_ID,
      workspace_id: activeForgeWorkspace?.id || activeWorkspace?.id || DEFAULT_PERSONAL_WORKSPACE_ID,
      workspaceName: activeForgeWorkspace?.name || activeWorkspace?.name || "Forge",
    };
    const savedReceiptLines = (result.lines?.length ? result.lines : receipt.lines.map((line) => ({ ...line, receiptId: savedReceiptId })));
    syncForgeReceiptWorkflowState(savedReceipt, savedReceiptLines);
    const receiptReference = { ...receiptScanDraft, id: savedReceiptId };
    const createdItems = importableItems.map((item) => receiptItemToInventoryRecord(item, receiptReference, receiptItemDbDestination(item)));
    const inventorySaveResult = await saveInventoryRecords(createdItems);
    const savedInventoryItems = inventorySaveResult.saved;
    if (savedInventoryItems.length) setItems((current) => [...savedInventoryItems, ...current]);
    const receiptExpenseRecords = expenseOnlyItems.map((item) => ({
      ...expenseFromReceiptLine(item, { ...receipt, id: savedReceiptId }, {
        id: makeId("receipt-expense"),
        buyer: currentUserProfile?.displayName || currentUserProfile?.fullName || "",
        taxDeductible: false,
      }),
      workspaceId: activeForgeWorkspace?.id || activeWorkspace?.id || DEFAULT_PERSONAL_WORKSPACE_ID,
      workspace_id: activeForgeWorkspace?.id || activeWorkspace?.id || DEFAULT_PERSONAL_WORKSPACE_ID,
      workspaceName: activeForgeWorkspace?.name || activeWorkspace?.name || "Forge",
    }));
    const savedReceiptExpenses = [];
    const receiptExpenseFailures = [];
    if (receiptExpenseRecords.length) {
      if (BETA_LOCAL_MODE || user?.id === "local-beta") {
        savedReceiptExpenses.push(...receiptExpenseRecords);
      } else if (isSupabaseConfigured && supabase && user?.id) {
        const expenseRows = receiptExpenseRecords.map((expense) => ({
          user_id: user.id,
          workspace_id: uuidOrNull(expense.workspaceId),
          date: expense.date || null,
          vendor: expense.vendor,
          category: expense.category,
          subcategory: expense.subcategory,
          buyer: expense.buyer,
          amount: Number(expense.amount || 0),
          payment_method: expense.paymentMethod,
          linked_item_id: null,
          linked_sale_id: null,
          notes: expense.notes,
          receipt_image: expense.receiptImage,
          receipt_photo: expense.receiptImage,
          tax_deductible: Boolean(expense.taxDeductible),
        }));
        const { data: expenseData, error: expenseError } = await supabase.from("business_expenses").insert(expenseRows).select();
        if (expenseError) {
          receiptExpenseFailures.push(expenseError.message || "Could not save receipt expenses.");
        } else {
          savedReceiptExpenses.push(...(expenseData || []).map(mapExpense));
        }
      }
      if (savedReceiptExpenses.length) {
        setExpenses((current) => [...savedReceiptExpenses, ...current]);
      }
    }
    const savedByReceiptLine = new Map();
    savedInventoryItems.forEach((savedItem) => {
      const sourceLine = importableItems.find((item) =>
        normalizeSearchText(item.suggestedMatchName || item.itemName || item.rawText) === normalizeSearchText(savedItem.name || savedItem.itemName)
      );
      if (sourceLine?.id) savedByReceiptLine.set(sourceLine.id, savedItem.id);
    });
    if (result.source === "supabase" && savedByReceiptLine.size && isSupabaseConfigured && supabase) {
      await Promise.all([...savedByReceiptLine.entries()].map(([lineId, inventoryItemId]) => {
        if (!/^[0-9a-f-]{36}$/i.test(String(lineId)) || !/^[0-9a-f-]{36}$/i.test(String(inventoryItemId))) return null;
        return supabase
          .from("receipt_line_items")
          .update({ created_inventory_item_id: inventoryItemId, updated_at: new Date().toISOString() })
          .eq("id", lineId);
      }).filter(Boolean));
    }
    const report = {
      receiptId: savedReceiptId,
      store: receiptScanDraft.storeName,
      date: receiptScanDraft.purchaseDate,
      totalSpent: receiptScanDraft.total,
      itemsAdded: savedInventoryItems.length,
      itemsIgnored: 0,
      expensesAdded: savedReceiptExpenses.length,
      needsFutureReview: receiptScanDraft.items.filter((item) => item.status === "needs_review").length,
      vaultValueAdded: savedInventoryItems.filter((item) => item.vaultStatus || isVaultItemRecord(item)).reduce((sum, item) => sum + Number(item.marketValue || item.marketPrice || 0) * Number(item.quantity || 1), 0),
      forgeInventoryCostAdded: savedInventoryItems.filter((item) => isForgeInventoryItem(item)).reduce((sum, item) => sum + Number(item.unitCost || 0) * Number(item.quantity || 1), 0),
      estimatedMsrpTotal: savedInventoryItems.reduce((sum, item) => sum + Number(item.msrpPrice || 0) * Number(item.quantity || 1), 0),
      estimatedMarketTotal: savedInventoryItems.reduce((sum, item) => sum + Number(item.marketPrice || 0) * Number(item.quantity || 1), 0),
      submittedBy: user?.email || user?.id || "local beta",
      status: inventorySaveResult.failures.length || receiptExpenseFailures.length ? "needs_review" : "submitted",
    };
    if (result.source === "supabase") {
      await retryPhase2Sync();
    }
    setPhase2Data((current) => ({
      ...current,
      receiptReports: [report, ...(current.receiptReports || [])],
    }));
    if (inventorySaveResult.failures.length) {
      const compactFailure = compactInventorySaveFailure(inventorySaveResult.failures);
      setReceiptScanStatus("ready_for_review");
      setReceiptScanDraft((current) => current ? {
        ...current,
        status: "needs_review",
        report,
        warnings: [...warnings, `${inventorySaveResult.failures.length} destination item(s) failed to save.`],
      } : current);
      setReceiptScanMessage(`Receipt synced, but destination save failed: ${compactFailure} Review remains open.`);
      return;
    }
    if (receiptExpenseFailures.length) {
      setReceiptScanStatus("ready_for_review");
      setReceiptScanDraft((current) => current ? {
        ...current,
        status: "needs_review",
        report,
        warnings: [...warnings, `Expense-only line(s) did not save: ${receiptExpenseFailures.join(" | ")}`],
      } : current);
      setReceiptScanMessage(`Receipt synced, but expense-only line(s) did not save: ${receiptExpenseFailures.join(" | ")}`);
      return;
    }
    setReceiptScanStatus("submitted");
    setReceiptScanDraft((current) => current ? { ...current, status: "submitted", report } : current);
    setReceiptScanMessage(result.source === "supabase"
      ? `Receipt submitted and cloud synced. Added ${savedInventoryItems.length} inventory item(s) and ${savedReceiptExpenses.length} expense record(s).`
      : `Receipt saved locally. Added ${savedInventoryItems.length} inventory item(s) and ${savedReceiptExpenses.length} expense record(s).`
    );
  }

  function openPictureLookupFlow(defaultDestination = "none") {
    beginScanProduct(defaultDestination);
    setScanMode("picture");
    setPictureLookup({
      imageUrl: "",
      fileName: "",
      text: "",
      message: "Take or upload a photo, then enter any visible text, UPC/SKU, card number, or product name for a reviewable match.",
    });
  }

  function handlePictureLookupFile(event) {
    const file = event.target.files?.[0];
    if (!file) return;
    setPictureLookup((current) => {
      if (current.imageUrl?.startsWith("blob:")) URL.revokeObjectURL(current.imageUrl);
      return {
        ...current,
        imageUrl: URL.createObjectURL(file),
        fileName: file.name,
        message: `Image preview ready. ${AI_UPLOAD_WARNING} Enter visible text, UPC/SKU, card number, or product name for reviewable matching.`,
      };
    });
  }

  function runPictureLookupSearch() {
    const lookup = String(pictureLookup.text || scanInput || "").trim();
    const clues = detectPhotoLookupClues(lookup);
    void logAiAssistEvent(AI_FEATURE_AREAS.PHOTO_LOOKUP, {
      inputSummary: lookup ? `Visible text clues: ${lookup}` : "No visible text clues entered",
      outputSummary: clues.outputSummary,
      confidenceScore: clues.confidenceScore,
    });
    if (!lookup) {
      setPictureLookup((current) => ({
        ...current,
        message: "No match found - add manually, search with fewer words, or submit it for review.",
      }));
      setScanSearchState("empty");
      setScanMessage("No match found - add manually, search with fewer words, or submit it for review.");
      return;
    }
    setPictureLookup((current) => ({
      ...current,
      message: `${clues.outputSummary} ${AI_REVIEW_DISCLAIMER}`,
    }));
    setScanMode("manual");
    handleCatalogScanMatch(clues.searchText || lookup);
  }

  async function handleCatalogScanMatch(value) {
    const lookupValue = String(value || "").trim();
    if (!lookupValue) {
      setScanMessage("Scan a barcode or enter a product name before searching.");
      setScanReview(null);
      setScanMatches([]);
      setScanSearchState("idle");
      return;
    }
    setScanInput(lookupValue);
    setScanReview(null);
    setScanMatches([]);
    setScanSearchState("loading");
    setScanMessage("Searching for matches...");

    let matches = [];
    const mode = detectCatalogSearchMode(lookupValue);
    const normalizedLookupCode = normalizeBarcodeValue(lookupValue);
    const exactIdentifier = ["barcode", "id"].includes(mode) || isLikelyBarcodeValue(lookupValue);
    const localBarcodeProduct = exactIdentifier ? findCatalogProductByBarcode(catalogProducts, lookupValue) : null;
    if (localBarcodeProduct) {
      matches = [{
        item: localBarcodeProduct,
        score: 1200,
        confidencePercent: 98,
        explanation: "Exact UPC/EAN/GTIN or SKU match",
        reason: "local identifier match",
      }];
    }
    if (isSupabaseConfigured && supabase && lookupValue.length >= 2) {
      try {
        const result = await searchPokemonCatalogOnDemand({
          supabase,
          query: exactIdentifier ? normalizedLookupCode || lookupValue : lookupValue,
          barcode: exactIdentifier ? normalizedLookupCode || lookupValue : "",
          mode: exactIdentifier ? "barcode" : mode,
          page: 1,
          pageSize: 8,
          force: true,
        });
        const remoteMatches = (result.rows || []).map((row, index) => {
          const item = mapCatalog(row);
          const identifiers = catalogIdentifiersForProduct(item);
          const exactMatch = exactIdentifier && identifiers.includes(normalizedLookupCode || normalizeBarcodeValue(lookupValue));
          return {
            item,
            score: exactMatch ? 1000 : Math.max(400, 850 - index * 40),
            confidencePercent: exactMatch ? 98 : Math.max(72, 92 - index * 5),
            explanation: exactMatch ? "Exact catalog identifier match" : `Fast ${result.sourceName || "catalog"} match`,
            reason: result.searchPhase || result.searchMode || "catalog search",
          };
        });
        matches = [...matches, ...remoteMatches].filter((match, index, allMatches) => {
          const id = String(match.item?.id || match.item?.name || index);
          return allMatches.findIndex((candidate) => String(candidate.item?.id || candidate.item?.name || "") === id) === index;
        });
      } catch (error) {
        setScanMessage(error?.message ? `Catalog lookup unavailable. Using local fallback: ${error.message}` : "Catalog lookup unavailable. Using local fallback.");
      }
    }

    if (!matches.length) {
      matches = getBestCatalogMatches(lookupValue, catalogProducts);
    }
    const aiSummary = buildAiCatalogMatchSummary({ query: lookupValue, matches });
    void logAiAssistEvent(AI_FEATURE_AREAS.CATALOG_MATCH, {
      ...aiSummary,
      relatedEntityType: "scanner_intake",
    });
    setScanMatches(matches);
    if (matches.length) {
      setScanReview({ ...buildScanReview(lookupValue, matches, scanDestination), aiSummary: aiSummary.outputSummary });
      setScanSearchState("results");
      setScanMessage(`${aiSummary.outputSummary} Review every match before saving.`);
    } else {
      setScanReview(null);
      setScanSearchState("empty");
      setScanMessage("No match found - add manually, search with fewer words, or submit the product for review.");
    }
  }

  function confirmScanMatch(productId) {
    const match = scanMatches.find((candidate) => String(candidate.item.id) === String(productId));
    if (!match?.item) return;
    setScanReview(buildScanReview(scanReview?.rawValue || scanInput || match.item.name, [match, ...scanMatches.filter((candidate) => String(candidate.item.id) !== String(productId))], scanDestination));
    setScanSearchState("results");
  }

  async function persistScannerIntake(destinationOverride = "", status = "saved") {
    if (blockGuestSave()) return null;
    if (!scanReview) return null;
    const explicitDestination = typeof destinationOverride === "string" ? destinationOverride : "";
    const destination = normalizeAddDestinationValue(explicitDestination || scanDestination || scanReview.destination || "search_only", "none", { allowIgnore: true });
    const destinationMap = {
      tidetradr: "search_only",
      pinned: "wishlist",
      watchlist: "wishlist",
      scout_report: "store_report",
      expense_only: "search_only",
      ignore: "search_only",
    };
    const scanType = scanReview.scanType === "barcode" ? (scanReview.upc ? "upc" : "manual") : scanReview.scanType;
    const session = {
      id: scanReview.scanId || makeId("scan"),
      scanType: ["upc", "sku", "card_image", "sealed_image", "slab_label", "receipt", "shelf_photo", "marketplace_screenshot", "manual"].includes(scanType)
        ? scanType
        : "manual",
      rawValue: scanReview.rawValue || scanInput || "",
      matchedCatalogItemId: scanReview.masterCatalogItemId || scanReview.master_catalog_item_id || "",
      matchConfidence: scanReview.matchConfidence || 0,
      destination: destinationMap[destination] || destination,
      status,
      extractedClues: {
        itemName: scanReview.itemName,
        catalogType: scanReview.catalogType,
        productType: scanReview.productType,
        setName: scanReview.setName,
        upc: scanReview.upc,
        sku: scanReview.sku,
        requestedDestination: destination,
      },
      possibleMatches: (scanReview.possibleMatches || []).slice(0, 5).map((match) => ({
        id: match.item?.id,
        name: match.item?.name || match.item?.productName || match.item?.cardName,
        confidence: match.confidencePercent,
      })),
      createdAt: scanReview.createdAt || new Date().toISOString(),
    };
    setPhase2Data((current) => ({
      ...current,
      scannerIntakeSessions: [session, ...(current.scannerIntakeSessions || []).filter((entry) => entry.id !== session.id)],
    }));
    const result = await saveScannerIntakeSession(phase2Context(), session);
    updatePhase2Status(result, "Scanner intake saved locally.");
    return result;
  }

  function submitScannerCorrection(reason) {
    if (!scanReview) return;
    const hasCatalogMatch = Boolean(scanReview.matchedCatalogItemId);
    const missingProductPrefill = buildMissingProductPrefill({
      query: scanReview.itemName || scanReview.rawValue || scanInput,
      detectedText: scanReview.rawValue || scanInput,
      productType: scanReview.productType,
      setName: scanReview.setName,
      upc: scanReview.upc,
    });
    void logAiAssistEvent(AI_FEATURE_AREAS.MISSING_PRODUCT, {
      inputSummary: missingProductPrefill.inputSummary || scanReview.rawValue || scanInput,
      outputSummary: missingProductPrefill.outputSummary,
      confidenceScore: missingProductPrefill.confidenceScore,
      relatedEntityType: hasCatalogMatch ? "catalog_correction" : "missing_catalog_product",
      relatedEntityId: scanReview.matchedCatalogItemId || "",
    });
    submitUniversalSuggestion({
      suggestionType: hasCatalogMatch ? SUGGESTION_TYPES.CORRECT_CATALOG_PRODUCT : SUGGESTION_TYPES.ADD_MISSING_CATALOG_PRODUCT,
      targetTable: "product_catalog",
      targetId: scanReview.matchedCatalogItemId || "",
      submittedData: {
        reason,
        rawScan: scanReview.rawValue || scanInput || "",
        itemName: missingProductPrefill.productName || scanReview.itemName,
        setName: missingProductPrefill.setName || scanReview.setName,
        productType: missingProductPrefill.productType || scanReview.productType || scanReview.catalogType,
        upc: missingProductPrefill.upc || scanReview.upc,
        sku: scanReview.sku,
        aiPrefillReviewRequired: true,
        source: "scanner_review",
      },
      currentDataSnapshot: {
        matchedCatalogItemId: scanReview.matchedCatalogItemId,
        matchConfidence: scanReview.matchConfidence,
        possibleMatches: (scanReview.possibleMatches || []).slice(0, 3).map((match) => ({
          id: match.item?.id,
          name: match.item?.name || match.item?.productName || match.item?.cardName,
          confidence: match.confidencePercent,
        })),
      },
      notes: `Scanner correction: ${reason}. AI prefill is review-only. User/admin must verify before any catalog change.`,
      source: "user",
    });
    setScanMessage(`${reason} was sent for admin review. ${missingProductPrefill.outputSummary}`);
  }

  function submitScannerNoMatchForReview() {
    const prefill = buildMissingProductPrefill({
      query: scanInput || pictureLookup.text,
      detectedText: pictureLookup.text || scanInput,
    });
    const suggestion = submitSuggestion({
      suggestionType: SUGGESTION_TYPES.ADD_MISSING_CATALOG_PRODUCT,
      targetTable: "product_catalog",
      submittedData: {
        productName: prefill.productName || scanInput || pictureLookup.text || "Unknown scanned item",
        productType: prefill.productType,
        setName: prefill.setName,
        upc: prefill.upc,
        source: "scanner_no_match",
        aiPrefillReviewRequired: true,
      },
      notes: prefill.notes || "Scanner no-match product suggestion. User/admin must review before catalog creation.",
      source: "scanner-no-match",
    });
    void logAiAssistEvent(AI_FEATURE_AREAS.MISSING_PRODUCT, {
      inputSummary: prefill.inputSummary || scanInput || pictureLookup.text,
      outputSummary: prefill.outputSummary,
      confidenceScore: prefill.confidenceScore,
      relatedEntityType: "missing_catalog_product",
      relatedEntityId: suggestion?.suggestion?.id || "",
    });
    setScanMessage(suggestion.ok
      ? `${prefill.outputSummary} Missing product suggestion created for admin review.`
      : "Similar catalog suggestion is already under review.");
  }

  async function confirmScannerDestination(destinationOverride = "") {
    const explicitDestination = typeof destinationOverride === "string" ? destinationOverride : "";
    const destination = normalizeAddDestinationValue(explicitDestination || scanDestination || scanReview?.destination || "none", "none", { allowIgnore: true });
    const productId = scanReview?.matchedCatalogItemId;
    if (!destination || destination === "none") {
      setScanMessage("Choose where this scanned item should go.");
      return;
    }
    if ((destination === "vault" || destination === "forge" || destination === "wishlist") && !productId) {
      setScanMessage("No catalog match yet. Submit the item for review or choose a Market Watch lookup first.");
      return;
    }
    if (destination === "vault" || destination === "forge" || destination === "wishlist") {
      const product = catalogProducts.find((item) => String(item.id) === String(productId))
        || (scanReview?.possibleMatches || []).map((match) => match.item).find((item) => String(item?.id) === String(productId));
      if (!product) {
        setScanMessage("No verified catalog match yet. Search Market Watch, enter UPC/SKU manually, add manually, or suggest a missing product.");
        return;
      }
      if (!guestPreviewActive) {
        await persistScannerIntake(destination, "confirmed");
      }
      closeInventoryScanner();
      return openProductAddFlow({
        product,
        source: "scanner",
        destinations: destinationDefaults({ [destination]: true }),
        seed: {
          catalogSearchQuery: scanReview?.rawValue || scanInput || catalogTitle(product),
        },
      });
    }
    if (destination === "expense_only" || destination === "ignore") {
      if (blockGuestSave()) return;
      await persistScannerIntake(destination, destination === "ignore" ? "discarded" : "confirmed");
      closeInventoryScanner();
      setVaultToast(destination === "ignore"
        ? "Scanner result ignored. No Vault or Forge item was saved."
        : "Scanner result saved as expense-only review. No Vault or Forge item was created.");
      return;
    }
    if (destination === "tidetradr") {
      await persistScannerIntake(destination, "review");
      if (productId) selectTideTradrProduct(productId);
      setActiveTab("market");
    }
    if (destination === "deal_finder") {
      await persistScannerIntake(destination, "review");
      setActiveTab("market");
      if (productId) useCatalogProductInDeal(productId);
      else openDealFinderModal();
    }
    if (destination === "watchlist" || destination === "pinned") {
      await persistScannerIntake(destination, "saved");
      if (productId) addProductToTideTradrWatchlist(productId, destination === "pinned");
      setActiveTab("market");
      setTideTradrSubTab("watch");
    }
    if (destination === "scout_report") {
      await persistScannerIntake(destination, "review");
      openScoutSubmitFlow({ source: "scanner-result" });
    }
    if (destination === "scout_report" || destination === "tidetradr" || destination === "deal_finder" || destination === "watchlist" || destination === "pinned") {
      setShowInventoryScanner(false);
      setScanReview(null);
      setScanMatches([]);
    }
  }

