  function scoutText(value = "") {
    return String(value || "").trim();
  }

  function getScoutQuickStoreId(store = {}) {
    return scoutText(store.id || store.storeId || store.store_id || store.locationId || store.location_id);
  }

  function getScoutQuickStoreName(store = {}) {
    return scoutText(
      store.officialName ||
      store.official_name ||
      store.storeName ||
      store.store_name ||
      store.name ||
      store.locationName ||
      store.location_name ||
      store.nickname ||
      store.storeAlias ||
      store.store_alias
    ) || "Store location";
  }

  function getScoutStoreDisplayName(store = {}) {
    const primaryName = getScoutQuickStoreName(store);
    const retailer = scoutText(store.retailer || store.chain || store.storeGroup || store.store_group || store.banner);
    const nickname = scoutText(store.nickname);
    const address = scoutText(store.address || store.streetAddress || store.street_address);
    const normalizedPrimary = normalizeStoreSearch(primaryName);
    const normalizedRetailer = normalizeStoreSearch(retailer);
    const normalizedNickname = normalizeStoreSearch(nickname);
    const primaryLooksGeneric = normalizedRetailer && (
      normalizedPrimary === normalizedRetailer ||
      normalizedPrimary === "walmart supercenter" ||
      normalizedPrimary === "cvs pharmacy" ||
      normalizedPrimary === "best buy"
    );

    if (primaryLooksGeneric && nickname && normalizedNickname !== normalizedPrimary) {
      return nickname;
    }

    if (primaryLooksGeneric && address) {
      const roadName = address.replace(/^\d+\s+/, "").trim();
      return `${primaryName} - ${roadName || address}`;
    }

    if (
      retailer &&
      primaryName &&
      !normalizedPrimary.includes(normalizedRetailer) &&
      /\b(road|rd|drive|dr|boulevard|blvd|pkwy|parkway|avenue|ave|street|st|lane|ln|commons|center|mall|hilltop|greenbrier|pembroke|redmill|colonial)\b/.test(normalizedPrimary)
    ) {
      return `${retailer} - ${primaryName}`;
    }

    return primaryName;
  }

  function getScoutQuickRetailer(store = {}) {
    return scoutText(store.retailer || store.chain || store.storeGroup || store.store_group || store.banner) || "Retailer";
  }

  function getScoutQuickStoreZip(store = {}) {
    return scoutText(store.zip || store.zipCode || store.zip_code || store.postalCode || store.postal_code);
  }

  function getScoutQuickStoreRegion(store = {}) {
    return scoutText(store.region || store.area || store.county || store.storeRegion || store.store_region);
  }

  function scoutStoreAliasValues(store = {}) {
    const values = [
      store.nickname,
      store.shortName,
      store.short_name,
      store.storeAlias,
      store.store_alias,
      store.localName,
      store.local_name,
      ...(Array.isArray(store.aliases) ? store.aliases : []),
      ...(Array.isArray(store.searchAliases) ? store.searchAliases : []),
      ...(Array.isArray(store.search_aliases) ? store.search_aliases : []),
    ].map(scoutText).filter(Boolean);
    return [...new Map(values.map((value) => [normalizeStoreSearch(value), value])).values()];
  }

  function scoutStoreAliasDisplayValues(store = {}) {
    const officialName = normalizeStoreSearch(getScoutStoreDisplayName(store));
    return scoutStoreAliasValues(store)
      .filter((value) => {
        const normalized = normalizeStoreSearch(value);
        return normalized && normalized !== officialName;
      })
      .slice(0, 3);
  }

  function scoutStoreShorthandLabel(store = {}) {
    const values = scoutStoreAliasDisplayValues(store);
    const storeNumber = scoutText(
      store.storeNumber ||
      store.store_number ||
      store.retailerStoreNumber ||
      store.retailer_store_number ||
      store.locationCode ||
      store.location_code
    );
    if (storeNumber && !values.some((value) => normalizeStoreSearch(value).includes(normalizeStoreSearch(storeNumber)))) {
      values.push(`Store #${storeNumber}`);
    }
    return values.slice(0, 3).join(" / ");
  }

  function scoutStoreLocationSummary(store = {}) {
    const cityStateZip = [
      scoutText(store.city || store.addressCity || store.region),
      scoutText(store.state),
      getScoutQuickStoreZip(store),
    ].filter(Boolean).join(", ").replace(/, ([A-Z]{2}), /, "$1 ");
    return cityStateZip || scoutText(store.address || store.streetAddress || store.street_address) || "Area unknown";
  }

  function scoutStoreRecentSignalLabel(row = {}) {
    const reportCount = Array.isArray(row.reports) ? row.reports.length : 0;
    return reportCount ? `${reportCount} recent signal${reportCount === 1 ? "" : "s"}` : "No recent signals";
  }

  function scoutStoreDistanceAreaLabel(row = {}) {
    if (Number.isFinite(row.distance)) return `${row.distance.toFixed(1)} mi`;
    if (row.areaScore > 0) return "Local area";
    if (row.watchlisted) return "Following";
    return "Area unknown";
  }

  function scoutStoreAreaText(store = {}) {
    return [
      getScoutQuickStoreName(store),
      getScoutQuickRetailer(store),
      store.city,
      store.state,
      getScoutQuickStoreZip(store),
      getScoutQuickStoreRegion(store),
      store.address,
      store.shoppingCenter,
      store.streetAddress,
      store.street_address,
      ...scoutStoreAliasValues(store),
    ].filter(Boolean).join(" ");
  }

  function scoutActiveAreaText() {
    return String(
      locationSettings.manualLocation ||
      locationSettings.selectedSavedLocation ||
      currentUserProfile?.homeArea ||
      currentUserProfile?.home_area ||
      currentUserProfile?.preferredRegion ||
      currentUserProfile?.preferred_region ||
      ""
    ).trim();
  }

  function scoutAreaHints(value = "") {
    const text = normalizeStoreSearch(value);
    const compact = text.replace(/[^a-z0-9]/g, "");
    const hints = new Set();
    if (!text) return hints;
    if (/\b224\d{2}\b|\b225\d{2}\b|\bfredericksburg\b|\bstafford\b|\bspotsylvania\b/.test(text)) {
      ["fredericksburg", "stafford", "spotsylvania", "224", "225"].forEach((item) => hints.add(item));
    }
    if (/\b23[4567]\d{2}\b|\bhampton\b|\bchesapeake\b|\bnorfolk\b|\bvirginia beach\b|\bsuffolk\b|\bnewport news\b|\bportsmouth\b|\b757\b|\bhampton roads\b/.test(text)) {
      ["hampton roads", "757", "chesapeake", "norfolk", "virginia beach", "suffolk", "newport news", "portsmouth", "234", "235", "236", "237"].forEach((item) => hints.add(item));
    }
    if (/\b232\d{2}\b|\b230\d{2}\b|\brichmond\b|\bhenrico\b|\bshort pump\b|\bchesterfield\b/.test(text)) {
      ["richmond", "henrico", "short pump", "chesterfield", "232", "230"].forEach((item) => hints.add(item));
    }
    if (/\b231\d{2}\b|\bwilliamsburg\b|\byorktown\b|\bnew kent\b/.test(text)) {
      ["williamsburg", "yorktown", "new kent", "231"].forEach((item) => hints.add(item));
    }
    if (compact.length >= 3) hints.add(compact);
    return hints;
  }

  function scoutStoreSearchScore(row = {}, query = "") {
    const search = normalizeStoreSearch(query);
    if (!search) return 0;
    const store = row.store || row;
    const haystack = normalizeStoreSearch(scoutStoreAreaText(store));
    const compactSearch = search.replace(/[^a-z0-9]/g, "");
    const compactHaystack = haystack.replace(/[^a-z0-9]/g, "");
    const aliases = scoutStoreAliasValues(store).map((value) => normalizeStoreSearch(value));
    const name = normalizeStoreSearch(row.name || getScoutQuickStoreName(store));
    const retailer = normalizeStoreSearch(row.retailer || getScoutQuickRetailer(store));
    let score = 0;
    if (aliases.some((alias) => alias === search || alias.replace(/[^a-z0-9]/g, "") === compactSearch)) score += 900;
    if (name === search || name.replace(/[^a-z0-9]/g, "") === compactSearch) score += 760;
    if (name.includes(search)) score += 420;
    if (retailer === search || retailer.includes(search)) score += 260;
    if (compactSearch && compactHaystack.includes(compactSearch)) score += 220;
    const tokens = search.split(/\s+/).filter((token) => token.length > 2);
    score += tokens.filter((token) => haystack.includes(token) || compactHaystack.includes(token.replace(/[^a-z0-9]/g, ""))).length * 48;
    return score;
  }

  function scoutStoreAreaScore(row = {}, areaText = "", query = "") {
    const store = row.store || row;
    const areaHints = scoutAreaHints(areaText);
    const queryHints = scoutAreaHints(query);
    const haystack = normalizeStoreSearch(scoutStoreAreaText(store));
    const compactHaystack = haystack.replace(/[^a-z0-9]/g, "");
    let score = 0;
    areaHints.forEach((hint) => {
      if (!hint) return;
      const compactHint = String(hint).replace(/[^a-z0-9]/g, "");
      if (haystack.includes(hint) || (compactHint && compactHaystack.includes(compactHint))) score += 120;
    });
    queryHints.forEach((hint) => {
      if (!hint) return;
      const compactHint = String(hint).replace(/[^a-z0-9]/g, "");
      if (haystack.includes(hint) || (compactHint && compactHaystack.includes(compactHint))) score += 260;
    });
    if (Number.isFinite(row.distance)) score += Math.max(0, 90 - row.distance * 4);
    if (row.watchlisted) score += 70;
    if ((row.reports || []).length) score += Math.min(60, row.reports.length * 12);
    return score;
  }

  function scoutStoreMatchesLookup(row = {}, query = "") {
    const search = normalizeStoreSearch(query);
    if (!search) return true;
    return storeMatchesSearch(row.store || row, query) || scoutStoreSearchScore(row, query) > 0;
  }

  function getScoutQuickStores(options = {}) {
    const seen = new Set();
    const reportStores = [...(scoutSnapshot.reports || []), ...(scoutSnapshot.tidepoolReports || [])]
      .map((report) => ({
        id: report.storeId || report.store_id || "",
        name: report.storeName || report.store_name || "",
        nickname: report.storeName || report.store_name || "",
        retailer: report.retailer || report.chain || "",
        chain: report.retailer || report.chain || "",
        city: report.city || "",
        address: report.address || "",
        region: report.region || "",
        source: "scout-report",
      }))
      .filter((store) => store.name || store.id);
    const deduped = [...(scoutSnapshot.stores || []), ...reportStores, ...SCOUT_KNOWN_LOCAL_STORE_SEED, ...virginiaStoreSeed]
      .filter(Boolean)
      .filter((store, index) => {
        const key = String(getScoutQuickStoreId(store) || `${getScoutQuickRetailer(store)}-${getScoutQuickStoreName(store)}-${store.city || index}`).toLowerCase();
        if (seen.has(key)) return false;
        seen.add(key);
        return true;
      });
    return filterStoresForScoutPicker(deduped, { admin: Boolean(options.admin) });
  }

  function findScoutQuickStore(storeLike = {}, options = {}) {
    const explicitId = getScoutQuickStoreId(storeLike);
    const storeName = scoutText(storeLike.storeName || storeLike.store_name || storeLike.nickname || storeLike.name || storeLike.locationName || storeLike.location_name).toLowerCase();
    const retailer = scoutText(storeLike.retailer || storeLike.chain || storeLike.storeGroup || storeLike.store_group || storeLike.banner).toLowerCase();
    const stores = getScoutQuickStores(options);
    if (explicitId) return stores.find((store) => getScoutQuickStoreId(store) === explicitId) || null;
    if (!storeName) return null;
    return stores.find((store) => {
      const candidateName = getScoutQuickStoreName(store).toLowerCase();
      const candidateRetailer = getScoutQuickRetailer(store).toLowerCase();
      return candidateName === storeName && (!retailer || candidateRetailer === retailer);
    }) || null;
  }

  function buildQuickScoutStoreDraft(store = {}) {
    if (!store || !Object.keys(store).length) return {};
    const storeId = getScoutQuickStoreId(store);
    return {
      storeId,
      storeName: getScoutStoreDisplayName(store),
      retailer: getScoutQuickRetailer(store),
      city: store.city || store.addressCity || store.region || "",
      address: store.address || store.streetAddress || "",
      state: store.state || store.province || "",
      zip: getScoutQuickStoreZip(store),
      region: getScoutQuickStoreRegion(store),
      manualLocation: "",
      manualLocationOpen: false,
      storeSearch: "",
      storeConfirmed: Boolean(storeId),
    };
  }

  function resolveQuickScoutStoreSelection(form = quickScoutReportForm) {
    const storeId = getScoutQuickStoreId({ id: form.storeId });
    const manualLocation = scoutText(form.manualLocation);
    const formStoreName = scoutText(form.storeName);
    const formRetailer = scoutText(form.retailer);
    if (storeId) {
      const matchedStore = findScoutQuickStore({ id: storeId });
      if (!matchedStore && !formStoreName) {
        return {
          valid: false,
          message: "Selected store could not be found. Choose the store again before submitting.",
          storeId,
        };
      }
      const store = matchedStore || {
        id: storeId,
        storeId,
        name: formStoreName,
        nickname: formStoreName,
        retailer: formRetailer || "Retailer",
        city: form.city || "",
        address: form.address || "",
      };
      return {
        valid: true,
        mode: "known",
        store,
        storeId,
        storeName: getScoutStoreDisplayName(store),
        retailer: getScoutQuickRetailer(store),
        city: store.city || form.city || "",
        address: store.address || form.address || "",
        state: store.state || form.state || "",
        zip: getScoutQuickStoreZip(store) || form.zip || "",
        region: getScoutQuickStoreRegion(store) || form.region || "",
        needsStoreReview: false,
      };
    }
    const manualName = manualLocation || formStoreName;
    if (manualName) {
      const store = {
        id: "",
        storeId: "",
        name: manualName,
        nickname: manualName,
        retailer: formRetailer || "Manual",
        city: form.city || "",
        address: form.address || "",
      };
      return {
        valid: true,
        mode: "manual",
        store,
        storeId: "",
        storeName: manualName,
        retailer: formRetailer || "Manual",
        city: form.city || "",
        address: form.address || "",
        state: form.state || "",
        zip: form.zip || "",
        region: form.region || "",
        needsStoreReview: true,
      };
    }
    return {
      valid: false,
      message: "Choose the store or enter a manual store/location before saving.",
      storeId: "",
    };
  }

  function updateQuickScoutReportForm(field, value) {
    setQuickScoutReportMessage("");
    setQuickScoutReportForm((current) => {
      const next = { ...current, [field]: value };
      if (field === "dateMode") {
        if (value === "today") next.reportDate = getLocalDateInputKey();
        if (value === "yesterday") next.reportDate = getYesterdayDateInputKey();
      }
      if (field === "reportDate") {
        next.dateMode = value === getLocalDateInputKey()
          ? "today"
          : value === getYesterdayDateInputKey()
            ? "yesterday"
            : "pick_date";
        const parsedDate = new Date(`${value}T00:00:00`);
        if (!Number.isNaN(parsedDate.getTime())) next.dayOfWeek = SCOUT_WEEKDAYS[parsedDate.getDay()];
      }
      if (field === "reportType") {
        const nextType = SCOUT_QUICK_REPORT_TYPES.find((option) => option.value === value);
        next.visibility = nextType?.isGuess ? normalizeScoutGuessVisibility(current.visibility || "private") : normalizeScoutReportVisibility(current.visibility || "public");
        if (nextType?.isGuess) next.dateMode = current.dateMode === "today" ? "day_only" : current.dateMode;
      }
      if (["storeId", "storeName", "retailer", "city", "address", "state", "zip", "region", "manualLocation"].includes(field)) {
        next.storeConfirmed = false;
      }
      return next;
    });
  }

  function applyQuickScoutReportTimePreset(preset = "now") {
    if (preset === "pick_date") {
      setQuickScoutReportMessage("");
      setQuickScoutReportForm((current) => ({
        ...current,
        dateMode: "pick_date",
        reportDate: current.reportDate || getLocalDateInputKey(),
        reportTime: current.reportTime || getLocalTimeKey(),
      }));
      return;
    }
    const date = new Date();
    if (preset === "earlier_today") date.setHours(Math.max(0, date.getHours() - 2));
    if (preset === "yesterday") date.setDate(date.getDate() - 1);
    setQuickScoutReportMessage("");
    setQuickScoutReportForm((current) => ({
      ...current,
      dateMode: preset === "yesterday" ? "yesterday" : preset === "earlier_today" ? "earlier_today" : "today",
      reportDate: getLocalDateInputKey(date),
      reportTime: getLocalTimeKey(date),
      dayOfWeek: SCOUT_WEEKDAYS[date.getDay()],
    }));
  }

  function selectQuickScoutReportStore(store = {}) {
    setQuickScoutReportMessage("");
    setQuickScoutReportForm((current) => ({ ...current, ...buildQuickScoutStoreDraft(store), storeConfirmed: true }));
  }

  function quickScoutReportTypeMeta(value = quickScoutReportForm.reportType) {
    return SCOUT_QUICK_REPORT_TYPES.find((option) => option.value === value) || SCOUT_QUICK_REPORT_TYPES[0];
  }

  function quickScoutStockLeftLabel(value = quickScoutReportForm.stockLeft) {
    const option = SCOUT_QUICK_STOCK_LEFT_OPTIONS.find((item) => item.value === value);
    return option ? option.label : "Not sure";
  }

  function quickScoutProofLabel(value = quickScoutReportForm.proofType) {
    const option = SCOUT_QUICK_PROOF_TYPES.find((item) => item.value === value);
    return option ? option.label : "Manual";
  }

  function quickScoutDateLabel(form = quickScoutReportForm) {
    if (form.dateMode === "not_sure") return "Not sure";
    if (form.dateMode === "day_only") return form.dayOfWeek || "Day not selected";
    if (form.dateMode === "earlier_today") return `${form.reportDate || getLocalDateInputKey()} at ${form.reportTime || "earlier today"}`;
    const dateLabel = form.dateMode === "yesterday" ? getYesterdayDateInputKey() : form.reportDate || getLocalDateInputKey();
    return `${dateLabel}${form.reportTime ? ` at ${form.reportTime}` : ""}`;
  }

  function quickScoutVisitDateTimeValue(form = quickScoutReportForm) {
    const date = form.reportDate || getLocalDateInputKey();
    const time = form.reportTime || getLocalTimeKey();
    return `${String(date).slice(0, 10)}T${String(time || "00:00").slice(0, 5)}`;
  }

  function updateQuickScoutVisitDateTime(value = "") {
    const [date = "", time = ""] = String(value || "").split("T");
    setQuickScoutReportMessage("");
    setQuickScoutReportForm((current) => {
      const parsedDate = date ? new Date(`${date}T00:00:00`) : null;
      const next = {
        ...current,
        reportDate: date,
        reportTime: time.slice(0, 5),
        dateMode: date === getLocalDateInputKey()
          ? "today"
          : date === getYesterdayDateInputKey()
            ? "yesterday"
            : "pick_date",
      };
      if (parsedDate && !Number.isNaN(parsedDate.getTime())) next.dayOfWeek = SCOUT_WEEKDAYS[parsedDate.getDay()];
      return next;
    });
  }

  function parseScoutVisitDateTime(date = "", time = "") {
    const dateText = String(date || "").slice(0, 10);
    const timeText = String(time || "").slice(0, 5);
    if (!dateText || !timeText) return { ok: false, message: "Add a visit date and time before submitting." };
    const parsed = new Date(`${dateText}T${timeText}`);
    if (Number.isNaN(parsed.getTime())) return { ok: false, message: "Use a valid visit date and time." };
    return {
      ok: true,
      date: dateText,
      time: timeText,
      parsed,
      iso: parsed.toISOString(),
    };
  }

  function validateScoutVisitDateTime(form = quickScoutReportForm, options = {}) {
    const parsed = parseScoutVisitDateTime(form.reportDate, form.reportTime);
    if (!parsed.ok) return parsed;
    const nowMs = Date.now();
    const futureMs = parsed.parsed.getTime() - nowMs;
    const oldMs = nowMs - parsed.parsed.getTime();
    if (futureMs > SCOUT_VISIT_TIME_FUTURE_GRACE_MS) {
      return {
        ...parsed,
        ok: Boolean(options.allowFutureConfirmation),
        needsFutureConfirmation: Boolean(options.allowFutureConfirmation),
        message: "Visit time is in the future. Use a past visit time unless an admin is correcting the report.",
      };
    }
    return {
      ...parsed,
      oldBackfill: oldMs > SCOUT_BACKFILL_OLD_DAYS * 24 * 60 * 60 * 1000,
    };
  }

  function scoutReportObservedAt(report = {}) {
    if (report.observedAt || report.observed_at) return report.observedAt || report.observed_at;
    if (report.report_time && String(report.report_time).includes("T")) return report.report_time;
    if (report.reportedAt || report.reported_at) return report.reportedAt || report.reported_at;
    if (report.reportDate || report.report_date) {
      const parsed = new Date(`${String(report.reportDate || report.report_date).slice(0, 10)}T${String(report.reportTime || report.time || "00:00").slice(0, 5)}`);
      if (!Number.isNaN(parsed.getTime())) return parsed.toISOString();
    }
    return report.createdAt || report.created_at || report.submittedAt || report.submitted_at || "";
  }

  function scoutReportSubmittedAt(report = {}) {
    return report.submittedAt || report.submitted_at || report.createdAt || report.created_at || report.reportedAt || report.reported_at || "";
  }

  function scoutReportFreshnessMeta(report = {}) {
    const rawStatus = String(report.status || report.verificationStatus || report.verification_status || "").toLowerCase();
    const expiresAt = report.expiresAt || report.expires_at || "";
    if (rawStatus.includes("expired") || rawStatus.includes("stale")) {
      return { key: "expired", label: rawStatus.includes("stale") ? "Old" : "Expired", helper: "This report should not be treated as current stock." };
    }
    if (expiresAt) {
      const expiresTime = new Date(expiresAt).getTime();
      if (!Number.isNaN(expiresTime) && expiresTime < Date.now()) {
        return { key: "expired", label: "Expired", helper: "This report is past its configured freshness window." };
      }
    }
    const rawTimestamp = scoutReportObservedAt(report);
    if (!rawTimestamp) return { key: "unknown", label: "Freshness unknown", helper: "Visit time was not added." };
    const observedTime = new Date(rawTimestamp).getTime();
    if (Number.isNaN(observedTime)) return { key: "unknown", label: "Freshness unknown", helper: "Visit time could not be read." };
    const ageMs = Date.now() - observedTime;
    if (ageMs < 0) return { key: "fresh", label: "Fresh", helper: "Visit time is very recent." };
    const ageHours = ageMs / 3600000;
    if (ageHours < 2) return { key: "fresh", label: "Fresh", helper: "Reported under 2 hours ago." };
    if (ageHours <= 8) return { key: "aging", label: "Aging", helper: "Reported 2 to 8 hours ago; confirm before relying on it." };
    return { key: "old", label: "Old", helper: "Reported over 8 hours ago; do not treat as live stock." };
  }

  function scoutReportDateTimeInputValue(report = {}) {
    const observedAt = scoutReportObservedAt(report);
    const parsed = observedAt ? new Date(observedAt) : new Date();
    return getLocalDateTimeInputValue(Number.isNaN(parsed.getTime()) ? new Date() : parsed);
  }

  function normalizeScoutReportVisibility(value = "") {
    const normalized = String(value || "").toLowerCase();
    if (["public", "public_cleaned", "community", "community_report"].includes(normalized)) return "public";
    if (["admin_only", "admin review only"].includes(normalized)) return "admin_only";
    return "private_from_map";
  }

  function normalizeScoutGuessVisibility(value = "") {
    const normalized = String(value || "").toLowerCase();
    if (["public", "public_cleaned", "community"].includes(normalized)) return "public";
    if (["shared", "shared_with_team", "team"].includes(normalized)) return "shared";
    return "private";
  }

  function scoutVisibilityOptionLabel(value = "", isGuess = false) {
    const options = isGuess ? SCOUT_GUESS_VISIBILITY_OPTIONS : SCOUT_REPORT_VISIBILITY_OPTIONS;
    return options.find((option) => option.value === value)?.label || value.replace(/_/g, " ");
  }

  function scoutConfidenceScore(value = "") {
    const normalized = String(value || "").toLowerCase();
    if (normalized === "admin_reviewed" || normalized === "admin-reviewed") return 96;
    if (normalized === "verified") return 95;
    if (normalized === "confirmed") return 95;
    if (normalized === "community_confirmed" || normalized === "community-confirmed") return 82;
    if (normalized === "photo" || normalized === "photo_attached") return 62;
    if (normalized === "likely") return 72;
    if (normalized === "needs_confirmation") return 56;
    if (normalized === "possible") return 48;
    if (normalized === "unverified_historical") return 25;
    if (normalized === "historical") return 25;
    if (normalized === "unconfirmed") return 34;
    if (normalized === "rumor") return 30;
    if (normalized === "guess") return 22;
    return 40;
  }

  function scoutConfidenceBadgeMeta(value = "unconfirmed") {
    const key = String(value || "").toLowerCase();
    if (["strong", "strong_confidence", "strong-confidence"].includes(key)) {
      return {
        key: "strong-confidence",
        label: "Strong confidence",
        helper: "Proof, reporter history, or matching community reports make this signal strong.",
        score: 84,
      };
    }
    if (["fair", "fair_confidence", "fair-confidence", "likely", "medium"].includes(key)) {
      return {
        key: "fair-confidence",
        label: "Fair confidence",
        helper: "Useful signal with some support, but another report or proof would make it stronger.",
        score: 62,
      };
    }
    if (["new", "new_report", "new-report", "unconfirmed", "unverified"].includes(key)) {
      return {
        key: "new-report",
        label: "New report",
        helper: "Fresh user-observed report. It can improve as proof or confirmations are added.",
        score: 40,
      };
    }
    if (["low", "low_confidence", "low-confidence", "rumor"].includes(key)) {
      return {
        key: "low-confidence",
        label: "Low confidence",
        helper: "Plausible, but there is little proof or history behind it yet.",
        score: 28,
      };
    }
    if (["conflicting", "conflicting_reports", "conflicting-reports", "disputed"].includes(key)) {
      return {
        key: "conflicting-reports",
        label: "Conflicting reports",
        helper: "Recent reports for the same store disagree. Check details before relying on it.",
        score: 24,
      };
    }
    if (["unusual", "needs_review", "unusual_needs_review", "unusual-needs-review", "pending"].includes(key)) {
      return {
        key: "unusual-needs-review",
        label: "Unusual / needs review",
        helper: "Saved, but routed to moderation because it is unusual or needs more context.",
        score: 32,
      };
    }
    if (["stale", "expired", "stale_expired", "stale-expired"].includes(key)) {
      return {
        key: "stale-expired",
        label: "Stale / expired",
        helper: "Too old to treat as current stock. Kept for history only.",
        score: 12,
      };
    }
    if (key === "admin_reviewed" || key === "admin-reviewed") {
      return {
        key: "admin-reviewed",
        label: "Strong confidence",
        helper: "Reviewed by an Ember & Tide admin or moderator.",
        score: 96,
      };
    }
    if (key === "verified" || key === "confirmed" || key === "high") {
      return {
        key: "verified",
        label: "Strong confidence",
        helper: "Confirmed by admin review, trusted confirmation, or verified source.",
        score: 95,
      };
    }
    if (key === "community_confirmed" || key === "community-confirmed") {
      return {
        key: "community-confirmed",
        label: "Verified by community",
        helper: "Multiple Scout signals support this report.",
        score: 82,
      };
    }
    if (key === "photo" || key === "photo_attached") {
      return {
        key: "fair-confidence",
        label: "Fair confidence",
        helper: "Proof is attached, but the community can still confirm it.",
        score: 62,
      };
    }
    if (key === "historical" || key === "unverified_historical") {
      return {
        key: "historical",
        label: "Historical import",
        helper: historicalScoutImportNotice(),
        score: 25,
      };
    }
    return {
      key: "new-report",
      label: "New report",
      helper: "Fresh user-observed report. It can improve as proof or confirmations are added.",
      score: 34,
    };
  }

  function scoutQuickReportTypeLabel(value = "") {
    const normalized = String(value || "").toLowerCase();
    const match = SCOUT_QUICK_REPORT_TYPES.find((option) => option.value === normalized || option.stockStatus === normalized || option.reportType?.toLowerCase() === normalized);
    if (match) return match.label;
    return scoutStockStatusLabel(value) || String(value || "").replace(/_/g, " ").replace(/\b\w/g, (letter) => letter.toUpperCase());
  }

  function scoutReportObservationStatusLabel(report = {}) {
    const quickType = report.quickReportType || report.quick_report_type || report.reportStatus || report.report_status || "";
    const quickLabel = report.quickReportLabel || report.quick_report_label || scoutQuickReportTypeLabel(quickType);
    if (quickLabel) return quickLabel;
    return scoutStockStatusLabel(report.stockStatus || report.stock_status || report.reportType || report.report_type) || "Store report";
  }

  function scoutReportLooksSpammy(report = {}) {
    const text = [
      report.notes,
      report.note,
      report.reportText,
      report.report_text,
      report.proofText,
      report.storeName,
      report.store_name,
    ].filter(Boolean).join(" ").toLowerCase();
    return /buy followers|free crypto|airdrop|casino|adult\s+link|spam\.|https?:\/\/.*(casino|crypto|airdrop|adult)/i.test(text);
  }

  function scoutReportStatusIsPositive(value = "") {
    return /stock|vendor|purchase|in_stock|behind_counter|limit|line|crowd|restock/.test(String(value || "").toLowerCase());
  }

  function scoutReportStatusIsEmpty(value = "") {
    return /no_stock|empty|sold out|sold_out/.test(String(value || "").toLowerCase());
  }

  function evaluateScoutReportReliability(report = {}, options = {}) {
    if (isHistoricalScoutImport(report)) return scoutConfidenceBadgeMeta("historical");
    const proofType = String(report.proofType || report.proof_type || "").toLowerCase();
    const photoCount = scoutReportPhotoUrls(report).length;
    const receiptProof = proofType === "receipt" || /receipt/i.test(`${report.notes || ""} ${report.proofText || report.proof_text || ""}`);
    const hasStrongProof = receiptProof || photoCount > 0 || ["stock_photo", "screenshot"].includes(proofType);
    const reportId = getScoutReportId(report);
    const store = getScoutReportStore(report);
    const storeId = report.storeId || report.store_id || store.id || "";
    const sameStoreReports = (options.sameStoreReports || (storeId ? scoutReportsByStore[String(storeId)] || [] : []))
      .filter((candidate) => String(getScoutReportId(candidate)) !== String(reportId));
    const observedMs = new Date(scoutReportObservedAt(report) || report.createdAt || report.created_at || Date.now()).getTime();
    const recentWindowMs = 8 * 60 * 60 * 1000;
    const currentStatus = report.quickReportType || report.quick_report_type || report.reportStatus || report.report_status || report.stockStatus || report.stock_status || "";
    const similarRecent = sameStoreReports.filter((candidate) => {
      const candidateObservedMs = new Date(scoutReportObservedAt(candidate) || candidate.createdAt || candidate.created_at || 0).getTime();
      if (!Number.isFinite(candidateObservedMs) || Math.abs(observedMs - candidateObservedMs) > recentWindowMs) return false;
      const candidateStatus = candidate.quickReportType || candidate.quick_report_type || candidate.reportStatus || candidate.report_status || candidate.stockStatus || candidate.stock_status || "";
      return scoutReportStatusIsPositive(currentStatus) === scoutReportStatusIsPositive(candidateStatus)
        && scoutReportStatusIsEmpty(currentStatus) === scoutReportStatusIsEmpty(candidateStatus);
    });
    const conflictingRecent = sameStoreReports.filter((candidate) => {
      const candidateObservedMs = new Date(scoutReportObservedAt(candidate) || candidate.createdAt || candidate.created_at || 0).getTime();
      if (!Number.isFinite(candidateObservedMs) || Math.abs(observedMs - candidateObservedMs) > recentWindowMs) return false;
      const candidateStatus = candidate.quickReportType || candidate.quick_report_type || candidate.reportStatus || candidate.report_status || candidate.stockStatus || candidate.stock_status || "";
      return (scoutReportStatusIsPositive(currentStatus) && scoutReportStatusIsEmpty(candidateStatus))
        || (scoutReportStatusIsEmpty(currentStatus) && scoutReportStatusIsPositive(candidateStatus));
    });
    const reporterScore = Number(report.reporterReputation || report.reporter_reputation || report.trustScore || report.trust_score || 0);
    const reporterPoints = Number(report.scoutPointsAtSubmit || report.scout_points_at_submit || scoutGuessPoints || 0);
    const freshness = scoutReportFreshnessMeta(report);
    const unusual = Boolean(report.needsReview || report.needs_review || options.needsReview || String(report.sourceType || report.source_type || "").includes("employee_tip"));
    const spammy = scoutReportLooksSpammy(report);
    const reasons = [];
    let score = 34;
    if (hasStrongProof) {
      score += receiptProof ? 28 : 22;
      reasons.push(receiptProof ? "Receipt proof attached" : "Photo/proof attached");
    }
    if (reporterScore >= 85 || reporterPoints >= MIN_SCOUT_POINTS_FOR_GUESS) {
      score += 18;
      reasons.push("Reporter has Scout history");
    } else if (reporterPoints > 0) {
      score += 8;
      reasons.push("Reporter has some Scout points");
    }
    if (similarRecent.length) {
      score += Math.min(24, similarRecent.length * 12);
      reasons.push("Similar recent community report");
    }
    if (sameStoreReports.length >= 3) {
      score += 8;
      reasons.push("Store has report history");
    }
    if (conflictingRecent.length) {
      score -= 34;
      reasons.push("Conflicts with a recent report");
    }
    if (freshness.key === "old" || freshness.key === "expired") {
      score -= 36;
      reasons.push("Report is outside the fresh window");
    }
    if (unusual) {
      score -= 8;
      reasons.push("Needs moderator context");
    }
    if (spammy) {
      score = 0;
      reasons.push("Possible spam or unsafe content");
    }
    score = Math.max(0, Math.min(96, score));
    if (spammy) return { ...scoutConfidenceBadgeMeta("unusual-needs-review"), score, hidden: true, needsReview: true, reasons };
    if (freshness.key === "old" || freshness.key === "expired") return { ...scoutConfidenceBadgeMeta("stale-expired"), score, needsReview: false, reasons };
    if (conflictingRecent.length) return { ...scoutConfidenceBadgeMeta("conflicting-reports"), score, needsReview: true, reasons };
    if (Number(report.confirmationCount || report.confirmation_count || report.communityConfirmations || report.community_confirmations || 0) >= 2 || similarRecent.length >= 2) {
      return { ...scoutConfidenceBadgeMeta("community_confirmed"), score: Math.max(score, 82), needsReview: false, reasons };
    }
    if (unusual) return { ...scoutConfidenceBadgeMeta("unusual-needs-review"), score, needsReview: true, reasons };
    if (score >= 78) return { ...scoutConfidenceBadgeMeta("strong-confidence"), score, needsReview: false, reasons };
    if (score >= 52) return { ...scoutConfidenceBadgeMeta("fair-confidence"), score, needsReview: false, reasons };
    if (score >= 32) return { ...scoutConfidenceBadgeMeta("new-report"), score, needsReview: false, reasons };
    return { ...scoutConfidenceBadgeMeta("low-confidence"), score, needsReview: false, reasons };
  }

  function scoutPointsForReport(report = {}) {
    const reliability = evaluateScoutReportReliability(report);
    if (reliability.hidden) return 0;
    let points = 6;
    const proofType = String(report.proofType || report.proof_type || "").toLowerCase();
    const photoCount = scoutReportPhotoUrls(report).length;
    if (photoCount || ["stock_photo", "screenshot"].includes(proofType)) points += 4;
    if (proofType === "receipt") points += 6;
    if (normalizeScoutReportItems(report).length) points += 3;
    if (report.quantitySeen || report.quantity_estimate || report.price || report.price_seen) points += 2;
    if (["strong-confidence", "community-confirmed"].includes(reliability.key)) points += 3;
    if (["conflicting-reports", "unusual-needs-review", "low-confidence"].includes(reliability.key)) points = Math.max(2, points - 3);
    return Math.max(0, Math.min(20, points));
  }

  function awardScoutReportPoints(profile = {}, report = {}) {
    const points = scoutPointsForReport(report);
    const now = new Date().toISOString();
    const proofAttached = Boolean(scoutReportPhotoUrls(report).length || ["stock_photo", "receipt", "screenshot"].includes(String(report.proofType || report.proof_type || "").toLowerCase()));
    return {
      ...(profile || {}),
      scoutPoints: Number(profile?.scoutPoints || profile?.scout_points || 0) + points,
      scout_points: Number(profile?.scout_points || profile?.scoutPoints || 0) + points,
      rewardPoints: Number(profile?.rewardPoints || profile?.reward_points || 0) + points,
      reward_points: Number(profile?.reward_points || profile?.rewardPoints || 0) + points,
      reportStreak: Math.max(1, Number(profile?.reportStreak || profile?.report_streak || 0) + 1),
      report_streak: Math.max(1, Number(profile?.report_streak || profile?.reportStreak || 0) + 1),
      proofReportCount: Number(profile?.proofReportCount || profile?.proof_report_count || 0) + (proofAttached ? 1 : 0),
      proof_report_count: Number(profile?.proof_report_count || profile?.proofReportCount || 0) + (proofAttached ? 1 : 0),
      lastReportDate: now,
      last_report_date: now,
    };
  }

  function quickScoutStoreHasHistory(storeSelection = resolveQuickScoutStoreSelection()) {
    const store = storeSelection.store || {};
    const storeId = storeSelection.storeId || getScoutQuickStoreId(store);
    const historyRows = storeId ? scoutReportsByStore[String(storeId)] || [] : [];
    return Boolean(
      historyRows.length ||
      store.lastReport ||
      store.lastReportDate ||
      store.lastConfirmedReport ||
      store.bestCheckWindow ||
      store.restockWindow ||
      store.truckDays
    );
  }

  function quickScoutConfidenceBadge(form = quickScoutReportForm, type = quickScoutReportTypeMeta(form.reportType), storeSelection = resolveQuickScoutStoreSelection(form)) {
    const draft = {
      quickReportType: type?.value,
      reportStatus: type?.value,
      stockStatus: type?.stockStatus,
      sourceType: type?.sourceType,
      proofType: form.proofType,
      photoUrls: form.photoUrl ? [form.photoUrl] : [],
      notes: [form.note, form.proofText].filter(Boolean).join(" | "),
      storeId: storeSelection.storeId,
      storeName: storeSelection.storeName,
      retailer: storeSelection.retailer,
      needsReview: Boolean(type?.needsReview || storeSelection.needsStoreReview),
      observedAt: quickScoutVisitDateTimeValue(form),
      scoutPointsAtSubmit: scoutGuessPoints,
    };
    return evaluateScoutReportReliability(draft, { needsReview: Boolean(type?.needsReview || storeSelection.needsStoreReview) });
  }

  function quickScoutNormalizedReportType(type = quickScoutReportTypeMeta()) {
    if (type.value === "no_stock") return "no_stock";
    if (type.value === "line_queue_seen") return "line_seen";
    if (type.value === "restock_happening_now" || type.value === "stock_on_shelf" || type.value === "confirmed_purchase" || type.value === "behind_counter") return "restock";
    if (type.value === "truck_vendor_seen" || type.value === "vendor_seen") return "vendor_seen";
    if (type.value === "online_stock_changed") return "online_drop";
    if (type.stockStatus === "low_stock") return "low_stock";
    return "other";
  }

  function quickScoutHasMeaningfulReportDetail(form = quickScoutReportForm) {
    return Boolean(
      scoutText(form.productCategory) ||
      scoutText(form.productName) ||
      scoutText(form.catalogProductName) ||
      scoutText(form.note) ||
      scoutText(form.proofText) ||
      scoutText(form.photoUrl)
    );
  }

  function quickScoutReportReady() {
    const currentType = quickScoutReportTypeMeta();
    const storeSelection = resolveQuickScoutStoreSelection();
    const visitValidation = currentType.isGuess
      ? { ok: true }
      : validateScoutVisitDateTime(quickScoutReportForm, { allowFutureConfirmation: adminEditModeActive });
    return Boolean(
      quickScoutReportForm.reportType &&
      quickScoutReportForm.proofType &&
      storeSelection.valid &&
      visitValidation.ok &&
      (currentType.isGuess || quickScoutHasMeaningfulReportDetail())
    );
  }

  function quickScoutStoreNeedsReviewConfirmation(form = quickScoutReportForm) {
    const storeSelection = resolveQuickScoutStoreSelection(form);
    return Boolean(storeSelection.valid && storeSelection.needsStoreReview && !form.storeConfirmed);
  }

  function scoutWizardStepError(stepKey = quickScoutReportStep) {
    const currentType = quickScoutReportTypeMeta();
    if (currentType.isGuess && !currentUserCanSubmitScoutGuess && ["details", "review"].includes(stepKey)) return DROP_RADAR_GUESS_LOCKED_MESSAGE;
    if (stepKey === "where" || stepKey === "essentials") {
      const storeSelection = resolveQuickScoutStoreSelection();
      if (!storeSelection.valid) return storeSelection.message;
      if (quickScoutStoreNeedsReviewConfirmation()) return "Confirm the manual store/location before saving.";
      const visitValidation = validateScoutVisitDateTime(quickScoutReportForm, { allowFutureConfirmation: adminEditModeActive });
      if (!visitValidation.ok) return visitValidation.message;
    }
    if (stepKey === "status" && !quickScoutReportForm.reportType) {
      return "Choose the shelf status before continuing.";
    }
    if (stepKey === "details" && currentType.isGuess && !quickScoutReportForm.reportType) return "Choose the stock status before continuing.";
    if (stepKey === "details" && !currentType.isGuess && !quickScoutReportForm.proofType) return "Choose how you know this report before saving.";
    if (stepKey === "details" && !currentType.isGuess && !quickScoutHasMeaningfulReportDetail()) return "Add a category, item name, or useful detail before saving this report.";
    if (stepKey === "product" && !quickScoutHasMeaningfulReportDetail() && !currentType.isGuess) return "Add a category, item name, or useful detail before continuing.";
    if (stepKey === "review" && !currentType.isGuess) return scoutWizardStepError("where") || scoutWizardStepError("status") || scoutWizardStepError("details");
    if (stepKey === "review" && !quickScoutReportReady()) return scoutWizardStepError("where") || scoutWizardStepError("details") || "Complete the missing Scout report details before submitting.";
    if (stepKey === "review" && quickScoutStoreNeedsReviewConfirmation()) return "Confirm the manual store/location before saving.";
    if (["details", "review"].includes(stepKey) && !currentType.isGuess) {
      const visitValidation = validateScoutVisitDateTime(quickScoutReportForm, { allowFutureConfirmation: adminEditModeActive });
      if (!visitValidation.ok) return visitValidation.message;
    }
    return "";
  }

  function getScoutWizardSteps() {
    if (!quickScoutReportTypeMeta().isGuess) {
      return [
        { key: "where", label: "Where" },
        { key: "status", label: "Status" },
        { key: "details", label: "Details" },
        { key: "review", label: "Post" },
      ];
    }
    return [
      { key: "where", label: "Where" },
      { key: "details", label: "Guess" },
      { key: "review", label: "Review" },
    ];
  }

  function canAdvanceScoutWizard(stepKey = quickScoutReportStep) {
    return !scoutWizardStepError(stepKey);
  }

  function goNextScoutWizardStep() {
    const error = scoutWizardStepError();
    if (error) {
      setQuickScoutReportMessage(error);
      return;
    }
    setQuickScoutReportMessage("");
    const wizardSteps = getScoutWizardSteps();
    const activeStepIndex = Math.max(0, wizardSteps.findIndex((step) => step.key === quickScoutReportStep));
    setQuickScoutReportStep(wizardSteps[Math.min(activeStepIndex + 1, wizardSteps.length - 1)].key);
  }

  function goBackScoutWizardStep() {
    const wizardSteps = getScoutWizardSteps();
    const activeStepIndex = Math.max(0, wizardSteps.findIndex((step) => step.key === quickScoutReportStep));
    setQuickScoutReportStep(wizardSteps[Math.max(activeStepIndex - 1, 0)].key);
  }

  function buildQuickScoutReportRecord() {
    const type = quickScoutReportTypeMeta();
    const storeSelection = resolveQuickScoutStoreSelection();
    if (!storeSelection.valid) return null;
    const selectedStore = storeSelection.store || {};
    const timestampSourceDate = quickScoutReportForm.dateMode === "yesterday"
      ? getYesterdayDateInputKey()
      : quickScoutReportForm.dateMode === "pick_date" || quickScoutReportForm.dateMode === "today"
        ? quickScoutReportForm.reportDate || getLocalDateInputKey()
        : getLocalDateInputKey();
    const visitValidation = validateScoutVisitDateTime({ reportDate: timestampSourceDate, reportTime: quickScoutReportForm.reportTime }, { allowFutureConfirmation: true });
    const observedAt = visitValidation.ok ? visitValidation.iso : new Date(`${timestampSourceDate}T${quickScoutReportForm.reportTime || getLocalTimeKey()}`).toISOString();
    const submittedAt = new Date().toISOString();
    const explicitProductName = quickScoutReportForm.productName.trim()
      || quickScoutReportForm.catalogProductName
      || quickScoutReportForm.productType
      || "";
    const productName = explicitProductName;
    const reportProductCategory = quickScoutReportForm.productCategory || (productName ? "Pokemon TCG" : "");
    const storeName = storeSelection.storeName;
    const retailer = storeSelection.retailer;
    const notes = [
      quickScoutReportForm.note.trim(),
      quickScoutReportForm.proofText.trim() ? `Proof/text: ${quickScoutReportForm.proofText.trim()}` : "",
      quickScoutReportForm.manualLocation.trim() && !storeSelection.storeId ? `Manual location: ${quickScoutReportForm.manualLocation.trim()}` : "",
      storeSelection.needsStoreReview ? `Manual location confirmed: ${quickScoutReportForm.storeConfirmed ? "yes" : "no"}` : "",
      quickScoutReportForm.storeFollowPreference ? `Store follow preference: ${quickScoutReportForm.storeFollowPreference.replace(/_/g, " ")}` : "",
      `Proof source: ${quickScoutProofLabel()}`,
      productName ? `Products seen: ${productName}` : reportProductCategory ? `Product category: ${reportProductCategory}` : "Products seen: not added yet",
      `Stock left: ${quickScoutStockLeftLabel()}`,
      quickScoutReportForm.dateMode === "day_only" ? `Day reported: ${quickScoutReportForm.dayOfWeek}` : "",
      quickScoutReportForm.dateMode === "not_sure" ? "Date/time not sure" : "",
    ].filter(Boolean).join(" | ");
    const id = makeId("quick-scout-report");
    const workspaceId = activeWorkspaceId || currentUserProfile?.workspaceId || currentUserProfile?.workspace_id || "";
    const baseReport = {
      id,
      reportId: id,
      reportType: type.reportType,
      quickReportType: type.value,
      quickReportLabel: type.label,
      reportStatus: type.value,
      report_status: type.value,
      stockStatus: type.stockStatus,
      sourceType: type.sourceType,
      source_type: type.sourceType,
      storeId: storeSelection.storeId,
      store_id: storeSelection.storeId,
      selectedStoreId: storeSelection.storeId,
      selected_store_id: storeSelection.storeId,
      storeName,
      store_name: storeName,
      retailer,
      chain: retailer,
      city: storeSelection.city || selectedStore.city || quickScoutReportForm.city || "",
      address: storeSelection.address || selectedStore.address || quickScoutReportForm.address || "",
      state: storeSelection.state || selectedStore.state || quickScoutReportForm.state || "",
      zip: storeSelection.zip || getScoutQuickStoreZip(selectedStore) || quickScoutReportForm.zip || "",
      region: storeSelection.region || getScoutQuickStoreRegion(selectedStore) || quickScoutReportForm.region || "",
      manualLocation: quickScoutReportForm.manualLocation.trim(),
      needsStoreReview: storeSelection.needsStoreReview,
      needsReview: Boolean(type.needsReview || storeSelection.needsStoreReview),
      verificationStatus: type.needsReview || storeSelection.needsStoreReview ? "needs_review" : "new_report",
      verification_status: type.needsReview || storeSelection.needsStoreReview ? "needs_review" : "new_report",
      status: "active",
      verified: false,
      visibility: normalizeScoutReportVisibility(quickScoutReportForm.visibility),
      visibilitySelection: quickScoutReportForm.visibility,
      itemName: productName,
      productName,
      product_name: productName,
      catalogProductId: quickScoutReportForm.catalogProductId || "",
      catalog_product_id: quickScoutReportForm.catalogProductId || "",
      catalogProductName: quickScoutReportForm.catalogProductName || "",
      productImageUrl: quickScoutReportForm.productImageUrl || "",
      product_image_url: quickScoutReportForm.productImageUrl || "",
      productCategory: reportProductCategory,
      product_category: reportProductCategory,
      productType: productName ? quickScoutReportForm.productType || reportProductCategory || "" : "",
      product_type: productName ? quickScoutReportForm.productType || reportProductCategory || "" : "",
      setName: quickScoutReportForm.productSetName || "",
      set_name: quickScoutReportForm.productSetName || "",
      quantitySeen: quickScoutReportForm.quantity,
      quantity_estimate: quickScoutReportForm.quantity,
      price: quickScoutReportForm.price,
      itemsSeen: productName ? [{
        productName,
        productId: quickScoutReportForm.catalogProductId || "",
        category: reportProductCategory || "Pokemon TCG",
        productType: quickScoutReportForm.productType || reportProductCategory || "",
        setName: quickScoutReportForm.productSetName || "",
        imageUrl: quickScoutReportForm.productImageUrl || "",
        quantity: quickScoutReportForm.quantity,
        price: quickScoutReportForm.price,
        note: quickScoutReportForm.note.trim(),
      }] : [],
      reportText: notes || type.label,
      notes,
      photoUrls: quickScoutReportForm.photoUrl ? [quickScoutReportForm.photoUrl] : [],
      proofType: quickScoutReportForm.proofType,
      stockLeft: quickScoutReportForm.stockLeft,
      storeFollowPreference: quickScoutReportForm.storeFollowPreference || "verified_restocks",
      store_follow_preference: quickScoutReportForm.storeFollowPreference || "verified_restocks",
      reportDate: timestampSourceDate,
      reportTime: quickScoutReportForm.reportTime,
      observedAt,
      observed_at: observedAt,
      report_time: observedAt,
      dayOfWeek: quickScoutReportForm.dayOfWeek,
      reportedAt: observedAt,
      reported_at: observedAt,
      submittedAt,
      submitted_at: submittedAt,
      createdAt: submittedAt,
      created_at: submittedAt,
      updatedAt: submittedAt,
      updated_at: submittedAt,
      userId: currentUserProfile?.userId || currentUserProfile?.id || user?.id || "local-beta-scout",
      displayName: publicProfileLabel(),
      username: currentPublicUsername(),
      publicUsername: currentPublicUsername(),
      public_username: currentPublicUsername(),
      workspaceId,
      workspace_id: workspaceId,
      sourceStatus: BETA_LOCAL_MODE ? "local_beta" : "local",
      report_type: quickScoutNormalizedReportType(type),
    };
    const reliability = evaluateScoutReportReliability(baseReport, { needsReview: Boolean(type.needsReview || storeSelection.needsStoreReview) });
    const scoutPointsValue = scoutPointsForReport({ ...baseReport, confidence: reliability.key });
    return {
      ...baseReport,
      confidence: reliability.key,
      confidenceLevel: reliability.key,
      confidence_level: reliability.key,
      confidenceLabel: reliability.label,
      confidence_label: reliability.label,
      confidenceScore: reliability.score,
      confidence_score: reliability.score,
      confidenceReasons: reliability.reasons || [],
      confidence_reasons: reliability.reasons || [],
      reliabilityLabel: reliability.label,
      reliability_label: reliability.label,
      reliabilityReason: reliability.helper,
      reliability_reason: reliability.helper,
      sourceLabel: reliability.label,
      source_label: reliability.label,
      needsReview: Boolean(baseReport.needsReview || reliability.needsReview),
      needs_review: Boolean(baseReport.needsReview || reliability.needsReview),
      hidden: Boolean(reliability.hidden),
      status: reliability.hidden ? "hidden" : "active",
      verificationStatus: reliability.needsReview ? "needs_review" : "new_report",
      verification_status: reliability.needsReview ? "needs_review" : "new_report",
      scoutPointsValue,
      scout_points_value: scoutPointsValue,
      scoutPointsAwarded: scoutPointsValue > 0,
      scout_points_awarded: scoutPointsValue > 0,
      scoutPointsAtSubmit: scoutGuessPoints,
      scout_points_at_submit: scoutGuessPoints,
      shouldTrainPredictions: false,
      affectsDropRadarPredictions: false,
      affects_drop_radar_predictions: false,
    };
  }

  function buildQuickScoutGuessRecord() {
    const storeSelection = resolveQuickScoutStoreSelection();
    if (!storeSelection.valid) return null;
    const selectedStore = storeSelection.store || {};
    const storeName = storeSelection.storeName;
    const guessedDay = quickScoutReportForm.dateMode === "day_only"
      ? quickScoutReportForm.dayOfWeek
      : quickScoutReportForm.dateMode === "not_sure"
        ? "Unknown"
        : new Date(`${quickScoutReportForm.reportDate || getLocalDateInputKey()}T00:00:00`).toLocaleDateString(undefined, { weekday: "long" });
    const id = makeId("store-guess");
    const now = new Date().toISOString();
    const workspaceId = activeWorkspaceId || currentUserProfile?.workspaceId || currentUserProfile?.workspace_id || "";
    return {
      id,
      recordType: "guess",
      recordKind: "community_guess",
      eventType: "Community Guess",
      shouldTrainPredictions: false,
      trainingEligible: false,
      verified: false,
      userId: currentUserProfile?.userId || currentUserProfile?.id || user?.id || "local-beta-scout",
      user_id: currentUserProfile?.userId || currentUserProfile?.id || user?.id || "local-beta-scout",
      displayName: publicProfileLabel(),
      username: currentPublicUsername(),
      publicUsername: currentPublicUsername(),
      public_username: currentPublicUsername(),
      storeId: storeSelection.storeId,
      store_id: storeSelection.storeId,
      selectedStoreId: storeSelection.storeId,
      selected_store_id: storeSelection.storeId,
      storeName,
      store_name: storeName,
      retailer: storeSelection.retailer,
      city: storeSelection.city || selectedStore.city || quickScoutReportForm.city || "",
      guessedDay,
      guessed_day: guessedDay,
      guessedTimeWindow: quickScoutReportForm.guessedTimeWindow || (quickScoutReportForm.reportTime ? `Around ${quickScoutReportForm.reportTime}` : ""),
      guessed_time_window: quickScoutReportForm.guessedTimeWindow || (quickScoutReportForm.reportTime ? `Around ${quickScoutReportForm.reportTime}` : ""),
      restockPatternNotes: quickScoutReportForm.note.trim() || quickScoutReportForm.proofText.trim() || "User pattern note; not confirmed stock.",
      restock_pattern_notes: quickScoutReportForm.note.trim() || quickScoutReportForm.proofText.trim() || "User pattern note; not confirmed stock.",
      productType: quickScoutReportForm.productName.trim(),
      product_type: quickScoutReportForm.productName.trim(),
      confidenceSelfRating: Number(quickScoutReportForm.confidenceSelfRating || 50),
      confidence_self_rating: Number(quickScoutReportForm.confidenceSelfRating || 50),
      confidence: "guess",
      confidenceLabel: "Community Guess",
      verificationStatus: "community_guess",
      verification_status: "community_guess",
      status: "guess",
      sourceType: "manual_prediction",
      source_type: "manual_prediction",
      visibility: normalizeScoutGuessVisibility(quickScoutReportForm.visibility),
      workspaceId,
      workspace_id: workspaceId,
      createdAt: now,
      created_at: now,
      updatedAt: now,
      updated_at: now,
    };
  }

  async function submitQuickScoutReport(event) {
    event?.preventDefault?.();
    if (quickScoutReportSubmitLockRef.current) {
      setQuickScoutReportMessage("Scout report is already saving. Please wait a moment.");
      return;
    }
    quickScoutReportSubmitLockRef.current = true;
    setQuickScoutReportSubmitting(true);
    try {
    if (guestPreviewActive) {
      setQuickScoutReportMessage("Create a free account to submit reports and build forecasts.");
      setVaultToast("Create a free account to submit reports and build forecasts.");
      return;
    }
    const validationError = scoutWizardStepError("review");
    if (validationError) {
      setQuickScoutReportMessage(validationError);
      if (!quickScoutReportTypeMeta().isGuess) {
        setQuickScoutReportStep(scoutWizardStepError("where") ? "where" : scoutWizardStepError("status") ? "status" : "review");
      }
      else if (scoutWizardStepError("where")) setQuickScoutReportStep("where");
      return;
    }
    const currentType = quickScoutReportTypeMeta();
    const scoutData = getSharedScoutData();
    const visitValidation = currentType.isGuess
      ? { ok: true, oldBackfill: false }
      : validateScoutVisitDateTime(quickScoutReportForm, { allowFutureConfirmation: adminEditModeActive });
    if (!visitValidation.ok) {
      setQuickScoutReportMessage(visitValidation.message || "Add a valid visit date and time before submitting.");
      setQuickScoutReportStep(currentType.isGuess ? "details" : "where");
      showErrorToast("Couldn’t submit Scout report.", { message: visitValidation.message || "Add a valid visit date and time." });
      return;
    }
    if (visitValidation.needsFutureConfirmation) {
      const confirmedFutureVisit = await requestConfirmation({
        title: "Use a future visit time?",
        message: "This report is dated more than 15 minutes in the future. Only use this when correcting a report intentionally.",
        confirmLabel: "Use this time",
        cancelLabel: "Edit time",
      });
      if (!confirmedFutureVisit) {
        setQuickScoutReportStep(currentType.isGuess ? "details" : "where");
        return;
      }
    }
    if (currentType.isGuess) {
      if (!currentUserCanSubmitScoutGuess) {
        setQuickScoutReportMessage(DROP_RADAR_GUESS_LOCKED_MESSAGE);
        setVaultToast(DROP_RADAR_GUESS_LOCKED_MESSAGE);
        return;
      }
      const guess = buildQuickScoutGuessRecord();
      if (!guess) {
        setQuickScoutReportMessage(scoutWizardStepError("where") || "Choose the store/location before saving this guess.");
        setQuickScoutReportStep("where");
        return;
      }
      const nextLocalGuesses = [guess, ...(scoutData.storeGuesses || scoutData.guesses || [])]
        .filter((entry, index, list) => list.findIndex((candidate) => String(candidate.id) === String(entry.id)) === index);
      const nextVisibleGuesses = mergeScoutRows(scoutSnapshot.storeGuesses || [], [guess], scoutBackendGuessMergeKey);
      saveSharedScoutData({ ...scoutData, storeGuesses: nextLocalGuesses });
      setScoutSnapshot((current) => ({ ...current, storeGuesses: nextVisibleGuesses }));
      void persistScoutGuessToSupabase(guess).then((cloudGuess) => {
        if (!cloudGuess) return;
        setScoutSnapshot((current) => ({
          ...current,
          storeGuesses: mergeScoutRows(current.storeGuesses || [], [cloudGuess], scoutBackendGuessMergeKey),
        }));
      });
      setQuickScoutReportSaved(guess);
      setQuickScoutReportStep("submitted");
      setQuickScoutReportMessage("Guess saved to the planner. Forecasts will treat it as a guess, not confirmed stock.");
      setScoutView("guesses");
      setVaultToast("Guess saved to Scout Planner.");
      flowModalBaselineRef.current.scoutSubmit = quickScoutReportForm;
      void trackBetaActivity("submitted_scout_report", {
        eventContext: "scout",
        entityType: "scout_guess",
        entityId: guess.id,
        metadata: { confidence: "guess", storeId: guess.storeId || "" },
      });
      return;
    }
    const report = buildQuickScoutReportRecord();
    if (!report) {
      setQuickScoutReportMessage(scoutWizardStepError("where") || "Choose the store/location before saving this report.");
      setQuickScoutReportStep("where");
      return;
    }
    const nextLocalReports = [report, ...(scoutData.reports || [])]
      .filter((entry, index, list) => list.findIndex((candidate) => getScoutReportId(candidate) === getScoutReportId(entry)) === index);
    try {
      const nextScoutProfile = awardScoutReportPoints(scoutData.scoutProfile || scoutSnapshot.scoutProfile || {}, report);
      saveSharedScoutData({ ...scoutData, reports: nextLocalReports, scoutProfile: nextScoutProfile });
      setScoutSnapshot((current) => ({
        ...current,
        reports: mergeScoutRows(current.reports || [], [report], scoutBackendReportMergeKey),
        scoutProfile: nextScoutProfile,
      }));
    } catch (error) {
      logAppError("scout_report_local_save", error, { storeName: report.storeName || report.store_name || "" }, "normal");
      setQuickScoutReportMessage("Report could not be saved. Please review and try again.");
      showErrorToast("Report could not be saved.", { message: "Please review and try again." });
      return;
    }

    let savedReport = report;
    let backendSaveResult = { ok: false, skipped: true, reason: "not_attempted" };
    try {
      backendSaveResult = await persistScoutReportToSupabase(report);
      if (backendSaveResult?.ok && backendSaveResult.report) {
        savedReport = backendSaveResult.report;
        const localReportId = getScoutReportId(report);
        const latestScoutData = getSharedScoutData();
        const cloudMergeBase = (latestScoutData.reports || []).filter((candidate) => String(getScoutReportId(candidate)) !== String(localReportId));
        const mergedReports = mergeScoutRows(cloudMergeBase, [savedReport], scoutBackendReportMergeKey)
          .sort((a, b) => scoutReportSortTime(b) - scoutReportSortTime(a));
        saveSharedScoutData({ ...latestScoutData, reports: mergedReports });
        setScoutSnapshot((current) => ({
          ...current,
          reports: mergeScoutRows((current.reports || []).filter((candidate) => String(getScoutReportId(candidate)) !== String(localReportId)), [savedReport], scoutBackendReportMergeKey),
        }));
      }
    } catch (error) {
      backendSaveResult = { ok: false, error, reason: "backend_save_failed" };
      logAppError("scout_report_backend_save_unhandled", error, { storeName: report.storeName || report.store_name || "" }, "normal");
    }

    const savedToCloud = Boolean(backendSaveResult?.ok);
    const savedLocallyOnly = !savedToCloud;
    const scoutSaveMessage = savedToCloud
      ? (visitValidation.oldBackfill ? "Backfilled report saved." : "Scout report saved.")
      : "Scout report saved locally. Cloud sync is unavailable right now.";
    setQuickScoutReportSaved(savedReport);
    setQuickScoutReportStep("submitted");
    setQuickScoutReportMessage(savedToCloud
      ? (visitValidation.oldBackfill ? "Backfilled report saved." : "Scout report saved. Want to add proof or more details?")
      : "Report saved on this device and is visible in Scout. Cloud sync is unavailable right now.");
    setScoutReportFilter("Latest");
    setScoutReportsPage(1);
    setScoutView("reports");
    completeDailyAction("store", { badge: "restock_reporter", points: Math.max(6, Number(savedReport.scoutPointsValue || savedReport.scout_points_value || report.scoutPointsValue || 6)) });
    if (savedLocallyOnly) {
      showWarningToast("Scout report saved locally.", {
        message: backendSaveResult?.reason === "backend_unavailable"
          ? "Cloud sync is not available in this session, but the report is visible in Scout."
          : "Cloud sync failed, but the report is visible in Scout on this device.",
      });
    } else {
      setVaultToast(scoutSaveMessage, {
        message: visitValidation.oldBackfill ? "The visit time was saved for an earlier store check." : "You can add details now or later.",
      });
    }
    flowModalBaselineRef.current.scoutSubmit = quickScoutReportForm;
    void trackBetaActivity("submitted_scout_report", {
      eventContext: "scout",
      entityType: "scout_report",
      entityId: savedReport.id || report.id,
      metadata: { confidence: savedReport.confidence || report.confidence || "", storeId: savedReport.storeId || report.storeId || "", savedToCloud },
    });
    } finally {
      quickScoutReportSubmitLockRef.current = false;
      setQuickScoutReportSubmitting(false);
    }
  }

  function openQuickScoutReportDetails() {
    const savedReport = quickScoutReportSaved;
    const savedReportId = getScoutReportId(savedReport || {});
    closeFlowModal({ force: true, reset: true });
    setActiveTab("scout");
    setScoutView("reports");
    if (typeof window !== "undefined") {
      window.setTimeout(() => openScoutReportDetail(savedReportId || savedReport, { fallback: savedReport, focus: "details" }), 80);
    } else {
      openScoutReportDetail(savedReportId || savedReport, { fallback: savedReport, focus: "details" });
    }
  }

  function openScoutSubmitFlow(options = {}) {
    const seededStore = options.store || findScoutQuickStore(options);
    const seededReportType = SCOUT_QUICK_REPORT_TYPES.find((option) => option.value === options.reportType || option.reportType === options.reportType);
    const draft = createQuickScoutReportDraft({
      ...buildQuickScoutStoreDraft(seededStore || {}),
      reportType: seededReportType?.value || (options.action === "addGuess" ? "restock_guess" : "stock_on_shelf"),
      proofType: options.proofType || (options.action === "importIntel" ? "text_link" : "manual"),
      ...(options.action === "addGuess" ? { dateMode: "day_only", visibility: "private" } : {}),
      productName: options.productName || "",
      proofText: options.proofText || "",
      manualLocation: options.manualLocation || "",
    });
    setQuickScoutReportForm(draft);
    setQuickScoutReportStep("where");
    setQuickScoutReportMessage("");
    setQuickScoutReportSaved(null);
    flowModalBaselineRef.current.scoutSubmit = draft;
    setScoutSubTabTarget({
      tab: "reports",
      id: Date.now(),
      ...options,
    });
    openFlowModal("scoutSubmit", { size: "medium", source: options.source });
  }

