      msrpPrice: Number(row.msrpPrice ?? row.msrp_price ?? row.msrp ?? 0),
      msrp: Number(row.msrp ?? row.msrpPrice ?? row.msrp_price ?? 0),
      msrpSource: row.msrpSource || row.msrp_source || "",
      setCode: row.setCode || row.set_code || "",
