  function startEditingVaultItem(item) {
    const rawItem = rawVaultItems.find((entry) => String(entry.id) === String(item?.id)) || inventoryGroupEntries(item)[0] || item;
    startEditingItem(rawItem);
    setActiveTab("vault");
  }

  async function quickUpdatePlannedSalePrice(item = {}) {
    if (!item?.id || !ensureWorkspaceEditor(item?.workspaceId || item?.workspace_id || activeWorkspace?.id)) return;
    const current = Number(item.salePrice || item.plannedSalePrice || item.planned_sale_price || 0);
    const allEntrySummary = plannedSalePriceUpdateSummary(item);
    const updateIds = groupedInventoryUnsoldEntryIds(item);
    const entrySummary = updateIds.length === groupedInventoryEntryIds(item).length
      ? allEntrySummary
      : `${updateIds.length} unsold ${updateIds.length === 1 ? "entry" : "entries"}`;
    if (!updateIds.length) {
      showAppMessage("No unsold Forge entries are available for a grouped planned price update. Edit sold records individually.");
      return;
    }
    const input = window.prompt(`Update planned sale price for ${item.name || "this item"} (${entrySummary})`, current ? current.toFixed(2) : "");
    if (input == null) return;
    const nextPrice = Number.parseFloat(String(input).trim());
    if (!Number.isFinite(nextPrice) || nextPrice < 0) {
      showAppMessage("Planned sale price must be a valid number.");
      return;
    }
    if (updateIds.length > 1) {
      const confirmed = await requestConfirmation({
        title: "Apply grouped price update?",
        message: `Apply ${money(nextPrice)} to ${entrySummary} in this grouped Forge item? Sold entries will not change.`,
        confirmLabel: "Apply update",
        cancelLabel: "Cancel",
      });
      if (!confirmed) return;
    }
    const changedAt = new Date().toISOString();
    setItems((currentItems) => currentItems.map((entry) => updateIds.includes(entry.id)
      ? { ...entry, ...buildPlannedSalePricePatch(entry, nextPrice, changedAt) }
      : entry));
    if (!BETA_LOCAL_MODE && signedInWithSupabase && supabase) {
      const { error } = await supabase.from("inventory_items").update({
        sale_price: nextPrice,
        updated_at: changedAt,
      }).in("id", updateIds);
      if (error) {
        showAppMessage(`Planned sale price saved locally, but cloud sync failed: ${error.message}`);
        return;
      }
    }
    setVaultToast(`Planned sale price updated for ${entrySummary}.`);
  }

  async function quickUpdateMarketValue(item = {}) {
    if (!item?.id || !ensureWorkspaceEditor(item?.workspaceId || item?.workspace_id || activeWorkspace?.id)) return;
    const current = Number(item.marketPrice || item.marketValue || item.market_price || item.market_value || 0);
    const entrySummary = plannedSalePriceUpdateSummary(item);
    const input = window.prompt(`Review market value for ${item.name || "this item"} (${entrySummary})`, current ? current.toFixed(2) : "");
    if (input == null) return;
    const nextPrice = Number.parseFloat(String(input).trim());
    if (!Number.isFinite(nextPrice) || nextPrice < 0) {
      showAppMessage("Market value must be a valid number.");
      return;
    }
    const noteInput = window.prompt("Optional price review note/reason", item.priceReviewNote || "");
    const changedAt = new Date().toISOString();
    const updateIds = groupedInventoryEntryIds(item);
    const note = noteInput == null ? "" : noteInput;
    setItems((currentItems) => currentItems.map((entry) => updateIds.includes(entry.id)
      ? { ...entry, ...buildMarketValueReviewPatch(entry, nextPrice, { changedAt, note }) }
      : entry));
    if (!BETA_LOCAL_MODE && signedInWithSupabase && supabase) {
      const { error } = await supabase.from("inventory_items").update({
        market_price: nextPrice,
        market_value: nextPrice,
        market_value_source: "manual",
        market_value_updated_at: changedAt,
        last_price_checked: changedAt,
        updated_at: changedAt,
      }).in("id", updateIds);
      if (error) {
        showAppMessage(`Market value saved locally, but cloud sync failed: ${error.message}`);
        return;
      }
    }
    setVaultToast(`Manual market value reviewed for ${entrySummary}.`);
  }

  function inventoryDeleteContext(item = {}) {
    const destination = normalizeInventoryDestination(item);
    const itemName = item?.name || item?.itemName || "this item";
    if (destination === "forge") {
      return {
        title: "Delete Forge inventory item?",
        body: `This removes the Forge inventory record for ${itemName}. Vault collection records are not removed.`,
        toast: "Forge inventory item deleted.",
        error: "Could not delete Forge inventory item: ",
      };
    }
    if (destination === "wishlist") {
      return {
        title: "Remove from Wishlist?",
        body: `This removes ${itemName} from your Wishlist.`,
        toast: "Wishlist item removed.",
        error: "Could not remove Wishlist item: ",
      };
    }
    if (destination === "market") {
      return {
        title: "Remove market listing?",
        body: `This removes the market listing or draft for ${itemName}.`,
        toast: "Market listing removed.",
        error: "Could not remove market listing: ",
      };
    }
    if (destination === "vault_archive") {
      return {
        title: "Remove transferred Vault record?",
        body: `This removes the archived Vault transfer record for ${itemName}. The Forge inventory copy is not removed.`,
        toast: "Transferred Vault record removed.",
        error: "Could not remove transferred Vault record: ",
      };
    }
    return {
      title: "Delete vaulted item?",
      body: `This removes the Vault collection record for ${itemName}. Forge inventory records are not removed.`,
      toast: "Vault item deleted.",
      error: "Could not delete Vault item: ",
    };
  }

