function renderForgeBusinessCommandPanel() {
  const topForgeGroups = groupedSortedFilteredItems.slice(0, 3);
  const recentForgeSales = [...workspaceSales]
    .sort((a, b) => String(b.saleDate || b.createdAt || "").localeCompare(String(a.saleDate || a.createdAt || "")))
    .slice(0, 3);
  const recentForgeTrades = [...workspaceTradeRecords]
    .sort((a, b) => String(b.tradeDate || b.createdAt || "").localeCompare(String(a.tradeDate || a.createdAt || "")))
    .slice(0, 3);
  const forgeLedgerCards = [
    {
      key: "groups",
      label: "Grouped inventory",
      value: groupedSortedFilteredItems.length || 0,
      helper: `${forgeTotalProductQuantity || 0} sellable item${forgeTotalProductQuantity === 1 ? "" : "s"}`,
    },
    {
      key: "cost",
      label: "Cost basis",
      value: forgeValuationSummary.costKnownQuantity ? money(totalSpent) : "Unknown",
      helper: forgeValuationSummary.missingCostCount ? `${forgeValuationSummary.missingCostCount} cost detail${forgeValuationSummary.missingCostCount === 1 ? "" : "s"} needed` : "Known inventory cost",
    },
    {
      key: "sales",
      label: "Sales records",
      value: workspaceSales.length || 0,
      helper: workspaceSales.length ? `${totalItemsSold || 0} item${totalItemsSold === 1 ? "" : "s"} sold` : "No sales yet",
    },
    {
      key: "trades",
      label: "Trade history",
      value: workspaceTradeRecords.length || 0,
      helper: workspaceTradeRecords.length ? "Saved local trade reviews" : "No trades saved yet",
    },
    {
      key: "profit",
      label: "Profit / loss",
      value: forgeHasProfitSnapshot ? money(salesSummary.estimatedProfitLoss - totalExpenses) : "Not started",
      helper: `${money(totalSalesRevenue)} revenue | ${money(totalExpenses)} expenses`,
    },
  ];
  const forgeExactCopyCards = [
    {
      label: "Master card",
      value: "One identity",
      helper: "Same name, set, and card number stay grouped before seller actions.",
    },
    {
      label: "Exact copy",
      value: "Variant first",
      helper: "Choose raw, graded, sealed-related, promo, or duplicate before trade/listing review.",
    },
    {
      label: "Family rule",
      value: "Review before action",
      helper: "Kid-owned items should get parent approval before moving into sale or trade context.",
    },
  ];
  const forgeWorkspaceFlows = [
    {
      key: "trade-analyzer",
      eyebrow: "Trade Analyzer",
      title: "Worth it for the family?",
      summary: "Compare exact variants and copies before any record changes.",
      detail: "Give: NM foil copy + sealed item | Receive: binder lot",
      value: "+$18 fair range",
      note: "Parent approval recommended for kid-owned items.",
      cta: "Add Trade",
      onClick: () => openAddTradeFlow({ source: "forge-trade-analyzer" }),
    },
    {
      key: "listing-builder",
      eyebrow: "Listing Builder",
      title: "Draft before posting.",
      summary: "Stage title, exact variant, condition, fair range, and family-safe notes without publishing.",
      detail: "Variant: Reverse Holo | Condition: Near Mint",
      value: "Draft only",
      note: "No checkout, payment, or marketplace posting is connected.",
      cta: "Mock listing draft",
    },
    {
      key: "sales-ledger",
      eyebrow: "Sales Ledger",
      title: "Keep the record clear.",
      summary: "Track revenue, cost basis, fees, and receipt needs for seller recordkeeping.",
      detail: "Revenue $128 | Cost basis $76 | Receipt needed",
      value: "$52 est. P/L",
      note: "For recordkeeping. Confirm summaries with your tax professional.",
      cta: "Open Sales Records",
      onClick: () => setActiveTab("sales"),
    },
  ];
  const renderForgeGroupPreview = (item) => {
    const entryCount = item.groupedEntryCount || inventoryGroupEntries(item).length;
    const valuation = item.valuationSummary || buildGroupedInventoryValuation(item, { context: "forge" });
    const status = item.statusSummary || summarizeForgeGroupedInventoryStatus(inventoryGroupEntries(item), item.saleHistory || []);
    return (
      <article className="forge-command-group-preview" key={item.groupId || item.id}>
        <div>
          <span className="forge-preview-kicker">{entryCount > 1 ? `${entryCount} entries grouped` : "Single entry"}</span>
          <h4>{item.name}</h4>
          <p>{[item.productType, item.expansion, item.locationSummary || forgePhysicalLocationLabel(item)].filter(Boolean).join(" | ") || "Business inventory"}</p>
        </div>
        <dl>
          <div><dt>Held</dt><dd>{status.currentQuantity || item.quantity || 0}</dd></div>
          <div><dt>Sold</dt><dd>{status.soldQuantity || 0}</dd></div>
          <div><dt>Cost</dt><dd>{valuation.costKnownQuantity ? money(valuation.totalCostBasis) : "Unknown"}</dd></div>
          <div><dt>Planned</dt><dd>{valuation.plannedKnownQuantity ? money(valuation.plannedSaleTotal) : "Not set"}</dd></div>
        </dl>
        <button type="button" className="secondary-button" onClick={() => setSelectedForgeDetailId(item.groupId || item.id)}>
          View history
        </button>
      </article>
    );
  };

  return (
    <EtMockupSectionCard
      title="Inventory, sales, and profit in one workspace."
      detail="Forge keeps sellable inventory separate from Vault, groups same items, and keeps cost basis, sale records, receipts, mileage, and item history easy to review."
      className="forge-main-command-panel forge-mockup-command-panel"
      ariaLabel="Forge business dashboard"
      action={<EtMockupPill tone="collector">Owner-safe tools</EtMockupPill>}
    >

      <div className="forge-ledger-card-grid" aria-label="Forge ledger summary">
        {forgeLedgerCards.map((card) => (
          <div className="forge-ledger-card" key={card.key}>
            <span>{card.label}</span>
            <strong>{card.value}</strong>
            <small>{card.helper}</small>
          </div>
        ))}
      </div>

      <div className="forge-exact-copy-strip" aria-label="Forge exact variant and copy rules">
        {forgeExactCopyCards.map((card) => (
          <article key={card.label}>
            <span>{card.label}</span>
            <strong>{card.value}</strong>
            <small>{card.helper}</small>
          </article>
        ))}
      </div>

      <div className="forge-workspace-flow-grid" aria-label="Forge trade listing and sales flows">
        {forgeWorkspaceFlows.map((flow) => (
          <article className={`forge-workspace-flow-card is-${flow.key}`} key={flow.key}>
            <div>
              <span className="forge-preview-kicker">{flow.eyebrow}</span>
              <h4>{flow.title}</h4>
              <p>{flow.summary}</p>
            </div>
            <dl>
              <div>
                <dt>Preview</dt>
                <dd>{flow.detail}</dd>
              </div>
              <div>
                <dt>Value</dt>
                <dd>{flow.value}</dd>
              </div>
            </dl>
            <div className="forge-workspace-flow-footer">
              <small>{flow.note}</small>
              {flow.onClick ? (
                <button type="button" className="secondary-button" onClick={flow.onClick}>{flow.cta}</button>
              ) : (
                <span className="status-badge">{flow.cta}</span>
              )}
            </div>
          </article>
        ))}
      </div>

      {!forgeBusinessHasRecords ? (
        <div className="small-empty-state forge-start-empty-state">
          <strong>Start tracking sales and trades.</strong>
          <span>Add sellable inventory, record a sale, or save a receipt when you are ready.</span>
        </div>
      ) : null}

      <div className="forge-main-command-columns">
        <div className="forge-main-command-card">
          <div className="compact-card-header">
            <div>
              <h4>Grouped inventory</h4>
              <p>Same products roll up together, while purchaser, location, dates, and sale history stay preserved in details.</p>
            </div>
            <span className="forge-command-count-badge">{groupedSortedFilteredItems.length} groups</span>
          </div>
          <div className="forge-command-preview-list">
            {topForgeGroups.length ? topForgeGroups.map(renderForgeGroupPreview) : (
              <div className="small-empty-state forge-start-empty-state">
                <strong>Start tracking sales and trades.</strong>
                <span>Add your first Forge item to create grouped business inventory.</span>
              </div>
            )}
          </div>
        </div>

        <div className="forge-main-command-card">
          <div className="compact-card-header">
            <div>
              <h4>Sales records</h4>
              <p>Scan gross sales, fees, cost basis, and estimated profit/loss before opening the full sales view.</p>
            </div>
            <button type="button" className="secondary-button" onClick={() => setActiveTab("sales")}>Open Sales</button>
          </div>
          <div className="forge-sales-preview-list">
            {recentForgeSales.length ? recentForgeSales.map((sale) => (
              <article className="forge-sale-preview-row" key={sale.id}>
                <div>
                  <strong>{sale.itemName || "Sale record"}</strong>
                  <span>{[sale.platform || "Sale", sale.saleDate || shortDate(sale.createdAt)].filter(Boolean).join(" | ")}</span>
                </div>
                <dl>
                  <div><dt>Gross</dt><dd>{money(sale.grossSale || sale.finalSalePrice || 0)}</dd></div>
                  <div><dt>Cost</dt><dd>{money(sale.costBasis || sale.itemCost || 0)}</dd></div>
                  <div><dt>Profit</dt><dd>{money(sale.estimatedProfitLoss ?? sale.netProfit ?? 0)}</dd></div>
                </dl>
              </article>
            )) : (
              <div className="small-empty-state forge-start-empty-state">
                <strong>No sales records yet.</strong>
                <span>Record your first sale when an item leaves Forge.</span>
                <button type="button" className="secondary-button" onClick={() => openAddSaleFlow()}>Add Sale</button>
              </div>
            )}
          </div>
        </div>

        <div className="forge-main-command-card forge-trade-history-card">
          <div className="compact-card-header">
            <div>
              <h4>Trade History</h4>
              <p>Record what you gave, what you got, estimated values, and notes. Saving a trade never changes Vault or Forge inventory counts.</p>
            </div>
            <button type="button" className="secondary-button" onClick={() => openAddTradeFlow({ source: "forge-trade-history-card" })}>Add Trade</button>
          </div>
          <div className="trade-history-list forge-trade-history-list">
            {recentForgeTrades.length ? recentForgeTrades.map((record) => (
              <article key={record.id}>
                <span>{record.tradeDate ? shortDate(record.tradeDate) : shortDate(record.createdAt)}</span>
                <strong>{record.sourceItemName || "Item traded"} for {record.receivedName || "received item"}</strong>
                <small>{record.resultLabel || record.guidance || "Trade saved"} | {record.difference || record.difference === 0 ? money(Math.abs(Number(record.difference || 0))) : "Unknown value"} | Inventory unchanged</small>
              </article>
            )) : (
              <div className="small-empty-state forge-start-empty-state">
                <strong>No trade history yet.</strong>
                <span>Add a manual trade or choose a saved Vault/Forge item to compare estimated value before updating inventory records.</span>
                <button type="button" className="secondary-button" onClick={() => openAddTradeFlow({ source: "forge-trade-history-empty" })}>Add Trade</button>
              </div>
            )}
          </div>
        </div>

        <div className="forge-main-command-card forge-activity-command-card">
          <div className="compact-card-header">
            <div>
              <h4>Recent activity</h4>
              <p>Latest inventory, sale, expense, and mileage activity in this Forge workspace.</p>
            </div>
          </div>
          {forgeRecentActivity.length ? (
            <div className="forge-activity-preview-list">
              {forgeRecentActivity.slice(0, 4).map((entry) => (
                <div className="forge-activity-preview-row" key={entry.key}>
                  <span>{entry.source}</span>
                  <strong>{entry.title}</strong>
                  <small>{entry.detail}</small>
                  <time>{shortDate(entry.date)}</time>
                </div>
              ))}
            </div>
          ) : (
            <div className="small-empty-state forge-start-empty-state">
              <strong>No Forge activity yet.</strong>
              <span>Add inventory, a sale, receipt, or mileage trip to build your business record.</span>
            </div>
          )}
        </div>
      </div>
    </EtMockupSectionCard>
  );
}

