  function buildReceiptWorkflowFromExpense(expense = {}) {
    const rawText = expense.rawReceiptText || "";
    const parsedLines = parseReceiptText(rawText);
    const fallbackLine = !parsedLines.length && expense.vendor
      ? [{
          productName: expense.subcategory || expense.category || expense.vendor,
          quantity: 1,
          unitPrice: Number(expense.amount || 0),
          lineTotal: Number(expense.amount || 0),
          destination: "expense_only",
          matchedConfidence: "needs_review",
        }]
      : [];
    return {
      id: expense.receiptId || expense.receipt_id || makeId("receipt"),
      merchant: expense.vendor || "",
      purchasedAt: expense.date ? new Date(`${expense.date}T12:00:00`).toISOString() : new Date().toISOString(),
      total: Number(expense.amount || 0),
      tax: Number(expense.receiptTax || 0),
      paymentMethod: expense.paymentMethod || "",
      category: expense.category || "Supplies",
      imageUrl: expense.receiptImage || expense.receiptPhoto || "",
      splitMode: expense.receiptSplitMode || "expense_only",
      businessTotal: Math.max(0, Number(expense.amount || 0) - Number(expense.receiptPersonalTotal || 0)),
      personalTotal: Number(expense.receiptPersonalTotal || 0),
      workspaceId: activeForgeWorkspace?.id || activeWorkspace?.id || DEFAULT_PERSONAL_WORKSPACE_ID,
      workspace_id: activeForgeWorkspace?.id || activeWorkspace?.id || DEFAULT_PERSONAL_WORKSPACE_ID,
      workspaceName: activeForgeWorkspace?.name || activeWorkspace?.name || "Forge",
      notes: expense.notes || "",
      rawOcrText: rawText,
      lines: parsedLines.length ? parsedLines : fallbackLine,
      createdAt: expense.createdAt || new Date().toISOString(),
    };
  }

  async function persistReceiptWorkflowFromExpense(expense = {}) {
    if (!expense.receiptImage && !expense.rawReceiptText && !expense.receiptPhoto) return null;
    if (expense.receiptId && findReceiptRecord(expense.receiptId)) {
      const existingReceipt = findReceiptRecord(expense.receiptId);
      const existingLines = receiptLinesFor(existingReceipt);
      syncForgeReceiptWorkflowState(existingReceipt, existingLines);
      return { source: "local", data: existingReceipt, lines: existingLines };
    }
    const receipt = buildReceiptWorkflowFromExpense(expense);
    const receiptLines = receipt.lines.map((line) => ({ ...line, receiptId: receipt.id }));
    syncForgeReceiptWorkflowState(receipt, receiptLines);
    const result = await saveReceiptRecord(forgePhase2Context(), receipt);
    if (result.data) {
      syncForgeReceiptWorkflowState(
        {
          ...receipt,
          ...result.data,
          workspaceId: receipt.workspaceId,
          workspace_id: receipt.workspace_id,
          workspaceName: receipt.workspaceName,
        },
        result.lines?.length ? result.lines : receiptLines
      );
    }
    updatePhase2Status(result, "Receipt workflow saved locally.");
    return result;
  }

  function prefillQaReceiptDraft() {
    if (!QA_UNLOCK_PAID_FEATURES) return;
    setExpenseForm((current) => ({
      ...current,
      date: "2026-05-10",
      vendor: "QA Receipt Merchant 2026-05-10",
      category: current.category || "Supplies",
      subcategory: "QA Receipt Line Item",
      amount: "12.34",
      paymentMethod: "QA card",
      notes: "QA Receipt 2026-05-10 persistence test",
      rawReceiptText: "QA Receipt Line Item 11.35",
      receiptTax: "0.99",
      receiptSplitMode: "expense_only",
    }));
    setVaultToast("QA receipt draft filled. Save with Add Expense to test normal persistence.");
  }

  async function addExpense(event) {
    event.preventDefault();
    if (blockGuestSave()) return;
    if (!user) return showAppMessage("Please log in first.");
    const targetForgeWorkspace = activeForgeWorkspace;
    if (!targetForgeWorkspace) return showAppMessage(forgeWorkspaceUnavailableMessage);
    if (!ensureWorkspaceEditor(targetForgeWorkspace.id)) return;
    if (!expenseForm.vendor || !expenseForm.amount) return showAppMessage("Please enter vendor and amount.");

    if (BETA_LOCAL_MODE || user.id === "local-beta") {
      const localId = editingExpenseId || makeId("expense");
      const localExpense = {
        ...blankExpense,
        ...expenseForm,
        id: localId,
        expenseId: localId,
        workspaceId: targetForgeWorkspace.id,
        workspace_id: targetForgeWorkspace.id,
        workspaceName: targetForgeWorkspace.name || "Forge",
        amount: Number(expenseForm.amount),
        receiptPhoto: expenseForm.receiptImage,
        createdAt: expenses.find((expense) => expense.id === editingExpenseId)?.createdAt || new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      };
      setExpenses(editingExpenseId ? expenses.map((expense) => (expense.id === editingExpenseId ? localExpense : expense)) : [localExpense, ...expenses]);
      void persistReceiptWorkflowFromExpense(localExpense);
      setEditingExpenseId(null);
      setExpenseForm(blankExpense);
      if (activeFlowModal?.type === "addExpense") closeFlowModal({ force: true, reset: false });
      setVaultToast(editingExpenseId ? "Expense updated." : "Expense added.");
      return;
    }

    const row = {
      user_id: user.id,
      workspace_id: uuidOrNull(targetForgeWorkspace.id),
      date: expenseForm.date || null,
      vendor: expenseForm.vendor,
      category: expenseForm.category,
      subcategory: expenseForm.subcategory,
      buyer: expenseForm.buyer,
      amount: Number(expenseForm.amount),
      payment_method: expenseForm.paymentMethod,
      linked_item_id: expenseForm.linkedItemId || null,
      linked_sale_id: expenseForm.linkedSaleId || null,
      notes: expenseForm.notes,
      receipt_image: expenseForm.receiptImage,
      receipt_photo: expenseForm.receiptImage,
      tax_deductible: !!expenseForm.taxDeductible,
      campaign_name: expenseForm.campaignName,
      platform: expenseForm.platform,
      goal: expenseForm.goal,
      start_date: expenseForm.startDate || null,
      end_date: expenseForm.endDate || null,
      linked_sales: expenseForm.linkedSales,
      results_notes: expenseForm.resultsNotes,
    };

    const { data, error } = editingExpenseId
      ? await supabase.from("business_expenses").update({ ...row, updated_at: new Date().toISOString() }).eq("id", editingExpenseId).select().single()
      : await supabase.from("business_expenses").insert(row).select().single();

    if (error) return showAppMessage("Could not save expense: " + error.message);

    const mapped = { ...mapExpense(data), receiptId: expenseForm.receiptId || "", rawReceiptText: expenseForm.rawReceiptText || "" };
    void persistReceiptWorkflowFromExpense({ ...mapped, ...expenseForm, receiptPhoto: expenseForm.receiptImage });
    setExpenses(editingExpenseId ? expenses.map((e) => (e.id === editingExpenseId ? mapped : e)) : [mapped, ...expenses]);
    setEditingExpenseId(null);
    setExpenseForm(blankExpense);
    if (activeFlowModal?.type === "addExpense") closeFlowModal({ force: true, reset: false });
    setVaultToast(editingExpenseId ? "Expense updated." : "Expense added.");
  }

  function startEditingExpense(expense) {
    if (!ensureWorkspaceEditor(expense?.workspaceId || expense?.workspace_id || activeWorkspace?.id)) return;
    setEditingExpenseId(expense.id);
    setExpenseForm({ ...blankExpense, ...expense });
    openFlowModal("addExpense", { size: "medium", source: "edit" });
  }

  function deleteExpense(id) {
    const expense = expenses.find((entry) => entry.id === id);
    if (!ensureWorkspaceEditor(expense?.workspaceId || expense?.workspace_id || activeWorkspace?.id)) return;
    requestAdminActionConfirmation({
      title: "Delete expense?",
      message: `This removes ${expense?.vendor || "this expense"} from Forge business expenses. This cannot be undone.`,
      confirmLabel: "Delete expense",
      danger: true,
      successMessage: "Expense deleted.",
      errorMessage: "Could not delete expense.",
      onConfirm: async () => {
        const expenseVendorKey = normalizeExpenseVendor(expense?.vendor).key;
        const remainingInGroup = expenses.filter((entry) =>
          entry.id !== id &&
          recordBelongsToWorkspace(entry, expense?.workspaceId || expense?.workspace_id || activeWorkspace?.id) &&
          normalizeExpenseVendor(entry.vendor).key === expenseVendorKey
        ).length;
        if (BETA_LOCAL_MODE || user?.id === "local-beta") {
          setExpenses(expenses.filter((expenseRow) => expenseRow.id !== id));
          if (editingExpenseId === id) {
            setEditingExpenseId(null);
            setExpenseForm(blankExpense);
          }
          if (selectedExpenseVendorKey === expenseVendorKey && remainingInGroup <= 0) setSelectedExpenseVendorKey("");
          return;
        }
        const { error } = await supabase.from("business_expenses").delete().eq("id", id);
        if (error) throw new Error("Could not delete expense: " + error.message);
        setExpenses(expenses.filter((expenseRow) => expenseRow.id !== id));
        if (selectedExpenseVendorKey === expenseVendorKey && remainingInGroup <= 0) setSelectedExpenseVendorKey("");
      },
    });
  }

