  function expenseLinkedItemLabel(expense = {}) {
    if (!expense.linkedItemId) return "";
    return forgeInventoryItems.find((item) => String(item.id) === String(expense.linkedItemId))?.name || "Linked Forge item";
  }

  function renderExpenseRecordCard(expense, options = {}) {
    const linkedItemLabel = expenseLinkedItemLabel(expense);
    const receiptUrl = expense.receiptImage || expense.receiptImageUrl || expense.receiptPhoto || expense.imageUrl || "";
    const linkedReceipt = findReceiptRecord(expense.receiptId) || visibleReceiptRecords.find((receipt) => {
      const image = receiptImageUrl(receipt);
      return image && receiptUrl && String(image) === String(receiptUrl);
    });
    return (
      <div className={`expense-record-card${options.compact ? " is-compact" : ""}`} key={expense.id}>
        <div className="expense-record-main">
          <div>
            <h3>{expense.vendor || EXPENSE_VENDOR_EMPTY_LABEL}</h3>
            <p>{[formatExpenseDate(expenseDateValue(expense)), expense.category || "Supplies", expense.subcategory].filter(Boolean).join(" | ")}</p>
          </div>
          <strong>{money(expense.amount)}</strong>
        </div>
        <div className="expense-record-meta">
          {expense.buyer ? <span>Paid by {expense.buyer}</span> : null}
          {expense.paymentMethod ? <span>{expense.paymentMethod}</span> : null}
          {expense.taxDeductible ? <span>Tax deductible</span> : null}
          {expenseHasReceipt(expense) ? <span>Receipt attached</span> : <span>Receipt missing</span>}
          {linkedItemLabel ? <span>{linkedItemLabel}</span> : null}
        </div>
        {expense.notes ? <p className="compact-subtitle">{expense.notes}</p> : null}
        <div className="expense-record-actions">
          {linkedReceipt ? <button type="button" className="secondary-button" onClick={() => openReceiptDetail(linkedReceipt)}>Receipt detail</button> : null}
          {receiptUrl ? <a href={receiptUrl} target="_blank" rel="noreferrer">View Receipt</a> : null}
          <OverflowMenu
            onEdit={() => startEditingExpense(expense)}
            onDelete={() => deleteExpense(expense.id)}
            editLabel="Edit Expense"
            deleteLabel="Delete Expense"
          />
        </div>
      </div>
    );
  }

  async function saveVehicleRecord(draft = {}, options = {}) {
    if (blockGuestSave()) return;
    if (!user) return showAppMessage("Please log in first.");
    const name = String(draft.name || "").trim();
    if (!name) return showAppMessage("Please enter vehicle name.");
    const targetForgeWorkspace = activeForgeWorkspace || activeWorkspace || { id: DEFAULT_PERSONAL_WORKSPACE_ID, name: "My Personal Space" };
    const vehicleId = options.editingId || editingVehicleId || "";
    const now = new Date().toISOString();
    const averageMpg = Number(draft.averageMpg || 0);
    const wearCostPerMile = Number(draft.wearCostPerMile || 0);

    const row = {
      user_id: user.id,
      workspace_id: uuidOrNull(targetForgeWorkspace.id),
      name,
      owner: String(draft.owner || "").trim(),
      average_mpg: averageMpg,
      wear_cost_per_mile: wearCostPerMile,
      notes: String(draft.notes || "").trim(),
    };

    if (BETA_LOCAL_MODE || user.id === "local-beta") {
      const localRow = {
        ...row,
        id: vehicleId || makeId("vehicle"),
        workspaceId: targetForgeWorkspace.id,
        workspace_id: targetForgeWorkspace.id,
        averageMpg,
        wearCostPerMile,
        active: true,
        defaultMileageRate: IRS_MILEAGE_RATE,
        createdAt: vehicles.find((vehicle) => vehicle.id === vehicleId)?.createdAt || now,
        updatedAt: now,
      };
      const mapped = mapVehicle(localRow);
      setVehicles((current) => vehicleId ? current.map((vehicle) => (vehicle.id === vehicleId ? mapped : vehicle)) : [mapped, ...current]);
      if (!options.keepForm) {
        setEditingVehicleId(null);
        setVehicleForm({ name: "", owner: "", averageMpg: "", wearCostPerMile: "", notes: "" });
      }
      setVaultToast(vehicleId ? "Vehicle updated." : "Vehicle added.");
      return mapped;
    }

    const { data, error } = vehicleId
      ? await supabase.from("vehicles").update({ ...row, updated_at: now }).eq("id", vehicleId).select().single()
      : await supabase.from("vehicles").insert(row).select().single();

    if (error) return showAppMessage("Could not save vehicle: " + error.message);

    const mapped = mapVehicle(data);
    setVehicles((current) => vehicleId ? current.map((v) => (v.id === vehicleId ? mapped : v)) : [mapped, ...current]);
    if (!options.keepForm) {
      setEditingVehicleId(null);
      setVehicleForm({ name: "", owner: "", averageMpg: "", wearCostPerMile: "", notes: "" });
    }
    setVaultToast(vehicleId ? "Vehicle updated." : "Vehicle added.");
    return mapped;
  }

