  async function addSale(event) {
    event.preventDefault();
    if (blockGuestSave()) return;
    if (!user) return showAppMessage("Please log in first.");

    const item = forgeInventoryItems.find((i) => String(i.id) === String(saleForm.itemId));
    const targetWorkspaceId = item?.workspaceId || item?.workspace_id || activeForgeWorkspace?.id || activeWorkspace?.id;
    if (!ensureWorkspaceEditor(targetWorkspaceId)) return;
    const saleWasEditing = Boolean(editingSaleId);

    const saleBuild = buildSalesRecordFromDraft(saleForm, item || {}, {
      id: editingSaleId || makeId("sale"),
      workspaceId: targetWorkspaceId,
      workspaceName: item?.workspaceName || activeForgeWorkspace?.name || activeWorkspace?.name || "Forge",
      createdAt: sales.find((sale) => sale.id === editingSaleId)?.createdAt,
    });
    if (!saleBuild.valid) {
      const firstError = Object.values(saleBuild.errors)[0] || "Sale details need review before saving.";
      return showAppMessage(firstError);
    }

    const saleRecord = saleBuild.sale;
    const qty = Number(saleRecord.quantitySold || 0);
    if (item && qty > Number(item.quantity || 0)) return showAppMessage("You cannot sell more than you have.");
    const remaining = item ? Number(item.quantity || 0) - qty : 0;
    const saleNotes = [
      saleRecord.notes,
      saleRecord.saleDate ? `Sale date: ${saleRecord.saleDate}` : "",
      saleRecord.buyerName ? `Buyer/customer: ${saleRecord.buyerName}` : "",
      saleRecord.shippingCharged ? `Shipping charged: ${money(saleRecord.shippingCharged)}` : "",
      saleRecord.paymentProcessingFees ? `Payment processing fee: ${money(saleRecord.paymentProcessingFees)}` : "",
      saleRecord.suppliesCost ? `Supplies cost: ${money(saleRecord.suppliesCost)}` : "",
      saleRecord.discountsRefunds ? `Discounts/refunds: ${money(saleRecord.discountsRefunds)}` : "",
      `Estimated net proceeds: ${money(saleRecord.netProceeds)}`,
      saleRecord.referenceId ? `Reference: ${saleRecord.referenceId}` : "",
    ].filter(Boolean).join(" | ");

    const row = {
      user_id: user.id,
      workspace_id: uuidOrNull(targetWorkspaceId),
      item_id: item?.id || null,
      item_name: saleRecord.itemName,
      sku: saleRecord.sku,
      original_buyer: item?.buyer || saleRecord.buyerName || "",
      category: item?.category || "",
      store: item?.store || "",
      platform: saleRecord.platform,
      quantity_sold: qty,
      final_sale_price: saleRecord.finalSalePrice,
      gross_sale: saleRecord.grossSale,
      item_cost: saleRecord.costBasis,
      shipping_cost: saleRecord.shippingCost + saleRecord.suppliesCost,
      platform_fees: saleRecord.totalFees,
      net_profit: saleRecord.estimatedProfitLoss,
      notes: saleNotes,
    };
    if (saleRecord.saleDate) row.created_at = `${saleRecord.saleDate}T12:00:00.000Z`;

    if (BETA_LOCAL_MODE || user.id === "local-beta") {
      const localRow = {
        ...row,
        ...saleRecord,
        id: editingSaleId || saleRecord.id || makeId("sale"),
        workspaceId: targetWorkspaceId || DEFAULT_PERSONAL_WORKSPACE_ID,
        workspace_id: targetWorkspaceId || DEFAULT_PERSONAL_WORKSPACE_ID,
        workspaceName: saleRecord.workspaceName || activeForgeWorkspace?.name || activeWorkspace?.name || "Forge",
        notes: saleNotes,
        created_at: sales.find((sale) => sale.id === editingSaleId)?.createdAt || saleRecord.createdAt || new Date().toISOString(),
      };
      const mapped = mapSale(localRow);
      setSales(editingSaleId ? sales.map((sale) => (sale.id === editingSaleId ? mapped : sale)) : [mapped, ...sales]);
      if (!editingSaleId && item) {
        setItems(items.map((currentItem) => (
          currentItem.id === item.id
            ? { ...currentItem, quantity: remaining, status: remaining === 0 ? "Sold" : currentItem.status, updatedAt: new Date().toISOString() }
            : currentItem
        )));
      }
      setEditingSaleId(null);
      setSaleForm(blankSale);
      if (activeFlowModal?.type === "addSale") {
        setForgeSaleSaveSuccess({
          sale: mapped,
          itemName: mapped.itemName || saleRecord.itemName,
          quantity: mapped.quantitySold || qty || 1,
          destination: "Forge sales",
          saleWasEditing,
        });
      } else {
        setActiveTab("sales");
      }
      setVaultToast(saleWasEditing ? "Sale updated." : "Sale added.");
      return;
    }

    const { data: saleData, error: saleError } = editingSaleId
      ? await supabase.from("sales_records").update({ ...row, updated_at: new Date().toISOString() }).eq("id", editingSaleId).select().single()
      : await supabase.from("sales_records").insert(row).select().single();

    if (saleError) return showAppMessage("Could not save sale: " + saleError.message);

    if (!editingSaleId && item) {
      const { data: updatedItem, error: updateError } = await supabase
        .from("inventory_items")
        .update({ quantity: remaining, status: remaining === 0 ? "Sold" : item.status, updated_at: new Date().toISOString() })
        .eq("id", item.id)
        .select()
        .single();

      if (updateError) {
        showAppMessage("Sale saved, but inventory quantity did not update: " + updateError.message);
        await loadAllData();
        return;
      }

      setItems(items.map((i) => (i.id === item.id ? mapItem(updatedItem) : i)));
    }

    const mapped = mapSale(saleData);
    setSales(editingSaleId ? sales.map((s) => (s.id === editingSaleId ? mapped : s)) : [mapped, ...sales]);
    setEditingSaleId(null);
    setSaleForm(blankSale);
    if (activeFlowModal?.type === "addSale") {
      setForgeSaleSaveSuccess({
        sale: mapped,
        itemName: mapped.itemName || saleRecord.itemName,
        quantity: mapped.quantitySold || qty || 1,
        destination: "Forge sales",
        saleWasEditing,
      });
    } else {
      setActiveTab("sales");
    }
    setVaultToast(saleWasEditing ? "Sale updated." : "Sale added.");
  }

  function startEditingSale(sale) {
    if (!ensureWorkspaceEditor(sale?.workspaceId || sale?.workspace_id || activeWorkspace?.id)) return;
    setEditingSaleId(sale.id);
    setSaleForm({
      ...blankSale,
      itemId: sale.itemId || "",
      manualItemName: sale.itemId ? "" : sale.itemName || "",
      saleDate: sale.saleDate || String(sale.createdAt || "").slice(0, 10),
      platform: normalizeSalesPlatform(sale.platform || ""),
      quantitySold: sale.quantitySold || 1,
      finalSalePrice: sale.finalSalePrice || "",
      shippingCharged: sale.shippingCharged || "",
      shippingCost: sale.shippingCost || "",
      platformFees: sale.platformFees || "",
      paymentProcessingFees: sale.paymentProcessingFees || "",
      suppliesCost: sale.suppliesCost || "",
      discountsRefunds: sale.discountsRefunds || "",
      costBasis: sale.costBasis || sale.itemCost || "",
      buyerName: sale.buyerName || "",
      referenceId: sale.referenceId || "",
      receiptImage: sale.receiptImage || sale.receiptImageUrl || "",
      notes: sale.notes,
    });
    openFlowModal("addSale", { size: "medium", source: "edit" });
  }

  async function deleteSale(id) {
    const sale = sales.find((entry) => entry.id === id);
    if (!sale) {
      showAppMessage("Sale could not be found.");
      return;
    }
    if (!ensureWorkspaceEditor(sale?.workspaceId || sale?.workspace_id || activeWorkspace?.id)) return;
    const confirmed = await confirmDestructive({
      title: "Delete sale?",
      message: `Delete this sale and return the items to inventory? This removes the sale record for ${sale?.itemName || "this item"}.`,
      confirmLabel: "Delete sale",
    });
    if (!confirmed) return;
    const now = new Date().toISOString();
    const saleId = String(id);
    const restoreLocally = () => {
      if (restoredSaleInventoryIdsRef.current.has(saleId)) {
        return {
          ok: true,
          alreadyRestored: true,
          items,
          restoredLines: [],
          missingLines: [],
          updatedItems: [],
        };
      }
      return restoreSaleItemsToInventory(items, sale, { now });
    };
    const markSaleInventoryRestored = () => {
      restoredSaleInventoryIdsRef.current.add(saleId);
      setSales((current) => current.map((entry) => (
        String(entry.id) === saleId ? { ...entry, inventoryRestoredAt: now } : entry
      )));
    };
    const applyRestoredItems = (restoration) => {
      if (!restoration.alreadyRestored) {
        setItems(restoration.items);
        restoredSaleInventoryIdsRef.current.add(saleId);
      }
    };
    const inventoryRestoreFailureMessage = "Sale could not be deleted because inventory could not be restored.";
    if (BETA_LOCAL_MODE || user?.id === "local-beta") {
      const restoration = restoreLocally();
      if (!restoration.ok) {
        showAppMessage(inventoryRestoreFailureMessage);
        return;
      }
      applyRestoredItems(restoration);
      setSales(sales.filter((sale) => sale.id !== id));
      if (editingSaleId === id) {
        setEditingSaleId(null);
        setSaleForm(blankSale);
      }
      setVaultToast("Sale deleted. Items returned to inventory.");
      return;
    }

    const isMissingRpc = (error) => {
      const message = String(error?.message || "");
      return error?.code === "42883"
        || error?.code === "PGRST202"
        || /function .*delete_sale_and_restore_inventory.* does not exist/i.test(message)
        || /could not find the function .*delete_sale_and_restore_inventory/i.test(message);
    };

    const { error: rpcError } = await supabase.rpc("delete_sale_and_restore_inventory", { target_sale_id: id });
    if (!rpcError) {
      const restoration = restoreLocally();
      if (restoration.ok) {
        applyRestoredItems(restoration);
      } else {
        await loadAllData();
      }
      setSales((current) => current.filter((saleEntry) => saleEntry.id !== id));
      if (editingSaleId === id) {
        setEditingSaleId(null);
        setSaleForm(blankSale);
      }
      setVaultToast("Sale deleted. Items returned to inventory.");
      return;
    }

    if (!isMissingRpc(rpcError)) {
      console.error("Could not delete sale and restore inventory", rpcError);
      showAppMessage(inventoryRestoreFailureMessage);
      return;
    }

    const restoration = restoreLocally();
    if (!restoration.ok) {
      showAppMessage(inventoryRestoreFailureMessage);
      return;
    }

    if (!restoration.alreadyRestored) {
      for (const restoredItem of restoration.updatedItems) {
        const updatePayload = {
          quantity: Number(restoredItem.quantity || 0),
          updated_at: restoredItem.updated_at || now,
        };
        if (restoredItem.status) updatePayload.status = restoredItem.status;
        const { error: restoreError } = await supabase
          .from("inventory_items")
          .update(updatePayload)
          .eq("id", restoredItem.id);
        if (restoreError) {
          console.error("Could not restore inventory before deleting sale", restoreError);
          showAppMessage(inventoryRestoreFailureMessage);
          await loadAllData();
          return;
        }
      }
      applyRestoredItems(restoration);
    }

    const { error } = await supabase.from("sales_records").delete().eq("id", id);
    if (error) {
      console.error("Inventory restored, but sale delete failed", error);
      markSaleInventoryRestored();
      showAppMessage("Sale inventory was restored, but the sale record could not be deleted. Please refresh before retrying.");
      return;
    }
    setSales(sales.filter((sale) => sale.id !== id));
    if (editingSaleId === id) {
      setEditingSaleId(null);
      setSaleForm(blankSale);
    }
    setVaultToast("Sale deleted. Items returned to inventory.");
  }

  function downloadCSV(filename, rows) {
    if (!rows.length) return showAppMessage("No data to export yet.");
    const headers = Object.keys(rows[0]);
    const csv = [headers.join(","), ...rows.map((row) => headers.map((h) => `"${String(row[h] ?? "").replaceAll('"', '""')}"`).join(","))].join("\n");
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = filename;
    link.click();
    URL.revokeObjectURL(url);
    setVaultToast("Export complete.");
  }

  function downloadBackup() {
    const backup = createBetaBackup();
    const blob = new Blob([JSON.stringify(backup, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `ember-tide-beta-backup-${new Date().toISOString().slice(0, 10)}.json`;
    link.click();
    URL.revokeObjectURL(url);
    setBackupImportMessage("Backup exported. Keep this file somewhere safe before clearing browser data or switching phones.");
    setVaultToast("Backup exported.");
  }

