              {(auditLogs.slice(0, 5)).map((entry) => (
                <article className="admin-compact-row" key={entry.id}>
                  <div><strong>{entry.action}</strong><p>{entry.entityType} | {shortDate(entry.createdAt)}</p></div>
                  <span className="status-badge">audit</span>
                </article>
              ))}
